def capture_game_config_defaults() -> None:
    if _GAME_CONFIG_DEFAULTS:
        return
    for key, target in game_config_targets().items():
        _GAME_CONFIG_DEFAULTS[key] = decode_json(encode_json(target), {})


def deep_merge_dict(base: Dict[str, Any], override: Dict[str, Any]) -> Dict[str, Any]:
    merged = decode_json(encode_json(base), {})
    for key, value in (override or {}).items():
        if isinstance(value, dict) and isinstance(merged.get(key), dict):
            merged[key] = deep_merge_dict(merged[key], value)
        else:
            merged[key] = value
    return merged


def ensure_game_settings_table(conn: sqlite3.Connection) -> None:
    conn.execute("""
        CREATE TABLE IF NOT EXISTS game_settings (
            key TEXT PRIMARY KEY,
            value_json TEXT NOT NULL,
            updated_at TEXT NOT NULL,
            updated_by TEXT
        )
    """)


def game_setting_rows(conn: sqlite3.Connection) -> Dict[str, Dict[str, Any]]:
    ensure_game_settings_table(conn)
    out: Dict[str, Dict[str, Any]] = {}
    for r in rows(conn, "SELECT * FROM game_settings"):
        out[str(r["key"])] = dict(r)
    return out


def apply_runtime_game_settings(conn: sqlite3.Connection) -> None:
    capture_game_config_defaults()
    ensure_game_settings_table(conn)
    saved = game_setting_rows(conn)
    targets = game_config_targets()
    for key, target in targets.items():
        default = decode_json(encode_json(_GAME_CONFIG_DEFAULTS.get(key, {})), {})
        override = decode_json((saved.get(key) or {}).get("value_json"), {}) if saved.get(key) else {}
        next_value = deep_merge_dict(default, override) if isinstance(default, dict) and isinstance(override, dict) else default
        target.clear()
        target.update(next_value)


def save_game_config_override(conn: sqlite3.Connection, key: str, value: Dict[str, Any], updated_by: str) -> None:
    if key not in game_config_targets():
        raise HTTPException(404, f"Unknown game config group: {key}")
    if not isinstance(value, dict):
        raise HTTPException(400, "Game config value must be a JSON object")
    ensure_game_settings_table(conn)
    conn.execute(
        "INSERT INTO game_settings (key,value_json,updated_at,updated_by) VALUES (?,?,?,?) ON CONFLICT(key) DO UPDATE SET value_json=excluded.value_json, updated_at=excluded.updated_at, updated_by=excluded.updated_by",
        (key, encode_json(value), iso(), updated_by),
    )
    apply_runtime_game_settings(conn)


def reset_game_config_override(conn: sqlite3.Connection, key: str) -> None:
    if key not in game_config_targets():
        raise HTTPException(404, f"Unknown game config group: {key}")
    ensure_game_settings_table(conn)
    conn.execute("DELETE FROM game_settings WHERE key=?", (key,))
    apply_runtime_game_settings(conn)


def reset_all_game_config_overrides(conn: sqlite3.Connection) -> None:
    ensure_game_settings_table(conn)
    conn.execute("DELETE FROM game_settings")
    apply_runtime_game_settings(conn)


def build_game_tuning_state(conn: sqlite3.Connection, user: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    apply_runtime_game_settings(conn)
    saved = game_setting_rows(conn)
    groups = []
    for key, value in game_config_targets().items():
        default_value = _GAME_CONFIG_DEFAULTS.get(key, {})
        record = saved.get(key) or {}
        groups.append({
            "key": key,
            "label": key.replace("_", " ").title(),
            "description": GAME_CONFIG_DESCRIPTIONS.get(key, "Runtime game tuning."),
            "value": decode_json(encode_json(value), {}),
            "default": decode_json(encode_json(default_value), {}),
            "override": decode_json(record.get("value_json"), {}) if record else None,
            "changed": bool(record),
            "updated_at": record.get("updated_at"),
            "updated_by": record.get("updated_by"),
        })
    return {
        "enabled": bool((user or {}).get("god_mode")),
        "client_runtime": decode_json(encode_json(CLIENT_RUNTIME_BALANCE), {}),
        "groups": groups,
        "help": "Edit JSON and save. Saved overrides persist in SQLite game_settings and apply immediately without rebuilding.",
    }



