def loop_set_recipe_from_module(module: Dict[str, Any]) -> Dict[str, Any]:
    recipe = module["recipe"]
    return {
        "code": module["code"],
        "name": module["name"],
        "category": "Ship Modules",
        "description": f"{module['name']} tuned for the {module.get('set','')} gameplay loop.",
        "inputs": dict(recipe.get("inputs") or {}),
        "credits": int(recipe.get("credits") or 0),
        "energy": int(recipe.get("energy") or 0),
        "craft_minutes": int(recipe.get("minutes") or 30),
        "required_jobs": list(recipe.get("jobs") or ["shipwright"]),
        "required_job_rank": int(recipe.get("job_rank") or 1),
        "required_skill_tree": recipe.get("skill") or "engineering",
        "required_skill_total": int(recipe.get("skill_total") or 6),
        "base_success": float(recipe.get("base_success") or 0.86),
        "xp": int(recipe.get("xp") or max(40, int(recipe.get("credits") or 1000) // 90)),
        "output": {"kind": "module", "module_code": module["code"], "qty": 1},
    }

CRAFTING_BASE_RECIPE_DEFINITIONS.extend([loop_set_recipe_from_module(m) for m in CRAFTING_LOOP_SET_BASE_MODULES])

