def recipe_base_code_from_variant(code: str) -> str:
    return str(code or "").split("__")[0]

def crafting_rank_config(rank_key: str) -> Dict[str, Any]:
    configs = get_crafting_rank_configs()
    for cfg in configs:
        if cfg["key"] == rank_key:
            return cfg
    return configs[0]

def recipe_output_family_code(output: Dict[str, Any]) -> str:
    if not output:
        return ""
    return str(output.get("module_code") or output.get("item_code") or "")

def recipe_variant_code(base_recipe_code: str, rank_key: str) -> str:
    return base_recipe_code if rank_key == "basic" else f"{base_recipe_code}__{rank_key}"

def item_variant_code(base_code: str, rank_key: str) -> str:
    return base_code if rank_key == "basic" else f"{base_code}__{rank_key}"

def module_variant_code(base_code: str, rank_key: str) -> str:
    return base_code if rank_key == "basic" else f"{base_code}__{rank_key}"

def recipe_variant_display_name(base_name: str, rank_key: str, rank_name: str) -> str:
    prefix = CRAFTING_RANK_PREFIX.get(rank_key, rank_name)
    return base_name if not prefix else f"{prefix} {base_name}"

def scale_recipe_stat_value(value: Any, mult: float) -> Any:
    if isinstance(value, (int, float)):
        if isinstance(value, float) and abs(value) < 3:
            return round(value * mult, 2)
        return max(1, int(round(float(value) * mult)))
    return value

def build_ranked_recipe_definitions() -> List[Dict[str, Any]]:
    families = {
        recipe_output_family_code(r.get("output") or {}): (r.get("output") or {}).get("kind", "item")
        for r in CRAFTING_BASE_RECIPE_DEFINITIONS
        if recipe_output_family_code(r.get("output") or {})
    }
    out: List[Dict[str, Any]] = []
    for base in CRAFTING_BASE_RECIPE_DEFINITIONS:
        output = dict(base.get("output") or {})
        output_kind = output.get("kind") or "item"
        output_family = recipe_output_family_code(output)
        module_set = MODULE_SET_FAMILIES.get(recipe_base_code_from_variant(output_family), {})
        for rank_cfg in get_crafting_rank_configs():
            rank_key = rank_cfg["key"]
            rank_name = rank_cfg["name"]
            recipe = {
                "code": recipe_variant_code(base["code"], rank_key),
                "base_recipe_code": base["code"],
                "name": recipe_variant_display_name(base["name"], rank_key, rank_name),
                "category": base["category"],
                "description": (base.get("description") or "") + ("" if rank_key == "basic" else f" {rank_name} pattern. Higher output quality, stronger stats, and a consumable recipe copy."),
                "required_jobs": list(base.get("required_jobs", [])),
                "required_job_rank": int(base.get("required_job_rank", 1)),
                "required_skill_tree": base.get("required_skill_tree", ""),
                "required_skill_total": max(0, int(base.get("required_skill_total", 0)) + max(0, rank_cfg["tier"] - 1) * int(RANKED_CRAFTING_BALANCE.get("skill_total_per_rank_above_basic", 3))),
                "credits": max(0, int(round(int(base.get("credits") or 0) * rank_cfg["cost_mult"]))),
                "energy": max(0, int(round(int(base.get("energy") or 0) * (1.0 + (rank_cfg["tier"] - 1) * float(RANKED_CRAFTING_BALANCE.get("energy_mult_per_rank_above_basic", 0.28)))))),
                "craft_minutes": max(1, int(round(int(base.get("craft_minutes") or 0) * rank_cfg["time_mult"]))),
                "base_success": max(0.42, min(0.98, float(base.get("base_success") or 0.85) + float(rank_cfg["success_adj"]))),
                "xp": max(1, int(round(int(base.get("xp") or 0) * rank_cfg["xp_mult"]))),
                "recipe_rank_key": rank_key,
                "recipe_rank_name": rank_name,
                "unlock_model": rank_cfg["unlock_model"],
                "set_code": module_set.get("set_code", ""),
                "set_name": module_set.get("set_name", ""),
                "recipe_family": output_family,
            }
            inputs = {}
            req_tiers = {}
            for input_code, input_qty in (base.get("inputs") or {}).items():
                family = recipe_base_code_from_variant(input_code)
                if family in families and families[family] == "item":
                    ingredient_code = item_variant_code(family, rank_key)
                    if rank_cfg["tier"] >= 2:
                        req_tiers[ingredient_code] = max(1, rank_cfg["tier"] - 1)
                else:
                    ingredient_code = input_code
                inputs[ingredient_code] = max(1, int(math.ceil(float(input_qty) * float(rank_cfg["input_mult"]))))
            recipe["inputs"] = inputs
            recipe["required_material_tiers"] = req_tiers
            if output_kind == "module":
                recipe["output"] = {"kind": "module", "module_code": module_variant_code(str(output.get("module_code") or ""), rank_key), "qty": int(output.get("qty") or 1), "tier": rank_cfg["tier"], "set_code": module_set.get("set_code", ""), "set_name": module_set.get("set_name", "")}
            else:
                qty = max(1, int(output.get("qty") or 1) + int(rank_cfg.get("output_qty_bonus", 0)))
                recipe["output"] = {
                    "kind": "item",
                    "item_code": item_variant_code(str(output.get("item_code") or ""), rank_key),
                    "name": recipe_variant_display_name(output.get("name") or base["name"], rank_key, rank_name),
                    "qty": qty,
                    "item_type": output.get("item_type") or "goods",
                    "category": output.get("category") or inventory_category(output.get("item_type", "goods"), int(output.get("legal", 1) or 1)),
                    "legal": int(output.get("legal", 1) or 1),
                    "base_value": max(1, int(round(int(output.get("base_value") or max(1, int(base.get("credits") or 1))) * rank_cfg["item_value_mult"]))),
                    "mass": float(output.get("mass") or 1),
                    "rarity": rank_cfg.get("rarity", output.get("rarity") or "common"),
                    "description": (output.get("description") or base.get("description") or "") + ("" if rank_key == "basic" else f" {rank_name} quality output."),
                    "tier": rank_cfg["tier"],
                    "maxTier": rank_cfg["tier"],
                    "outputTier": rank_cfg["tier"],
                }
            out.append(recipe)
    return out

