def job_rank_from_metrics(job_code: str, xp: int, metrics: Dict[str, int]) -> int:
    profile = JOB_PROFILE.get(job_code, {})
    primary = profile.get("primary", "runs")
    value = profile.get("value", "value")
    rank = 1
    for req in JOB_RANK_THRESHOLDS:
        if xp >= req["xp"] and metrics.get(primary, 0) >= req["primary"] and metrics.get(value, 0) >= req["value"]:
            rank = req["rank"]
    return rank


def job_next_requirement(job_code: str, xp: int, metrics: Dict[str, int]) -> Dict[str, Any]:
    profile = JOB_PROFILE.get(job_code, {})
    primary = profile.get("primary", "runs")
    value = profile.get("value", "value")
    current = job_rank_from_metrics(job_code, xp, metrics)
    next_req = next((r for r in JOB_RANK_THRESHOLDS if r["rank"] == min(10, current + 1)), JOB_RANK_THRESHOLDS[-1])
    return {
        "current_rank": current,
        "next_rank": min(10, current + 1),
        "xp_needed": max(0, next_req["xp"] - xp),
        "primary_metric": primary,
        "primary_needed": max(0, next_req["primary"] - metrics.get(primary, 0)),
        "value_metric": value,
        "value_needed": max(0, next_req["value"] - metrics.get(value, 0)),
    }


