def clamp_int(value: int, low: int = 1, high: int = 100) -> int:
    return max(low, min(high, int(value)))


def planet_npc_profile_from_seed(p: tuple) -> tuple[int, int, int, int, int, int, int, int]:
    # p = (galaxy_id, code, name, type, x, y, security, market, customs, pirates, defense, medical)
    typ = str(p[3]).lower()
    security = int(p[6]); market = int(p[7]); customs = int(p[8]); pirates = int(p[9]); defense = int(p[10]); medical = int(p[11])
    base_pop = {
        "core": 8_500_000,
        "trade": 3_800_000,
        "jump": 1_600_000,
        "shadow": 920_000,
        "dark": 780_000,
        "freeport": 1_150_000,
        "industrial": 2_400_000,
        "shipyard": 1_250_000,
        "mining": 640_000,
        "research": 1_100_000,
        "ancient": 260_000,
    }
    population = 750_000
    for key, val in base_pop.items():
        if key in typ:
            population = val
            break
    density = clamp_int((population // 120_000) + market // 3 + security // 8, 20, 95)
    activity = clamp_int(market * 0.62 + (100 - pirates) * 0.12 + population / 180_000, 20, 95)
    friendly = clamp_int((security + medical + market) / 3 - pirates * 0.18, 8, 92)
    hostile = clamp_int(pirates * 0.72 + (100 - security) * 0.25, 5, 95)
    lawful = clamp_int((security + customs + defense) / 3, 8, 95)
    economy_bias = clamp_int(market * 0.75 + population / 200_000, 20, 96)
    criminal_bias = clamp_int(pirates * 0.8 + (100 - customs) * 0.25, 8, 94)
    return int(population), int(density), int(activity), int(friendly), int(hostile), int(lawful), int(economy_bias), int(criminal_bias)


