def target_npc_count_for_planet(planet: Dict[str, Any]) -> int:
    # Represents active simulated NPC actors, not literal census. Population and density both matter.
    population = int(planet.get("population") or 250000)
    density = int(planet.get("npc_density") or 50)
    activity = int(planet.get("npc_activity") or 50)
    base = int((population ** 0.32) + density * 0.45 + activity * 0.25)
    return clamp_int(base, 18, 120)


