def build_mission_action_message_library() -> Dict[str, Dict[str, List[str]]]:
    libraries: Dict[str, Dict[str, List[str]]] = {}
    for mission_key, parts in MISSION_TEXT_PARTS.items():
        libraries[mission_key] = {}
        subjects = parts.get("subject") or ["object"]
        places = parts.get("place") or ["route"]
        for outcome, openers in MISSION_OUTCOME_OPENERS.items():
            endings = MISSION_OUTCOME_ENDINGS[outcome]
            templates: List[str] = []
            idx = 0
            while len(templates) < 200:
                opener = openers[idx % len(openers)]
                subj = subjects[idx % len(subjects)]
                place = places[(idx // len(subjects)) % len(places)]
                ending = endings[(idx // (len(subjects) * len(places))) % len(endings)]
                templates.append(opener + f" Around the {place}, the {subj} keeps things interesting. " + ending)
                idx += 1
            libraries[mission_key][outcome] = templates[:200]
    return libraries


MISSION_ACTION_MESSAGE_LIBRARY = build_mission_action_message_library()


def mission_tier_label_from_difficulty(difficulty: int) -> str:
    diff = max(1, int(difficulty or 1))
    if diff <= 12:
        return "Tier 1"
    if diff <= 22:
        return "Tier 2"
    if diff <= 38:
        return "Tier 3"
    if diff <= 60:
        return "Tier 4"
    return "Tier 5"


def mission_scene_hint_from_event(mission_key: str, reward_item: Optional[Dict[str, Any]], rng: random.Random) -> Tuple[str, str, str]:
    hints = MISSION_OBJECT_HINTS.get(mission_key) or ["relic"]
    if reward_item:
        code = str(reward_item.get("code") or "")
        name = str(reward_item.get("name") or label_for_api(code or "object"))
        if ultra_item_def(code):
            return ("item", code, name)
        if any(k in code for k in ["survey", "data", "sample"]):
            return ("material", "ore", name)
        if any(k in code for k in ["salvage", "relic", "plate", "core"]):
            return ("material", "salvage", name)
        if any(k in code for k in ["hazard", "containment", "catalyst"]):
            return ("material", "crystal", name)
        return ("material", rng.choice(hints), name)
    hint = rng.choice(hints)
    return ("material", hint, label_for_api(hint))


def mission_roll_outcome(rng: random.Random, level: int) -> str:
    # General = no reward. Success/critical success are the only XP/item sources.
    success_bonus = min(16, max(0, int(level or 1) // 4))
    weights = [
        ("general", max(34, 48 - success_bonus)),
        ("failure", max(11, 20 - success_bonus // 3)),
        ("critical_failure", max(4, 8 - success_bonus // 5)),
        ("success", min(38, 20 + success_bonus)),
        ("critical_success", min(12, 4 + success_bonus // 3)),
    ]
    total = sum(w for _, w in weights)
    pick = rng.randint(1, total)
    cursor = 0
    for key, weight in weights:
        cursor += weight
        if pick <= cursor:
            return key
    return "general"


def mission_event_xp_roll(rng: random.Random, level: int, difficulty: int, critical: bool = False) -> int:
    lvl = max(1, int(level or 1))
    diff = max(1, int(difficulty or 1))
    base = rng.randint(4, 9) + int(lvl * 0.45) + int(diff * 0.08)
    if critical:
        base = int(math.ceil(base * rng.uniform(2.0, 2.65)))
    return max(1, int(base))


def mission_event_log(seed: str, cfg: Dict[str, Any], minutes: int, mission_key: str = "", planet: Optional[Dict[str, Any]] = None, reward_items: Optional[List[Dict[str, Any]]] = None, level: int = 1, difficulty: int = 1) -> List[Dict[str, Any]]:
    rng = random.Random(seed)
    mission_key = mission_key or next((k for k, v in (WORLD_MISSION_BALANCE.get("mission_types") or {}).items() if v == cfg), "survey")
    mission_library = MISSION_ACTION_MESSAGE_LIBRARY.get(mission_key) or MISSION_ACTION_MESSAGE_LIBRARY.get("survey") or {}
    count = max(10, min(18, int(minutes // 4) + 4))
    tier_label = mission_tier_label_from_difficulty(difficulty)
    trait_pool = MISSION_PLANET_TRAITS.get(mission_key) or ["mission zone"]
    objects = ["crooked beacon", "wobbling crate", "strange marker", "polite-looking rock", "half-buried relay", "micro-crater stash", "shimmering panel", "singed toolbox", "dusty scanner pod", "battered antenna", "sparky conduit", "mischievous rubble pile", "sealed locker", "old field cache", "tilted drone shell", "magnetic shard cluster"]
    center_ratio = 0.5
    reward_success_events: List[int] = []
    events: List[Dict[str, Any]] = []
    used_indexes: Dict[str, set] = {k: set() for k in MISSION_RESULT_PROFILE.keys()}

    # One ultra roll per mission. If it hits, attach it to a success/critical success event, not the mission preview.
    ultra_reward = roll_mission_ultra_reward(mission_key, level, seed)

    for i in range(count):
        outcome = mission_roll_outcome(rng, level)
        profile = MISSION_RESULT_PROFILE[outcome]
        templates = mission_library.get(outcome) or mission_library.get("general") or ["{resultLabel}: You continue through the mission zone. {endingLine}"]
        used = used_indexes.setdefault(outcome, set())
        while True:
            t_idx = rng.randint(0, len(templates) - 1)
            if t_idx not in used or len(used) >= len(templates) - 2:
                used.add(t_idx)
                template = templates[t_idx]
                break

        critical = outcome == "critical_success"
        reward_list: List[Dict[str, Any]] = []
        reward_xp = 0
        if outcome in {"success", "critical_success"}:
            reward_list = mission_success_item_roll(mission_key, cfg, level, center_ratio, rng, critical=critical)
            reward_xp = mission_event_xp_roll(rng, level, difficulty, critical=critical)
            reward_success_events.append(i)

        cd_range = profile.get("cooldown") or (0, 0)
        cooldown_add = rng.randint(int(cd_range[0]), int(cd_range[1])) if int(cd_range[1]) > 0 else 0
        cooldown_text = f"(+{cooldown_add} min mission cooldown)." if cooldown_add > 0 else ""
        primary_reward = (reward_list or [{}])[0]
        asset_type, asset_hint, scene_name = mission_scene_hint_from_event(mission_key, primary_reward if reward_list else None, rng)
        text = template.format(
            resultLabel=profile["label"],
            tierLabel=tier_label,
            itemName=primary_reward.get("name") or "field sample",
            cooldownText=cooldown_text,
            objectName=rng.choice(objects),
            planetName=(planet or {}).get("name") or "the surface",
            planetTrait=rng.choice(trait_pool),
            endingLine="",
            rewardXp=reward_xp,
        )
        events.append({
            "atPct": round((i + 1) / (count + 1), 3),
            "text": text,
            "kind": profile["kind"],
            "outcome": outcome,
            "resultLabel": profile["label"],
            "cooldownAddMinutes": cooldown_add,
            "rewardXp": reward_xp,
            "rewardItems": reward_list,
            "sceneAssetType": asset_type,
            "sceneAssetHint": asset_hint,
            "sceneObjectName": scene_name,
            "itemName": primary_reward.get("name") or "",
            "itemCode": primary_reward.get("code") or "",
        })

    if ultra_reward:
        target_indexes = [idx for idx, ev in enumerate(events) if ev.get("outcome") in {"success", "critical_success"}]
        if target_indexes:
            target_idx = rng.choice(target_indexes)
        else:
            target_idx = min(len(events) - 1, max(0, int(len(events) * 0.75)))
            events[target_idx]["outcome"] = "critical_success"
            events[target_idx]["kind"] = "crit_success"
            events[target_idx]["resultLabel"] = "Critical Success"
            events[target_idx]["rewardXp"] = max(8, mission_event_xp_roll(rng, level, difficulty, critical=True))
            events[target_idx]["rewardItems"] = []
        ultra_def = ultra_item_def(ultra_reward.get("code")) or {}
        events[target_idx]["rewardItems"] = list(events[target_idx].get("rewardItems") or []) + [ultra_reward]
        events[target_idx]["sceneAssetType"] = "item"
        events[target_idx]["sceneAssetHint"] = ultra_reward.get("code") or ""
        events[target_idx]["sceneObjectName"] = ultra_reward.get("name") or "Ultra discovery"
        events[target_idx]["itemName"] = ultra_reward.get("name") or ""
        events[target_idx]["itemCode"] = ultra_reward.get("code") or ""
        events[target_idx]["text"] = ultra_def.get("special_text") or f"Ultra Discovery: You uncover {ultra_reward.get('name') or 'an ultra item'}."

    return events


def player_planet_mission_cooldown_info(conn: sqlite3.Connection, player_id: int) -> Dict[str, Any]:
    rec = row(conn, "SELECT planet_mission_cooldown_until, planet_mission_cooldown_reason FROM players WHERE id=?", (player_id,)) or {}
    until = parse_dt(rec.get("planet_mission_cooldown_until"))
    now = utcnow()
    seconds = max(0, int((until - now).total_seconds())) if until else 0
    active = bool(until and seconds > 0)
    return {
        "active": active,
        "until": iso(until) if until and active else None,
        "secondsRemaining": seconds,
        "minutesRemaining": max(0, math.ceil(seconds / 60)) if active else 0,
        "reason": rec.get("planet_mission_cooldown_reason") or ("Mission cooldown active." if active else ""),
    }


def set_player_planet_mission_cooldown(conn: sqlite3.Connection, player_id: int, minutes: int, reason: str = "") -> Dict[str, Any]:
    minutes = clamp_int(int(minutes or 0), 0, int(WORLD_MISSION_BALANCE.get("mission_cooldown_cap_minutes", 120) or 120))
    if minutes <= 0:
        conn.execute("UPDATE players SET planet_mission_cooldown_until=NULL, planet_mission_cooldown_reason='' WHERE id=?", (player_id,))
        return {"active": False, "until": None, "secondsRemaining": 0, "minutesRemaining": 0, "reason": ""}
    until = utcnow() + timedelta(minutes=minutes)
    conn.execute("UPDATE players SET planet_mission_cooldown_until=?, planet_mission_cooldown_reason=? WHERE id=?", (iso(until), reason or f"Planet mission cooldown: {minutes} minutes.", player_id))
    return player_planet_mission_cooldown_info(conn, player_id)


def mission_cooldown_minutes_from_events(events: List[Dict[str, Any]], progress: float = 1.0) -> int:
    return int(aggregate_mission_event_rewards(events, progress).get("cooldown") or 0)


def mission_contracts_for_planet(conn: sqlite3.Connection, player: Dict[str, Any], planet: Dict[str, Any]) -> List[Dict[str, Any]]:
    mission_types = WORLD_MISSION_BALANCE.get("mission_types") or {}
    distribution = WORLD_MISSION_BALANCE.get("mission_distribution") or list(mission_types.keys())
    band = world_band_for_galaxy(conn, int(planet.get("galaxy_id") or 0))
    center_ratio = galaxy_progression_ratio(conn, row(conn, "SELECT * FROM galaxies WHERE id=?", (planet.get("galaxy_id"),)) or {})
    center_mult = 1.0 + center_ratio * (float(WORLD_MISSION_BALANCE.get("center_reward_multiplier_max", 3.0)) - 1.0)
    rng = random.Random(f"planet-contracts:{planet.get('id')}:{planet.get('type')}")
    picks = list(distribution)
    rng.shuffle(picks)
    picks = picks[:3]
    out = []
    active = active_planet_mission(conn, int(player["id"]))
    cooldown = player_planet_mission_cooldown_info(conn, int(player["id"]))
    for key in picks:
        cfg = mission_types.get(key) or {}
        prog = row(conn, "SELECT * FROM planet_mission_progress WHERE player_id=? AND planet_id=? AND mission_key=?", (player["id"], planet["id"], key)) or {}
        level = max(1, int(prog.get("level") or mission_level_from_xp(int(prog.get("xp") or 0))))
        time_mult = 1.0 + (level - 1) * float(WORLD_MISSION_BALANCE.get("mission_time_growth_pct_per_level", 0.10))
        base_minutes = rng.randint(int(WORLD_MISSION_BALANCE.get("mission_base_minutes_min", 30)), int(WORLD_MISSION_BALANCE.get("mission_base_minutes_max", 60)))
        minutes = int(base_minutes * time_mult)
        credits = 0
        xp = 0
        reward_items: List[Dict[str, Any]] = []
        difficulty = clamp_int(int((int(band.get("npc_level_min") or 1) + int(band.get("npc_level_max") or 10)) / 2) + level, 1, 120)
        can_start = not bool(active) and not bool(cooldown.get("active"))
        blocked_reason = "Mission already active" if active else (f"Cooldown {cooldown.get('minutesRemaining')} min" if cooldown.get("active") else "")
        out.append({"key": key, "name": cfg.get("name") or label_for_api(key), "description": f"{label_for_api(str(planet.get('type') or 'planet'))} contract. Planet mission level {level}; stronger contracts appear closer to center space.", "planetId": planet["id"], "planetName": planet.get("name"), "planetType": planet.get("type"), "level": level, "tierLabel": mission_tier_label_from_difficulty(difficulty), "planetMissionXp": int(prog.get("xp") or 0), "completed": int(prog.get("completed_count") or 0), "minutes": minutes, "rewardCredits": credits, "rewardXp": xp, "rewardItems": reward_items, "rewardText": "Rewards are rolled during the mission", "difficulty": difficulty, "tags": cfg.get("tags") or [], "canStart": can_start, "blockedReason": blocked_reason})
    return out


def active_planet_mission(conn: sqlite3.Connection, player_id: int) -> Optional[Dict[str, Any]]:
    mission = row(conn, """
        SELECT pmr.*, p.name as planet_name, p.type as planet_type, g.name as galaxy_name
        FROM planet_mission_runs pmr
        JOIN planets p ON p.id=pmr.planet_id
        JOIN galaxies g ON g.id=p.galaxy_id
        WHERE pmr.player_id=? AND pmr.status IN ('active','return_ready')
        ORDER BY CASE WHEN pmr.status='return_ready' THEN 0 ELSE 1 END, pmr.id DESC LIMIT 1
    """, (player_id,))
    if not mission:
        return None
    now = utcnow()
    started = parse_dt(mission.get("started_at")) or now
    done = parse_dt(mission.get("completes_at")) or now
    if mission.get("status") == "return_ready":
        progress = 1.0
        seconds_remaining = 0
    else:
        total = max(1, (done - started).total_seconds())
        progress = max(0.0, min(1.0, (now - started).total_seconds() / total))
        seconds_remaining = max(0, int((done - now).total_seconds()))
    all_events = decode_json(mission.get("event_log_json"), []) or []
    earned = aggregate_mission_event_rewards(all_events, progress)
    mission["progress"] = progress
    mission["secondsRemaining"] = seconds_remaining
    mission["eventLog"] = earned["events"]
    mission["totalEventCount"] = len(all_events)
    mission["rewardItems"] = earned["items"]
    mission["rewardXpEarned"] = earned["xp"]
    mission["rewardText"] = mission_reward_text(earned["items"], int(earned["xp"] or 0))
    mission["cooldownAccruedMinutes"] = earned["cooldown"]
    mission["cooldownProjectedMinutes"] = earned["cooldown"] if mission.get("status") == "return_ready" else 0
    mission["returnReady"] = mission.get("status") == "return_ready"
    return mission


def resolve_completed_planet_missions(conn: sqlite3.Connection, player_id: int, record_guild: bool = True) -> List[Dict[str, Any]]:
    completed = []
    now = utcnow()
    for m in rows(conn, "SELECT * FROM planet_mission_runs WHERE player_id=? AND status='active' AND completes_at<=?", (player_id, iso(now))):
        events = decode_json(m.get("event_log_json"), []) or []
        earned = aggregate_mission_event_rewards(events, 1.0)
        reward_items = earned["items"]
        personal_xp = int(earned["xp"] or 0)
        xp_gain = personal_xp
        if personal_xp:
            conn.execute("UPDATE players SET xp=xp+? WHERE id=?", (personal_xp, player_id))
        if reward_items:
            grant_planet_mission_item_rewards(conn, player_id, reward_items)
        progress = row(conn, "SELECT * FROM planet_mission_progress WHERE player_id=? AND planet_id=? AND mission_key=?", (player_id, m["planet_id"], m["mission_key"]))
        old_xp = int((progress or {}).get("xp") or 0)
        new_xp = old_xp + xp_gain
        new_level = mission_level_from_xp(new_xp)
        item_value = sum(int(i.get("qty") or 0) * int(i.get("baseValue") or i.get("base_value") or 0) for i in reward_items)
        if progress:
            conn.execute("UPDATE planet_mission_progress SET xp=?, level=?, completed_count=completed_count+1, total_rewards=total_rewards+?, updated_at=? WHERE id=?", (new_xp, new_level, item_value, iso(now), progress["id"]))
        else:
            conn.execute("INSERT INTO planet_mission_progress (player_id,planet_id,mission_key,xp,level,completed_count,total_rewards,updated_at) VALUES (?,?,?,?,?,?,?,?)", (player_id, m["planet_id"], m["mission_key"], new_xp, new_level, 1, item_value, iso(now)))
        cooldown_minutes = int(earned["cooldown"] or 0)
        cooldown = set_player_planet_mission_cooldown(conn, player_id, cooldown_minutes, f"Planet mission recovery time: {cooldown_minutes} minutes." if cooldown_minutes > 0 else "")
        reward_text = mission_reward_text(reward_items, personal_xp)
        suffix = f" Cooldown {cooldown_minutes} min." if cooldown_minutes > 0 else ""
        conn.execute(
            "UPDATE planet_mission_runs SET status='return_ready', reward_xp=?, reward_items_json=?, completed_at=?, message=? WHERE id=?",
            (personal_xp, encode_json(reward_items), iso(now), f"Mission complete. Recovered {reward_text}.{suffix}", m["id"])
        )
        grant_action_progression(conn, player_id, "planet_mission", 1.0 + new_level / 10, True)
        if record_guild:
            nova_safe_record_guild_contribution(conn, player_id, "mission", max(50, personal_xp + item_value // 10), 1, "planet_mission_complete", {"missionId": m["id"], "missionKey": m["mission_key"], "planetId": m["planet_id"], "personalXp": personal_xp, "itemValue": item_value})
        add_event(conn, player_id, "planet_mission", f"Completed {m.get('mission_name')} on planet mission level {new_level}.", {"missionId": m["id"], "items": reward_items, "personalXp": personal_xp, "missionXp": xp_gain, "level": new_level, "cooldownMinutes": cooldown_minutes})
        emit_player_metrics(conn, player_id, {
            "missions_completed": 1,
            "mission_reward_value": item_value,
        }, planet_id=m["planet_id"], metadata={"action": "planet_mission", "mission_id": m["id"], "mission_key": m.get("mission_key"), "mission_name": m.get("mission_name"), "level": new_level, "xp": personal_xp})
        queue_territory_influence(conn, player_id, m["planet_id"], "mission", max(2, 5 + new_level // 2), {"mission_id": m["id"], "mission_key": m.get("mission_key"), "level": new_level})
        completed.append({"id": m["id"], "items": reward_items, "personalXp": personal_xp, "level": new_level, "name": m.get("mission_name"), "cooldown": cooldown})
    return completed


def build_planet_missions_state(conn: sqlite3.Connection, player: Dict[str, Any]) -> Dict[str, Any]:
    resolve_completed_planet_missions(conn, int(player["id"]), record_guild=False)
    planet = row(conn, "SELECT p.*, g.name as galaxy_name FROM planets p JOIN galaxies g ON g.id=p.galaxy_id WHERE p.id=?", (player["location_planet_id"],))
    active = active_planet_mission(conn, int(player["id"]))
    contracts = mission_contracts_for_planet(conn, player, planet) if planet else []
    history = rows(conn, "SELECT pmr.*, p.name as planet_name FROM planet_mission_runs pmr JOIN planets p ON p.id=pmr.planet_id WHERE pmr.player_id=? ORDER BY pmr.id DESC LIMIT 20", (player["id"],))
    progress = rows(conn, "SELECT pmp.*, p.name as planet_name, p.type as planet_type FROM planet_mission_progress pmp JOIN planets p ON p.id=pmp.planet_id WHERE pmp.player_id=? ORDER BY pmp.updated_at DESC LIMIT 50", (player["id"],))
    cooldown = player_planet_mission_cooldown_info(conn, int(player["id"]))
    return {"location": planet, "contracts": contracts, "active": active, "history": history, "progress": progress, "cooldown": cooldown, "config": WORLD_MISSION_BALANCE}


def planet_mission_travel_state_key(player_id: int) -> str:
    return f"player:{int(player_id)}:planet_mission_travel"


def set_planet_mission_travel_intent(conn: sqlite3.Connection, player_id: int, meta: Dict[str, Any]) -> None:
    app_state_put_json(conn, planet_mission_travel_state_key(player_id), meta)


def get_planet_mission_travel_intent(conn: sqlite3.Connection, player_id: int) -> Dict[str, Any]:
    return app_state_get_json(conn, planet_mission_travel_state_key(player_id))


def clear_planet_mission_travel_intent(conn: sqlite3.Connection, player_id: int) -> None:
    app_state_delete(conn, planet_mission_travel_state_key(player_id))


def start_planet_mission_run(conn: sqlite3.Connection, player: Dict[str, Any], planet: Dict[str, Any], mission_key: str, god: bool = False) -> Dict[str, Any]:
    pid = int(player["id"])
    if active_planet_mission(conn, pid):
        raise HTTPException(409, "A planet mission is already active")
    cooldown = player_planet_mission_cooldown_info(conn, pid)
    if cooldown.get("active") and not god:
        raise HTTPException(409, f"Planet mission cooldown active for {cooldown.get('minutesRemaining')} more minutes")
    mission_key = str(mission_key or "").strip()
    contracts = mission_contracts_for_planet(conn, player, planet)
    contract = next((c for c in contracts if c["key"] == mission_key), None)
    if not contract:
        raise HTTPException(404, "Mission contract not available here")
    cfg = (WORLD_MISSION_BALANCE.get("mission_types") or {}).get(mission_key, {})
    starts = utcnow()
    completes = starts + timedelta(minutes=max(1, int(contract["minutes"])))
    events = mission_event_log(f"{pid}:{planet['id']}:{mission_key}:{iso(starts)}", cfg, int(contract["minutes"]), mission_key=mission_key, planet=planet, reward_items=[], level=int(contract.get("level") or 1), difficulty=int(contract.get("difficulty") or 1))
    conn.execute(
        """INSERT INTO planet_mission_runs
           (player_id,planet_id,mission_key,mission_name,status,level,reward_credits,reward_xp,reward_items_json,started_at,completes_at,event_log_json,message)
           VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (pid, planet["id"], mission_key, contract["name"], "active", contract["level"], 0, 0, encode_json([]), iso(starts), iso(completes), encode_json(events), "Mission in progress."),
    )
    run_id = int(scalar(conn, "SELECT last_insert_rowid()") or 0)
    add_event(conn, pid, "planet_mission", f"Started {contract['name']} on {planet['name']}.", {"missionId": run_id, "planetId": planet["id"], "missionKey": mission_key})
    return {"message": f"Started {contract['name']}. Return timer running.", "openPage": "Map", "missionId": run_id}


def rebalance_existing_npcs_for_world_progression(conn: sqlite3.Connection) -> int:
    adjusted = 0
    npc_rows = rows(conn, "SELECT n.*, p.galaxy_id FROM npc_agents n JOIN planets p ON p.id=n.planet_id WHERE COALESCE(n.alive,1)=1")
    for n in npc_rows:
        lo, hi = world_level_range_for_galaxy(conn, int(n.get("galaxy_id") or 0))
        current = int(n.get("level") or 1)
        if lo <= current <= hi:
            continue
        rng = random.Random(f"npc-world-reband:{n.get('id')}:{lo}:{hi}")
        mode_level = min(hi, max(lo, lo + int((hi - lo) * 0.35)))
        new_level = clamp_int(int(rng.triangular(lo, hi, mode_level)), lo, hi)
        new_xp = int(level_xp_required(new_level) * rng.uniform(0.10, 0.70)) if new_level > 1 else rng.randint(0, 300)
        rank = clamp_int(1 + new_level // 9, 1, 12)
        power = clamp_int(int((int(n.get("power") or 100) + new_level * 24) * rng.uniform(0.74, 1.08)), 25, 99999)
        conn.execute("UPDATE npc_agents SET level=?, xp=?, job_rank=?, power=?, last_action_at=? WHERE id=?", (new_level, new_xp, rank, power, iso(), n["id"]))
        adjusted += 1
    if adjusted:
        conn.execute(
            "INSERT INTO npc_action_log (planet_id,action_type,actor_name,message,impact_json,created_at) VALUES (?,?,?,?,?,?)",
            (None, "npc_world_rebalanced", "World Progression", f"Rebalanced {adjusted} existing NPCs into configured world-progression level bands.", encode_json({"adjusted": adjusted}), iso()),
        )
    return adjusted


_GALAXY_FACTION_CONTENT_LAST_RUN: float = 0.0
_GALAXY_FACTION_CONTENT_INTERVAL_SECONDS: float = 300.0  # 5 min


def _invalidate_galaxy_faction_content_guard() -> None:
    global _GALAXY_FACTION_CONTENT_LAST_RUN
    _GALAXY_FACTION_CONTENT_LAST_RUN = 0.0


def ensure_galaxy_faction_content(conn: sqlite3.Connection, force: bool = False) -> None:
    global _GALAXY_FACTION_CONTENT_LAST_RUN
    now_mono = time.monotonic()
    if not force and (now_mono - _GALAXY_FACTION_CONTENT_LAST_RUN) < _GALAXY_FACTION_CONTENT_INTERVAL_SECONDS:
        return
    _GALAXY_FACTION_CONTENT_LAST_RUN = now_mono
    now = iso()
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='factions'"):
        return
    for f in FACTION_SEED_DEFS:
        conn.execute(
            "INSERT INTO factions (code,name,color,description,home_galaxy_code) VALUES (?,?,?,?,?) ON CONFLICT(code) DO UPDATE SET name=excluded.name,color=excluded.color,description=excluded.description,home_galaxy_code=excluded.home_galaxy_code",
            (f["code"], f["name"], f["color"], f["description"], f["home_galaxy_code"]),
        )
    factions = {r["code"]: r for r in rows(conn, "SELECT * FROM factions")}
    for code, name, sector, color, desc, x, y, faction_code, home_depth, capturable in GALAXY_EXPANSION_SEED:
        faction = factions[faction_code]
        center_value = galaxy_center_value_from_xy(x, y)
        bonus = galaxy_control_bonus_from_value(center_value)
        existing = row(conn, "SELECT * FROM galaxies WHERE code=?", (code,))
        if existing:
            conn.execute(
                """
                UPDATE galaxies SET name=?, sector=?, color=?, description=?, x_pct=?, y_pct=?, faction_id=?, home_depth=?, capturable=?, center_value=?, control_bonus_pct=?
                WHERE code=?
                """,
                (name, sector, color, desc, float(x), float(y), faction["id"], int(home_depth), int(capturable), center_value, bonus, code),
            )
        else:
            conn.execute(
                "INSERT INTO galaxies (code,name,sector,color,description,x_pct,y_pct,faction_id,home_depth,capturable,center_value,control_bonus_pct) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)",
                (code, name, sector, color, desc, float(x), float(y), faction["id"], int(home_depth), int(capturable), center_value, bonus),
            )

    galaxy_rows = rows(conn, "SELECT g.*, f.code as faction_code FROM galaxies g LEFT JOIN factions f ON f.id=g.faction_id")
    galaxy_by_code = {g["code"]: g for g in galaxy_rows}
    # Create enough planets/objects per galaxy to make the map feel larger.
    for g in galaxy_rows:
        existing_count = int(scalar(conn, "SELECT COUNT(*) FROM planets WHERE galaxy_id=?", (g["id"],)) or 0)
        center_value = int(g.get("center_value") or galaxy_center_value_from_xy(g.get("x_pct") or 50, g.get("y_pct") or 50))
        danger_bias = center_value * 7
        base_seed = [
            ("gate", f"{g['code']}gate", f"{g['name']} Gate", "Jump Gate", 36, 14, 58, 56, 60, 30 + danger_bias, 68, 55),
            ("hub", f"{g['code']}hub", f"{g['name']} Hub", "Trade Station", -8, -4, 58, 72, 58, 24 + danger_bias, 62, 60),
            ("prime", f"{g['code']}prime", f"{g['name']} Prime", "Colony World", -28, 19, 55, 64, 55, 28 + danger_bias, 55, 58),
            ("belt", f"{g['code']}belt", f"{g['name']} Belt", "Mining Belt", 23, -26, 42, 58, 44, 38 + danger_bias, 46, 40),
            ("moon", f"{g['code']}moon", f"{g['name']} Moon", "Refinery Moon", -42, -21, 48, 70, 46, 34 + danger_bias, 58, 52),
            ("relay", f"{g['code']}relay", f"{g['name']} Relay", "Relay Station", 9, 31, 56, 62, 58, 32 + danger_bias, 64, 62),
            ("ruins", f"{g['code']}ruins", f"{g['name']} Ruins", "Ancient Ruins", -16, -36, 38, 52, 42, 48 + danger_bias, 42, 48),
            ("freeport", f"{g['code']}freeport", f"{g['name']} Freeport", "Freeport", 41, -11, 44, 82, 36, 54 + danger_bias, 50, 44),
        ]
        target_planets = max(4, int(WORLD_PROGRESSION_BALANCE.get("target_planets_per_galaxy", 8) or 8))
        if existing_count < target_planets:
            for _, code, name, typ, x, y, sec, market, customs, pirates, defense, med in base_seed[:target_planets]:
                current_count = int(scalar(conn, "SELECT COUNT(*) FROM planets WHERE galaxy_id=?", (g["id"],)) or 0)
                if current_count >= target_planets:
                    break
                if row(conn, "SELECT 1 FROM planets WHERE code=?", (code,)):
                    continue
                p = (g["id"], code, name, typ, x, y, clamp_int(sec - center_value * 2, 15, 95), clamp_int(market + center_value * 2, 15, 95), customs, clamp_int(pirates, 5, 95), defense, med)
                population, density, activity, friendly, hostile, lawful, economy_bias, criminal_bias = planet_npc_profile_from_seed(p)
                stability = clamp_int((p[6] + p[7] + p[10] + p[11]) / 4 - p[9] * 0.12 + p[8] * 0.05, 15, 95)
                conn.execute(
                    """INSERT INTO planets (galaxy_id,code,name,type,x,y,security_level,market_activity,customs_rating,pirate_activity,defense_strength,medical_quality,stability_level,population,npc_density,npc_activity,friendliness,hostility,lawfulness,npc_economy_bias,npc_criminal_bias,controller_type,tax_rate)
                       VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                    (*p, stability, population, density, activity, friendly, hostile, lawful, economy_bias, criminal_bias, "npc", 0.03),
                )

    normalize_all_planet_classes(conn)

    # Deterministic adjacency graph. Gates are the actual galaxy-to-galaxy travel edges.
    # Do not delete/reinsert here: /api/state can run concurrently and old code could
    # race itself into UNIQUE(route_key) crashes. Upsert each route instead.
    galaxies = rows(conn, "SELECT * FROM galaxies ORDER BY id")
    edges = set()
    # nearest 3 links per galaxy, de-duped
    for a in galaxies:
        ranked = []
        for b in galaxies:
            if int(a["id"]) == int(b["id"]):
                continue
            d = math.sqrt((float(a.get("x_pct") or 50) - float(b.get("x_pct") or 50)) ** 2 + (float(a.get("y_pct") or 50) - float(b.get("y_pct") or 50)) ** 2)
            ranked.append((d, a, b))
        for d, a, b in sorted(ranked, key=lambda x: (x[0], int(x[2]['id'])))[:3]:
            k = tuple(sorted((int(a["id"]), int(b["id"]))))
            edges.add(k)
    for a_id, b_id in sorted(edges):
        a_gate = row(conn, "SELECT * FROM planets WHERE galaxy_id=? AND type LIKE '%Gate%' ORDER BY id LIMIT 1", (a_id,))
        b_gate = row(conn, "SELECT * FROM planets WHERE galaxy_id=? AND type LIKE '%Gate%' ORDER BY id LIMIT 1", (b_id,))
        a = row(conn, "SELECT * FROM galaxies WHERE id=?", (a_id,))
        b = row(conn, "SELECT * FROM galaxies WHERE id=?", (b_id,))
        d = math.sqrt((float(a.get("x_pct") or 50) - float(b.get("x_pct") or 50)) ** 2 + (float(a.get("y_pct") or 50) - float(b.get("y_pct") or 50)) ** 2)
        for left, right, left_gate, right_gate in [(a_id, b_id, a_gate, b_gate), (b_id, a_id, b_gate, a_gate)]:
            conn.execute(
                """INSERT INTO galaxy_gates (from_galaxy_id,to_galaxy_id,from_planet_id,to_planet_id,distance,route_key)
                   VALUES (?,?,?,?,?,?)
                   ON CONFLICT(route_key) DO UPDATE SET
                     from_galaxy_id=excluded.from_galaxy_id,
                     to_galaxy_id=excluded.to_galaxy_id,
                     from_planet_id=excluded.from_planet_id,
                     to_planet_id=excluded.to_planet_id,
                     distance=excluded.distance""",
                (left, right, left_gate["id"] if left_gate else None, right_gate["id"] if right_gate else None, d, f"{left}:{right}"),
            )

    # Initialize planet faction control from galaxy control. Planet wars later override individual planets;
    # galaxy ownership flips only when every planet in that galaxy is controlled by the same faction.
    conn.execute("""
        UPDATE planets
        SET faction_id=(SELECT faction_id FROM galaxies WHERE galaxies.id=planets.galaxy_id)
        WHERE faction_id IS NULL
    """)
    sync_all_galaxy_control_from_planets(conn)

    # Assign factions to players that do not have one, balanced by id.
    faction_ids = [r["id"] for r in rows(conn, "SELECT * FROM factions ORDER BY id")]
    if faction_ids:
        for p in rows(conn, "SELECT id FROM players WHERE faction_id IS NULL"):
            conn.execute("UPDATE players SET faction_id=? WHERE id=?", (faction_ids[(int(p["id"]) - 1) % len(faction_ids)], p["id"]))


def player_faction(conn: sqlite3.Connection, player: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    fid = player.get("faction_id")
    if fid:
        return row(conn, "SELECT * FROM factions WHERE id=?", (fid,))
    factions = rows(conn, "SELECT * FROM factions ORDER BY id")
    if not factions:
        return None
    fid = factions[(int(player["id"]) - 1) % len(factions)]["id"]
    conn.execute("UPDATE players SET faction_id=? WHERE id=?", (fid, player["id"]))
    return row(conn, "SELECT * FROM factions WHERE id=?", (fid,))


def player_faction_code(conn: sqlite3.Connection, player: Dict[str, Any]) -> str:
    faction = player_faction(conn, player) if player else None
    return str((faction or {}).get("code") or DEFAULT_FACTION_CODE)


def territory_tables_ready(conn: sqlite3.Connection) -> bool:
    try:
        return bool(scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='territory_control_state'"))
    except Exception:
        return False


def territory_influence_map(value: Any) -> Dict[int, int]:
    raw = decode_json(value, {}) if isinstance(value, str) else (value or {})
    out: Dict[int, int] = {}
    if isinstance(raw, dict):
        for k, v in raw.items():
            try:
                fid = int(k)
                amt = int(v or 0)
                if fid > 0 and amt > 0:
                    out[fid] = amt
            except Exception:
                continue
    return out


def territory_supply_tier(points: int) -> Dict[str, Any]:
    best = {"tier": 0, "points": 0, "label": "Unstocked", "buff": {}}
    for tier in TERRITORY_CONTROL_BALANCE.get("supply_tiers", []):
        if int(points or 0) >= int(tier.get("points") or 0):
            best = tier
    return dict(best)


def ensure_territory_state_for_planet(conn: sqlite3.Connection, planet: Optional[Dict[str, Any]]) -> Optional[Dict[str, Any]]:
    if not planet or not territory_tables_ready(conn):
        return None
    now = iso()
    controlling_faction_id = int(planet.get("faction_id") or 0) or None
    conn.execute(
        """
        INSERT INTO territory_control_state
          (planet_id, controlling_faction_id, status, contested_by_faction_id, influence_json, supply_points, supply_tier, zone_buff_json, war_started_at, last_processed_at, updated_at)
        VALUES (?, ?, 'secure', NULL, '{}', 0, 0, '{}', NULL, NULL, ?)
        ON CONFLICT(planet_id) DO NOTHING
        """,
        (int(planet["id"]), controlling_faction_id, now),
    )
    state = row(conn, "SELECT * FROM territory_control_state WHERE planet_id=?", (int(planet["id"]),))
    if state and str(state.get("status") or "secure") == "secure" and int(state.get("controlling_faction_id") or 0) != int(controlling_faction_id or 0):
        conn.execute("UPDATE territory_control_state SET controlling_faction_id=?, updated_at=? WHERE planet_id=?", (controlling_faction_id, now, int(planet["id"])))
        state = row(conn, "SELECT * FROM territory_control_state WHERE planet_id=?", (int(planet["id"]),))
    return state


def territory_state_for_planet(conn: sqlite3.Connection, planet_id: Optional[int]) -> Optional[Dict[str, Any]]:
    if not planet_id or not territory_tables_ready(conn):
        return None
    planet = row(conn, "SELECT * FROM planets WHERE id=?", (int(planet_id),))
    if not planet:
        return None
    return ensure_territory_state_for_planet(conn, planet)


def territory_states_for_galaxy(conn: sqlite3.Connection, galaxy_id: int) -> List[Dict[str, Any]]:
    if not territory_tables_ready(conn):
        return []
    for p in rows(conn, "SELECT * FROM planets WHERE galaxy_id=?", (int(galaxy_id),)):
        ensure_territory_state_for_planet(conn, p)
    return rows(conn, """
        SELECT t.*, p.name AS planet_name, p.galaxy_id, p.faction_id AS planet_faction_id
        FROM territory_control_state t
        JOIN planets p ON p.id=t.planet_id
        WHERE p.galaxy_id=?
        ORDER BY t.status DESC, p.name
    """, (int(galaxy_id),))


def faction_planet_owner_counts(conn: sqlite3.Connection) -> Dict[int, int]:
    return {int(r["faction_id"]): int(r["count"]) for r in rows(conn, "SELECT faction_id, COUNT(*) as count FROM planets WHERE faction_id IS NOT NULL GROUP BY faction_id")}


def territory_declare_cost_multiplier(conn: sqlite3.Connection, faction_id: Optional[int], guild_id: Optional[int] = None) -> float:
    balance = TERRITORY_CONTROL_BALANCE
    counts = faction_planet_owner_counts(conn)
    owned_by_faction = int(counts.get(int(faction_id or 0), 0))
    owned_by_guild = guild_owned_planet_count(conn, int(guild_id or 0)) if guild_id else 0
    mult = 1.0
    mult += owned_by_faction * (float(balance.get("faction_owned_cost_step_pct", 8)) / 100.0)
    mult += owned_by_guild * (float(balance.get("guild_owned_cost_step_pct", 18)) / 100.0)
    if faction_id and counts:
        leader = max(counts.values() or [0])
        gap = max(0, leader - owned_by_faction)
        mult -= gap * (float(balance.get("losing_faction_discount_step_pct", 10)) / 100.0)
    return max(float(balance.get("min_declare_cost_multiplier", 0.45)), min(float(balance.get("max_declare_cost_multiplier", 4.0)), mult))


def territory_faction_batch_scale(conn: sqlite3.Connection, faction_id: int) -> float:
    counts = faction_planet_owner_counts(conn)
    owned = int(counts.get(int(faction_id), 0))
    leader = max(counts.values() or [owned])
    gap = max(0, leader - owned)
    weak_bonus = weak_faction_capture_bonus(conn, int(faction_id)) / 100.0
    expansion_drag = min(0.65, owned * 0.018)
    catchup = min(0.28, gap * 0.045)
    return max(0.35, 1.0 + weak_bonus + catchup - expansion_drag)


def queue_territory_influence(conn: sqlite3.Connection, player_id: int, planet_id: Optional[int], source: str, amount: int, metadata: Optional[Dict[str, Any]] = None, player: Optional[Dict[str, Any]] = None) -> None:
    if not planet_id or int(amount or 0) <= 0 or not territory_tables_ready(conn):
        return
    player_row = player or row(conn, "SELECT * FROM players WHERE id=?", (int(player_id),))
    faction = player_faction(conn, player_row) if player_row else None
    if not faction:
        return
    planet = row(conn, "SELECT * FROM planets WHERE id=?", (int(planet_id),))
    if not planet:
        return
    ensure_territory_state_for_planet(conn, planet)
    source_key = str(source or "activity").lower()
    cap = int((TERRITORY_CONTROL_BALANCE.get("source_amount_caps") or {}).get(source_key, 8))
    safe_amount = max(1, min(cap, int(amount or 0)))
    meta = dict(metadata or {})
    meta.setdefault("source", source_key)
    conn.execute(
        """
        INSERT INTO territory_influence_queue (planet_id, player_id, faction_id, source, amount, metadata_json, status, queued_at, processed_at)
        VALUES (?, ?, ?, ?, ?, ?, 'queued', ?, NULL)
        """,
        (int(planet_id), int(player_id), int(faction["id"]), source_key, safe_amount, encode_json(meta), iso()),
    )
    metric_meta = {"action": "territory_influence", "source": source_key, **meta}
    emit_player_metric(conn, int(player_id), "planet_influence_gained", safe_amount, player=player_row, planet_id=int(planet_id), metadata=metric_meta)
    state = territory_state_for_planet(conn, int(planet_id))
    if state and str(state.get("status") or "") in {"contested", "war"}:
        emit_player_metric(conn, int(player_id), "war_participation_score", safe_amount, player=player_row, planet_id=int(planet_id), metadata=metric_meta)


def process_territory_influence(conn: sqlite3.Connection, force: bool = False) -> int:
    if not territory_tables_ready(conn):
        return 0
    conn.execute("CREATE TABLE IF NOT EXISTS app_state (key TEXT PRIMARY KEY, value TEXT NOT NULL)")
    now = utcnow()
    last_row = row(conn, "SELECT value FROM app_state WHERE key='territory_influence_last_batch_at'")
    last = parse_dt(last_row.get("value")) if last_row else None
    interval = int(TERRITORY_CONTROL_BALANCE.get("batch_seconds", 300))
    if not force and last and (now - last).total_seconds() < interval:
        return 0
    conn.execute("INSERT INTO app_state (key,value) VALUES ('territory_influence_last_batch_at',?) ON CONFLICT(key) DO UPDATE SET value=excluded.value", (iso(now),))
    queued = rows(conn, """
        SELECT q.*, p.galaxy_id, p.faction_id AS current_faction_id
        FROM territory_influence_queue q
        JOIN planets p ON p.id=q.planet_id
        WHERE q.status='queued'
        ORDER BY q.id
        LIMIT ?
    """, (int(TERRITORY_CONTROL_BALANCE.get("queued_row_limit", 1200)),))
    if not queued:
        return 0
    grouped: Dict[Tuple[int, int], int] = {}
    players_by_group: Dict[Tuple[int, int], List[int]] = {}
    for q in queued:
        key = (int(q["planet_id"]), int(q["faction_id"]))
        grouped[key] = grouped.get(key, 0) + int(q.get("amount") or 0)
        if q.get("player_id"):
            players_by_group.setdefault(key, []).append(int(q["player_id"]))
    processed_planets = 0
    batch_cap = int(TERRITORY_CONTROL_BALANCE.get("per_planet_faction_batch_cap", 140))
    decay = int(TERRITORY_CONTROL_BALANCE.get("influence_decay_per_batch", 6))
    for planet_id in sorted({k[0] for k in grouped}):
        planet = row(conn, "SELECT * FROM planets WHERE id=?", (planet_id,))
        if not planet:
            continue
        state = ensure_territory_state_for_planet(conn, planet) or {}
        influence = territory_influence_map(state.get("influence_json"))
        touched_factions = {fid for (pid, fid), amt in grouped.items() if pid == planet_id and amt > 0}
        for fid in list(influence.keys()):
            if fid not in touched_factions:
                influence[fid] = max(0, int(influence.get(fid, 0)) - decay)
                if influence[fid] <= 0:
                    influence.pop(fid, None)
        for fid in touched_factions:
            raw = min(batch_cap, int(grouped.get((planet_id, fid), 0)))
            effective = max(1, int(raw * territory_faction_batch_scale(conn, fid)))
            influence[fid] = max(0, int(influence.get(fid, 0)) + effective)
        controller = int(planet.get("faction_id") or state.get("controlling_faction_id") or 0)
        challenger_id = 0
        challenger_score = 0
        for fid, score in influence.items():
            if int(fid) != controller and int(score) > challenger_score:
                challenger_id = int(fid)
                challenger_score = int(score)
        defender_score = int(influence.get(controller, 0)) if controller else 0
        status = "secure"
        war_started_at = state.get("war_started_at")
        if challenger_id and challenger_score >= int(TERRITORY_CONTROL_BALANCE.get("war_threshold", 100)):
            status = "war"
            if str(state.get("status") or "") != "war":
                war_started_at = iso(now)
                conn.execute("INSERT INTO npc_action_log (planet_id,action_type,actor_name,message,impact_json,created_at) VALUES (?,?,?,?,?,?)", (planet_id, "territory_war", "Faction war office", f"{planet.get('name') or 'A planet'} has entered WAR state.", encode_json({"severity":"danger", "challengerFactionId": challenger_id}), iso(now)))
        elif challenger_id and challenger_score >= int(TERRITORY_CONTROL_BALANCE.get("contested_threshold", 35)):
            status = "contested"
        flip_threshold = int(TERRITORY_CONTROL_BALANCE.get("control_flip_threshold", 220))
        if status == "war" and challenger_id and challenger_score >= flip_threshold and challenger_score >= defender_score + int(TERRITORY_CONTROL_BALANCE.get("war_threshold", 100)):
            old_controller = controller
            conn.execute("UPDATE planets SET faction_id=?, controller_type='npc', controller_id=NULL, war_cooldown_until=?, attack_cooldown_until=? WHERE id=?", (challenger_id, iso(now + timedelta(hours=6)), iso(now + timedelta(hours=6)), planet_id))
            influence = {old_controller: int(flip_threshold * 0.2)} if old_controller else {}
            controller = challenger_id
            challenger_id = None
            status = "secure"
            war_started_at = None
            sync_galaxy_control_from_planets(conn, int(planet.get("galaxy_id") or 0))
            conn.execute("INSERT INTO npc_action_log (planet_id,action_type,actor_name,message,impact_json,created_at) VALUES (?,?,?,?,?,?)", (planet_id, "territory_flip", "Faction war office", f"{planet.get('name') or 'A planet'} changed faction control.", encode_json({"severity":"danger", "winnerFactionId": controller, "oldFactionId": old_controller}), iso(now)))
        conn.execute(
            """
            UPDATE territory_control_state
            SET controlling_faction_id=?, status=?, contested_by_faction_id=?, influence_json=?, war_started_at=?, last_processed_at=?, updated_at=?
            WHERE planet_id=?
            """,
            (controller or None, status, challenger_id or None, encode_json({str(k): int(v) for k, v in influence.items() if int(v) > 0}), war_started_at, iso(now), iso(now), planet_id),
        )
        processed_planets += 1
    ids = [int(q["id"]) for q in queued]
    if ids:
        placeholders = ",".join(["?"] * len(ids))
        conn.execute(f"UPDATE territory_influence_queue SET status='processed', processed_at=? WHERE id IN ({placeholders})", tuple([iso(now), *ids]))
    return processed_planets


def territory_zone_modifier(conn: sqlite3.Connection, planet_id: Optional[int]) -> Dict[str, Any]:
    state = territory_state_for_planet(conn, int(planet_id or 0)) if planet_id else None
    if not state:
        return {"status": "secure", "war": False, "multiplier": 1.0, "buff": {}, "tier": 0}
    status = str(state.get("status") or "secure")
    buff = decode_json(state.get("zone_buff_json"), {}) or {}
    mult = 1.0
    if status == "war":
        mult *= float(TERRITORY_CONTROL_BALANCE.get("war_reward_multiplier", 1.25))
    mult *= 1.0 + (float(buff.get("reward_pct") or 0) / 100.0)
    return {"status": status, "war": status == "war", "multiplier": mult, "buff": buff, "tier": int(state.get("supply_tier") or 0)}


def territory_war_pressure_for_galaxy(conn: sqlite3.Connection, galaxy_id: int) -> int:
    if not territory_tables_ready(conn):
        return 0
    wars = int(scalar(conn, "SELECT COUNT(*) FROM territory_control_state t JOIN planets p ON p.id=t.planet_id WHERE p.galaxy_id=? AND t.status='war'", (int(galaxy_id),)) or 0)
    contested = int(scalar(conn, "SELECT COUNT(*) FROM territory_control_state t JOIN planets p ON p.id=t.planet_id WHERE p.galaxy_id=? AND t.status='contested'", (int(galaxy_id),)) or 0)
    return wars * int(TERRITORY_CONTROL_BALANCE.get("war_npc_traffic_bonus", 6)) + contested * 2


def build_territory_control_state(conn: sqlite3.Connection, player: Dict[str, Any], planet: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    planet = planet or row(conn, "SELECT * FROM planets WHERE id=?", (player.get("location_planet_id"),))
    if not planet or not territory_tables_ready(conn):
        return {"status": "secure", "available": False}
    state = ensure_territory_state_for_planet(conn, planet) or {}
    faction = player_faction(conn, player)
    influence = territory_influence_map(state.get("influence_json"))
    supply_tier = territory_supply_tier(int(state.get("supply_points") or 0))
    if int(state.get("supply_tier") or 0) != int(supply_tier.get("tier") or 0):
        conn.execute("UPDATE territory_control_state SET supply_tier=?, zone_buff_json=?, updated_at=? WHERE planet_id=?", (int(supply_tier.get("tier") or 0), encode_json(supply_tier.get("buff") or {}), iso(), int(planet["id"])))
        state = row(conn, "SELECT * FROM territory_control_state WHERE planet_id=?", (int(planet["id"]),)) or state
    galaxy_war_count = int(scalar(conn, "SELECT COUNT(*) FROM territory_control_state t JOIN planets p ON p.id=t.planet_id WHERE p.galaxy_id=? AND t.status IN ('war','contested')", (int(planet["galaxy_id"]),)) or 0)
    own_zone = faction and int(planet.get("faction_id") or 0) == int(faction["id"])
    eligible = bool(own_zone and (str(state.get("status") or "secure") in {"war", "contested"} or galaxy_war_count > 0))
    candidates = []
    if eligible:
        for inv in rows(conn, "SELECT item_code,name,item_type,category,qty,reserved_qty,base_value,mass,current_tier,craftable_material FROM inventory WHERE player_id=? AND qty>0 ORDER BY category, name LIMIT 60", (int(player["id"]),)):
            available = max(0, int(inv.get("qty") or 0) - int(inv.get("reserved_qty") or 0))
            category = str(inv.get("category") or "")
            item_type = str(inv.get("item_type") or "")
            if available <= 0:
                continue
            if category not in {"raw_materials", "crafting_materials", "refined_materials", "salvage", "goods"} and item_type not in {"ore", "gas", "crystal", "material", "component", "salvage", "scrap"} and not int(inv.get("craftable_material") or 0):
                continue
            candidates.append({"item_code": inv["item_code"], "name": inv["name"], "available_qty": available, "tier": int(inv.get("current_tier") or 1), "points_each": territory_supply_points_for_item(inv)})
            if len(candidates) >= 8:
                break
    return {
        "available": True,
        "planet_id": int(planet["id"]),
        "status": str(state.get("status") or "secure"),
        "controlling_faction_id": int(state.get("controlling_faction_id") or planet.get("faction_id") or 0) or None,
        "contested_by_faction_id": int(state.get("contested_by_faction_id") or 0) or None,
        "influence": [{"faction_id": fid, "amount": amt} for fid, amt in sorted(influence.items(), key=lambda kv: kv[1], reverse=True)[:5]],
        "supply": {
            "points": int(state.get("supply_points") or 0),
            "tier": int(state.get("supply_tier") or 0),
            "label": supply_tier.get("label"),
            "buff": decode_json(state.get("zone_buff_json"), {}) or supply_tier.get("buff") or {},
            "eligible": eligible,
            "items": candidates,
        },
        "batch_seconds": int(TERRITORY_CONTROL_BALANCE.get("batch_seconds", 300)),
        "galaxy_active_zones": galaxy_war_count,
    }


def territory_supply_points_for_item(item: Dict[str, Any]) -> int:
    tier = clamp_int(item.get("current_tier") or item.get("tier") or 1, 1, 10)
    value = max(0, int(item.get("base_value") or 0))
    category = str(item.get("category") or item.get("item_type") or "")
    category_bonus = 2 if category in {"crafting_materials", "refined_materials", "salvage"} else 1
    return clamp_int(1 + tier + value // 500 + category_bonus, 1, 14)


def run_territory_supply_delivery(conn: sqlite3.Connection, player: Dict[str, Any], item_code: str, qty: int, god: bool = False) -> Dict[str, Any]:
    planet = row(conn, "SELECT * FROM planets WHERE id=?", (player.get("location_planet_id"),))
    if not planet:
        raise HTTPException(404, "Planet not found")
    faction = player_faction(conn, player)
    if not faction:
        raise HTTPException(400, "Faction required")
    state_payload = build_territory_control_state(conn, player, planet)
    if not state_payload.get("supply", {}).get("eligible") and not god:
        raise HTTPException(400, "War supplies must be delivered to a faction-owned planet in a contested or war galaxy.")
    item_code = str(item_code or "").strip()
    qty = clamp_int(qty or 1, 1, 500)
    inv = row(conn, "SELECT * FROM inventory WHERE player_id=? AND item_code=?", (int(player["id"]), item_code))
    if not inv:
        raise HTTPException(404, "Supply item not found")
    available = max(0, int(inv.get("qty") or 0) - int(inv.get("reserved_qty") or 0))
    if available < qty and not god:
        raise HTTPException(400, "Not enough available supply material")
    points_each = territory_supply_points_for_item(inv)
    points = points_each * qty
    if not god:
        remove_inventory_item(conn, int(player["id"]), item_code, qty)
    state = territory_state_for_planet(conn, int(planet["id"])) or {}
    new_points = int(state.get("supply_points") or 0) + points
    tier = territory_supply_tier(new_points)
    conn.execute(
        "UPDATE territory_control_state SET supply_points=?, supply_tier=?, zone_buff_json=?, updated_at=? WHERE planet_id=?",
        (new_points, int(tier.get("tier") or 0), encode_json(tier.get("buff") or {}), iso(), int(planet["id"])),
    )
    conn.execute(
        "INSERT INTO territory_supply_deliveries (planet_id,player_id,faction_id,item_code,item_name,qty,points,created_at) VALUES (?,?,?,?,?,?,?,?)",
        (int(planet["id"]), int(player["id"]), int(faction["id"]), item_code, inv.get("name") or item_code, qty, points, iso()),
    )
    queue_territory_influence(conn, int(player["id"]), int(planet["id"]), "supply", max(1, points // 12), {"item": item_code, "qty": qty, "points": points}, player=player)
    emit_player_metric(conn, int(player["id"]), "war_participation_score", max(1, points // 6), player=player, planet_id=int(planet["id"]), metadata={"action": "territory_supply_delivery", "item": item_code, "qty": qty, "points": points})
    add_event(conn, int(player["id"]), "territory_supply", f"Delivered {qty}x {inv.get('name') or item_code} to {planet.get('name')} for {points} war supply points.", {"planetId": int(planet["id"]), "points": points, "supplyTier": tier})
    return {"message": f"Delivered {qty}x {inv.get('name') or item_code}. {planet.get('name')} supply tier is now {tier.get('label')}.", "territory_control": build_territory_control_state(conn, player, planet)}


def galaxy_gate_planet(conn: sqlite3.Connection, galaxy_id: int) -> Optional[Dict[str, Any]]:
    return row(conn, "SELECT * FROM planets WHERE galaxy_id=? AND type LIKE '%Gate%' ORDER BY id LIMIT 1", (galaxy_id,))


def galaxy_gate_neighbors(conn: sqlite3.Connection, galaxy_id: int) -> List[Dict[str, Any]]:
    return rows(conn, "SELECT gg.*, g.name as target_name, g.color as target_color, g.faction_id as target_faction_id FROM galaxy_gates gg JOIN galaxies g ON g.id=gg.to_galaxy_id WHERE gg.from_galaxy_id=? ORDER BY gg.distance", (galaxy_id,))


def galaxy_is_adjacent(conn: sqlite3.Connection, from_gid: int, to_gid: int) -> bool:
    return bool(row(conn, "SELECT 1 FROM galaxy_gates WHERE from_galaxy_id=? AND to_galaxy_id=?", (from_gid, to_gid)))


def galaxy_owner_counts(conn: sqlite3.Connection) -> Dict[int, int]:
    return {int(r["faction_id"]): int(r["count"]) for r in rows(conn, "SELECT faction_id, COUNT(*) as count FROM galaxies WHERE faction_id IS NOT NULL GROUP BY faction_id")}


def weak_faction_capture_bonus(conn: sqlite3.Connection, faction_id: int) -> int:
    if not FACTION_WAR_BALANCE.get("weak_faction_help_enabled", True):
        return 0
    counts = galaxy_owner_counts(conn)
    if not counts:
        return 0
    max_count = max(counts.values())
    own = int(counts.get(int(faction_id), 0))
    gap = max_count - own
    cfg = FACTION_WAR_BALANCE.get("weak_bonus_check") or {}
    if gap >= int(cfg.get("struggling_gap", 3)):
        return int(cfg.get("struggling_capture_bonus_pct", 18))
    if gap >= int(cfg.get("ok_gap", 1)):
        return int(cfg.get("ok_capture_bonus_pct", 8))
    return 0


def galaxy_capture_bonus(conn: sqlite3.Connection, galaxy: Dict[str, Any], faction_id: int) -> Dict[str, Any]:
    center_bonus = int(galaxy.get("control_bonus_pct") or galaxy_control_bonus_from_value(int(galaxy.get("center_value") or 1)))
    weak_bonus = weak_faction_capture_bonus(conn, faction_id)
    return {"center_bonus_pct": center_bonus, "weak_faction_capture_bonus_pct": weak_bonus, "total_capture_bonus_pct": center_bonus + weak_bonus}


def guild_member_count(conn: sqlite3.Connection, guild_id: int) -> int:
    return int(scalar(conn, "SELECT COUNT(*) FROM guild_members WHERE guild_id=?", (guild_id,)) or 0)


def guild_owned_planet_count(conn: sqlite3.Connection, guild_id: int) -> int:
    return int(scalar(conn, "SELECT COUNT(*) FROM planets WHERE controller_type='guild' AND controller_id=?", (guild_id,)) or 0)


def guild_planet_war_declare_cost(conn: sqlite3.Connection, guild_id: int, planet: Dict[str, Any]) -> int:
    owned = guild_owned_planet_count(conn, guild_id)
    base = int(FACTION_WAR_BALANCE.get("planet_war_base_declare_cost", 2500000))
    defense = int(planet.get("defense_strength") or 0) * int(FACTION_WAR_BALANCE.get("planet_war_defense_cost_mult", 25000))
    exp_base = float(FACTION_WAR_BALANCE.get("planet_war_owned_planet_cost_base", 1.65))
    faction_row = row(conn, """
        SELECT p.faction_id, COUNT(*) AS members
        FROM guild_members gm
        JOIN players p ON p.id=gm.player_id
        WHERE gm.guild_id=? AND p.faction_id IS NOT NULL
        GROUP BY p.faction_id
        ORDER BY members DESC
        LIMIT 1
    """, (int(guild_id),))
    faction_id = int((faction_row or {}).get("faction_id") or 0)
    multiplier = territory_declare_cost_multiplier(conn, faction_id, guild_id)
    return int((base + defense) * (exp_base ** owned) * multiplier)


def sync_galaxy_control_from_planets(conn: sqlite3.Connection, galaxy_id: Optional[int] = None) -> None:
    gids = [int(galaxy_id)] if galaxy_id else [int(r["id"]) for r in rows(conn, "SELECT id FROM galaxies")]
    for gid in gids:
        g = row(conn, "SELECT * FROM galaxies WHERE id=?", (gid,))
        if not g or not int(g.get("capturable") or 0):
            continue
        planet_factions = [int(r["faction_id"]) for r in rows(conn, "SELECT DISTINCT faction_id FROM planets WHERE galaxy_id=? AND faction_id IS NOT NULL", (gid,))]
        planet_count = int(scalar(conn, "SELECT COUNT(*) FROM planets WHERE galaxy_id=?", (gid,)) or 0)
        controlled_count = int(scalar(conn, "SELECT COUNT(*) FROM planets WHERE galaxy_id=? AND faction_id IS NOT NULL", (gid,)) or 0)
        if planet_count > 0 and controlled_count == planet_count and len(planet_factions) == 1:
            conn.execute("UPDATE galaxies SET faction_id=? WHERE id=?", (planet_factions[0], gid))


def sync_all_galaxy_control_from_planets(conn: sqlite3.Connection) -> None:
    for g in rows(conn, "SELECT id FROM galaxies"):
        sync_galaxy_control_from_planets(conn, int(g["id"]))


def faction_can_declare_on_planet(conn: sqlite3.Connection, faction_id: int, guild_id: int, planet: Dict[str, Any]) -> Tuple[bool, str]:
    if not planet:
        return False, "Planet not found."
    galaxy = row(conn, "SELECT * FROM galaxies WHERE id=?", (planet["galaxy_id"],))
    if not galaxy:
        return False, "Galaxy not found."
    if not int(galaxy.get("capturable") or 0):
        return False, "Planets in home/shield galaxies are not capturable."
    if int(planet.get("faction_id") or 0) == int(faction_id):
        return False, "Your faction already controls this planet."
    cd = planet.get("war_cooldown_until") or planet.get("attack_cooldown_until")
    if cd and parse_dt(cd) and parse_dt(cd) > utcnow():
        return False, "Planet is on post-war cooldown."
    if row(conn, "SELECT 1 FROM planet_faction_wars WHERE planet_id=? AND status IN ('declared','active')", (planet["id"],)):
        return False, "A guild has already declared war on this planet."
    if guild_member_count(conn, guild_id) < int(FACTION_WAR_BALANCE.get("min_guild_members_to_declare", 10)):
        return False, f"Guild needs at least {FACTION_WAR_BALANCE.get('min_guild_members_to_declare', 10)} members to declare."
    # Beachhead rule: planet is in your galaxy, adjacent to owned galaxy, or your faction already controls at least one planet in the galaxy.
    same_galaxy_planet = row(conn, "SELECT 1 FROM planets WHERE galaxy_id=? AND faction_id=?", (planet["galaxy_id"], faction_id))
    adjacent_owned_galaxy = row(conn, "SELECT 1 FROM galaxy_gates gg JOIN galaxies g ON g.id=gg.to_galaxy_id WHERE gg.from_galaxy_id=? AND g.faction_id=?", (planet["galaxy_id"], faction_id))
    galaxy_owned = int(galaxy.get("faction_id") or 0) == int(faction_id)
    if not (same_galaxy_planet or adjacent_owned_galaxy or galaxy_owned):
        return False, "Planet wars require an adjacent faction-owned galaxy or an existing faction foothold in this galaxy."
    return True, "Can declare planet war."


def planet_war_side_for_faction(war: Dict[str, Any], faction_id: int) -> str:
    if int(faction_id) == int(war.get("attacking_faction_id") or 0):
        return "attacker"
    if int(faction_id) == int(war.get("defending_faction_id") or 0):
        return "defender"
    return "blocked"


def process_guild_planet_xp_bonus(conn: sqlite3.Connection) -> None:
    now = utcnow()
    xp_each = int(FACTION_WAR_BALANCE.get("guild_hourly_xp_per_planet", 40))
    respect_each = int(FACTION_WAR_BALANCE.get("guild_hourly_respect_per_planet", 5))
    for g in rows(conn, "SELECT * FROM guilds"):
        last = parse_dt(g.get("last_planet_xp_at")) or now
        hours = int((now - last).total_seconds() // 3600)
        if hours <= 0:
            if not g.get("last_planet_xp_at"):
                conn.execute("UPDATE guilds SET last_planet_xp_at=? WHERE id=?", (iso(now), g["id"]))
            continue
        owned = guild_owned_planet_count(conn, int(g["id"]))
        if owned > 0:
            gain = owned * xp_each * hours
            respect_gain = owned * respect_each * hours
            conn.execute("UPDATE guilds SET xp=xp+?, respect=respect+?, last_planet_xp_at=? WHERE id=?", (gain, respect_gain, iso(now), g["id"]))
        else:
            conn.execute("UPDATE guilds SET last_planet_xp_at=? WHERE id=?", (iso(now), g["id"]))


def active_or_upcoming_planet_wars(conn: sqlite3.Connection) -> List[Dict[str, Any]]:
    return rows(conn, """
        SELECT w.*, p.name as planet_name, p.x as planet_x, p.y as planet_y, p.type as planet_type,
               g.name as galaxy_name, g.control_bonus_pct, g.center_value,
               ag.name as declaring_guild_name,
               af.name as attacking_faction_name, af.color as attacking_faction_color,
               df.name as defending_faction_name, df.color as defending_faction_color,
               wf.name as winner_faction_name
        FROM planet_faction_wars w
        JOIN planets p ON p.id=w.planet_id
        JOIN galaxies g ON g.id=w.galaxy_id
        JOIN guilds ag ON ag.id=w.declaring_guild_id
        JOIN factions af ON af.id=w.attacking_faction_id
        LEFT JOIN factions df ON df.id=w.defending_faction_id
        LEFT JOIN factions wf ON wf.id=w.winner_faction_id
        WHERE w.status IN ('declared','active')
        ORDER BY w.opens_at, w.id
    """)


def resolved_planet_faction_wars(conn: sqlite3.Connection) -> List[Dict[str, Any]]:
    return rows(conn, """
        SELECT w.*, p.name as planet_name, g.name as galaxy_name, wf.name as winner_faction_name, ag.name as declaring_guild_name
        FROM planet_faction_wars w
        JOIN planets p ON p.id=w.planet_id
        JOIN galaxies g ON g.id=w.galaxy_id
        JOIN guilds ag ON ag.id=w.declaring_guild_id
        LEFT JOIN factions wf ON wf.id=w.winner_faction_id
        WHERE w.status='resolved'
        ORDER BY w.id DESC LIMIT 30
    """)


def active_or_upcoming_galaxy_wars(conn: sqlite3.Connection) -> List[Dict[str, Any]]:
    # Backward-compatible alias: war is now planet-level; galaxies flip only after all planets are controlled.
    return active_or_upcoming_planet_wars(conn)


def process_galaxy_wars(conn: sqlite3.Connection, player: Optional[Dict[str, Any]] = None) -> None:
    process_planet_faction_wars(conn, player)


def process_planet_faction_wars(conn: sqlite3.Connection, player: Optional[Dict[str, Any]] = None, resolve_global: bool = True) -> None:
    now = utcnow()
    if resolve_global:
        for w in rows(conn, "SELECT * FROM planet_faction_wars WHERE status='declared' AND opens_at<=?", (iso(now),)):
            conn.execute("UPDATE planet_faction_wars SET status='active', message=? WHERE id=?", ("Planet capture zone is now active.", w["id"]))

    if player:
        faction = player_faction(conn, player)
        current_planet = row(conn, "SELECT * FROM planets WHERE id=?", (player["location_planet_id"],))
        travel = build_travel_state(conn, player)
        if faction and current_planet:
            wars = rows(conn, "SELECT * FROM planet_faction_wars WHERE status='active' AND galaxy_id=?", (current_planet["galaxy_id"],))
            if wars:
                active_map = build_system_map_shallow(conn, player)
                node_by_id = {int(n["id"]): n for n in active_map.get("nodes", []) if str(n.get("id") or "").isdigit()}
                point = {"x_pct": -999.0, "y_pct": -999.0}
                if travel.get("open_space") and travel.get("open_space_map_type") == "system":
                    point = {"x_pct": float(travel.get("open_space_x_pct") or 50), "y_pct": float(travel.get("open_space_y_pct") or 50)}
                elif travel.get("active") and travel.get("mode") in {"local", "waypoint", "intercept"}:
                    o = node_by_id.get(int(travel.get("origin_planet_id") or current_planet["id"]))
                    if travel.get("mode") in {"waypoint", "intercept"} and travel.get("destination_x_pct") is not None:
                        d = {"x_pct": float(travel.get("destination_x_pct") or 50), "y_pct": float(travel.get("destination_y_pct") or 50)}
                    else:
                        d = node_by_id.get(int(travel.get("destination_planet_id") or current_planet["id"]))
                    if o and d:
                        p = map_point_between(o, d, float(travel.get("progress") or 0))
                        point = {"x_pct": p["x_pct"], "y_pct": p["y_pct"]}
                # Docked players are not inside a war ring until they undock/move into open space.
                for w in wars:
                    side = planet_war_side_for_faction(w, int(faction["id"]))
                    planet_node = node_by_id.get(int(w["planet_id"]))
                    inside = 0
                    if side in {"attacker", "defender"} and planet_node:
                        dist = math.sqrt((point["x_pct"] - float(planet_node.get("x_pct") or 50)) ** 2 + (point["y_pct"] - float(planet_node.get("y_pct") or 50)) ** 2)
                        inside = 1 if dist <= float(FACTION_WAR_BALANCE.get("capture_ring_radius_pct", 10.5)) else 0
                    # Third faction cannot enter the ring once war starts.
                    conn.execute(
                        "INSERT INTO planet_war_presence (war_id,player_id,faction_id,side,inside_ring,x_pct,y_pct,last_seen) VALUES (?,?,?,?,?,?,?,?) ON CONFLICT(war_id,player_id) DO UPDATE SET faction_id=excluded.faction_id, side=excluded.side, inside_ring=excluded.inside_ring, x_pct=excluded.x_pct, y_pct=excluded.y_pct, last_seen=excluded.last_seen",
                        (w["id"], player["id"], faction["id"], side, inside, point["x_pct"], point["y_pct"], iso(now)),
                    )

    stale_before = iso(now - timedelta(seconds=75))
    conn.execute("DELETE FROM planet_war_presence WHERE last_seen<?", (stale_before,))
    if not resolve_global:
        return

    for w in rows(conn, "SELECT * FROM planet_faction_wars WHERE status='active'"):
        pres = rows(conn, "SELECT side, faction_id, COUNT(*) as count FROM planet_war_presence WHERE war_id=? AND inside_ring=1 AND side IN ('attacker','defender') GROUP BY side,faction_id", (w["id"],))
        sides = {r["side"]: int(r["faction_id"]) for r in pres if int(r["count"] or 0) > 0}
        if len(sides) == 1:
            holder = next(iter(sides.values()))
            if int(w.get("capture_owner_faction_id") or 0) != holder or not w.get("capture_started_at"):
                conn.execute("UPDATE planet_faction_wars SET capture_owner_faction_id=?, capture_started_at=?, message=? WHERE id=?", (holder, iso(now), "One war side controls the planet capture ring. Hold countdown started.", w["id"]))
            else:
                started = parse_dt(w.get("capture_started_at"))
                if started and now >= started + timedelta(seconds=int(FACTION_WAR_BALANCE.get("capture_hold_seconds", 300))):
                    cooldown = now + timedelta(hours=float(FACTION_WAR_BALANCE.get("post_capture_cooldown_hours", 24)))
                    winner = holder
                    declaring_guild_id = int(w.get("declaring_guild_id") or 0)
                    controller_type = "guild" if winner == int(w.get("attacking_faction_id") or 0) else "npc"
                    controller_id = declaring_guild_id if controller_type == "guild" else None
                    conn.execute("UPDATE planets SET faction_id=?, controller_type=?, controller_id=?, war_cooldown_until=?, attack_cooldown_until=? WHERE id=?", (winner, controller_type, controller_id, iso(cooldown), iso(cooldown), w["planet_id"]))
                    conn.execute("UPDATE planet_faction_wars SET status='resolved', resolved_at=?, winner_faction_id=?, cooldown_until=?, message=? WHERE id=?", (iso(now), winner, iso(cooldown), "Planet captured by faction king-of-the-hill control.", w["id"]))
                    if controller_type == "guild":
                        conn.execute("UPDATE guilds SET respect=respect+2500, xp=xp+1000 WHERE id=?", (declaring_guild_id,))
                    sync_galaxy_control_from_planets(conn, int(w["galaxy_id"]))
                    conn.execute("DELETE FROM planet_war_presence WHERE war_id=?", (w["id"],))
        else:
            if w.get("capture_started_at") or w.get("capture_owner_faction_id"):
                conn.execute("UPDATE planet_faction_wars SET capture_owner_faction_id=NULL, capture_started_at=NULL, message=? WHERE id=?", ("Capture countdown reset. Both sides contested or ring is empty.", w["id"]))


def build_system_map_shallow(conn: sqlite3.Connection, player: Dict[str, Any]) -> Dict[str, Any]:
    current = row(conn, "SELECT * FROM planets WHERE id=?", (player["location_planet_id"],))
    if not current:
        return {"nodes": []}
    planets = rows(conn, "SELECT * FROM planets WHERE galaxy_id=? ORDER BY name", (current["galaxy_id"],))
    nodes = []
    for p in planets:
        nodes.append({
            "id": p["id"],
            "name": p["name"],
            "x_pct": round(max(7, min(93, 50 + float(p.get("x") or 0) / 2.3)), 2),
            "y_pct": round(max(8, min(92, 50 + float(p.get("y") or 0) / 2.3)), 2),
        })
    return {"nodes": nodes, "current_planet_id": current["id"], "current_galaxy_id": current["galaxy_id"]}


def build_galaxy_map_shallow(conn: sqlite3.Connection, player: Dict[str, Any]) -> Dict[str, Any]:
    current_planet = row(conn, "SELECT * FROM planets WHERE id=?", (player["location_planet_id"],))
    current_gid = int(current_planet.get("galaxy_id") if current_planet else 0)
    nodes = []
    for g in rows(conn, "SELECT g.*, f.name as faction_name, f.color as faction_color FROM galaxies g LEFT JOIN factions f ON f.id=g.faction_id ORDER BY g.id"):
        node = dict(g)
        node.update({"x_pct": float(g.get("x_pct") or 50), "y_pct": float(g.get("y_pct") or 50), "current": int(g["id"]) == current_gid})
        nodes.append(node)
    return {"nodes": nodes, "current_galaxy_id": current_gid}


def build_galaxy_map(conn: sqlite3.Connection, player: Dict[str, Any]) -> Dict[str, Any]:
    # Global war resolution is advanced by the background world tick. Map building
    # only reads the latest known state and leaves presentation sorting to the client.
    current_planet = row(conn, "SELECT * FROM planets WHERE id=?", (player["location_planet_id"],))
    current_gid = int(current_planet.get("galaxy_id") if current_planet else 0)
    planets = rows(conn, "SELECT * FROM planets")
    travel = build_travel_state(conn, player)
    visited_galaxies = set(travel.get("visited_galaxies") or []) | {current_gid}
    pf = player_faction(conn, player)
    territory_counts = {}
    if territory_tables_ready(conn):
        territory_counts = {
            int(r["galaxy_id"]): {"war": int(r["war_count"] or 0), "contested": int(r["contested_count"] or 0)}
            for r in rows(conn, """
                SELECT p.galaxy_id,
                       SUM(CASE WHEN t.status='war' THEN 1 ELSE 0 END) AS war_count,
                       SUM(CASE WHEN t.status='contested' THEN 1 ELSE 0 END) AS contested_count
                FROM planets p
                LEFT JOIN territory_control_state t ON t.planet_id=p.id
                GROUP BY p.galaxy_id
            """)
        }
    nodes = []
    for g in rows(conn, "SELECT g.*, f.name as faction_name, f.color as faction_color, f.code as faction_code FROM galaxies g LEFT JOIN factions f ON f.id=g.faction_id ORDER BY g.id"):
        gps = [p for p in planets if int(p.get("galaxy_id") or 0) == int(g["id"])]
        def avg(key: str, default: int = 50) -> int:
            return int(sum(int(p.get(key) or default) for p in gps) / max(1, len(gps)))
        node = dict(g)
        can_declare, declare_reason = (False, "Galaxy control flips only after all planets in the galaxy are captured.")
        bonus = galaxy_capture_bonus(conn, g, pf["id"] if pf else 0) if pf else {}
        tc = territory_counts.get(int(g["id"]), {"war": 0, "contested": 0})
        node.update({
            "x_pct": round(clamp_pct(float(g.get("x_pct") or 50), 2, 98), 2),
            "y_pct": round(clamp_pct(float(g.get("y_pct") or 50), 2, 98), 2),
            "current": int(g["id"]) == current_gid,
            "visited": int(g["id"]) in visited_galaxies,
            "planet_count": len(gps),
            "station_count": len([p for p in gps if "station" in str(p.get("type") or "").lower()]),
            "gate_count": len([p for p in gps if "gate" in str(p.get("type") or "").lower()]),
            "security_avg": avg("security_level"),
            "market_activity_avg": avg("market_activity"),
            "conflict_avg": avg("conflict_level", 20),
            "faction_influence": int(sum(int(p.get("player_influence") or 0) for p in gps) / max(1, len(gps))),
            "capturable": bool(int(g.get("capturable") or 0)),
            "home_depth": int(g.get("home_depth") or 99),
            "center_value": int(g.get("center_value") or 1),
            "control_bonus_pct": int(g.get("control_bonus_pct") or 0),
            "can_declare_war": bool(can_declare),
            "declare_reason": declare_reason,
            "player_faction_owned": bool(pf and int(g.get("faction_id") or 0) == int(pf["id"])),
            "capture_station_x_pct": float(FACTION_WAR_BALANCE.get("capture_station_x_pct", 50.0)),
            "capture_station_y_pct": float(FACTION_WAR_BALANCE.get("capture_station_y_pct", 50.0)),
            "capture_bonus": bonus,
            "territory_war_count": int(tc.get("war") or 0),
            "contested_zone_count": int(tc.get("contested") or 0),
            "territory_status": "war" if int(tc.get("war") or 0) else "contested" if int(tc.get("contested") or 0) else "secure",
            "image_url": galaxy_visual_payload(g),
        })
        nodes.append(node)

    node_by_id = {int(n["id"]): n for n in nodes}
    lanes = []
    visited_routes = set(travel.get("visited_galaxy_routes") or [])
    for gg in rows(conn, "SELECT * FROM galaxy_gates ORDER BY from_galaxy_id,to_galaxy_id"):
        if int(gg["from_galaxy_id"]) > int(gg["to_galaxy_id"]):
            continue
        a = node_by_id.get(int(gg["from_galaxy_id"]))
        b = node_by_id.get(int(gg["to_galaxy_id"]))
        if not a or not b:
            continue
        key = route_key(a["id"], b["id"])
        active = travel.get("active") and travel.get("mode") in {"galaxy", "galaxy_route"} and key == route_key(travel.get("origin_galaxy_id"), travel.get("destination_galaxy_id"))
        lanes.append({"from": a["id"], "to": b["id"], "key": key, "visited": key in visited_routes, "active": bool(active), "gate": True})

    # Performance rule: galaxy view is gate navigation only.
    # No NPC AI, signatures, scans, or combat objects are built here.
    event_sites = build_server_event_map_sites(conn, player, nodes, "galaxy", int(current_gid or 0))
    scan_area = scan_area_profile_for_player(conn, player, "galaxy")
    scan_blips = build_scan_area_blips(conn, player, nodes, "galaxy")
    scan_pings = build_scan_area_pings(conn, player, "galaxy")
    separate_stationary_map_objects([nodes, event_sites, scan_blips])
    annotate_object_scan_unlocks(conn, player, nodes, "galaxy", int(current_gid or 0))
    annotate_object_scan_unlocks(conn, player, scan_blips, "galaxy", int(current_gid or 0))
    ship = active_ship_for_player(conn, player)
    radar_range = ship_radar_range_pct(conn, ship, "galaxy")
    radar_center = player_map_center(conn, player, "galaxy", nodes)
    summary = {
        "ships_in_transit": 0,
        "ore_signatures": 0,
        "ancient_sites": 0,
        "server_events": len(event_sites),
        "wrecks": 0,
        "hostile_contacts": 0,
        "risk_band": "Regional",
        "security_level": int(sum([n.get("security_avg", 50) for n in nodes]) / max(1, len(nodes))),
        "radar_range_pct": radar_range,
        "radar_center_x_pct": round(float(radar_center.get("x_pct") or 50), 2),
        "radar_center_y_pct": round(float(radar_center.get("y_pct") or 50), 2),
        "hidden_by_radar": 0,
        "scan_area": scan_area,
        "player_faction": pf,
        "war_count": len(active_or_upcoming_planet_wars(conn)),
        "readable_hint": f"Galaxy map is gate-only. Select a destination galaxy; autopilot follows connected gate lanes. Local objects exist only in system view. Radar boundary: {radar_range}%.",
        "nearby_opportunities": ["Gate lanes", "Faction borders", "Gate destinations"],
    }
    return {"nodes": nodes, "lanes": lanes, "current_galaxy_id": current_gid, "traffic": [], "ore_sites": [], "exploration_sites": [], "event_sites": event_sites, "war_zones": [], "scan_blips": scan_blips, "scan_pings": scan_pings, "summary": summary}

    return {"nodes": nodes, "lanes": lanes, "current_galaxy_id": current_gid, "traffic": traffic, "ore_sites": ore_sites, "exploration_sites": exploration_sites, "event_sites": event_sites, "war_zones": war_zones, "summary": summary}



def build_system_map(conn: sqlite3.Connection, player: Dict[str, Any]) -> Dict[str, Any]:
    current = row(conn, "SELECT * FROM planets WHERE id=?", (player["location_planet_id"],))
    if not current:
        return {"nodes": [], "lanes": [], "current_planet_id": None, "current_galaxy_id": None}
    ensure_planet_classes_applied(conn)
    current = row(conn, "SELECT * FROM planets WHERE id=?", (player["location_planet_id"],))
    travel = build_travel_state(conn, player)
    planets = rows(conn, "SELECT * FROM planets WHERE galaxy_id=? ORDER BY name", (current["galaxy_id"],))
    visited_planets = set(travel.get("visited_planets") or []) | {int(current["id"])}
    local_routes = set(travel.get("visited_local_routes") or [])
    ops_counts = {r["planet_id"]: r["count"] for r in rows(conn, "SELECT planet_id, COUNT(*) as count FROM pve_operations WHERE planet_id IS NOT NULL GROUP BY planet_id")}
    pf = player_faction(conn, player)
    player_guild_id = int(player.get("guild_id") or 0)
    faction_by_id = {int(f["id"]): f for f in rows(conn, "SELECT * FROM factions")}
    territory_by_planet = {int(t["planet_id"]): t for t in territory_states_for_galaxy(conn, int(current["galaxy_id"]))}
    galaxy_owner_faction_id = int((row(conn, "SELECT faction_id FROM galaxies WHERE id=?", (int(current["galaxy_id"]),)) or {}).get("faction_id") or 0)
    nodes = []
    for p in planets:
        effects = planet_control_effects(p)
        territory_state = territory_by_planet.get(int(p["id"])) or ensure_territory_state_for_planet(conn, p) or {}
        territory_status = str(territory_state.get("status") or "secure")
        territory_influence = territory_influence_map(territory_state.get("influence_json"))
        legal_strength = int((int(p.get("market_activity") or 50) + int(p.get("stability_level") or 60) + int(p.get("security_level") or 50)) / 3)
        illicit_strength = int((int(p.get("market_activity") or 50) + int(p.get("pirate_activity") or 40) + (100 - int(p.get("security_level") or 50))) / 3)
        node = dict(p)
        can_declare, declare_reason = (False, "")
        declare_cost = 0
        if pf and player_guild_id:
            can_declare, declare_reason = faction_can_declare_on_planet(conn, int(pf["id"]), player_guild_id, p)
            declare_cost = guild_planet_war_declare_cost(conn, player_guild_id, p)
        owner_faction = faction_by_id.get(int(p.get("faction_id") or 0))
        p_type = str(p.get("type") or "")
        is_uninhabitable = is_uninhabitable_planet_type(p_type)
        node.update({
            "kind":"planet",
            "x_pct": round(max(7, min(93, 50 + float(p.get("x") or 0) / 2.3)), 2),
            "y_pct": round(max(8, min(92, 50 + float(p.get("y") or 0) / 2.3)), 2),
            "current": int(p["id"]) == int(current["id"]),
            "visited": int(p["id"]) in visited_planets,
            "legal_market_strength": clamp_int(legal_strength, 1, 99),
            "illicit_market_strength": clamp_int(illicit_strength, 1, 99),
            "available_operations": int(ops_counts.get(p["id"], 0) or 0),
            "risk_level": clamp_int(int(effects["travel_danger"]) + (10 if territory_status == "war" else 5 if territory_status == "contested" else 0), 1, 99),
            "is_gate": "gate" in p_type.lower(),
            "is_uninhabitable": bool(is_uninhabitable),
            "isUninhabitable": bool(is_uninhabitable),
            "details_label": f"Uninhabitable Planet — {p_type}" if is_uninhabitable else p_type,
            "mission_contracts": mission_contracts_for_planet(conn, player, p) if is_uninhabitable else [],
            "faction_name": owner_faction.get("name") if owner_faction else "Neutral",
            "faction_color": owner_faction.get("color") if owner_faction else "",
            "can_declare_planet_war": bool(can_declare),
            "declare_reason": declare_reason,
            "declare_cost": declare_cost,
            "territory_status": territory_status,
            "territory_war": territory_status == "war",
            "territory_contested": territory_status == "contested",
            "territory_influence": [{"faction_id": fid, "amount": amt} for fid, amt in sorted(territory_influence.items(), key=lambda kv: kv[1], reverse=True)[:3]],
            "territory_supply_tier": int(territory_state.get("supply_tier") or 0),
            "territory_supply_buff": decode_json(territory_state.get("zone_buff_json"), {}) or {},
            "is_border_system": bool(territory_status in {"contested", "war"} or (galaxy_owner_faction_id and int(p.get("faction_id") or 0) != galaxy_owner_faction_id)),
            "image_url": planet_visual_payload(p)
        })
        nodes.append(node)

    gate_planet = galaxy_gate_planet(conn, int(current["galaxy_id"]))
    gate_node = next((n for n in nodes if gate_planet and int(n["id"]) == int(gate_planet["id"])), None)
    gate_links = galaxy_gate_neighbors(conn, int(current["galaxy_id"]))
    for idx, gg in enumerate(gate_links):
        angle = (math.pi * 2 * idx / max(1, len(gate_links))) - math.pi / 2
        gx = clamp_pct((float(gate_node.get("x_pct") if gate_node else 50) + math.cos(angle) * 16), 3, 97)
        gy = clamp_pct((float(gate_node.get("y_pct") if gate_node else 50) + math.sin(angle) * 16), 3, 97)
        nodes.append({
            "id": f"gate:{gg['to_galaxy_id']}",
            "kind": "gate",
            "name": f"Gate to {gg['target_name']}",
            "type": "Galaxy Gate",
            "target_galaxy_id": int(gg["to_galaxy_id"]),
            "target_faction_id": gg.get("target_faction_id"),
            "x_pct": gx,
            "y_pct": gy,
            "current": False,
            "visited": False,
            "risk_level": 35,
            "security_level": 50,
            "stability_level": 50,
            "legal_market_strength": 0,
            "illicit_market_strength": 0,
            "available_operations": 0,
            "image_url": item_visual_payload("Galaxy Gate", "gate", "ship_modules", 1).get("image_url"),
        })

    lanes = []
    for i, a in enumerate([n for n in nodes if n.get("kind") == "planet"]):
        for b in [n for n in nodes if n.get("kind") == "planet"][i+1:]:
            key = route_key(a["id"], b["id"])
            active = travel.get("active") and travel.get("mode") == "local" and key == route_key(travel.get("origin_planet_id"), travel.get("destination_planet_id"))
            lanes.append({"from": a["id"], "to": b["id"], "key": key, "visited": key in local_routes, "active": bool(active)})
    if gate_node:
        for n in nodes:
            if n.get("kind") == "gate":
                lanes.append({"from": gate_node["id"], "to": n["id"], "key": f"gate:{current['galaxy_id']}:{n['target_galaxy_id']}", "visited": False, "active": False, "gate": True})

    for n in nodes:
        n["x_pct"] = clamp_pct((float(n.get("x_pct") or 50) - 50) * 1.45 + 50, 2, 98)
        n["y_pct"] = clamp_pct((float(n.get("y_pct") or 50) - 50) * 1.45 + 50, 2, 98)

    ore_all = build_open_world_ore_sites(conn, player, nodes, "system")
    salvage_all = build_map_salvage_icons(conn, player["location_planet_id"])
    exploration_all = build_open_world_exploration_sites(conn, player, nodes, "system")
    pirate_station_all = build_system_pirate_stations(conn, player, nodes, int(current["galaxy_id"]))
    player_base_all = build_player_bases_for_map(conn, player, int(current["galaxy_id"]))
    event_sites_all = build_server_event_map_sites(conn, player, nodes, "system", int(current["galaxy_id"]), int(current["id"]))
    separate_stationary_map_objects([nodes, ore_all, salvage_all, exploration_all, pirate_station_all, player_base_all, event_sites_all])
    traffic_all = build_open_world_traffic(conn, player, "system", nodes, ore_all + salvage_all + exploration_all + pirate_station_all + player_base_all + event_sites_all)
    ore_sites = annotate_and_filter_by_player_radar(conn, player, nodes, ore_all, "system")
    salvage_icons = annotate_and_filter_by_player_radar(conn, player, nodes, [attach_tool_permissions(conn, player, o) for o in salvage_all], "system")
    exploration_sites = annotate_and_filter_by_player_radar(conn, player, nodes, exploration_all, "system")
    pirate_stations = annotate_and_filter_by_player_radar(conn, player, nodes, pirate_station_all, "system")
    player_bases = annotate_and_filter_by_player_radar(conn, player, nodes, player_base_all, "system")
    event_sites = annotate_and_filter_by_player_radar(conn, player, nodes, event_sites_all, "system")
    traffic = [attach_tool_permissions(conn, player, o) for o in annotate_and_filter_by_player_radar(conn, player, nodes, traffic_all, "system") if o.get("id") != "player:self"]
    scan_blips = build_scan_area_blips(conn, player, nodes, "system")
    scan_pings = build_scan_area_pings(conn, player, "system")
    separate_stationary_map_objects([nodes, ore_sites, salvage_icons, exploration_sites, pirate_stations, player_bases, event_sites, traffic, scan_blips])
    for group in (nodes, ore_sites, salvage_icons, exploration_sites, pirate_stations, player_bases, event_sites, traffic, scan_blips):
        annotate_object_scan_unlocks(conn, player, group, "system", int(current["galaxy_id"]))
    active_wars = active_or_upcoming_planet_wars(conn)
    node_by_id_for_war = {int(n["id"]): n for n in nodes if str(n.get("id") or "").isdigit()}
    war_zones = []
    for w in active_wars:
        if int(w.get("galaxy_id") or 0) != int(current["galaxy_id"]):
            continue
        n = node_by_id_for_war.get(int(w["planet_id"]))
        if not n:
            continue
        if w.get("status") == "active":
            war_zones.append({
                "id": f"planetwar:{w['id']}",
                "kind": "war_zone",
                "war_id": w["id"],
                "planet_id": w["planet_id"],
                "galaxy_id": w["galaxy_id"],
                "name": f"{w['planet_name']} Capture Zone",
                "x_pct": float(n.get("x_pct") or 50),
                "y_pct": float(n.get("y_pct") or 50),
                "radius_pct": float(FACTION_WAR_BALANCE.get("capture_ring_radius_pct", 10.5)),
                "status": w["status"],
                "attacking_faction_name": w.get("attacking_faction_name"),
                "defending_faction_name": w.get("defending_faction_name"),
            })
    existing_war_planets = {int(w.get("planet_id") or 0) for w in war_zones}
    for tstate in territory_by_planet.values():
        status = str(tstate.get("status") or "secure")
        if status not in {"contested", "war"}:
            continue
        planet_id = int(tstate.get("planet_id") or 0)
        if status == "war" and planet_id in existing_war_planets:
            continue
        n = node_by_id_for_war.get(planet_id)
        if not n:
            continue
        contested_faction = faction_by_id.get(int(tstate.get("contested_by_faction_id") or 0))
        war_zones.append({
            "id": f"territory:{planet_id}",
            "kind": "war_zone",
            "territory": True,
            "planet_id": planet_id,
            "galaxy_id": int(current["galaxy_id"]),
            "name": f"{n.get('name')} {'War Zone' if status == 'war' else 'Contested Zone'}",
            "x_pct": float(n.get("x_pct") or 50),
            "y_pct": float(n.get("y_pct") or 50),
            "radius_pct": 10.5 if status == "war" else 7.5,
            "status": status,
            "territory_status": status,
            "attacking_faction_name": contested_faction.get("name") if contested_faction else None,
            "defending_faction_name": (faction_by_id.get(int(tstate.get("controlling_faction_id") or 0)) or {}).get("name"),
        })

    ship = active_ship_for_player(conn, player)
    radar_range = ship_radar_range_pct(conn, ship, "system")
    radar_center = player_map_center(conn, player, "system", nodes)
    scan_area = scan_area_profile_for_player(conn, player, "system")
    hidden_total = (len(ore_all) - len(ore_sites)) + (len(salvage_all) - len(salvage_icons)) + (len(exploration_all) - len(exploration_sites)) + (len(pirate_station_all) - len(pirate_stations)) + (len(player_base_all) - len(player_bases)) + (len(event_sites_all) - len(event_sites)) + (len([t for t in traffic_all if t.get("id") != "player:self"]) - len([t for t in traffic if t.get("id") != "player:self"]))
    summary = {
        "ships_in_transit": len(traffic),
        "ore_signatures": len(ore_sites),
        "wrecks": len(salvage_icons),
        "ancient_sites": len(exploration_sites),
        "hostile_contacts": len([t for t in traffic if t.get("hostile")]),
        "pirate_stations": len(pirate_stations),
        "server_events": len(event_sites),
        "territory_wars": len([t for t in territory_by_planet.values() if str(t.get("status") or "") == "war"]),
        "contested_zones": len([t for t in territory_by_planet.values() if str(t.get("status") or "") == "contested"]),
        "gate_links": len(gate_links),
        "security_level": int(sum([n.get("security_level", 50) for n in nodes]) / max(1, len(nodes))),
        "risk_band": "High" if any(int(n.get("risk_level") or 0) >= 65 for n in nodes) else "Moderate",
        "radar_range_pct": radar_range,
        "radar_center_x_pct": round(float(radar_center.get("x_pct") or 50), 2),
        "radar_center_y_pct": round(float(radar_center.get("y_pct") or 50), 2),
        "hidden_by_radar": max(0, hidden_total),
        "scan_area": scan_area,
        "player_faction": pf,
        "admin_spawn_constraints": admin_spawn_constraints(conn, int(current["galaxy_id"]), int(current["id"])) if player_has_god_mode(conn, player) else None,
        "readable_hint": f"Unified system view: planet/station nodes plus gate links to adjacent galaxies. Ships and hidden contacts remain radar-limited ({radar_range}%).",
        "nearby_opportunities": ["Galaxy gates", "Radar-limited contacts", "Player bases", "Pirate stations", "Mine ore", "Scan ancient sites", "Salvage wrecks"],
    }
    return {"nodes": nodes, "lanes": lanes, "current_planet_id": current["id"], "current_galaxy_id": current["galaxy_id"], "traffic": traffic, "ore_sites": ore_sites, "salvage_icons": salvage_icons, "exploration_sites": exploration_sites, "pirate_stations": pirate_stations, "player_bases": player_bases, "event_sites": event_sites, "war_zones": war_zones, "scan_blips": scan_blips, "scan_pings": scan_pings, "summary": summary}




def pirate_station_visual_payload(station: Dict[str, Any]) -> str:
    tier = int(station.get("tier") or 1)
    color = "ff4d57" if tier <= 2 else "ff8c35" if tier <= 4 else "d98cff"
    initials = "".join([x[:1] for x in str(station.get("name") or "Pirate Station").split()[:2]]).upper() or "PS"
    svg = f"""<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 120 120'>
<defs><radialGradient id='r' cx='50%' cy='48%' r='62%'><stop offset='0%' stop-color='#{color}' stop-opacity='.72'/><stop offset='62%' stop-color='#21070b'/><stop offset='100%' stop-color='#02060b'/></radialGradient></defs>
<rect width='120' height='120' rx='18' fill='#02060b'/>
<circle cx='60' cy='60' r='42' fill='url(#r)' stroke='#{color}' stroke-width='3'/>
<path d='M60 12 L72 45 L108 45 L78 66 L90 104 L60 81 L30 104 L42 66 L12 45 L48 45 Z' fill='none' stroke='#{color}' stroke-opacity='.55' stroke-width='3'/>
<circle cx='60' cy='60' r='18' fill='#02060b' stroke='#{color}' stroke-width='2'/>
<text x='60' y='68' text-anchor='middle' font-family='Segoe UI,Arial' font-size='22' font-weight='900' fill='#{color}'>{initials[:2]}</text>
</svg>"""
    return "data:image/svg+xml;utf8," + quote(svg)


def pct_distance(a: Dict[str, Any], b: Dict[str, Any]) -> float:
    return math.sqrt((float(a.get("x_pct") or 0) - float(b.get("x_pct") or 0)) ** 2 + (float(a.get("y_pct") or 0) - float(b.get("y_pct") or 0)) ** 2)


def ensure_pirate_station_content(conn: sqlite3.Connection) -> None:
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='pirate_stations'"):
        return
    now = utcnow()
    conn.execute(
        """
        UPDATE pirate_stations
        SET status='active', resource_pct=100, remaining_pirates=total_pirates,
            occupied_by_player_id=NULL, updated_at=?, respawn_at=NULL
        WHERE status='depleted' AND respawn_at IS NOT NULL AND respawn_at<=?
        """,
        (iso(now), iso(now)),
    )
    if bool(WORLD_SERVER_BALANCE.get("server_controls_resources", True)):
        return

    active_total = int(scalar(conn, "SELECT COUNT(*) FROM pirate_stations WHERE status IN ('active','occupied','depleted')") or 0)
    if active_total >= int(PIRATE_STATION_BALANCE["global_station_soft_cap"]):
        return

    galaxies = rows(conn, "SELECT * FROM galaxies ORDER BY id")
    for g in galaxies:
        existing = int(scalar(conn, "SELECT COUNT(*) FROM pirate_stations WHERE galaxy_id=? AND status IN ('active','occupied','depleted')", (g["id"],)) or 0)
        need = max(0, int(PIRATE_STATION_BALANCE["max_stations_per_galaxy"]) - existing)
        if need <= 0:
            continue
        planets = rows(conn, "SELECT * FROM planets WHERE galaxy_id=?", (g["id"],))
        if not planets:
            continue
        existing_points = rows(conn, "SELECT x_pct,y_pct FROM pirate_stations WHERE galaxy_id=? AND status IN ('active','occupied','depleted')", (g["id"],))
        for slot in range(need):
            if int(scalar(conn, "SELECT COUNT(*) FROM pirate_stations WHERE status IN ('active','occupied','depleted')") or 0) >= int(PIRATE_STATION_BALANCE["global_station_soft_cap"]):
                return
            rng = random.Random(f"pirate-station:{g['id']}:{existing}:{slot}:{len(planets)}")
            best = None
            best_score = -1.0
            for attempt in range(80):
                angle = rng.uniform(0, math.tau)
                radius = rng.uniform(24, 45)
                x = clamp_pct(50 + math.cos(angle) * radius, 5, 95)
                y = clamp_pct(50 + math.sin(angle) * radius, 5, 95)
                candidate = {"x_pct": x, "y_pct": y}
                nearest_planet = min(planets, key=lambda p: (x - clamp_pct((50 + float(p.get("x") or 0) / 2.3 - 50) * 1.45 + 50, 2, 98)) ** 2 + (y - clamp_pct((50 + float(p.get("y") or 0) / 2.3 - 50) * 1.45 + 50, 2, 98)) ** 2)
                nearest_node = {"x_pct": clamp_pct((50 + float(nearest_planet.get("x") or 0) / 2.3 - 50) * 1.45 + 50, 2, 98), "y_pct": clamp_pct((50 + float(nearest_planet.get("y") or 0) / 2.3 - 50) * 1.45 + 50, 2, 98)}
                nearest_station_dist = min([pct_distance(candidate, p) for p in existing_points] or [99])
                planet_dist = pct_distance(candidate, nearest_node)
                score = min(nearest_station_dist, 40) + min(planet_dist, 35) + radius * 0.35
                if nearest_station_dist < float(PIRATE_STATION_BALANCE["min_station_spacing_pct"]) or planet_dist < float(PIRATE_STATION_BALANCE["min_planet_spacing_pct"]):
                    score *= 0.45
                if score > best_score:
                    best_score = score
                    best = (candidate, nearest_planet, radius)
            if not best:
                continue
            candidate, nearest_planet, radius = best
            galaxy_center_value = int(g.get("center_value") or galaxy_center_value_from_xy(g.get("x_pct") or 50, g.get("y_pct") or 50))
            raw_level = (1 + int(radius // 10) + max(0, galaxy_center_value - 2) + int(int(nearest_planet.get("pirate_activity") or 40) >= 65)) * 8
            station_level = pirate_level_for_security(raw_level, int(nearest_planet.get("security_level") or 50), rng)
            tier = pirate_station_tier(pirate_base_tier_for_level(station_level))
            difficulty = clamp_int(tier + rng.randint(0, 2), 2, 9)
            total = pirate_station_enemy_count_for_tier(tier, rng)
            name = f"{rng.choice(['Blackwake','Red Dagger','Void Maw','Corsair','Grim Halo','Iron Fang'])} Station {g['code'].upper()}-{existing + slot + 1}"
            code = f"pirate_station_{g['id']}_{existing + slot + 1}_{int(now.timestamp())}"
            conn.execute(
                """
                INSERT INTO pirate_stations
                  (code,galaxy_id,nearest_planet_id,name,x_pct,y_pct,tier,difficulty,total_pirates,remaining_pirates,resource_pct,status,occupied_by_player_id,seed,created_at,updated_at,respawn_at)
                VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,NULL)
                """,
                (code, g["id"], nearest_planet["id"], name, candidate["x_pct"], candidate["y_pct"], tier, difficulty, total, total, 100, "active", None, f"{g['id']}:{slot}:{candidate['x_pct']:.2f}:{candidate['y_pct']:.2f}", iso(now), iso(now)),
            )
            existing_points.append(candidate)


def build_system_pirate_stations(conn: sqlite3.Connection, player: Dict[str, Any], nodes: List[Dict[str, Any]], galaxy_id: int) -> List[Dict[str, Any]]:
    ensure_pirate_station_content(conn)
    out = []
    cap = max(1, int(PIRATE_STATION_BALANCE.get("max_players_per_station", 3)))
    for st in rows(conn, "SELECT ps.*, p.name as nearest_planet_name FROM pirate_stations ps LEFT JOIN planets p ON p.id=ps.nearest_planet_id WHERE ps.galaxy_id=? AND ps.status IN ('active','occupied') ORDER BY ps.tier DESC, ps.name", (galaxy_id,)):
        active_count = pirate_station_active_player_count(conn, int(st["id"]))
        player_inside = bool(row(conn, "SELECT 1 FROM pirate_station_runs WHERE station_id=? AND player_id=? AND status='active'", (st["id"], player["id"])))
        locked = False
        remaining = pirate_station_remaining_for_station(conn, int(st["id"]))
        total = max(1, int(st.get("total_pirates") or 1))
        resource = clamp_int(round((remaining / total) * 100), 0, 100)
        st.update({
            "id": f"pirate-station:{st['id']}",
            "stationId": st["id"],
            "kind": "pirate_station",
            "name": st.get("name") or "Pirate Station",
            "locked": locked,
            "activePlayers": active_count,
            "maxPlayers": cap,
            "resourcePct": resource,
            "resource_pct": resource,
            "adminSpawned": str(st.get("code") or "").startswith("admin_pirate_base_") or str(st.get("seed") or "").startswith("admin:"),
            "label": f"Pirate Station - T{st.get('tier')} - {resource}% defenders - {active_count} pilot(s) inside",
            "selectedSummary": f"Pirate station map near {st.get('nearest_planet_name') or 'deep space'}. Entering removes you from the system map until you escape through the outer edge.",
            "outcomeFactors": "Pirates are level-appropriate for this area but use doubled station strength. Defeated pirates stay dead, even after everyone leaves.",
            "dangerHint": "Reach the outer 10% escape zone to return to the system map. Clearing every pirate removes the station.",
            "image_url": pirate_station_visual_payload(st),
        })
        out.append(st)
    return out


def active_pirate_station_run(conn: sqlite3.Connection, player_id: int) -> Optional[Dict[str, Any]]:
    return row(conn, "SELECT * FROM pirate_station_runs WHERE player_id=? AND status='active' ORDER BY id DESC LIMIT 1", (player_id,))


def active_pirate_station_runs(conn: sqlite3.Connection, station_id: int) -> List[Dict[str, Any]]:
    return rows(conn, "SELECT * FROM pirate_station_runs WHERE station_id=? AND status='active' ORDER BY id", (station_id,))


def pirate_station_active_player_count(conn: sqlite3.Connection, station_id: int) -> int:
    return int(scalar(conn, "SELECT COUNT(*) FROM pirate_station_runs WHERE station_id=? AND status='active'", (station_id,)) or 0)


def pirate_station_enemy_run(conn: sqlite3.Connection, station_id: int) -> Optional[Dict[str, Any]]:
    # The first run with persisted defenders is treated as the shared open-world station state.
    return row(
        conn,
        """
        SELECT r.*
        FROM pirate_station_runs r
        WHERE r.station_id=?
          AND r.status IN ('active','retreated')
          AND EXISTS (SELECT 1 FROM pirate_station_enemies e WHERE e.run_id=r.id)
        ORDER BY r.id
        LIMIT 1
        """,
        (station_id,),
    )


def pirate_station_enemy_run_id(conn: sqlite3.Connection, station_id: int, fallback_run_id: Optional[int] = None) -> Optional[int]:
    shared = pirate_station_enemy_run(conn, station_id)
    return int(shared["id"]) if shared else (int(fallback_run_id) if fallback_run_id else None)


def pirate_station_remaining_count(conn: sqlite3.Connection, run_id: int) -> int:
    return int(scalar(conn, "SELECT COUNT(*) FROM pirate_station_enemies WHERE run_id=? AND status='active' AND hull>0", (run_id,)) or 0)


def pirate_station_remaining_for_station(conn: sqlite3.Connection, station_id: int) -> int:
    shared = pirate_station_enemy_run(conn, station_id)
    if not shared:
        return int(scalar(conn, "SELECT remaining_pirates FROM pirate_stations WHERE id=?", (station_id,)) or 0)
    return pirate_station_remaining_count(conn, int(shared["id"]))


def update_pirate_station_resource(conn: sqlite3.Connection, run: Dict[str, Any]) -> None:
    station = row(conn, "SELECT * FROM pirate_stations WHERE id=?", (run["station_id"],))
    if not station:
        return
    shared_run_id = pirate_station_enemy_run_id(conn, int(station["id"]), int(run["id"]))
    remaining = pirate_station_remaining_count(conn, shared_run_id) if shared_run_id else 0
    total = max(1, int(station.get("total_pirates") or remaining or 1))
    pct = clamp_int(round((remaining / total) * 100), 0, 100)
    active_count = pirate_station_active_player_count(conn, int(station["id"]))
    status = "depleted" if remaining <= 0 else "active"
    respawn_at = None if remaining <= 0 else station.get("respawn_at")
    occupied = scalar(conn, "SELECT player_id FROM pirate_station_runs WHERE station_id=? AND status='active' ORDER BY id LIMIT 1", (station["id"],))
    conn.execute(
        "UPDATE pirate_stations SET remaining_pirates=?, resource_pct=?, status=?, occupied_by_player_id=?, updated_at=?, respawn_at=? WHERE id=?",
        (remaining, pct, status, occupied if active_count > 0 else None, iso(), respawn_at, station["id"]),
    )
    if remaining <= 0:
        conn.execute("UPDATE pirate_station_runs SET status='completed', completed_at=?, updated_at=?, battle_open=0, battle_target_enemy_id=NULL WHERE station_id=? AND status='active'", (iso(), iso(), station["id"]))


def create_pirate_station_enemies(conn: sqlite3.Connection, run_id: int, station: Dict[str, Any]) -> None:
    tier = pirate_station_tier(station.get("tier") or 1)
    count = max(1, int(station.get("remaining_pirates") or station.get("total_pirates") or pirate_station_enemy_count_for_tier(tier, random.Random(str(station.get("seed") or run_id)))))
    galaxy_id = int(station.get("galaxy_id") or 0)
    level_min, level_max = world_level_range_for_galaxy(conn, galaxy_id) if galaxy_id else (tier * 6, tier * 10)
    strength_mult = float(PIRATE_STATION_BALANCE.get("enemy_strength_mult", 2.0) or 2.0)
    station_planet = row(conn, "SELECT security_level FROM planets WHERE id=?", (int(station.get("nearest_planet_id") or station.get("planet_id") or 0),))
    station_security = int((station_planet or {}).get("security_level") or 50)
    station_band = pirate_security_band(station_security)
    rng = random.Random(f"pirate-run:{station.get('seed')}:{run_id}:{count}")
    points: List[Dict[str, float]] = []
    for i in range(count):
        best = None
        best_score = -1.0
        for attempt in range(80):
            edge = rng.choice(["left", "right", "top", "bottom"])
            if edge == "left":
                x, y = rng.uniform(8, 24), rng.uniform(10, 90)
            elif edge == "right":
                x, y = rng.uniform(76, 92), rng.uniform(10, 90)
            elif edge == "top":
                x, y = rng.uniform(10, 90), rng.uniform(8, 24)
            else:
                x, y = rng.uniform(10, 90), rng.uniform(76, 92)
            cand = {"x_pct": x, "y_pct": y}
            spacing = min([pct_distance(cand, p) for p in points] or [99])
            center_dist = pct_distance(cand, {"x_pct": 50, "y_pct": 50})
            score = spacing + center_dist * 0.35
            if score > best_score:
                best_score, best = score, cand
        points.append(best or {"x_pct": rng.uniform(10, 90), "y_pct": rng.uniform(10, 90)})
    for i, pt in enumerate(points):
        base_level = rng.randint(max(1, level_min), max(level_min, level_max))
        enemy_level = pirate_level_for_security(base_level, station_security, rng)
        enemy_tier = tier
        power = int((85 + enemy_level * rng.uniform(14.5, 20.5) + enemy_tier * 32 + rng.randint(0, 55)) * strength_mult)
        hull = int((150 + enemy_level * rng.uniform(32, 44) + enemy_tier * 45 + rng.randint(0, 80)) * strength_mult)
        shield = int((90 + enemy_level * rng.uniform(18, 28) + enemy_tier * 28 + rng.randint(0, 55)) * strength_mult)
        name_roots = {
            "high_sec": ["Knife", "Rutter", "Backdock", "Scrapjaw"],
            "border_sec": ["Raider", "Cutlass", "Corsair", "Blackwake"],
            "low_sec": ["Reaver", "Marauder", "Fang", "Voidhook"],
            "deep_low_sec": ["Dread Corsair", "Grav Maw", "Siegebreaker", "Iron Fang"],
            "null_sec": ["Null-Crown", "Abyssal Maw", "Relic Reaver", "Event Horizon"],
        }
        name = f"{rng.choice(name_roots.get(str(station_band['key']), name_roots['border_sec']))} {i+1}"
        conn.execute(
            """
            INSERT INTO pirate_station_enemies
              (run_id,enemy_key,name,role,x_pct,y_pct,hull,max_hull,shield,max_shield,power,tier,status,spawned_at,updated_at)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            """,
            (run_id, f"enemy-{i+1}", name, "pirate", pt["x_pct"], pt["y_pct"], hull, hull, shield, shield, power, enemy_tier, "active", iso(), iso()),
        )


def pirate_station_player_spawn_point(station_id: int, player_id: int) -> Dict[str, float]:
    edge = float(PIRATE_STATION_BALANCE.get("escape_edge_pct", 10.0))
    rng = random.Random(f"pirate-station-player-spawn:{int(station_id)}:{int(player_id)}:{uuid.uuid4().hex[:8]}")
    safe_min = edge + 8.0
    safe_max = 100.0 - edge - 8.0
    lane = max(edge + 8.0, min(edge + 12.0, edge + 10.0 + rng.uniform(-1.8, 1.8)))
    side = rng.choice(["left", "right", "top", "bottom"])
    if side == "left":
        x, y = lane, rng.uniform(safe_min, safe_max)
    elif side == "right":
        x, y = 100.0 - lane, rng.uniform(safe_min, safe_max)
    elif side == "top":
        x, y = rng.uniform(safe_min, safe_max), lane
    else:
        x, y = rng.uniform(safe_min, safe_max), 100.0 - lane
    return {"x_pct": clamp_pct(x, edge + 2.0, 100.0 - edge - 2.0), "y_pct": clamp_pct(y, edge + 2.0, 100.0 - edge - 2.0)}


def begin_pirate_station_run(conn: sqlite3.Connection, player: Dict[str, Any], station_id: int) -> Dict[str, Any]:
    ensure_pirate_station_content(conn)
    station = row(conn, "SELECT * FROM pirate_stations WHERE id=?", (station_id,))
    if not station:
        raise HTTPException(404, "Pirate station not found")
    if station.get("status") == "depleted":
        raise HTTPException(400, "Pirate station has already been cleared")
    current = active_pirate_station_run(conn, player["id"])
    if current and int(current["station_id"]) != int(station_id):
        update_pirate_station_resource(conn, current)
        conn.execute(
            "UPDATE pirate_station_runs SET status='retreated', battle_open=0, battle_target_enemy_id=NULL, battle_report_json='{}', completed_at=?, updated_at=? WHERE id=?",
            (iso(), iso(), current["id"]),
        )
        update_pirate_station_resource(conn, {**current, "status": "retreated"})
        current = None
    if current:
        clear_player_open_space(conn, player["id"])
        clear_player_waypoint(conn, player["id"])
        clear_player_intercept(conn, player["id"])
        clear_player_route(conn, player["id"])
        conn.execute("UPDATE players SET travel_until=NULL, travel_destination_id=NULL, travel_mode=NULL, travel_started_at=NULL, travel_origin_planet_id=NULL, travel_origin_galaxy_id=NULL, travel_destination_galaxy_id=NULL WHERE id=?", (player["id"],))
        update_pirate_station_resource(conn, current)
        return {"message": f"Returned to {station['name']}.", "openPage": "Pirate Station"}

    clear_player_open_space(conn, player["id"])
    clear_player_waypoint(conn, player["id"])
    clear_player_intercept(conn, player["id"])
    clear_player_route(conn, player["id"])
    clear_pirate_station_travel_intent(conn, player["id"])
    conn.execute("UPDATE players SET travel_until=NULL, travel_destination_id=NULL, travel_mode=NULL, travel_started_at=NULL, travel_origin_planet_id=NULL, travel_origin_galaxy_id=NULL, travel_destination_galaxy_id=NULL WHERE id=?", (player["id"],))

    spawn = pirate_station_player_spawn_point(station_id, player["id"])
    # Player position is per-player; enemies are shared using the oldest active/retreated station run.
    prior = row(conn, "SELECT * FROM pirate_station_runs WHERE player_id=? AND station_id=? AND status='retreated' ORDER BY id DESC LIMIT 1", (player["id"], station_id))
    if prior:
        conn.execute("UPDATE pirate_station_runs SET status='active', updated_at=?, player_x_pct=?, player_y_pct=?, battle_open=0, battle_target_enemy_id=NULL, battle_report_json='{}' WHERE id=?", (iso(), spawn["x_pct"], spawn["y_pct"], prior["id"]))
        run_id = int(prior["id"])
    else:
        conn.execute(
            """
            INSERT INTO pirate_station_runs (station_id,player_id,status,player_x_pct,player_y_pct,battle_open,battle_report_json,started_at,updated_at)
            VALUES (?,?,?,?,?,?,?,?,?)
            """,
            (station_id, player["id"], "active", spawn["x_pct"], spawn["y_pct"], 0, "{}", iso(), iso()),
        )
        run_id = int(scalar(conn, "SELECT last_insert_rowid()"))

    if not pirate_station_enemy_run(conn, station_id):
        create_pirate_station_enemies(conn, run_id, station)

    run = row(conn, "SELECT * FROM pirate_station_runs WHERE id=?", (run_id,))
    update_pirate_station_resource(conn, run)
    active_count = pirate_station_active_player_count(conn, station_id)
    add_event(conn, player["id"], "pirate_station", f"Entered pirate station map {station['name']} ({active_count} pilot(s) inside).")
    return {"message": f"Entered {station['name']}. You are now on the station map; reach the outer 10% edge to escape.", "openPage": "Pirate Station"}


def advance_pirate_station_run(conn: sqlite3.Connection, player_id: int) -> None:
    run = active_pirate_station_run(conn, player_id)
    if not run:
        return
    station_id = int(run["station_id"])
    shared = pirate_station_enemy_run(conn, station_id) or run
    now = utcnow()
    last = parse_dt(shared.get("updated_at")) or now
    elapsed = max(0.0, (now - last).total_seconds())
    tick_seconds = max(1, int(PIRATE_STATION_BALANCE["enemy_tick_seconds"]))
    if elapsed < tick_seconds:
        return
    steps = min(6, max(1, int(elapsed // tick_seconds)))
    move = float(PIRATE_STATION_BALANCE["enemy_move_pct_per_tick"]) * steps
    targets = active_pirate_station_runs(conn, station_id)
    if not targets:
        update_pirate_station_resource(conn, shared)
        return
    for enemy in rows(conn, "SELECT * FROM pirate_station_enemies WHERE run_id=? AND status='active' AND hull>0", (shared["id"],)):
        ex = float(enemy.get("x_pct") or 0)
        ey = float(enemy.get("y_pct") or 0)
        target = min(targets, key=lambda r: (float(r.get("player_x_pct") or 50) - ex) ** 2 + (float(r.get("player_y_pct") or 50) - ey) ** 2)
        px = float(target.get("player_x_pct") if target.get("player_x_pct") is not None else 50)
        py = float(target.get("player_y_pct") if target.get("player_y_pct") is not None else 50)
        dx = px - ex
        dy = py - ey
        dist = math.sqrt(dx * dx + dy * dy)
        if dist > 0:
            step = min(move, dist)
            ex += (dx / dist) * step
            ey += (dy / dist) * step
            dist = max(0.0, dist - step)
        conn.execute(
            "UPDATE pirate_station_enemies SET x_pct=?, y_pct=?, updated_at=? WHERE id=?",
            (clamp_pct(ex, 2, 98), clamp_pct(ey, 2, 98), iso(now), enemy["id"]),
        )
        if dist <= float(PIRATE_STATION_BALANCE["enemy_attack_range_pct"]):
            # Mark the closest player's current threat but do not pause movement.
            conn.execute(
                "UPDATE pirate_station_runs SET battle_target_enemy_id=?, updated_at=? WHERE id=?",
                (enemy["id"], iso(now), target["id"]),
            )
    conn.execute("UPDATE pirate_station_runs SET updated_at=? WHERE id=?", (iso(now), shared["id"]))
    update_pirate_station_resource(conn, shared)


def pirate_station_escape_ready(run: Dict[str, Any]) -> bool:
    edge = float(PIRATE_STATION_BALANCE["escape_edge_pct"])
    x = float(run.get("player_x_pct") if run.get("player_x_pct") is not None else 50)
    y = float(run.get("player_y_pct") if run.get("player_y_pct") is not None else 50)
    return x <= edge or x >= 100 - edge or y <= edge or y >= 100 - edge


def pirate_station_payload(conn: sqlite3.Connection, player_id: int) -> Optional[Dict[str, Any]]:
    run = active_pirate_station_run(conn, player_id)
    if not run:
        return None
    station = row(conn, "SELECT * FROM pirate_stations WHERE id=?", (run["station_id"],))
    if not station:
        return None
    shared = pirate_station_enemy_run(conn, int(station["id"])) or run
    enemies = rows(conn, "SELECT * FROM pirate_station_enemies WHERE run_id=? ORDER BY status, id", (shared["id"],))
    active_players = rows(
        conn,
        """
        SELECT r.*, u.username, COALESCE(up.display_name, p.callsign, u.username) as display_name
        FROM pirate_station_runs r
        JOIN players p ON p.id=r.player_id
        JOIN users u ON u.id=p.user_id
        LEFT JOIN user_profiles up ON up.user_id=u.id
        WHERE r.station_id=? AND r.status='active'
        ORDER BY r.id
        """,
        (station["id"],),
    )
    px = float(run.get("player_x_pct") if run.get("player_x_pct") is not None else 50)
    py = float(run.get("player_y_pct") if run.get("player_y_pct") is not None else 50)
    player_points = []
    for r in active_players:
        player_points.append({
            "player_id": r["player_id"],
            "name": r.get("display_name") or r.get("username") or f"Pilot {r['player_id']}",
            "x_pct": float(r.get("player_x_pct") or 50),
            "y_pct": float(r.get("player_y_pct") or 50),
            "self": int(r["player_id"]) == int(player_id),
        })
    for e in enemies:
        e["kind"] = "station_pirate"
        e["distancePct"] = round(math.sqrt((float(e.get("x_pct") or 0) - px) ** 2 + (float(e.get("y_pct") or 0) - py) ** 2), 2)
        e["hullPct"] = clamp_int(round((int(e.get("hull") or 0) / max(1, int(e.get("max_hull") or 1))) * 100), 0, 100)
        e["shieldPct"] = clamp_int(round((int(e.get("shield") or 0) / max(1, int(e.get("max_shield") or 1))) * 100), 0, 100)
        e["image_url"] = ship_visual_payload(e.get("name") or "Pirate", "combat")
        if player_points and e.get("status") == "active" and int(e.get("hull") or 0) > 0:
            nearest = min(player_points, key=lambda p: (p["x_pct"] - float(e.get("x_pct") or 0)) ** 2 + (p["y_pct"] - float(e.get("y_pct") or 0)) ** 2)
            e["targetPlayerId"] = nearest["player_id"]
            e["targetPlayerName"] = nearest["name"]
            e["targetingSelf"] = bool(nearest["self"])
    remaining = len([e for e in enemies if e.get("status") == "active" and int(e.get("hull") or 0) > 0])
    total = max(1, int(station.get("total_pirates") or len(enemies) or 1))
    resource = clamp_int(round((remaining / total) * 100), 0, 100)
    report = decode_json(run.get("battle_report_json"), {}) or {}
    target = row(conn, "SELECT * FROM pirate_station_enemies WHERE id=?", (run.get("battle_target_enemy_id"),)) if run.get("battle_target_enemy_id") else None
    if target:
        target["image_url"] = ship_visual_payload(target.get("name") or "Pirate", "combat")
    cap = max(1, int(PIRATE_STATION_BALANCE.get("max_players_per_station", 3)))
    return {
        "run": run,
        "station": {**station, "resourcePct": resource, "image_url": pirate_station_visual_payload(station)},
        "player": {"x_pct": px, "y_pct": py, "escapeReady": pirate_station_escape_ready(run)},
        "players": player_points,
        "activePlayerCount": len(player_points),
        "maxPlayers": cap,
        "enemies": enemies,
        "remaining": remaining,
        "total": total,
        "resourcePct": resource,
        "battle": {"open": bool(int(run.get("battle_open") or 0)), "target": target, "report": report},
        "balance": PIRATE_STATION_BALANCE,
        "openWorld": True,
    }

def move_pirate_station_player(conn: sqlite3.Connection, player: Dict[str, Any], dx: float, dy: float) -> Dict[str, Any]:
    run = active_pirate_station_run(conn, player["id"])
    if not run:
        raise HTTPException(400, "You are not inside a pirate station")
    step = float(PIRATE_STATION_BALANCE["player_move_pct"])
    x = clamp_pct(float(run.get("player_x_pct") if run.get("player_x_pct") is not None else 50) + float(dx) * step, 0, 100)
    y = clamp_pct(float(run.get("player_y_pct") if run.get("player_y_pct") is not None else 50) + float(dy) * step, 0, 100)
    conn.execute("UPDATE pirate_station_runs SET player_x_pct=?, player_y_pct=?, updated_at=? WHERE id=?", (x, y, iso(), run["id"]))
    run = row(conn, "SELECT * FROM pirate_station_runs WHERE id=?", (run["id"],))
    if pirate_station_escape_ready(run):
        return retreat_pirate_station(conn, player, escaped=True)
    advance_pirate_station_run(conn, player["id"])
    return {"message": f"Moved inside station to {x:.1f}/{y:.1f}. Pirates slowly converge on the closest pilot.", "openPage": "Pirate Station"}

def retreat_pirate_station(conn: sqlite3.Connection, player: Dict[str, Any], escaped: bool = False) -> Dict[str, Any]:
    run = active_pirate_station_run(conn, player["id"])
    if not run:
        raise HTTPException(400, "You are not inside a pirate station")
    if not escaped and not pirate_station_escape_ready(run):
        raise HTTPException(409, "You must reach the outer edge before retreating")
    update_pirate_station_resource(conn, run)
    conn.execute("UPDATE pirate_station_runs SET status='retreated', battle_open=0, battle_target_enemy_id=NULL, battle_report_json='{}', completed_at=?, updated_at=? WHERE id=?", (iso(), iso(), run["id"]))
    fresh_run = row(conn, "SELECT * FROM pirate_station_runs WHERE id=?", (run["id"],)) or run
    update_pirate_station_resource(conn, fresh_run)
    add_event(conn, player["id"], "pirate_station", "Retreated from open-world pirate station. Shared defender damage remains.")
    return {"message": "Retreated through the outer edge. Shared station progress was preserved.", "openPage": "System Map"}

def start_pirate_station_battle(conn: sqlite3.Connection, player: Dict[str, Any], enemy_id: int) -> Dict[str, Any]:
    run = active_pirate_station_run(conn, player["id"])
    if not run:
        raise HTTPException(400, "You are not inside a pirate station")
    shared_run_id = pirate_station_enemy_run_id(conn, int(run["station_id"]), int(run["id"]))
    enemy = row(conn, "SELECT * FROM pirate_station_enemies WHERE id=? AND run_id=? AND status='active' AND hull>0", (enemy_id, shared_run_id))
    if not enemy:
        raise HTTPException(404, "Pirate defender not available")
    conn.execute("UPDATE pirate_station_runs SET battle_open=1, battle_target_enemy_id=?, battle_report_json='{}', updated_at=? WHERE id=?", (enemy_id, iso(), run["id"]))
    return {"message": f"Engaged {enemy['name']}. Open-world movement continues; pirates still converge slowly.", "openPage": "Pirate Station"}

def apply_track_damage(shield: int, hull: int, damage: int) -> Tuple[int, int, int, int]:
    shield_hit = min(max(0, shield), max(0, int(damage)))
    shield -= shield_hit
    hull_hit = 0
    if damage > shield_hit:
        hull_hit = min(max(0, hull), int(damage - shield_hit))
        hull -= hull_hit
    return shield, hull, shield_hit, hull_hit


def resolve_pirate_station_battle(conn: sqlite3.Connection, player: Dict[str, Any], god: bool = False) -> Dict[str, Any]:
    run = active_pirate_station_run(conn, player["id"])
    if not run:
        raise HTTPException(400, "You are not inside a pirate station")
    if decode_json(run.get("battle_report_json"), {}) or {}:
        return {"message": "Battle already resolved. Close the battle panel to continue.", "openPage": "Pirate Station"}
    shared_run_id = pirate_station_enemy_run_id(conn, int(run["station_id"]), int(run["id"]))
    enemy = row(conn, "SELECT * FROM pirate_station_enemies WHERE id=? AND run_id=?", (run.get("battle_target_enemy_id"), shared_run_id))
    if not enemy or enemy.get("status") != "active":
        conn.execute("UPDATE pirate_station_runs SET battle_open=0, battle_target_enemy_id=NULL, battle_report_json='{}' WHERE id=?", (run["id"],))
        return {"message": "Target already cleared.", "openPage": "Pirate Station"}
    ship = row(conn, "SELECT * FROM ships WHERE id=? AND player_id=?", (player.get("active_ship_id"), player["id"])) if player.get("active_ship_id") else None
    if not ship or int(ship.get("destroyed") or 0):
        raise HTTPException(400, "No usable active ship")
    rng = random.Random(f"pirate-battle:{run['id']}:{enemy['id']}:{enemy.get('hull')}:{utcnow().timestamp()//3}")
    player_power = max(40, get_ship_power(conn, ship["id"]))
    enemy_power = max(20, int(enemy.get("power") or 50))
    y_hull = int(ship.get("hull") or 1)
    y_shield = int(ship.get("shield") or 0)
    e_hull = int(enemy.get("hull") or 1)
    e_shield = int(enemy.get("shield") or 0)
    log = []
    player_won = False
    station_for_drop = None
    for round_no in range(1, int(PIRATE_STATION_BALANCE["battle_max_rounds"]) + 1):
        p_damage = int(player_power * rng.uniform(0.20, 0.38)) + (20 if god else 0)
        e_shield, e_hull, sh, hh = apply_track_damage(e_shield, e_hull, p_damage)
        log.append({"round": round_no, "actor": "player", "text": f"Your ship hits {enemy['name']} for {sh} shield / {hh} hull damage.", "shieldDamage": sh, "hullDamage": hh, "enemyHull": e_hull, "enemyShield": e_shield, "playerHull": y_hull, "playerShield": y_shield})
        if e_hull <= 0:
            player_won = True
            break
        e_damage = 0 if god else int(enemy_power * rng.uniform(0.12, 0.27))
        y_shield, y_hull, sh, hh = apply_track_damage(y_shield, y_hull, e_damage)
        log.append({"round": round_no, "actor": "enemy", "text": f"{enemy['name']} returns fire for {sh} shield / {hh} hull damage.", "shieldDamage": sh, "hullDamage": hh, "enemyHull": e_hull, "enemyShield": e_shield, "playerHull": y_hull, "playerShield": y_shield})
        if y_hull <= 0:
            break
    player_destroyed = bool(not player_won and y_hull <= 0)
    if player_destroyed:
        death_note = damage_or_destroy_ship(
            conn,
            player["id"],
            max(int(ship.get("hull") or 1) + int(ship.get("shield") or 0) + enemy_power * 8, 999999),
            f"pirate station defeat by {enemy['name']}",
            god=god,
            hospital_minutes=30,
        )
        update_pirate_station_resource(conn, run)
        conn.execute(
            "UPDATE pirate_station_runs SET status='retreated', battle_open=0, battle_target_enemy_id=NULL, battle_report_json='{}', completed_at=?, updated_at=? WHERE id=?",
            (iso(), iso(), run["id"]),
        )
        fresh_run = row(conn, "SELECT * FROM pirate_station_runs WHERE id=?", (run["id"],)) or run
        update_pirate_station_resource(conn, fresh_run)
        message = f"Your ship was destroyed inside {enemy['name']}'s firing lane. {death_note}"
        emit_player_metrics(conn, player["id"], {
            "damage_dealt": sum(int(e.get("shieldDamage") or 0) + int(e.get("hullDamage") or 0) for e in log if e.get("actor") == "player"),
            "damage_taken": sum(int(e.get("shieldDamage") or 0) + int(e.get("hullDamage") or 0) for e in log if e.get("actor") == "enemy"),
        }, player=player, metadata={"action": "pirate_station_battle", "run_id": run["id"], "enemy_id": enemy["id"], "outcome": "death"})
        add_event(conn, player["id"], "pirate_station", message, {"runId": run["id"], "enemyId": enemy["id"], "outcome": "death"})
        return {"message": message, "openPage": "System Map"}
    conn.execute("UPDATE ships SET hull=?, shield=? WHERE id=?", (max(1, y_hull), max(0, y_shield), ship["id"]))
    rewards = {"credits": 0, "xp": 0, "items": []}
    outcome = "victory" if player_won else "damaged"
    if player_won:
        conn.execute("UPDATE pirate_station_enemies SET status='defeated', hull=0, shield=0, updated_at=? WHERE id=?", (iso(), enemy["id"]))
        tier = int(enemy.get("tier") or 1)
        credits = int(PIRATE_STATION_BALANCE["victory_credit_per_tier"]) * tier + int(enemy.get("power") or 0) * 4
        station_for_drop = row(conn, "SELECT * FROM pirate_stations WHERE id=?", (run["station_id"],))
        station_tier = pirate_station_tier((station_for_drop or {}).get("tier") or tier)
        xp = int(PIRATE_STATION_BALANCE["victory_xp_per_tier"]) * station_tier
        conn.execute("UPDATE players SET credits=credits+? WHERE id=?", (credits, player["id"]))
        add_xp(conn, player["id"], xp)
        nova_safe_record_guild_contribution(conn, player["id"], "combat", max(75, xp + credits // 100), 1, "pirate_station_battle", {"runId": run["id"], "enemyId": enemy["id"], "stationId": run["station_id"], "outcome": "victory"})
        nova_record_guild_war_battle_outcome(conn, player["id"], None, "pirate", (station_for_drop or {}).get("nearest_planet_id") or player.get("location_planet_id"), {"runId": run["id"], "enemyId": enemy["id"], "source": "pirate_station"})
        salvage_site = None
        if station_for_drop:
            defender_target = {
                "id": f"pirate_station_enemy:{enemy['id']}",
                "rawId": enemy["id"],
                "kind": "npc",
                "name": enemy.get("name") or "Pirate Defender",
                "role": enemy.get("role") or "pirate",
                "level": tier * 5,
                "power": enemy.get("power"),
                "shipName": enemy.get("name") or "Pirate Defender",
                "x_pct": enemy.get("x_pct"),
                "y_pct": enemy.get("y_pct"),
            }
            defender_ship = {
                "name": enemy.get("name") or "Pirate Defender",
                "role": enemy.get("role") or "pirate",
                "tier": tier,
                "hull": enemy.get("max_hull") or enemy.get("hull") or 1000,
                "shield": enemy.get("max_shield") or enemy.get("shield") or 300,
                "armor": tier * 10,
                "combatRating": enemy.get("power") or 100,
            }
            salvage_site = create_salvage_site(conn, int(station_for_drop.get("nearest_planet_id") or 0), None, defender_target, defender_ship, source_type="pirate_station_defender")
        recipe_drops = roll_pirate_station_enemy_recipe_drop(conn, player["id"], station_tier, rng)
        rewards = {"credits": credits, "xp": xp, "items": [], "recipes": recipe_drops, "salvageSite": salvage_site}
        if salvage_site:
            rewards["items"].append({"code": "salvage_site", "name": "Pirate Defender Wreck", "qty": 1, "siteId": salvage_site.get("id")})
        grant_action_progression(conn, player["id"], "combat", 1.0 + tier * 0.35, True)
    else:
        conn.execute("UPDATE pirate_station_enemies SET hull=?, shield=?, updated_at=? WHERE id=?", (max(1, e_hull), max(0, e_shield), iso(), enemy["id"]))
        grant_action_progression(conn, player["id"], "combat", 0.45, False)
        nova_safe_record_guild_contribution(conn, player["id"], "combat", 25, 1, "pirate_station_battle_damaged", {"runId": run["id"], "enemyId": enemy["id"], "stationId": run["station_id"], "outcome": outcome})
    remaining = pirate_station_remaining_count(conn, shared_run_id)
    station_now = row(conn, "SELECT * FROM pirate_stations WHERE id=?", (run["station_id"],))
    if station_now:
        total_now = max(1, int(station_now.get("total_pirates") or 1))
        pct_now = clamp_int(round((remaining / total_now) * 100), 0, 100)
        active_count = pirate_station_active_player_count(conn, int(run["station_id"]))
        status = "depleted" if remaining <= 0 else ("occupied" if active_count > 0 else "active")
        conn.execute("UPDATE pirate_stations SET remaining_pirates=?, resource_pct=?, status=?, occupied_by_player_id=?, updated_at=? WHERE id=?", (remaining, pct_now, status, player["id"] if active_count > 0 else None, iso(), run["station_id"]))
    fresh_run = row(conn, "SELECT * FROM pirate_station_runs WHERE id=?", (run["id"],)) or run
    report = {
        "outcome": outcome,
        "targetName": enemy["name"],
        "log": log,
        "rewards": rewards,
        "remaining": remaining,
        "playerHull": max(1, y_hull),
        "playerShield": max(0, y_shield),
        "enemyHull": max(0, e_hull),
        "enemyShield": max(0, e_shield),
        "message": f"{'Defeated' if player_won else 'Damaged'} {enemy['name']}. {remaining} defenders remain.",
    }
    if remaining <= 0:
        station_tier = int((station_now or {}).get("tier") or (station_for_drop or {}).get("tier") or enemy.get("tier") or 1)
        ultra_reward = roll_pirate_base_ultra_reward(station_tier, rng)
        if ultra_reward:
            granted_ultra = grant_ultra_item_to_player(conn, player["id"], ultra_reward["code"], "pirate_base_ultra", god=god)
            if granted_ultra:
                ultra_reward = granted_ultra
                rewards.setdefault("items", []).append(ultra_reward)
                rewards["ultraItem"] = ultra_reward
        report["message"] = f"Station cleared. Final defender {enemy['name']} destroyed. The pirate station vanished from the system map."
        if ultra_reward:
            report["message"] += f" Ultra vault find: {ultra_reward['name']}."
        conn.execute("DELETE FROM pirate_station_enemies WHERE run_id IN (SELECT id FROM pirate_station_runs WHERE station_id=?)", (run["station_id"],))
        conn.execute("DELETE FROM pirate_station_runs WHERE station_id=?", (run["station_id"],))
        conn.execute("DELETE FROM pirate_stations WHERE id=?", (run["station_id"],))
    if remaining > 0:
        conn.execute("UPDATE pirate_station_runs SET battle_report_json=?, updated_at=? WHERE id=?", (encode_json(report), iso(), run["id"]))
    emit_player_metrics(conn, player["id"], {
        "damage_dealt": sum(int(e.get("shieldDamage") or 0) + int(e.get("hullDamage") or 0) for e in log if e.get("actor") == "player"),
        "damage_taken": sum(int(e.get("shieldDamage") or 0) + int(e.get("hullDamage") or 0) for e in log if e.get("actor") == "enemy"),
        "battles_won": 1 if player_won else 0,
        "battles_survived": 1,
        "npc_kills": 1 if player_won else 0,
    }, player=player, metadata={"action": "pirate_station_battle", "run_id": run["id"], "enemy_id": enemy["id"], "outcome": outcome})
    add_event(conn, player["id"], "pirate_station", report["message"], {"runId": run["id"], "enemyId": enemy["id"], "outcome": outcome})
    return {"message": report["message"], "openPage": "System Map" if remaining <= 0 else "Pirate Station"}




def close_pirate_station_battle(conn: sqlite3.Connection, player: Dict[str, Any]) -> Dict[str, Any]:
    run = active_pirate_station_run(conn, player["id"])
    if not run:
        return {"message": "Pirate station assault complete.", "openPage": "System Map"}
    update_pirate_station_resource(conn, run)
    fresh = row(conn, "SELECT * FROM pirate_station_runs WHERE id=?", (run["id"],))
    if not fresh or fresh.get("status") == "completed":
        return {"message": "Pirate station cleared. Station vanished from the system map.", "openPage": "System Map"}
    conn.execute("UPDATE pirate_station_runs SET battle_open=0, battle_target_enemy_id=NULL, battle_report_json='{}', updated_at=? WHERE id=?", (iso(), run["id"]))
    return {"message": "Battle panel closed. Open-world station movement continues.", "openPage": "Pirate Station"}

def build_ship_status(conn: sqlite3.Connection, player: Dict[str, Any], ship: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    if not ship:
        return {"warnings": ["No active ship"], "systems": []}
    modules = rows(conn, "SELECT sm.*, mt.stats_json FROM ship_modules sm JOIN module_templates mt ON mt.id=sm.module_template_id WHERE sm.ship_id=?", (ship["id"],))
    equipped = [m for m in modules if int(m.get("equipped") or 0)]
    stats: Dict[str, float] = {}
    for m in equipped:
        for k, v in decode_json(m.get("stats_json"), {}).items():
            stats[k] = stats.get(k, 0) + float(v or 0)
    cargo_usage = build_cargo_usage(conn, player["id"])
    hull_pct = int((int(ship.get("hull") or 0) / max(1, int(ship.get("max_hull") or 1))) * 100)
    shield_pct = int((int(ship.get("shield") or 0) / max(1, int(ship.get("max_shield") or 1))) * 100)
    fuel_pct = int((int(player.get("fuel") or 0) / max(1, int(player.get("max_fuel") or 1))) * 100)
    energy_pct = int((int(player.get("energy") or 0) / max(1, int(player.get("max_energy") or 1))) * 100)
    cargo_pct = int((cargo_usage["total"] / max(1, cargo_usage["max"])) * 100)
    warnings = []
    if cargo_usage["over_capacity"] or cargo_pct >= 90: warnings.append("Cargo near or over capacity")
    if fuel_pct <= 18: warnings.append("Fuel low")
    if energy_pct <= 18: warnings.append("Energy low")
    if hull_pct <= 55: warnings.append("Hull damaged")
    if shield_pct <= 35: warnings.append("Shields weak")
    return {"image_url": ship_visual_payload(ship.get("name") or ship.get("template_name"), ship.get("role") or ship.get("class_name")), "warnings": warnings, "systems": [{"key":"hull", "label":"Hull", "value":ship.get("hull") or 0, "max":ship.get("max_hull") or 1, "pct":hull_pct, "danger": hull_pct <= 55}, {"key":"shield", "label":"Shield", "value":ship.get("shield") or 0, "max":ship.get("max_shield") or 1, "pct":shield_pct, "danger": shield_pct <= 35}, {"key":"armor", "label":"Armor", "value":ship.get("armor") or 0, "max":100, "pct":min(100, int(ship.get("armor") or 0)), "danger": False}, {"key":"cargo", "label":"Cargo", "value":cargo_usage["total"], "max":cargo_usage["max"], "pct":cargo_pct, "danger": cargo_pct >= 90}, {"key":"fuel", "label":"Fuel", "value":player.get("fuel") or 0, "max":player.get("max_fuel") or 1, "pct":fuel_pct, "danger": fuel_pct <= 18}, {"key":"energy", "label":"Energy", "value":player.get("energy") or 0, "max":player.get("max_energy") or 1, "pct":energy_pct, "danger": energy_pct <= 18}], "active_modules": len(equipped), "combat_rating": get_ship_power(conn, ship["id"]), "mining_efficiency": int(stats.get("mining", 0) + (ship.get("cargo_capacity") or 0) / 90), "stealth_rating": int(stats.get("smuggling", 0)), "scan_strength": int(stats.get("scanning", 0))}



def unique_list(values: List[Any], limit: int = 20) -> List[Any]:
    seen: List[Any] = []
    for value in values:
        if value not in seen:
            seen.append(value)
        if len(seen) >= limit:
            break
    return seen



