def canonical_slot_type(value: Optional[str]) -> str:
    raw = str(value or "utility").strip().lower().replace(" ", "_").replace("-", "_")
    return {
        "defense": "shield",
        "core": "engine",
        "ship_module": "utility",
        "module": "utility",
        "weaponry": "weapon",
        "mining_laser": "mining",
        "cargo_module": "cargo",
        "stealth_module": "stealth",
        "repair_module": "repair",
        "scanner_array": "scanner",
        "power": "energy",
        "power_core": "energy",
        "jump": "engine",
        "drive": "engine",
    }.get(raw, raw if raw in LOADOUT_SLOT_ORDER else "utility")


def size_fits(item_size: str, slot_size: str) -> bool:
    return SLOT_SIZE_RANK.get(str(item_size or "light"), 1) <= SLOT_SIZE_RANK.get(str(slot_size or "medium"), 2)


def module_loadout_metadata(module: Dict[str, Any]) -> Dict[str, Any]:
    code = str(module.get("code") or module.get("item_code") or "").lower()
    name = str(module.get("name") or "").lower()
    stats = decode_json(module.get("stats_json"), {}) if isinstance(module.get("stats_json"), str) else (module.get("stats") or {})
    raw_slot = canonical_slot_type(module.get("slot_type"))
    compatible = [raw_slot]
    size = "medium"
    equip_type = raw_slot
    unique = ""
    max_per_ship = 99
    if "mining" in code or "mining" in name or stats.get("mining"):
        compatible = ["mining"]
        size = "industrial"
        equip_type = "mining"
    elif "salvage" in code or "reclaimer" in name or stats.get("salvage"):
        compatible = ["mining", "repair", "utility"]
        size = "industrial"
        equip_type = "salvage"
    elif "smuggle" in code or "hidden" in name or stats.get("smuggling"):
        compatible = ["stealth", "cargo"]
        size = "medium"
        equip_type = "stealth"
        unique = "concealment"
        max_per_ship = 1
    elif "cargo" in code or stats.get("cargo"):
        compatible = ["cargo"]
        size = "industrial"
        equip_type = "cargo"
    elif "radar" in code or "radar" in name or stats.get("radar_range") or stats.get("radar_strength"):
        compatible = ["scanner", "utility"]
        size = "light"
        equip_type = "scanner"
        unique = "primary_radar"
        max_per_ship = 1
    elif "scanner" in code or "scan" in code or stats.get("scanning"):
        compatible = ["scanner", "utility"]
        size = "medium"
        equip_type = "scanner"
    elif "shield" in code or stats.get("shield"):
        compatible = ["shield"]
        size = "medium"
        equip_type = "shield"
        unique = "primary_shield"
        max_per_ship = 2
    elif "armor" in code or stats.get("armor"):
        compatible = ["armor"]
        size = "heavy"
        equip_type = "armor"
        unique = "hull_armor"
        max_per_ship = 1
    elif "jump" in code or "drive" in name or stats.get("drive_speed") or stats.get("jump"):
        compatible = ["engine"]
        size = "medium"
        equip_type = "engine"
        unique = "drive_core"
        max_per_ship = 1
    elif "power" in code or "zpm" in code or stats.get("power"):
        compatible = ["energy", "engine"]
        size = "medium"
        equip_type = "energy"
        unique = "power_core"
        max_per_ship = 1
    elif "med" in code or stats.get("medical") or "repair" in code:
        compatible = ["repair", "utility"]
        size = "medium"
        equip_type = "repair"
    elif "drone" in code or stats.get("damage"):
        compatible = ["weapon", "utility"] if "drone" in code else ["weapon"]
        size = "medium" if "railgun" not in code else "light"
        if "missile" in code or "void" in code or "plasma" in code:
            size = "heavy"
        equip_type = "weapon"
    module["equipmentType"] = equip_type
    module["slotTypeRequired"] = compatible[0]
    module["compatibleSlotTypes"] = unique_list(compatible, 6)
    module["sizeClass"] = size
    module["uniqueEquipGroup"] = unique
    module["stackableEquipped"] = False if unique else True
    module["maxEquippedPerShip"] = max_per_ship
    module["compatibleShipClasses"] = []
    module["compatibleShipRoles"] = []
    return module


def hydrate_module_for_loadout(module: Dict[str, Any]) -> Dict[str, Any]:
    module["slot_type"] = canonical_slot_type(module.get("slot_type"))
    module_loadout_metadata(module)
    return module


def default_slots_from_counts(ship: Optional[Dict[str, Any]]) -> List[Dict[str, Any]]:
    if not ship:
        return []
    counts = normalized_ship_weapon_slots(ship.get("slots_json") or "{}", ship.get("role") or ship.get("class_name") or "", ship.get("size_class") or ship.get("template_size_class") or "M", int(ship.get("ship_tier") or ship.get("current_tier") or 1))
    slots: List[Dict[str, Any]] = []
    def add_slots(slot_type: str, count: int, label: str, accepted: List[str], size: str = "medium"):
        for i in range(max(0, int(count or 0))):
            slots.append({"slotId": f"{slot_type}_{i+1}", "slotType": slot_type, "slotLabel": f"{label} {i+1}" if count > 1 else label, "sizeLimit": size, "acceptedCategories": accepted})
    # Legacy templates used weapon/defense/utility/core. Expand them into explicit fitting slots.
    add_slots("weapon", int(counts.get("weapon", 0) or 0), "Weapon", ["weapon"], "medium")
    defense = int(counts.get("defense", 0) or 0)
    if defense:
        add_slots("shield", 1, "Shield", ["shield"], "medium")
        add_slots("armor", max(0, defense - 1), "Armor", ["armor"], "medium")
    utility = int(counts.get("utility", 0) or 0)
    add_slots("utility", utility, "Utility", ["utility", "scanner", "repair"], "medium")
    core = int(counts.get("core", 0) or 0)
    if core:
        add_slots("engine", 1, "Engine", ["engine", "fuel"], "medium")
        add_slots("energy", max(0, core - 1), "Energy Core", ["energy"], "medium")
    return slots


def get_ship_slot_layout(ship: Optional[Dict[str, Any]]) -> List[Dict[str, Any]]:
    if not ship:
        return []
    code = str(ship.get("template_code") or ship.get("code") or "").lower()
    profile = SHIP_LOADOUT_PROFILES.get(code)
    slots = [dict(x) for x in profile] if profile else default_slots_from_counts(ship)
    if not slots:
        slots = [{"slotId":"utility_1","slotType":"utility","slotLabel":"Utility Bay","sizeLimit":"light","acceptedCategories":["utility","scanner","repair"]}]
    for slot in slots:
        slot["slotType"] = canonical_slot_type(slot.get("slotType"))
        slot["sizeLimit"] = slot.get("sizeLimit") or "medium"
        slot["acceptedCategories"] = [canonical_slot_type(x) for x in (slot.get("acceptedCategories") or [slot["slotType"]])]
        slot["acceptedSubcategories"] = slot.get("acceptedSubcategories") or []
        slot["empty"] = True
        slot["installedItemId"] = None
        slot["installedInventoryEntryId"] = None
        slot["installedItem"] = None
    return slots


def ship_slot_layout(ship: Optional[Dict[str, Any]]) -> Dict[str, int]:
    counts = {k: 0 for k in LOADOUT_SLOT_ORDER}
    for slot in get_ship_slot_layout(ship):
        counts[slot["slotType"]] = counts.get(slot["slotType"], 0) + 1
    return {k: v for k, v in counts.items() if v > 0}


def slot_accepts_equipment(slot: Dict[str, Any], module: Dict[str, Any]) -> bool:
    hydrate_module_for_loadout(module)
    slot_type = canonical_slot_type(slot.get("slotType"))
    if slot_type not in (module.get("compatibleSlotTypes") or []):
        return False
    if not size_fits(module.get("sizeClass") or "light", slot.get("sizeLimit") or "medium"):
        return False
    return True


def equipment_blocked_reason_for_slot(conn: sqlite3.Connection, ship: Dict[str, Any], slot: Dict[str, Any], module: Dict[str, Any]) -> Optional[str]:
    hydrate_module_for_loadout(module)
    if slot.get("installedItem"):
        return "Slot already occupied"
    if canonical_slot_type(slot.get("slotType")) not in (module.get("compatibleSlotTypes") or []):
        return f"This ship slot accepts {', '.join(slot.get('acceptedCategories') or [slot.get('slotType')])}; item needs {', '.join(module.get('compatibleSlotTypes') or [])}."
    if not size_fits(module.get("sizeClass") or "light", slot.get("sizeLimit") or "medium"):
        return f"{label_text(str(module.get('sizeClass') or 'light'))} equipment exceeds {label_text(str(slot.get('sizeLimit') or 'medium'))} slot size."
    ship_tier = clamp_tier(ship.get("current_tier", ship.get("ship_tier", 1)))
    if ship_tier < int(module.get("min_ship_tier") or 0):
        return f"Requires ship tier {module.get('min_ship_tier')}"
    return None


def label_text(value: str) -> str:
    return str(value or "").replace("_", " ").title()


def normalize_owned_ship_slots(conn: sqlite3.Connection, ship: Optional[Dict[str, Any]]) -> None:
    if not ship:
        return
    slots = get_ship_slot_layout(ship)
    occupied = {str(r.get("equipped_slot_id")): True for r in rows(conn, "SELECT equipped_slot_id FROM ship_modules WHERE ship_id=? AND equipped=1 AND equipped_slot_id IS NOT NULL", (ship["id"],))}
    legacy = rows(conn, """
        SELECT sm.*, mt.code, mt.name, mt.slot_type, mt.stats_json, mt.min_ship_tier, mt.power_usage
        FROM ship_modules sm JOIN module_templates mt ON mt.id=sm.module_template_id
        WHERE sm.ship_id=? AND sm.equipped=1 AND (sm.equipped_slot_id IS NULL OR sm.equipped_slot_id='')
        ORDER BY sm.id
    """, (ship["id"],))
    for mod in legacy:
        hydrate_module_for_loadout(mod)
        chosen = None
        for slot in slots:
            sid = str(slot["slotId"])
            if sid in occupied:
                continue
            if slot_accepts_equipment(slot, mod):
                chosen = sid
                break
        if chosen:
            occupied[chosen] = True
            conn.execute("UPDATE ship_modules SET equipped_slot_id=?, slot_type=? WHERE id=?", (chosen, canonical_slot_type(mod.get("slot_type")), mod["id"]))
        else:
            # Legacy overfit or incompatible equipment is safely moved to storage instead of crashing the hangar.
            conn.execute("UPDATE ship_modules SET ship_id=NULL, equipped=0, equipped_slot_id=NULL WHERE id=?", (mod["id"],))


def build_ship_slots(conn: sqlite3.Connection, ship: Optional[Dict[str, Any]]) -> List[Dict[str, Any]]:
    if not ship:
        return []
    normalize_owned_ship_slots(conn, ship)
    slots = get_ship_slot_layout(ship)
    installed = ship_installed_modules(conn, int(ship["id"]))
    by_slot = {str(m.get("equipped_slot_id") or ""): m for m in installed if m.get("equipped_slot_id")}
    for slot in slots:
        item = by_slot.get(slot["slotId"])
        if item:
            slot["empty"] = False
            slot["installedItemId"] = item.get("module_template_id")
            slot["installedInventoryEntryId"] = item.get("id")
            slot["installedItem"] = item
    return slots


def find_first_compatible_slot(conn: sqlite3.Connection, ship: Dict[str, Any], module: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    for slot in build_ship_slots(conn, ship):
        if slot.get("installedItem"):
            continue
        if equipment_blocked_reason_for_slot(conn, ship, slot, module) is None:
            return slot
    return None


def ship_role_tags(ship: Dict[str, Any], stats: Dict[str, Any]) -> List[str]:
    tags = []
    role = str(ship.get("role") or ship.get("class_name") or "").lower()
    if role in {"cargo", "trade", "hauler"} or int(stats.get("cargo_capacity") or 0) >= 300:
        tags.append("Trading")
    if role in {"mining", "miner"} or int(stats.get("mining_efficiency") or 0) >= 15:
        tags.append("Mining")
    if role in {"combat", "siege", "fleet"} or int(stats.get("combat_rating") or 0) >= 900:
        tags.append("Combat")
    if role in {"smuggling", "smuggler"} or int(stats.get("stealth") or 0) >= 20:
        tags.append("Smuggling")
    if role in {"exploration", "explorer"} or int(stats.get("scan_strength") or 0) >= 18:
        tags.append("Exploration")
    if role in {"salvage", "salvager"} or int(stats.get("salvage") or 0) >= 20:
        tags.append("Salvage")
    if not tags:
        tags.append("General Purpose")
    return unique_list(tags, 8)


def ship_weakness_tags(ship: Dict[str, Any], stats: Dict[str, Any]) -> List[str]:
    tags = []
    if int(stats.get("cargo_capacity") or 0) < 120:
        tags.append("Low cargo")
    if int(stats.get("combat_rating") or 0) < 700:
        tags.append("Poor combat")
    if float(stats.get("drive_speed") or 0) < 0.8:
        tags.append("Slow drive")
    if int(stats.get("stealth") or 0) < 10:
        tags.append("Weak stealth")
    if int(stats.get("scan_strength") or 0) < 10:
        tags.append("Low scan strength")
    layout = ship_slot_layout(ship)
    if sum(layout.values()) <= 4:
        tags.append("Limited slots")
    return unique_list(tags, 8)


def module_set_meta(code: str) -> Dict[str, Any]:
    return MODULE_SET_FAMILIES.get(recipe_base_code_from_variant(code), {})


def calculate_ship_set_bonuses(installed: List[Dict[str, Any]]) -> Dict[str, Any]:
    counts: Dict[str, int] = {}
    seen_pieces: Dict[str, List[str]] = {}
    stats: Dict[str, float] = {}
    active: List[Dict[str, Any]] = []
    for mod in installed:
        meta = module_set_meta(str(mod.get("code") or ""))
        set_code = meta.get("set_code")
        if not set_code:
            continue
        counts[set_code] = counts.get(set_code, 0) + 1
        seen_pieces.setdefault(set_code, []).append(str(mod.get("name") or mod.get("code") or ""))
    for set_code, count in counts.items():
        definition = SHIP_SET_BONUS_DEFINITIONS.get(set_code)
        if not definition:
            continue
        highest = 0
        for threshold in sorted([k for k in definition.keys() if isinstance(k, int)]):
            if count >= threshold:
                highest = threshold
        if not highest:
            continue
        bonus = definition.get(highest, {})
        for stat, value in bonus.items():
            stats[stat] = stats.get(stat, 0) + float(value or 0)
        active.append({"set_code": set_code, "set_name": definition.get("name") or label_for_api(set_code), "loop": definition.get("loop", ""), "pieces_equipped": count, "threshold": highest, "bonuses": bonus, "pieces": unique_list(seen_pieces.get(set_code, []), 6)})
    return {"stats": stats, "active": active, "counts": counts}


def ship_installed_modules(conn: sqlite3.Connection, ship_id: int) -> List[Dict[str, Any]]:
    mods = rows(conn, """
        SELECT sm.*, mt.code, mt.name, mt.slot_type, mt.rarity, mt.price, mt.stats_json,
               mt.tier as template_tier, mt.max_tier as template_max_tier,
               mt.min_ship_tier, mt.power_usage
        FROM ship_modules sm JOIN module_templates mt ON mt.id=sm.module_template_id
        WHERE sm.ship_id=? AND sm.equipped=1
        ORDER BY mt.slot_type, mt.name
    """, (ship_id,))
    for m in mods:
        m["item_type"] = "ship_module"
        m["category"] = "ship_modules"
        m["slot_type"] = canonical_slot_type(m.get("slot_type"))
        m["current_tier"] = clamp_tier(m.get("current_tier", m.get("template_tier", 1)))
        m["max_tier"] = clamp_tier(m.get("max_tier", m.get("template_max_tier", 5)))
        m["stats"] = apply_tier_to_item_stats(decode_json(m.get("stats_json"), {}) or {}, m["current_tier"])
        hydrate_module_for_loadout(m)
        set_meta = module_set_meta(str(m.get("code") or ""))
        m["set_code"] = set_meta.get("set_code", "")
        m["set_name"] = set_meta.get("set_name", "")
        m["set_loop"] = set_meta.get("loop", "")
        attach_tier_metadata(m)
        attach_item_visual(m)
    return mods


def ship_derived_stats(conn: sqlite3.Connection, ship: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    if not ship:
        return {}
    installed = ship_installed_modules(conn, int(ship["id"]))
    stats_sum: Dict[str, float] = {}
    set_bonus_state = calculate_ship_set_bonuses(installed)
    power_used = 0
    slots_used = {k: 0 for k in LOADOUT_SLOT_ORDER}
    for m in installed:
        slot = str(m.get("equipped_slot_id") or m.get("slot_type") or "utility").split("_")[0]
        slot = canonical_slot_type(slot)
        slots_used[slot] = slots_used.get(slot, 0) + 1
        power_used += int(m.get("power_usage") or 0)
        for k, v in (m.get("stats") or {}).items():
            stats_sum[k] = stats_sum.get(k, 0) + float(v or 0) * max(0.1, float(m.get("durability") or 100) / 100.0)
    tier = clamp_tier(ship.get("current_tier", ship.get("ship_tier", 1)))
    final = {
        "hull": int((ship.get("max_hull") or ship.get("hull") or 0) + stats_sum.get("hull", 0)),
        "shield": int((ship.get("max_shield") or ship.get("shield") or 0) + stats_sum.get("shield", 0)),
        "armor": int((ship.get("armor") or 0) + stats_sum.get("armor", 0)),
        "cargo_capacity": int((ship.get("cargo_capacity") or 0) + stats_sum.get("cargo", 0)),
        "fuel_capacity": int(ship.get("fuel_capacity") or 0),
        "energy_capacity": int(100 + tier * 25 + stats_sum.get("power", 0)),
        "drive_speed": round(float(ship.get("drive_speed") or 0) + float(stats_sum.get("drive_speed", 0)), 2),
        "evasion": int((float(ship.get("drive_speed") or 0) * 18) + stats_sum.get("evasion", 0)),
        "mining_efficiency": int(stats_sum.get("mining", 0) + ((ship.get("cargo_capacity") or 0) / 85)),
        "combat_rating": int(get_ship_power(conn, int(ship["id"]))),
        "scan_strength": int(stats_sum.get("scanning", 0)),
        "radar_strength": int(stats_sum.get("radar_strength", 0) + stats_sum.get("radar_range", 0)),
        "radar_range_system_pct": 0,
        "radar_range_galaxy_pct": 0,
        "stealth": int(stats_sum.get("smuggling", 0)),
        "salvage": int(stats_sum.get("salvage", 0)),
        "module_power_used": int(power_used),
        "module_power_capacity": int(100 + tier * 25 + stats_sum.get("power", 0)),
        "slots_used": slots_used,
        "slots_total": ship_slot_layout(ship),
        "condition_pct": int((int(ship.get("hull") or 0) / max(1, int(ship.get("max_hull") or 1))) * 100),
        "active_set_bonuses": set_bonus_state.get("active", []),
    }
    if ship.get("player_id"):
        try:
            buffs = achievement_passive_buffs(conn, int(ship.get("player_id")))
        except Exception:
            buffs = {}
        final["cargo_capacity"] = int(final["cargo_capacity"] * (1.0 + float(buffs.get("cargo_capacity_pct", 0))))
        final["combat_rating"] = int(final["combat_rating"] * (1.0 + float(buffs.get("combat_rating_pct", 0)) + float(buffs.get("pirate_damage_pct", 0))))
        final["mining_efficiency"] = int(final["mining_efficiency"] * (1.0 + float(buffs.get("mining_efficiency_pct", 0))))
        final["scan_strength"] = int(final["scan_strength"] * (1.0 + float(buffs.get("scan_strength_pct", 0)) + float(buffs.get("security_scan_pct", 0))))
        final["salvage"] = int(final["salvage"] * (1.0 + float(buffs.get("salvage_yield_pct", 0))))
        final["drive_speed"] = round(float(final["drive_speed"]) * (1.0 + float(buffs.get("travel_speed_pct", 0))), 2)
    final["radar_range_system_pct"] = ship_radar_range_pct(conn, ship, "system")
    final["radar_range_galaxy_pct"] = ship_radar_range_pct(conn, ship, "galaxy")
    final["best_for"] = ship_role_tags(ship, final)
    final["weaknesses"] = ship_weakness_tags(ship, final)
    return final


def module_blocked_reasons(conn: sqlite3.Connection, player_id: int, ship: Optional[Dict[str, Any]], module: Dict[str, Any], god: bool = False, slot_id: Optional[str] = None) -> List[str]:
    if god:
        return []
    if not ship:
        return ["No active ship"]
    hydrate_module_for_loadout(module)
    reasons: List[str] = []
    if int(module.get("equipped") or 0):
        reasons.append("Already equipped")
    ship_tier = clamp_tier(ship.get("current_tier", ship.get("ship_tier", 1)))
    if ship_tier < int(module.get("min_ship_tier") or 0):
        reasons.append(f"Requires ship tier {module.get('min_ship_tier')}")
    installed = ship_installed_modules(conn, int(ship["id"]))
    unique = module.get("uniqueEquipGroup") or ""
    if unique and any((x.get("uniqueEquipGroup") == unique) and int(x.get("id") or 0) != int(module.get("id") or 0) for x in installed):
        reasons.append(f"Only one {label_text(unique)} system can be installed")
    max_equipped = int(module.get("maxEquippedPerShip") or 99)
    same_code_count = sum(1 for x in installed if x.get("code") == module.get("code"))
    if same_code_count >= max_equipped:
        reasons.append(f"Max equipped on ship: {max_equipped}")
    derived = ship_derived_stats(conn, ship)
    if int(derived.get("module_power_used") or 0) + int(module.get("power_usage") or 0) > int(derived.get("module_power_capacity") or 1):
        reasons.append("Insufficient power capacity")
    slots = build_ship_slots(conn, ship)
    if slot_id:
        target = next((x for x in slots if x.get("slotId") == slot_id), None)
        if not target:
            reasons.append("Target slot does not exist on this ship")
        else:
            slot_reason = equipment_blocked_reason_for_slot(conn, ship, target, module)
            if slot_reason:
                reasons.append(slot_reason)
    else:
        if not any(equipment_blocked_reason_for_slot(conn, ship, x, module) is None for x in slots):
            accepted = ", ".join(module.get("compatibleSlotTypes") or [module.get("slot_type") or "utility"])
            reasons.append(f"No open compatible slot ({accepted})")
    return unique_list([r for r in reasons if r], 10)


def build_hangar_state(conn: sqlite3.Connection, player: Dict[str, Any], user: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    god = bool((user or {}).get("god_mode"))
    active_ship = row(conn, """
        SELECT s.*, t.code as template_code, t.name as template_name, t.class_name, t.role, t.price,
               t.slots_json, t.ship_tier, t.upkeep_cost, t.starter as template_starter
        FROM ships s JOIN ship_templates t ON t.id=s.template_id
        WHERE s.id=? AND s.player_id=?
    """, (player.get("active_ship_id"), player["id"])) if player.get("active_ship_id") else None
    if not active_ship:
        starter = row(conn, "SELECT s.id FROM ships s JOIN ship_templates t ON t.id=s.template_id WHERE s.player_id=? ORDER BY s.starter DESC, t.starter DESC, s.id LIMIT 1", (player["id"],))
        if starter:
            conn.execute("UPDATE players SET active_ship_id=? WHERE id=?", (starter["id"], player["id"]))
            active_ship = row(conn, """
                SELECT s.*, t.code as template_code, t.name as template_name, t.class_name, t.role, t.price,
                       t.slots_json, t.ship_tier, t.upkeep_cost, t.starter as template_starter
                FROM ships s JOIN ship_templates t ON t.id=s.template_id
                WHERE s.id=? AND s.player_id=?
            """, (starter["id"], player["id"]))
            player["active_ship_id"] = starter["id"]
    owned = rows(conn, """
        SELECT s.*, t.code as template_code, t.name as template_name, t.class_name, t.role, t.price,
               t.slots_json, t.ship_tier, t.upkeep_cost, t.starter as template_starter
        FROM ships s JOIN ship_templates t ON t.id=s.template_id
        WHERE s.player_id=? ORDER BY s.starter DESC, t.ship_tier DESC, t.price
    """, (player["id"],))
    usage = build_cargo_usage(conn, player["id"])
    for sh in owned:
        sh["active"] = int(sh["id"]) == int(player.get("active_ship_id") or 0)
        sh["current_tier"] = clamp_tier(sh.get("current_tier", sh.get("ship_tier", 1)))
        sh["max_tier"] = clamp_tier(sh.get("max_tier", max(sh["current_tier"], sh["current_tier"] + 2)))
        sh["tier_display"] = get_tier_display_data(sh["current_tier"], sh["max_tier"])
        sh["image_url"] = ship_visual_payload(sh.get("name") or sh.get("template_name"), sh.get("role") or sh.get("class_name"))
        sh["slot_layout"] = ship_slot_layout(sh)
        sh["slots"] = build_ship_slots(conn, sh)
        sh["slot_summary"] = {"occupied": sum(0 if x.get("empty") else 1 for x in sh["slots"]), "total": len(sh["slots"])}
        sh["installed_modules"] = ship_installed_modules(conn, int(sh["id"]))
        sh["derived_stats"] = ship_derived_stats(conn, sh)
        sh["speed_profile"] = ship_speed_profile(conn, sh)
        sh["insurance"] = ship_insurance_payload(conn, sh)
        active_capacity = int(sh["derived_stats"].get("cargo_capacity") or sh.get("cargo_capacity") or 0)
        sh["activation_blocked_reason"] = "" if int(usage.get("total") or 0) <= active_capacity or god else f"Cargo exceeds capacity by {int(usage.get('total') or 0) - active_capacity:,}"
    active_payload = next((x for x in owned if int(x["id"]) == int(player.get("active_ship_id") or 0)), None) or (owned[0] if owned else None)
    templates = rows(conn, "SELECT * FROM ship_templates ORDER BY ship_tier, price")
    owned_template_codes = {x.get("template_code") for x in owned}
    available = []
    for st in templates:
        st["owned"] = st.get("code") in owned_template_codes
        st["current_tier"] = clamp_tier(st.get("ship_tier", 1))
        st["max_tier"] = max(st["current_tier"], st["current_tier"] + 2)
        st["tier_display"] = get_tier_display_data(st["current_tier"], st["max_tier"])
        st["image_url"] = ship_visual_payload(st.get("name"), st.get("role") or st.get("class_name"))
        st["slot_layout"] = ship_slot_layout(st)
        st["slots"] = get_ship_slot_layout(st)
        st["slot_summary"] = {"occupied": 0, "total": len(st["slots"])}
        st["can_buy"] = bool(god or (not st["owned"] and int(player.get("credits") or 0) >= int(st.get("price") or 0)))
        st["blocked_reason"] = "Already owned" if st["owned"] else "Insufficient credits" if not st["can_buy"] else ""
        available.append(st)
    storage = rows(conn, """
        SELECT sm.*, mt.code, mt.name, mt.slot_type, mt.rarity, mt.price, mt.stats_json,
               mt.tier as template_tier, mt.max_tier as template_max_tier,
               mt.min_ship_tier, mt.power_usage
        FROM ship_modules sm JOIN module_templates mt ON mt.id=sm.module_template_id
        WHERE sm.player_id=? AND COALESCE(sm.equipped,0)=0
        ORDER BY mt.slot_type, mt.tier DESC, mt.name
    """, (player["id"],))
    active_slots = build_ship_slots(conn, active_payload) if active_payload else []
    for m in storage:
        m["item_type"] = "ship_module"; m["category"] = "ship_modules"; m["legal"] = 1
        m["slot_type"] = canonical_slot_type(m.get("slot_type"))
        m["current_tier"] = clamp_tier(m.get("current_tier", m.get("template_tier", 1)))
        m["max_tier"] = clamp_tier(m.get("max_tier", m.get("template_max_tier", 5)))
        m["stats"] = apply_tier_to_item_stats(decode_json(m.get("stats_json"), {}) or {}, m["current_tier"])
        hydrate_module_for_loadout(m)
        m["compatibleSlots"] = [x for x in active_slots if equipment_blocked_reason_for_slot(conn, active_payload, x, m) is None] if active_payload else []
        m["compatibleSlotIds"] = [x.get("slotId") for x in m["compatibleSlots"]]
        m["blocked_reasons"] = module_blocked_reasons(conn, player["id"], active_payload, m, god)
        m["compatible"] = len(m["blocked_reasons"]) == 0
        m["stat_preview"] = {k: v for k, v in (m.get("stats") or {}).items() if v}
        attach_tier_metadata(m); attach_item_visual(m)
    equipped = ship_installed_modules(conn, int(active_payload["id"])) if active_payload else []
    warnings = []
    if active_payload:
        d = active_payload.get("derived_stats") or {}
        if int(usage.get("pct") or 0) >= 80: warnings.append("Cargo is near full")
        if int(player.get("fuel") or 0) <= max(15, int(player.get("max_fuel") or 0) * 0.18): warnings.append("Fuel is low")
        if int(player.get("energy") or 0) <= max(10, int(player.get("max_energy") or 0) * 0.18): warnings.append("Energy is low")
        if int(active_payload.get("hull") or 0) < int(active_payload.get("max_hull") or 1): warnings.append("Hull needs repair")
        if int(d.get("stealth") or 0) < 10: warnings.append("Poor stealth for illicit market work")
        if int(d.get("mining_efficiency") or 0) < 10: warnings.append("No dedicated mining systems")
    return {
        "activeShipId": player.get("active_ship_id"),
        "activeShip": active_payload or {},
        "ownedShips": owned,
        "availableShips": available,
        "availableModules": storage,
        "availableWeapons": [m for m in storage if "weapon" in (m.get("compatibleSlotTypes") or [])],
        "availableArmor": [m for m in storage if any(x in (m.get("compatibleSlotTypes") or []) for x in ["armor", "shield"])],
        "equippedModules": equipped,
        "equippedWeapons": [m for m in equipped if m.get("slot_type") == "weapon"],
        "equippedArmor": [m for m in equipped if m.get("slot_type") == "defense"],
        "cargoSummary": usage,
        "fuelSummary": {"value": player.get("fuel") or 0, "max": player.get("max_fuel") or 1, "pct": int((int(player.get("fuel") or 0) / max(1, int(player.get("max_fuel") or 1))) * 100)},
        "energySummary": {"value": player.get("energy") or 0, "max": player.get("max_energy") or 1, "pct": int((int(player.get("energy") or 0) / max(1, int(player.get("max_energy") or 1))) * 100)},
        "shipStats": active_payload.get("derived_stats", {}) if active_payload else {},
        "derivedStats": active_payload.get("derived_stats", {}) if active_payload else {},
        "warnings": warnings,
        "compatibilityInfo": {"slotTypes": LOADOUT_SLOT_ORDER, "powerRule": "Installed equipment consumes power and must match explicit ship slots, size limits, tier rules, unique-equip rules, and ownership. Validation is enforced server-side."},
        "insuranceBalance": {"tiers": INSURANCE_BALANCE.get("tiers", {}), "pvpPayoutMult": INSURANCE_BALANCE.get("pvp_payout_mult", 0.70), "note": "Insurance pays credits only. Insured value includes ship price plus material gold-equivalent, but excludes cargo, modules, and salvage."},
        "actionPermissions": {"canRepair": bool(active_payload), "canRefuel": bool(active_payload), "canRecharge": True, "canBuyShips": True, "canInstallModules": bool(active_payload)},
        "statHelp": {
            "hull":"Structural durability. If it reaches zero, the ship can be disabled or destroyed.",
            "shield":"Renewable protection before hull damage.",
            "armor":"Damage mitigation and survivability against hard hits.",
            "cargo_capacity":"Inventory and trade cargo capacity.",
            "fuel_capacity":"Travel range and route flexibility.",
            "energy_capacity":"Action and module power pool.",
            "drive_speed":"Travel time modifier.",
            "evasion":"Reduces danger and combat hit chance.",
            "mining_efficiency":"Improves mining output and related operation odds.",
            "combat_rating":"Improves combat PvE and bounty success.",
            "scan_strength":"Improves exploration and scanning results.",
            "stealth":"Improves smuggling and escape odds."
        }
    }


def enrich_market_item(conn: sqlite3.Connection, item: Dict[str, Any], planet: Dict[str, Any]) -> Dict[str, Any]:
    supply = int(item.get("supply") or 0)
    demand = int(item.get("demand") or 0)
    legal = int(item.get("legal", 1) or 0)
    effects = planet_control_effects(planet)
    risk = effects["illegal_risk"] if not legal else max(1, int(effects["travel_danger"] * 0.35))
    scarcity = "critical" if supply < 18 else "tight" if supply < 38 else "balanced" if supply < 78 else "oversupplied"
    demand_rating = "high" if demand >= 88 else "medium" if demand >= 48 else "low"
    supply_rating = "high" if supply >= 78 else "medium" if supply >= 38 else "low"
    profit = max(0, int(item.get("sell_price") or 0) - int(item.get("buy_price") or 0))
    prior = rows(conn, "SELECT buy_price, sell_price FROM market_history WHERE planet_id=? AND commodity_id=? ORDER BY id DESC LIMIT 2", (item.get("planet_id"), item.get("commodity_id")))
    current_mid = (int(item.get("buy_price") or 0) + int(item.get("sell_price") or 0)) / 2
    prev_mid = ((int(prior[-1]["buy_price"]) + int(prior[-1]["sell_price"])) / 2) if len(prior) > 1 else current_mid
    trend = "up" if current_mid > prev_mid * 1.025 else "down" if current_mid < prev_mid * 0.975 else "flat"
    item.update({"priceTrend": trend, "demandRating": demand_rating, "supplyRating": supply_rating, "riskRating": risk, "profitPotential": profit, "scarcityLevel": scarcity, "pressureScore": clamp_int(int((demand - supply) + (risk if not legal else 0) + 50), 1, 99), "outOfStock": supply <= 0, "stockPct": max(0, min(100, int(round((supply / max(1, MARKET_LAW_BALANCE["max_stock"])) * 100))))})
    # Legal trade is clean. Illicit goods get a real preview from backend heat/security/skill state.
    try:
        current_player = row(conn, "SELECT id FROM players WHERE location_planet_id=? ORDER BY id LIMIT 1", (item.get("planet_id"),))
        if current_player:
            item["illicitRisk"] = illegal_trade_risk_preview(conn, int(current_player["id"]), item, 1, "market_trade") if not legal else {"legal": True, "caughtChance": 0, "passChance": 100, "message": "Legal trade. No risk."}
    except Exception:
        item["illicitRisk"] = None
    return item




def heat_label(heat: int) -> str:
    heat = max(0, min(100, int(heat or 0)))
    if heat >= 80:
        return "lockdown"
    if heat >= 60:
        return "hunted"
    if heat >= 40:
        return "wanted"
    if heat >= 20:
        return "watched"
    return "cold"


def resolve_player_legal_state(conn: sqlite3.Connection, player_id: int) -> Dict[str, Any]:
    player = get_player(conn, player_id)
    now = utcnow()
    heat = int(player.get("heat") or 0)
    last = parse_dt(player.get("heat_updated_at")) or now
    hours = max(0.0, (now - last).total_seconds() / 3600.0)
    if hours > 0:
        # Hot players cool down, but high heat decays slower because authorities keep watching them.
        decay_mult = 0.55 if heat >= 70 else 0.75 if heat >= 40 else 1.0
        heat = max(0, int(heat - (MARKET_LAW_BALANCE["heat_decay_per_hour"] * hours * decay_mult)))
        conn.execute("UPDATE players SET heat=?, heat_updated_at=? WHERE id=?", (heat, iso(now), player_id))
    jail_until = parse_dt(player.get("jailed_until"))
    if jail_until and jail_until <= now:
        cooldown_until = now + timedelta(seconds=MARKET_LAW_BALANCE["post_release_illegal_cooldown_seconds"])
        conn.execute(
            """
            UPDATE players
            SET jailed_until=NULL, jail_reason=NULL, jail_severity=NULL, jail_location=NULL,
                illegal_action_cooldown_until=CASE
                    WHEN illegal_action_cooldown_until IS NULL OR illegal_action_cooldown_until < ? THEN ?
                    ELSE illegal_action_cooldown_until END
            WHERE id=?
            """,
            (iso(cooldown_until), iso(cooldown_until), player_id),
        )
        add_event(conn, player_id, "legal", "Released from custody. Illegal market cooldown remains active.")
    return jail_heat_status(conn, player_id)


def increase_player_heat(conn: sqlite3.Connection, player_id: int, amount: int, reason: str = "illegal activity") -> int:
    status = resolve_player_legal_state(conn, player_id)
    heat = max(0, min(100, int(status.get("heat") or 0) + int(amount or 0)))
    conn.execute("UPDATE players SET heat=?, heat_updated_at=?, security_status=? WHERE id=?", (heat, iso(), heat_label(heat).title(), player_id))
    if amount:
        add_event(conn, player_id, "heat", f"Heat changed by +{int(amount)} from {reason}. Current heat: {heat} ({heat_label(heat)}).")
    return heat


def illegal_severity_for_item(item: Dict[str, Any], qty: int = 1) -> str:
    if int(item.get("legal", 1)):
        return "none"
    category = str(item.get("category") or item.get("item_type") or "").lower()
    base = int(item.get("base_price") or item.get("base_value") or item.get("buy_price") or 0)
    tier = int(item.get("current_tier") or item.get("tier") or 1)
    score = 0
    if category in {"arms", "weapon", "weapons", "black_market"}:
        score += 2
    if category in {"contraband", "documents", "medical", "booster"}:
        score += 1
    if base >= 10000:
        score += 2
    elif base >= 3500:
        score += 1
    if tier >= 5:
        score += 2
    elif tier >= 3:
        score += 1
    if qty >= 25:
        score += 1
    if score >= 5:
        return "extreme"
    if score >= 3:
        return "high"
    if score >= 1:
        return "medium"
    return "low"


def illegal_trade_risk_preview(conn: sqlite3.Connection, player_id: int, item: Dict[str, Any], qty: int, action: str) -> Dict[str, Any]:
    if int(item.get("legal", 1)):
        return {"legal": True, "caughtChance": 0, "passChance": 100, "severity": "none", "message": "Legal trade. No customs risk."}
    status = resolve_player_legal_state(conn, player_id)
    player = get_player(conn, player_id)
    planet = row(conn, "SELECT * FROM planets WHERE id=?", (player["location_planet_id"],)) or {}
    effects = planet_control_effects(planet) if planet else {}
    severity = illegal_severity_for_item(item, qty)
    cfg = MARKET_LAW_BALANCE["severity"][severity]
    security = int(planet.get("security_level") or 50)
    stability = int(planet.get("stability_level") or 50)
    customs = int(planet.get("customs_rating") or security)
    heat = int(status.get("heat") or 0)
    skills = player_skill_totals(conn, player_id)
    smuggling_skill = int(skills.get("smuggling", 0))
    jailbreak_skill = int(skills.get("jailbreaking", 0))
    stealth = max(0, get_ship_power(conn, player.get("active_ship_id")) // 900)
    tier = int(item.get("current_tier") or item.get("tier") or 1)
    base = float(cfg["risk"])
    chance = base
    chance += max(0, security - 40) * 0.0026
    chance += max(0, customs - 45) * 0.0020
    chance += max(0, 55 - stability) * 0.0018
    chance += heat * 0.0032
    chance += max(0, int(qty or 1) - 1) * 0.0012
    chance += max(0, tier - 1) * 0.018
    chance += float(effects.get("illegal_risk", 0)) / 900.0
    chance -= min(0.22, smuggling_skill * 0.006 + stealth * 0.004)
    chance -= min(0.03, jailbreak_skill * 0.0008)
    chance = max(0.02, min(0.95, chance))
    cooldown = int(cfg["cooldown"] + heat * 18 + max(0, int(qty or 1) - 1) * 20)
    cooldown = max(MARKET_LAW_BALANCE["illegal_cooldown_min_seconds"], min(MARKET_LAW_BALANCE["illegal_cooldown_max_seconds"], cooldown))
    return {
        "legal": False,
        "severity": severity,
        "caughtChance": round(chance * 100, 1),
        "passChance": round((1 - chance) * 100, 1),
        "jailMinutesMin": cfg["jail_min"],
        "jailMinutesMax": cfg["jail_max"],
        "heatGainSuccess": cfg["heat_success"],
        "heatGainFailure": cfg["heat_fail"],
        "cooldownSeconds": cooldown,
        "heat": heat,
        "heatLevel": heat_label(heat),
        "blockedReason": illegal_block_reason(status),
        "message": f"{severity.title()} contraband risk. {round(chance * 100, 1)}% caught chance at this location.",
    }


def illegal_block_reason(status: Dict[str, Any]) -> Optional[str]:
    if status.get("jailed"):
        return f"Jailed until {status.get('jailedUntil')}"
    cd = parse_dt(status.get("illegalActionCooldownUntil"))
    if cd and cd > utcnow():
        return f"Illegal market cooldown until {cd.isoformat()}"
    return None


def jail_heat_status(conn: sqlite3.Connection, player_id: int) -> Dict[str, Any]:
    p = get_player(conn, player_id)
    now = utcnow()
    heat = max(0, min(100, int(p.get("heat") or 0)))
    jail_until = parse_dt(p.get("jailed_until"))
    cooldown_until = parse_dt(p.get("illegal_action_cooldown_until"))
    breakout_until = parse_dt(p.get("breakout_cooldown_until"))
    jailed = bool(jail_until and jail_until > now)
    remaining = max(0, int((jail_until - now).total_seconds())) if jailed else 0
    planet = row(conn, "SELECT * FROM planets WHERE id=?", (p.get("location_planet_id"),)) or {}
    bribe = bribe_preview(conn, p, planet, remaining) if jailed else {"available": False, "cost": 0, "reason": "Not jailed"}
    breakout = breakout_preview(conn, p, planet) if jailed else {"available": False, "chance": 0, "reason": "Not jailed"}
    return {
        "heat": heat,
        "heatLevel": heat_label(heat),
        "heatUpdatedAt": p.get("heat_updated_at"),
        "jailed": jailed,
        "jailedUntil": p.get("jailed_until") if jailed else None,
        "jailReason": p.get("jail_reason") if jailed else None,
        "jailSeverity": p.get("jail_severity") if jailed else None,
        "jailLocation": p.get("jail_location") if jailed else None,
        "jailRemainingSeconds": remaining,
        "illegalActionCooldownUntil": p.get("illegal_action_cooldown_until") if cooldown_until and cooldown_until > now else None,
        "illegalCooldownRemainingSeconds": max(0, int((cooldown_until - now).total_seconds())) if cooldown_until and cooldown_until > now else 0,
        "breakoutCooldownUntil": p.get("breakout_cooldown_until") if breakout_until and breakout_until > now else None,
        "breakoutCooldownRemainingSeconds": max(0, int((breakout_until - now).total_seconds())) if breakout_until and breakout_until > now else 0,
        "bribe": bribe,
        "breakout": breakout,
        "balance": MARKET_LAW_BALANCE,
    }


def bribe_preview(conn: sqlite3.Connection, player: Dict[str, Any], planet: Dict[str, Any], remaining_seconds: int) -> Dict[str, Any]:
    severity = player.get("jail_severity") or "medium"
    sev_idx = {"low": 1.0, "medium": 1.8, "high": 3.5, "extreme": 6.0}.get(severity, 1.8)
    security = int(planet.get("security_level") or 50)
    stability = int(planet.get("stability_level") or 50)
    heat = int(player.get("heat") or 0)
    availability_score = 75 - security + max(0, 55 - stability) - int(heat * 0.15)
    available = availability_score >= 12 or security < 45
    minutes = max(10, int(remaining_seconds / 60))
    cost = int(minutes * MARKET_LAW_BALANCE["bribe_base_cost_per_minute"] * sev_idx * (1 + heat / 130.0) * (1 + security / 180.0))
    return {"available": available, "cost": max(1000, cost), "reason": None if available else "This facility is too secure for bribery right now."}


def breakout_preview(conn: sqlite3.Connection, player: Dict[str, Any], planet: Dict[str, Any]) -> Dict[str, Any]:
    cd = parse_dt(player.get("breakout_cooldown_until"))
    if cd and cd > utcnow():
        return {"available": False, "chance": 0, "reason": f"Breakout cooldown until {cd.isoformat()}"}
    skills = player_skill_totals(conn, int(player["id"]))
    jailbreak_skill = int(skills.get("jailbreaking", 0)) + int(skills.get("smuggling", 0))
    security = int(planet.get("security_level") or 50)
    stability = int(planet.get("stability_level") or 50)
    heat = int(player.get("heat") or 0)
    failures = int(player.get("breakout_failures") or 0)
    chance = MARKET_LAW_BALANCE["breakout_base_chance"]
    chance += min(0.62, jailbreak_skill * 0.012)
    chance -= max(0, security - 35) * 0.0025
    chance += max(0, 55 - stability) * 0.0015
    chance -= heat * 0.0015
    chance -= failures * 0.025
    chance = max(MARKET_LAW_BALANCE["breakout_min_chance"], min(MARKET_LAW_BALANCE["breakout_max_chance"], chance))
    return {"available": True, "chance": round(chance * 100, 1), "reason": None, "maxChance": int(MARKET_LAW_BALANCE["breakout_max_chance"] * 100)}


def apply_jail(conn: sqlite3.Connection, player_id: int, planet: Dict[str, Any], reason: str, severity: str, cooldown_seconds: int, *, extra_minutes: int = 0) -> int:
    cfg = MARKET_LAW_BALANCE["severity"].get(severity, MARKET_LAW_BALANCE["severity"]["medium"])
    seed = f"{player_id}:{reason}:{severity}:{int(time.time() // 60)}"
    rng = random.Random(seed)
    minutes = rng.randint(int(cfg["jail_min"]), int(cfg["jail_max"])) + int(extra_minutes or 0)
    until = utcnow() + timedelta(minutes=minutes)
    cooldown_until = until + timedelta(seconds=max(MARKET_LAW_BALANCE["post_release_illegal_cooldown_seconds"], int(cooldown_seconds or 0)))
    conn.execute(
        """
        UPDATE players
        SET jailed_until=?, jail_reason=?, jail_severity=?, jail_location=?, illegal_action_cooldown_until=?, breakout_cooldown_until=NULL
        WHERE id=?
        """,
        (iso(until), reason, severity, (planet or {}).get("name") or "Local Detention", iso(cooldown_until), player_id),
    )
    add_event(conn, player_id, "jail", f"Arrested for {reason}. Sentence: {minutes} minutes at {(planet or {}).get('name') or 'local detention'}.")
    return minutes


def resolve_illicit_trade_or_raise(conn: sqlite3.Connection, player_id: int, item: Dict[str, Any], qty: int, action: str, god: bool = False) -> Dict[str, Any]:
    if int(item.get("legal", 1)) or god:
        return {"legal": True, "caught": False, "risk": {"caughtChance": 0, "severity": "none"}}
    status = resolve_player_legal_state(conn, player_id)
    blocked = illegal_block_reason(status)
    if blocked:
        raise HTTPException(409, blocked)
    risk = illegal_trade_risk_preview(conn, player_id, item, qty, action)
    player = get_player(conn, player_id)
    planet = row(conn, "SELECT * FROM planets WHERE id=?", (player["location_planet_id"],)) or {}
    seed = f"{player_id}:{item.get('code') or item.get('item_code') or item.get('name')}:{qty}:{action}:{int(time.time() // 30)}"
    caught = random.Random(seed).random() < (float(risk["caughtChance"]) / 100.0)
    if caught:
        increase_player_heat(conn, player_id, int(risk["heatGainFailure"]), f"failed {action}")
        minutes = apply_jail(conn, player_id, planet, f"failed {action} involving {item.get('name') or item.get('item_code')}", str(risk["severity"]), int(risk["cooldownSeconds"]))
        return {"legal": False, "caught": True, "risk": risk, "jailMinutes": minutes}
    heat = increase_player_heat(conn, player_id, int(risk["heatGainSuccess"]), f"successful {action}")
    return {"legal": False, "caught": False, "risk": risk, "heat": heat}


def resolve_market_restock(conn: sqlite3.Connection, force: bool = False) -> int:
    now = utcnow()
    tick = row(conn, "SELECT * FROM market_ticks WHERE id=1")
    if not tick:
        conn.execute("INSERT INTO market_ticks (id,last_tick_at) VALUES (1,?)", (iso(now),))
        return 0
    last = parse_dt(tick.get("last_tick_at")) or now
    minutes = int((now - last).total_seconds() // 60)
    interval = int(MARKET_LAW_BALANCE["restock_tick_minutes"])
    if not force and minutes < interval:
        return 0
    steps = max(1, min(12, minutes // max(1, interval))) if not force else 1
    changed = 0
    mps = rows(conn, """
        SELECT mp.*, c.legal, c.category, c.base_price, c.tier, c.name as commodity_name, p.security_level, p.stability_level, p.economy_type, p.market_activity
        FROM market_prices mp
        JOIN commodities c ON c.id=mp.commodity_id
        JOIN planets p ON p.id=mp.planet_id
    """)
    for mp in mps:
        supply = int(mp.get("supply") or 0)
        demand = int(mp.get("demand") or 0)
        max_stock = int(MARKET_LAW_BALANCE["max_stock"])
        if supply >= max_stock and demand <= 50:
            continue
        legal = int(mp.get("legal", 1)) == 1
        tier = int(mp.get("tier") or 1)
        stability = int(mp.get("stability_level") or 50)
        security = int(mp.get("security_level") or 50)
        base_restock = MARKET_LAW_BALANCE["legal_restock_base"] if legal else MARKET_LAW_BALANCE["illegal_restock_base"]
        valuable = int(mp.get("base_price") or 0) >= NPC_MARKET_BALANCE["valuable_base_price"] or tier >= NPC_MARKET_BALANCE["valuable_tier"]
        if valuable:
            if security < 45:
                base_restock += 2
            elif security > 70:
                base_restock = max(0, base_restock - 2)
        category = str(mp.get("category") or "")
        if category in {"food", "civilian", "energy", "ore"} and legal:
            base_restock += 1
        if category in {"arms", "luxury", "contraband", "documents"} or tier >= 4:
            base_restock = max(0, base_restock // MARKET_LAW_BALANCE["rare_restock_divisor"])
        if not legal:
            base_restock += 1 if security < 45 else 0
            base_restock -= 1 if security > 75 else 0
        stability_bonus = 1 if stability >= 70 else -1 if stability <= 30 else 0
        demand_bonus = 1 if demand >= 95 else 0
        restock = max(0, (base_restock + stability_bonus + demand_bonus) * steps)
        if restock <= 0 and supply == 0 and (legal or security < 70):
            restock = 1
        supply_delta = min(max_stock - supply, restock)
        demand_delta = 0
        if supply <= 0:
            demand_delta += MARKET_LAW_BALANCE["zero_stock_demand_gain"] * steps
        elif supply < 18:
            demand_delta += MARKET_LAW_BALANCE["low_stock_demand_gain"] * steps
        elif supply > 95:
            demand_delta -= steps
        if supply_delta:
            demand_delta -= max(0, supply_delta // 4)
        if supply_delta or demand_delta:
            conn.execute(
                "UPDATE market_prices SET supply=max(0,min(?,supply+?)), demand=max(0,min(?,demand+?)) WHERE planet_id=? AND commodity_id=?",
                (max_stock, int(supply_delta), MARKET_LAW_BALANCE["max_demand"], int(demand_delta), mp["planet_id"], mp["commodity_id"]),
            )
            recalc_market_price(conn, mp["planet_id"], mp["commodity_id"], "system_restock", int(supply_delta), int(demand_delta))
            if supply_delta:
                conn.execute(
                    "INSERT INTO npc_action_log (planet_id,action_type,actor_name,message,impact_json,created_at) VALUES (?,?,?,?,?,?)",
                    (mp["planet_id"], "market", "Market Restock", f"{mp['commodity_name']} restocked by {supply_delta}. Demand pressure adjusted by {demand_delta}.", encode_json({"severity":"info","commodity":mp["commodity_name"],"supply_delta":supply_delta,"demand_delta":demand_delta}), iso()),
                )
            changed += 1
    conn.execute("UPDATE market_ticks SET last_tick_at=? WHERE id=1", (iso(now),))
    return changed


def pending_cargo_mass(conn: sqlite3.Connection, player_id: int) -> float:
    return float(scalar(conn, "SELECT COALESCE(SUM(mass),0) FROM pending_cargo_operations WHERE player_id=? AND status='active' AND operation_type LIKE 'buy%'", (player_id,)) or 0)


def cargo_operation_status(conn: sqlite3.Connection, player_id: int) -> Dict[str, Any]:
    op = row(conn, "SELECT * FROM pending_cargo_operations WHERE player_id=? AND status='active' ORDER BY complete_at LIMIT 1", (player_id,))
    if not op:
        return {"active": False, "protected": False, "pendingInboundMass": 0}
    started = parse_dt(op.get("started_at")) or utcnow()
    complete = parse_dt(op.get("complete_at")) or utcnow()
    now = utcnow()
    denom = max(1, (complete - started).total_seconds())
    progress = clamp_int(((now - started).total_seconds() / denom) * 100, 0, 100)
    op_type = str(op.get("operation_type") or "")
    label = "loading" if op_type.startswith("buy") else "mining" if op_type == "mine_ore_site" else "offloading"
    return {
        "active": True,
        "protected": True,
        "id": op.get("id"),
        "operationType": op.get("operation_type"),
        "operationLabel": label,
        "summary": op.get("item_name"),
        "qty": int(op.get("qty") or 0),
        "mass": float(op.get("mass") or 0),
        "gross": int(op.get("gross") or 0),
        "fee": int(op.get("fee") or 0),
        "net": int(op.get("net") or 0),
        "legal": bool(int(op.get("legal") or 0)),
        "startedAt": op.get("started_at"),
        "completeAt": op.get("complete_at"),
        "secondsRemaining": max(0, int((complete - now).total_seconds())),
        "progress": progress,
        "message": f"Cargo {label}: {op.get('qty')}x {op.get('item_name')}. You are protected but cannot travel, change ships, or fight until handling finishes.",
        "pendingInboundMass": pending_cargo_mass(conn, player_id),
        "canCancel": op_type in {"buy_commodity", "sell_commodity", "sell_inventory_item"},
    }


def cargo_handling_minutes(qty: int, mass: float, tier: int = 1, operation_type: str = "buy", god: bool = False) -> int:
    if god:
        return 0
    raw = CARGO_HANDLING_BALANCE["base_minutes"] + float(mass or 0) * CARGO_HANDLING_BALANCE["minutes_per_mass"] + int(qty or 1) * CARGO_HANDLING_BALANCE["minutes_per_unit"] + max(0, int(tier or 1)-1) * CARGO_HANDLING_BALANCE["tier_minutes"]
    if str(operation_type).startswith("sell"):
        raw *= CARGO_HANDLING_BALANCE["offload_mult"]
    if "player_market" in str(operation_type):
        raw *= CARGO_HANDLING_BALANCE["player_market_mult"]
    return int(max(CARGO_HANDLING_BALANCE["min_minutes"], min(CARGO_HANDLING_BALANCE["max_minutes"], math.ceil(raw))))


def begin_cargo_operation(conn: sqlite3.Connection, player_id: int, planet_id: int, operation_type: str, item_code: str, item_name: str, qty: int, mass: float, gross: int, fee: int, net: int, legal: int, payload: Dict[str, Any], god: bool=False) -> Dict[str, Any]:
    if not god and cargo_operation_status(conn, player_id).get("active"):
        raise HTTPException(409, "Cargo handling already in progress. Finish loading/offloading before starting another cargo operation.")
    tier = int(payload.get("tier") or payload.get("current_tier") or 1)
    minutes = cargo_handling_minutes(qty, mass, tier, operation_type, god)
    now = utcnow(); complete = now + timedelta(minutes=minutes)
    conn.execute(
        """
        INSERT INTO pending_cargo_operations (player_id,planet_id,operation_type,item_code,item_name,qty,mass,gross,fee,net,legal,payload_json,status,started_at,complete_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
        """,
        (player_id, planet_id, operation_type, item_code, item_name, int(qty), float(mass), int(gross), int(fee), int(net), int(legal), encode_json(payload), "active", iso(now), iso(complete)),
    )
    op_id = scalar(conn, "SELECT last_insert_rowid()")
    label = "loading" if operation_type.startswith("buy") else "mining" if operation_type == "mine_ore_site" else "offloading"
    summary = f"{label.title()} {qty}x {item_name}"
    conn.execute("UPDATE players SET cargo_operation_until=?, cargo_operation_started_at=?, cargo_operation_type=?, cargo_operation_summary=? WHERE id=?", (iso(complete), iso(now), operation_type, summary, player_id))
    if minutes == 0:
        resolve_completed_cargo_operations(conn, player_id, force=True)
        return {"message": f"God mode completed cargo {label} instantly: {qty}x {item_name}.", "minutes": 0, "operationId": op_id, "cargoProtected": False}
    add_event(conn, player_id, "cargo", f"Started cargo {label}: {qty}x {item_name}. ETA {minutes} minutes. You are protected but cannot travel, fight, or change ships.", {"operationId": op_id, "minutes": minutes, "operationType": operation_type})
    return {"message": f"Cargo {label} started for {qty}x {item_name}. ETA {minutes} minutes. You are protected until handling finishes.", "minutes": minutes, "operationId": op_id, "cargoProtected": True}


def resolve_completed_cargo_operations(conn: sqlite3.Connection, player_id: int, force: bool = False, record_guild: bool = True) -> int:
    now_iso = iso()
    if force:
        ops = rows(conn, "SELECT * FROM pending_cargo_operations WHERE player_id=? AND status='active' ORDER BY id", (player_id,))
    else:
        ops = rows(conn, "SELECT * FROM pending_cargo_operations WHERE player_id=? AND status='active' AND complete_at<=? ORDER BY id", (player_id, now_iso))
    completed = 0
    for op in ops:
        payload = decode_json(op.get("payload_json"), {}) or {}
        typ = str(op.get("operation_type") or "")
        qty = int(op.get("qty") or 0)
        item_name = op.get("item_name") or payload.get("name") or op.get("item_code")
        if typ == "buy_commodity":
            commodity_id = int(payload["commodity_id"])
            avg_cost = int(payload.get("unit_price") or 0)
            existing = row(conn, "SELECT * FROM cargo_hold WHERE player_id=? AND commodity_id=?", (player_id, commodity_id))
            if existing:
                old_qty = int(existing.get("qty") or 0); old_avg = int(existing.get("avg_cost") or avg_cost)
                new_qty = old_qty + qty
                weighted = int(((old_avg * old_qty) + (avg_cost * qty)) / max(1, new_qty))
                conn.execute("UPDATE cargo_hold SET qty=?, avg_cost=? WHERE id=?", (new_qty, weighted, existing["id"]))
            else:
                conn.execute("INSERT INTO cargo_hold (player_id,commodity_id,qty,avg_cost) VALUES (?,?,?,?)", (player_id, commodity_id, qty, avg_cost))
            conn.execute("UPDATE players SET cargo=cargo+? WHERE id=?", (int(math.ceil(float(op.get("mass") or 0))), player_id))
            log_market_transaction(conn, player_id, op.get("planet_id"), commodity_id, payload.get("code") or op.get("item_code"), item_name, "buy_illicit" if not int(op.get("legal") or 1) else "buy", qty, avg_cost, int(op.get("gross") or 0), int(op.get("fee") or 0), int(op.get("gross") or 0)+int(op.get("fee") or 0), int(op.get("legal") or 1))
            emit_player_metric(conn, player_id, "market_purchase_value", int(op.get("gross") or 0) + int(op.get("fee") or 0), planet_id=op.get("planet_id"), metadata={"action": typ, "item": payload.get("code") or op.get("item_code"), "qty": qty, "legal": int(op.get("legal") or 1)})
            add_event(conn, player_id, "cargo", f"Cargo loading complete: {qty}x {item_name} is now in your hold.")
        elif typ in {"sell_commodity", "sell_inventory_item"}:
            conn.execute("UPDATE players SET credits=credits+? WHERE id=?", (int(op.get("net") or 0), player_id))
            commodity_id = payload.get("commodity_id")
            log_market_transaction(conn, player_id, op.get("planet_id"), commodity_id, payload.get("code") or op.get("item_code"), item_name, "sell_inventory_illicit" if (typ=="sell_inventory_item" and not int(op.get("legal") or 1)) else "sell_illicit" if not int(op.get("legal") or 1) else "sell_inventory" if typ=="sell_inventory_item" else "sell", qty, int(payload.get("unit_price") or 0), int(op.get("gross") or 0), int(op.get("fee") or 0), int(op.get("net") or 0), int(op.get("legal") or 1))
            metadata = {"action": typ, "item": payload.get("code") or op.get("item_code"), "qty": qty, "legal": int(op.get("legal") or 1)}
            emit_player_metric(conn, player_id, "market_sales_value", int(op.get("gross") or 0), planet_id=op.get("planet_id"), metadata=metadata)
            if typ == "sell_commodity":
                profit = max(0, (int(payload.get("unit_price") or 0) - int(payload.get("avg_cost") or 0)) * qty - int(op.get("fee") or 0))
                emit_player_metric(conn, player_id, "trade_profit", profit, planet_id=op.get("planet_id"), metadata=metadata)
                if int(op.get("legal") or 1) and profit > 0:
                    trade_influence = max(1, min(10, profit // 5000 + qty // 20))
                    queue_territory_influence(conn, player_id, op.get("planet_id"), "trade", trade_influence, {**metadata, "profit": profit})
            if record_guild:
                nova_safe_record_guild_contribution(conn, player_id, "money", max(25, int(op.get("net") or 0) // 75), qty, "delivery_complete", {**metadata, "operationId": op["id"], "net": int(op.get("net") or 0)})
            add_event(conn, player_id, "cargo", f"Cargo offloading complete: sold {qty}x {item_name} for {int(op.get('net') or 0):,} credits.")
        elif typ == "mine_ore_site":
            code = payload.get("ore_code") or op.get("item_code") or "ore"
            name = payload.get("ore_name") or op.get("item_name") or item_name
            tier = int(payload.get("tier") or 1)
            value = int(payload.get("unit_value") or (60 + tier * 90))
            mass_each = float(payload.get("mass_each") or 0.8)
            add_inventory_item(conn, player_id, code, name, "ore", qty, 1, value, mass_each, f"Mined from an open-world ore field near {payload.get('location_name','the local system')}", "open_world_ore", category="raw_materials", rarity="rare" if tier >= 4 else "uncommon" if tier >= 2 else "common", tier=tier, respect_cargo=True, god=True)
            ultra_reward = None
            if payload.get("ultra_item_code"):
                ultra_reward = grant_ultra_item_to_player(conn, player_id, str(payload.get("ultra_item_code") or ""), "mining_ultra", god=True)
            grant_action_progression(conn, player_id, "mining", max(1.0, qty / 2), True)
            if record_guild:
                nova_safe_record_guild_contribution(conn, player_id, "mining", max(50, qty * max(1, tier) * 8), qty, "open_world_mining_complete", {"operationId": op["id"], "mapObjectKey": payload.get("map_object_key"), "oreCode": code, "tier": tier, "ultraItem": ultra_reward})
            mining_msg = f"Mining operation complete: recovered {qty}x {name} from an open-world ore field."
            if ultra_reward:
                mining_msg += f" Ultra discovery: {ultra_reward['name']}."
            add_event(conn, player_id, "mining", mining_msg, {"ultraItem": ultra_reward})
            emit_player_metrics(conn, player_id, {
                "resources_mined": qty,
                "mining_haul_value": qty * value,
                "mining_missions_completed": 1,
                "rare_resources_mined": qty if tier >= 4 or ultra_reward else 0,
            }, planet_id=op.get("planet_id"), metadata={"action": typ, "item": code, "qty": qty, "tier": tier, "ultra": bool(ultra_reward)})
        conn.execute("UPDATE pending_cargo_operations SET status='complete', completed_at=? WHERE id=?", (iso(), op["id"]))
        completed += 1
    if completed:
        if not row(conn, "SELECT 1 FROM pending_cargo_operations WHERE player_id=? AND status='active'", (player_id,)):
            conn.execute("UPDATE players SET cargo_operation_until=NULL, cargo_operation_started_at=NULL, cargo_operation_type=NULL, cargo_operation_summary=NULL WHERE id=?", (player_id,))
    return completed


def _cargo_operation_market_reversal(conn: sqlite3.Connection, op: Dict[str, Any], payload: Dict[str, Any], reverse_buy: bool) -> None:
    commodity_id = payload.get("commodity_id")
    if not commodity_id:
        return
    qty = int(op.get("qty") or 0)
    if qty <= 0:
        return
    supply_delta = int(qty * ECONOMY_CONFIG["player_market_force"])
    demand_delta = max(1, qty // MARKET_LAW_BALANCE["buy_demand_gain_divisor" if reverse_buy else "sell_demand_relief_divisor"])
    if reverse_buy:
        mutate_market(conn, int(op.get("planet_id") or 0), int(commodity_id), supply_delta, -demand_delta, "player_buy_cancelled")
    else:
        mutate_market(conn, int(op.get("planet_id") or 0), int(commodity_id), -supply_delta, demand_delta, "player_sell_cancelled")


def _restore_cancelled_inventory_sale(conn: sqlite3.Connection, player_id: int, op: Dict[str, Any], payload: Dict[str, Any]) -> None:
    qty = int(op.get("qty") or 0)
    if qty <= 0:
        return
    mass_each = float(payload.get("mass_each") if payload.get("mass_each") is not None else (float(op.get("mass") or 0) / max(1, qty)))
    add_inventory_item(
        conn,
        player_id,
        str(payload.get("code") or op.get("item_code") or "item"),
        str(payload.get("name") or op.get("item_name") or op.get("item_code") or "Item"),
        str(payload.get("item_type") or "goods"),
        qty,
        int(op.get("legal") if op.get("legal") is not None else payload.get("legal", 1)),
        int(payload.get("base_value") or payload.get("unit_price") or 0),
        mass_each,
        str(payload.get("description") or "Cancelled cargo offload returned to inventory."),
        str(payload.get("source") or "cargo_cancel"),
        payload.get("category"),
        payload.get("rarity"),
        subcategory=str(payload.get("subcategory") or ""),
        stack_size=int(payload.get("stack_size") or 9999),
        cargo_exempt=int(payload.get("cargo_exempt") or 0),
        usable=int(payload.get("usable") or 0),
        sellable=int(payload.get("sellable") if payload.get("sellable") is not None else 1),
        craftable_material=int(payload.get("craftable_material") or 0),
        equippable=int(payload.get("equippable") or 0),
        image_id=str(payload.get("image_id") or ""),
        tier=payload.get("current_tier") or payload.get("tier"),
        max_tier=payload.get("max_tier"),
        tier_locked=int(payload.get("tier_locked") or 0),
        tier_source=payload.get("tier_source") or "cargo_cancel",
        item_stats=payload.get("item_stats") or (decode_json(payload.get("item_stats_json"), {}) if isinstance(payload.get("item_stats_json"), str) else {}),
        god=True,
    )


def cancel_active_cargo_operation(conn: sqlite3.Connection, player_id: int) -> Dict[str, Any]:
    op = row(conn, "SELECT * FROM pending_cargo_operations WHERE player_id=? AND status='active' ORDER BY complete_at LIMIT 1", (player_id,))
    if not op:
        return {"message": "No active cargo handling to cancel."}
    payload = decode_json(op.get("payload_json"), {}) or {}
    typ = str(op.get("operation_type") or "")
    qty = int(op.get("qty") or 0)
    item_name = op.get("item_name") or payload.get("name") or op.get("item_code") or "cargo"
    message = f"Cancelled cargo handling for {qty}x {item_name}."
    if typ == "buy_commodity":
        refund = int(op.get("gross") or 0) + int(op.get("fee") or 0)
        if refund > 0:
            conn.execute("UPDATE players SET credits=credits+? WHERE id=?", (refund, player_id))
        _cargo_operation_market_reversal(conn, op, payload, reverse_buy=True)
        message = f"Cancelled loading {qty}x {item_name}. No cargo was loaded and {refund:,} credits were returned."
    elif typ == "sell_commodity":
        commodity_id = int(payload.get("commodity_id") or 0)
        if commodity_id:
            avg_cost = int(payload.get("avg_cost") or payload.get("unit_price") or 0)
            conn.execute(
                """
                INSERT INTO cargo_hold (player_id,commodity_id,qty,avg_cost)
                VALUES (?,?,?,?)
                ON CONFLICT(player_id, commodity_id) DO UPDATE SET
                  qty=qty+excluded.qty,
                  avg_cost=CASE WHEN avg_cost>0 THEN avg_cost ELSE excluded.avg_cost END
                """,
                (player_id, commodity_id, qty, avg_cost),
            )
            conn.execute("UPDATE players SET cargo=cargo+? WHERE id=?", (int(math.ceil(float(op.get("mass") or 0))), player_id))
            _cargo_operation_market_reversal(conn, op, payload, reverse_buy=False)
        message = f"Cancelled offloading {qty}x {item_name}. No sale completed; cargo returned to your hold."
    elif typ == "sell_inventory_item":
        _restore_cancelled_inventory_sale(conn, player_id, op, payload)
        _cargo_operation_market_reversal(conn, op, payload, reverse_buy=False)
        message = f"Cancelled offloading {qty}x {item_name}. No sale completed; items returned to your cargo."
    else:
        message = f"Cancelled cargo handling for {qty}x {item_name}."
    conn.execute("UPDATE pending_cargo_operations SET status='cancelled', completed_at=? WHERE id=?", (iso(), op["id"]))
    if not row(conn, "SELECT 1 FROM pending_cargo_operations WHERE player_id=? AND status='active'", (player_id,)):
        conn.execute("UPDATE players SET cargo_operation_until=NULL, cargo_operation_started_at=NULL, cargo_operation_type=NULL, cargo_operation_summary=NULL WHERE id=?", (player_id,))
    usage = build_cargo_usage(conn, player_id)
    if usage.get("over_capacity"):
        message += f" Cargo is overweight at {usage.get('total')}/{usage.get('max')}; reduce to 100% capacity before departing."
    add_event(conn, player_id, "cargo", message, {"operationId": int(op["id"]), "operationType": typ, "cancelled": True, "cargoUsage": usage})
    return {"message": message, "cancelled": True, "cargo_usage": usage, "forceStateRefresh": True}


def simulate_npc_market_arbitrage(conn: sqlite3.Connection, force: bool = False) -> int:
    conn.execute("CREATE TABLE IF NOT EXISTS app_state (key TEXT PRIMARY KEY, value TEXT NOT NULL)")
    tick = row(conn, "SELECT value FROM app_state WHERE key='npc_market_arbitrage_tick'")
    now = utcnow(); last = parse_dt(tick.get("value")) if tick else None
    if not force and last and (now - last).total_seconds() < NPC_MARKET_BALANCE["arbitrage_tick_minutes"] * 60:
        return 0
    conn.execute("INSERT INTO app_state (key,value) VALUES ('npc_market_arbitrage_tick',?) ON CONFLICT(key) DO UPDATE SET value=excluded.value", (iso(now),))
    changed = 0
    deals = rows(conn, """
        SELECT mp.*, c.name as commodity_name, c.base_price, c.tier, c.legal, c.category, p.name as planet_name, p.security_level, p.market_activity
        FROM market_prices mp JOIN commodities c ON c.id=mp.commodity_id JOIN planets p ON p.id=mp.planet_id
        WHERE (c.base_price>=? OR c.tier>=?) AND (mp.supply>=? OR mp.supply<=?)
        ORDER BY p.market_activity DESC, c.base_price DESC LIMIT 12
    """, (NPC_MARKET_BALANCE["valuable_base_price"], NPC_MARKET_BALANCE["valuable_tier"], NPC_MARKET_BALANCE["npc_buy_high_supply_threshold"], NPC_MARKET_BALANCE["npc_sell_low_supply_threshold"]))
    rng = random.Random(f"npc-market:{int(now.timestamp()//(NPC_MARKET_BALANCE['arbitrage_tick_minutes']*60))}")
    for d in deals:
        supply = int(d.get("supply") or 0); demand = int(d.get("demand") or 0); security = int(d.get("security_level") or 50)
        if supply >= NPC_MARKET_BALANCE["npc_buy_high_supply_threshold"]:
            qty = max(1, min(10, int((supply - 75) / 3) + rng.randint(1, 4)))
            mutate_market(conn, d["planet_id"], d["commodity_id"], -qty, max(1, qty//3), "npc_arbitrage_buy")
            conn.execute("INSERT INTO npc_action_log (planet_id,action_type,actor_name,message,impact_json,created_at) VALUES (?,?,?,?,?,?)", (d["planet_id"], "market", "NPC arbitrage convoy", f"NPC brokers bought {qty}x {d['commodity_name']} after local oversupply at {d['planet_name']}.", encode_json({"severity":"info", "commodity": d["commodity_name"], "supply_delta": -qty}), iso()))
            changed += 1
        elif supply <= NPC_MARKET_BALANCE["npc_sell_low_supply_threshold"] and (security < 55 or int(d.get("legal") or 1)):
            qty = max(1, min(6, rng.randint(1, 3) + (1 if security < 45 else 0)))
            mutate_market(conn, d["planet_id"], d["commodity_id"], qty, -max(1, qty//2), "npc_arbitrage_sell")
            conn.execute("INSERT INTO npc_action_log (planet_id,action_type,actor_name,message,impact_json,created_at) VALUES (?,?,?,?,?,?)", (d["planet_id"], "market", "NPC supply runner", f"NPC runners delivered {qty}x {d['commodity_name']} into a low-stock market at {d['planet_name']}.", encode_json({"severity":"info", "commodity": d["commodity_name"], "supply_delta": qty}), iso()))
            changed += 1
    return changed

def enrich_activity_event(event: Dict[str, Any]) -> Dict[str, Any]:
    meta = decode_json(event.get("impact_json"), {}) if event.get("impact_json") else {}
    typ = str(event.get("action_type") or "event")
    severity = meta.get("severity") or ("danger" if typ in {"pirate", "smuggling"} else "info")
    group = "piracy" if typ in {"pirate", "raid"} else "smuggling" if "smug" in typ else "security" if typ in {"security", "patrol", "customs"} else "economy" if typ in {"trader", "miner", "hauler", "market"} else "travel" if typ == "travel" else "planet control" if "control" in typ else typ
    event["group"] = group
    event["severity"] = severity
    event["icon"] = {"economy":"◈","piracy":"☠","security":"▣","smuggling":"☣","travel":"➤","planet control":"◆"}.get(group, "•")
    event["affected_location"] = event.get("planet_name") or meta.get("location")
    event["affected_good"] = meta.get("commodity") or meta.get("good")
    return event

def build_planet_control_state(conn: sqlite3.Connection, player_id: int, planet: Dict[str, Any]) -> Dict[str, Any]:
    effects = planet_control_effects(planet)
    actions = []
    active = active_job_runtime(conn, player_id)
    active_job = active.get("job_code") if active else None
    for key, cfg in PLANET_CONTROL_ACTIONS.items():
        action = dict(cfg)
        action["key"] = key
        action["job_bonus"] = bool(active_job and active_job in cfg.get("jobs", []))
        action["influence_preview"] = int(cfg.get("influence", 0)) + (2 if action["job_bonus"] else 0)
        actions.append(action)
    events = rows(
        conn,
        """
        SELECT pce.*, COALESCE(pl.callsign,'NPC/System') as actor
        FROM planet_control_events pce
        LEFT JOIN players pl ON pl.id=pce.player_id
        WHERE pce.planet_id=?
        ORDER BY pce.id DESC LIMIT 40
        """,
        (planet["id"],),
    )
    return {"planet": planet, "effects": effects, "actions": actions, "events": events, "balance": PLANET_CONTROL_BALANCE}


def run_planet_control_action(conn: sqlite3.Connection, player: Dict[str, Any], action_key: str, god: bool = False) -> Dict[str, Any]:
    cfg = PLANET_CONTROL_ACTIONS.get(action_key)
    if not cfg:
        raise HTTPException(404, "Planet control action not found")
    planet = row(conn, "SELECT * FROM planets WHERE id=?", (player["location_planet_id"],))
    if not planet:
        raise HTTPException(404, "Current planet not found")
    active = active_job_runtime(conn, player["id"])
    job_bonus = bool(active and active.get("job_code") in cfg.get("jobs", []))
    energy = int(cfg.get("energy") or 0)
    fuel = int(cfg.get("fuel") or 0)
    credits = int(cfg.get("credits") or 0)
    spend(conn, player["id"], credits=credits, fuel=fuel, energy=energy, god=god)
    influence = int(cfg.get("influence") or 0) + (2 if job_bonus else 0)
    security_delta = int(cfg.get("security") or 0)
    stability_delta = int(cfg.get("stability") or 0)
    pirate_delta = int(cfg.get("pirates") or 0)
    market_delta = int(cfg.get("market") or 0)
    conflict_delta = int(cfg.get("conflict") or 0)
    customs_delta = int(cfg.get("customs") or 0)
    production_delta = int(cfg.get("production") or 0)
    market_modifier_delta = int(cfg.get("market_modifier") or 0)
    conn.execute(
        """
        UPDATE planets
        SET security_level=max(1,min(99,security_level+?)),
            stability_level=max(1,min(99,stability_level+?)),
            pirate_activity=max(1,min(99,pirate_activity+?)),
            market_activity=max(1,min(99,market_activity+?)),
            customs_rating=max(1,min(99,customs_rating+?)),
            conflict_level=max(1,min(99,conflict_level+?)),
            production_bonus=max(0,min(50,production_bonus+?)),
            market_modifier=max(-30,min(40,market_modifier+?)),
            player_influence=max(0,min(?,player_influence+?))
        WHERE id=?
        """,
        (security_delta, stability_delta, pirate_delta, market_delta, customs_delta, conflict_delta, production_delta, market_modifier_delta, PLANET_CONTROL_BALANCE["max_player_influence"], influence, planet["id"]),
    )
    categories = cfg.get("market_categories") or []
    commodity = choose_market_commodity(conn, legal=None, categories=categories) or choose_market_commodity(conn)
    if commodity:
        mutate_market(conn, planet["id"], commodity["id"], int(cfg.get("supply") or 0), int(cfg.get("demand") or 0), f"player_control_{action_key}")
    updated = row(conn, "SELECT * FROM planets WHERE id=?", (planet["id"],)) or planet
    # Reprice the local market because control values affect price pressure even when stock did not move.
    for mp in rows(conn, "SELECT commodity_id FROM market_prices WHERE planet_id=?", (planet["id"],)):
        recalc_market_price(conn, planet["id"], mp["commodity_id"], f"planet_control_{action_key}", 0, 0)
    msg = f"{cfg['name']} changed {updated['name']}: influence +{influence}, security {security_delta:+}, stability {stability_delta:+}, pirates {pirate_delta:+}, conflict {conflict_delta:+}."
    conn.execute(
        """
        INSERT INTO planet_control_events
          (planet_id,player_id,action_key,action_name,influence_delta,security_delta,stability_delta,pirate_delta,market_delta,conflict_delta,message,created_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?)
        """,
        (planet["id"], player["id"], action_key, cfg["name"], influence, security_delta, stability_delta, pirate_delta, market_delta, conflict_delta, msg, iso()),
    )
    add_event(conn, player["id"], "planet_control", msg, {"action": action_key, "planet_id": planet["id"]})
    queue_territory_influence(conn, player["id"], planet["id"], "planet_control", max(1, influence), {"action": action_key, "jobBonus": job_bonus}, player=player)
    nova_safe_record_guild_contribution(conn, player["id"], "war", max(20, influence * 35 + max(0, conflict_delta) * 10), 1, "planet_control", {"action": action_key, "planetId": planet["id"], "influence": influence})
    player_guild_id = nova_guild_member_guild_id(conn, player["id"])
    if player_guild_id:
        for war in nova_guild_active_score_wars(conn, player_guild_id, None, planet["id"]):
            nova_guild_add_war_score(conn, int(war["id"]), player_guild_id, "influence_score", max(1, influence))
    return {"message": msg, "planet_control": build_planet_control_state(conn, player["id"], updated)}


def eco_get(path: str, default: Any = None) -> Any:
    cur: Any = ECOSYSTEM_BALANCE
    for part in str(path or "").split("."):
        if not isinstance(cur, dict) or part not in cur:
            return default
        cur = cur[part]
    return cur

def eco_mult(path: str, default: float = 1.0) -> float:
    try:
        return float(eco_get(path, default))
    except Exception:
        return float(default)

def commodity_base_price_balanced(commodity: Dict[str, Any]) -> int:
    base = int(commodity.get("base_price") or 1)
    category = str(commodity.get("category") or "goods").lower()
    mults = ECOSYSTEM_BALANCE.get("commodity_price_mult_by_category") or {}
    mult = float(mults.get(category, 1.0))
    if not int(commodity.get("legal", 1)):
        mult *= float(mults.get("contraband", 1.0)) if category != "contraband" else 1.0
    return max(1, int(base * mult))

def direct_vendor_sell_multiplier(item: Dict[str, Any]) -> float:
    cat = str(item.get("category") or item.get("item_type") or "goods").lower()
    typ = str(item.get("item_type") or "").lower()
    if typ == "ore" or cat == "raw_materials":
        base = float(ECONOMY_BALANCE.get("raw_ore_sell_mult", 0.18))
    else:
        base = float((ECOSYSTEM_BALANCE.get("direct_vendor_sell_mult_by_category") or {}).get(cat, ECONOMY_BALANCE.get("non_market_item_sell_mult", 0.46)))
    rarity = str(item.get("rarity") or item.get("item_rarity") or "common").lower()
    rarity_mult = float((ECOSYSTEM_BALANCE.get("rarity_vendor_mult") or {}).get(rarity, 1.0))
    legal_mult = 1.0 if int(item.get("legal", 1)) else 0.82
    return max(0.05, min(0.95, base * rarity_mult * legal_mult))

def balanced_ship_purchase_price(template: Dict[str, Any]) -> int:
    tier = max(1, int(template.get("ship_tier") or 1))
    size = str(template.get("size_class") or "M").upper()
    size_mult = {"S": 0.92, "M": 1.0, "L": 1.12, "C": 1.34}.get(size, 1.0)
    return max(1, int(int(template.get("price") or 1) * eco_mult("progression_cost_mult.ships", 1.18) * (1.0 + max(0, tier-1) * 0.04) * size_mult))

def insurance_tier_cfg(tier: Optional[str]) -> Dict[str, Any]:
    tiers = INSURANCE_BALANCE.get("tiers") or {}
    key = str(tier or INSURANCE_BALANCE.get("default_tier") or "none").lower()
    if key not in tiers:
        key = str(INSURANCE_BALANCE.get("default_tier") or "none")
    cfg = dict(tiers.get(key) or tiers.get("none") or {})
    cfg["key"] = key
    cfg["coverage_pct"] = max(0.0, min(1.0, float(cfg.get("coverage_pct") or 0)))
    cfg["premium_pct"] = max(0.0, float(cfg.get("premium_pct") or 0))
    cfg["buyable"] = bool(cfg.get("buyable"))
    return cfg

def insurance_material_unit_value(conn: sqlite3.Connection, code: str) -> int:
    code = str(code or "")
    if not code:
        return 0
    profile = SALVAGE_DROP_ITEM_PROFILES.get(code) or {}
    if profile.get("base_value") is not None:
        return max(1, int(profile.get("base_value") or 1))
    commodity = row(conn, "SELECT base_price FROM commodities WHERE code=?", (code,)) if scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='commodities'") else None
    if commodity:
        return commodity_base_price_balanced(commodity)
    inv = row(conn, "SELECT base_value FROM inventory WHERE item_code=? ORDER BY base_value DESC LIMIT 1", (code,)) if scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='inventory'") else None
    return max(1, int((inv or {}).get("base_value") or 100))

def ship_insurance_value_breakdown(conn: sqlite3.Connection, ship: Dict[str, Any]) -> Dict[str, Any]:
    if not ship:
        return {"shipValue": 0, "marketValue": 0, "materialValue": 0, "materials": {}}
    template = row(conn, "SELECT * FROM ship_templates WHERE id=?", (ship.get("template_id"),)) if ship.get("template_id") else None
    merged = dict(template or {})
    merged.update(dict(ship or {}))
    market_value = balanced_ship_purchase_price(merged)
    base_tier = clamp_tier(merged.get("ship_tier", 1))
    current_tier = clamp_tier(merged.get("current_tier", base_tier))
    if current_tier > base_tier:
        market_value = int(market_value * (1.0 + (current_tier - base_tier) * 0.18))
    materials: Dict[str, int] = {}
    material_value = 0
    if bool(INSURANCE_BALANCE.get("include_material_equivalent_in_value", True)):
        target = {
            "role": merged.get("role") or merged.get("class_name") or "ship",
            "tier": current_tier,
            "level": current_tier,
            "shipName": merged.get("name") or merged.get("template_name") or "Ship",
            "power": get_ship_power(conn, int(ship.get("id") or 0)) if ship.get("id") else 100,
        }
        enemy = {
            "name": merged.get("name") or merged.get("template_name") or "Ship",
            "tier": current_tier,
            "hull": int(merged.get("max_hull") or merged.get("hull") or 1000),
            "shield": int(merged.get("max_shield") or merged.get("shield") or 200),
            "combatRating": get_ship_power(conn, int(ship.get("id") or 0)) if ship.get("id") else 100,
            "role": merged.get("role") or merged.get("class_name") or "ship",
        }
        materials = salvage_materials_required_to_build_ship(target, enemy)
        material_value = int(sum(insurance_material_unit_value(conn, code) * int(qty) for code, qty in materials.items()) * float(INSURANCE_BALANCE.get("material_value_mult", 1.0)))
    value = max(0, int(market_value + material_value))
    return {"shipValue": value, "marketValue": int(market_value), "materialValue": int(material_value), "materials": materials}

def ship_insurance_payload(conn: sqlite3.Connection, ship: Dict[str, Any], *, loss_reason: str = "") -> Dict[str, Any]:
    is_starter = bool(int((ship or {}).get("starter") or (ship or {}).get("template_starter") or 0))
    current_key = "starter" if is_starter else str((ship or {}).get("insurance_tier") or INSURANCE_BALANCE.get("default_tier") or "none").lower()
    current = insurance_tier_cfg(current_key)
    breakdown = ship_insurance_value_breakdown(conn, ship or {})
    value = int(breakdown.get("shipValue") or 0)
    payout_mult = 1.0
    reason_l = str(loss_reason or "").lower()
    if reason_l and any(str(m).lower() in reason_l for m in (INSURANCE_BALANCE.get("pvp_reason_markers") or [])):
        payout_mult = max(0.0, min(1.0, float(INSURANCE_BALANCE.get("pvp_payout_mult", 0.70))))
    current_payout = int(value * float(current.get("coverage_pct") or 0) * payout_mult) if not is_starter else 0
    current_premium_value = int(value * float(current.get("premium_pct") or 0))
    options = []
    tier_order = ["basic", "standard", "premium"]
    for key in tier_order:
        cfg = insurance_tier_cfg(key)
        target_premium = int(value * float(cfg.get("premium_pct") or 0))
        upgrade_credit = current_premium_value if key != current.get("key") else target_premium
        if key != current.get("key"):
            upgrade_credit = int(upgrade_credit * float(INSURANCE_BALANCE.get("tier_upgrade_credit_pct", 1.0)))
        cost = max(0, target_premium - upgrade_credit)
        options.append({
            "key": key,
            "label": cfg.get("label") or key.title(),
            "coveragePct": int(round(float(cfg.get("coverage_pct") or 0) * 100)),
            "premiumPct": round(float(cfg.get("premium_pct") or 0) * 100, 2),
            "cost": cost,
            "payout": 0 if is_starter else int(value * float(cfg.get("coverage_pct") or 0)),
            "buyable": bool(cfg.get("buyable")) and not is_starter,
            "active": key == current.get("key"),
            "description": cfg.get("description") or "",
        })
    return {
        "tier": current.get("key"),
        "label": current.get("label") or str(current.get("key") or "none").title(),
        "coveragePct": int(round(float(current.get("coverage_pct") or 0) * 100)),
        "premiumPct": round(float(current.get("premium_pct") or 0) * 100, 2),
        "shipValue": value,
        "marketValue": int(breakdown.get("marketValue") or 0),
        "materialValue": int(breakdown.get("materialValue") or 0),
        "materials": breakdown.get("materials") or {},
        "estimatedPayout": current_payout,
        "payoutMultiplier": payout_mult,
        "starterBlocked": is_starter,
        "options": options,
    }

def balanced_module_purchase_price(module: Dict[str, Any]) -> int:
    tier = max(1, int(module.get("tier") or 1))
    rarity = str(module.get("rarity") or "common").lower()
    rarity_mult = {"common": 1.0, "uncommon": 1.05, "rare": 1.13, "epic": 1.24, "legendary": 1.38}.get(rarity, 1.0)
    return max(1, int(int(module.get("price") or 1) * eco_mult("progression_cost_mult.modules", 1.12) * (1.0 + max(0, tier-1) * 0.035) * rarity_mult))

def balanced_base_placement_cost() -> int:
    return max(1, int(BASE_PLACEMENT_COST * eco_mult("progression_cost_mult.base_placement", 1.35)))

def balanced_base_research_cfg(cfg: Dict[str, Any]) -> Dict[str, Any]:
    out = dict(cfg or {})
    out["cost"] = max(1, int(int(out.get("cost") or 0) * eco_mult("progression_cost_mult.base_research", 1.22)))
    out["hours"] = max(1, int(math.ceil(float(out.get("hours") or 1) * eco_mult("progression_time_mult.base_research", 1.12))))
    return out

def balanced_base_building_cfg(cfg: Dict[str, Any]) -> Dict[str, Any]:
    out = dict(cfg or {})
    out["cost"] = max(1, int(int(out.get("cost") or 0) * eco_mult("progression_cost_mult.base_building", 1.30)))
    out["hours"] = max(1, int(math.ceil(float(out.get("hours") or 1) * eco_mult("progression_time_mult.base_building", 1.18))))
    return out

def balanced_recipe_credit_cost(recipe: Dict[str, Any], base_cost: int) -> int:
    output_key = output_time_key(recipe) if "output_time_key" in globals() else str((recipe.get("output") or {}).get("kind") or "")
    mult = eco_mult("progression_cost_mult.crafting_recipes", 1.10)
    if output_key in {"module", "weapon", "armor"}:
        mult *= 1.12
    if output_key == "ship":
        mult *= 1.30
    return max(0, int(int(base_cost or 0) * mult))

def balanced_crafting_seconds(seconds: int, recipe: Dict[str, Any]) -> int:
    output_key = output_time_key(recipe) if "output_time_key" in globals() else str((recipe.get("output") or {}).get("kind") or "")
    mult = eco_mult("progression_time_mult.crafting", 1.16)
    if output_key in {"module", "weapon", "armor"}:
        mult *= 1.10
    if output_key == "ship":
        mult *= 1.22
    return max(0, int(math.ceil(int(seconds or 0) * mult)))

def ecosystem_balance_summary(conn: sqlite3.Connection) -> Dict[str, Any]:
    ship_prices = [balanced_ship_purchase_price(r) for r in rows(conn, "SELECT * FROM ship_templates")] if scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='ship_templates'") else []
    module_prices = [balanced_module_purchase_price(r) for r in rows(conn, "SELECT * FROM module_templates")] if scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='module_templates'") else []
    commodity_prices = [commodity_base_price_balanced(r) for r in rows(conn, "SELECT * FROM commodities")] if scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='commodities'") else []
    def stat(values: List[int]) -> Dict[str, int]:
        values = sorted([int(v) for v in values if int(v) > 0])
        if not values:
            return {"count": 0, "min": 0, "median": 0, "max": 0}
        return {"count": len(values), "min": values[0], "median": values[len(values)//2], "max": values[-1]}
    return {
        "ships": stat(ship_prices),
        "modules": stat(module_prices),
        "commodities": stat(commodity_prices),
        "vendorSell": {
            "rawOre": ECONOMY_BALANCE.get("raw_ore_sell_mult"),
            "defaultItem": ECONOMY_BALANCE.get("non_market_item_sell_mult"),
            "legalFee": ECONOMY_BALANCE.get("legal_sell_fee"),
            "illegalFee": ECONOMY_BALANCE.get("illegal_sell_fee"),
        },
        "targetShape": ECOSYSTEM_BALANCE.get("philosophy", {}),
        "simulation": {
            "runs": int(PROGRESSION_BALANCE.get("sim_runs", 1000) or 1000),
            "active_hours_per_day": int(PROGRESSION_BALANCE.get("baseline_active_hours_per_day", 12) or 12),
            "target_days": int(PROGRESSION_BALANCE.get("target_completion_days", 490) or 490),
            "mean_days": float((PROGRESSION_BALANCE.get("last_1000_run_result") or {}).get("mean_days", 490.34)),
            "median_days": float((PROGRESSION_BALANCE.get("last_1000_run_result") or {}).get("median_days", 490)),
            "p10_days": float((PROGRESSION_BALANCE.get("last_1000_run_result") or {}).get("p10_days", 487)),
            "p90_days": float((PROGRESSION_BALANCE.get("last_1000_run_result") or {}).get("p90_days", 494)),
            "first_quarter_days": float((PROGRESSION_BALANCE.get("last_1000_run_result") or {}).get("first_quarter_mean_days", 27.52)),
            "third_quarter_days": float((PROGRESSION_BALANCE.get("last_1000_run_result") or {}).get("third_quarter_mean_days", 176.99)),
            "component_mean_days": {
                "skills": 391.73,
                "credits": 222.48,
                "career_ranks": 205.33,
                "player_level": 158.4,
                "loop_achievements": 395.14,
                "completion_wall": 395.18,
            },
            "note": "1000-run no-lifer Monte Carlo target: first quarter around one month, next 50% around six months, final 25% around six months.",
        },
    }


def price_from_supply_demand(commodity: Dict[str, Any], planet: Dict[str, Any], supply: int, demand: int) -> Tuple[int, int]:
    base = commodity_base_price_balanced(commodity)
    supply = max(0, min(MARKET_LAW_BALANCE["max_stock"], int(supply)))
    demand = max(1, min(MARKET_LAW_BALANCE["max_demand"], int(demand)))
    security = int(planet.get("security_level", 50) or 50)
    stability = int(planet.get("stability_level", 60) or 60)
    customs = int(planet.get("customs_rating", 50) or 50)
    pirates = int(planet.get("pirate_activity", 50) or 50)
    market_activity = int(planet.get("market_activity", 50) or 50)
    conflict = int(planet.get("conflict_level", 20) or 20)
    production = int(planet.get("production_bonus", 0) or 0)
    market_modifier = int(planet.get("market_modifier", 0) or 0)
    tax_rate = float(planet.get("tax_rate", 0.03) or 0.03)

    # Supply and demand are the core price inputs. Planet control adds secondary pressure.
    scarcity = 1.0 + max(0, 55 - supply) / 95.0
    abundance = 1.0 - max(0, supply - 70) / 280.0
    demand_pressure = 0.72 + demand / 115.0
    security_tax = 1.0 + security / 1800.0
    stability_risk = 1.0 + max(0, 55 - stability) * ECONOMY_BALANCE["instability_price_mult"]
    activity = 1.0 + (market_activity - 55) / 1200.0 + market_modifier / 1000.0
    conflict_pressure = 1.0 + conflict * PLANET_CONTROL_BALANCE["conflict_price_pressure"]
    tax_pressure = 1.0 + tax_rate * PLANET_CONTROL_BALANCE["tax_price_pressure"]
    production_relief = 1.0 - min(0.22, production * PLANET_CONTROL_BALANCE["production_supply_bonus"])
    illegal_risk = 1.0
    if not commodity.get("legal", 1):
        illegal_risk += (customs + pirates + conflict) * ECONOMY_BALANCE["illegal_security_price_mult"]
        production_relief = 1.0

    buy = int(base * scarcity * demand_pressure * security_tax * illegal_risk * stability_risk * activity * conflict_pressure * tax_pressure * production_relief)
    spread = 0.78 if commodity.get("legal", 1) else 0.68
    sell = int(buy * spread * abundance)
    min_spread = max(1, int(buy * ECONOMY_BALANCE["minimum_trade_spread"]))
    sell = min(sell, max(1, buy - min_spread))
    return max(1, buy), max(1, sell)

def recalc_market_price(conn: sqlite3.Connection, planet_id: int, commodity_id: int, source: str = "system", supply_delta: int = 0, demand_delta: int = 0) -> None:
    mp = row(conn, "SELECT * FROM market_prices WHERE planet_id=? AND commodity_id=?", (planet_id, commodity_id))
    c = row(conn, "SELECT * FROM commodities WHERE id=?", (commodity_id,))
    p = row(conn, "SELECT * FROM planets WHERE id=?", (planet_id,))
    if not mp or not c or not p:
        return
    buy, sell = price_from_supply_demand(c, p, mp["supply"], mp["demand"])
    conn.execute("UPDATE market_prices SET buy_price=?, sell_price=?, updated_at=? WHERE planet_id=? AND commodity_id=?", (buy, sell, iso(), planet_id, commodity_id))
    conn.execute("INSERT INTO market_history (planet_id,commodity_id,source,supply_delta,demand_delta,buy_price,sell_price,created_at) VALUES (?,?,?,?,?,?,?,?)", (planet_id, commodity_id, source, int(supply_delta), int(demand_delta), buy, sell, iso()))


def mutate_market(conn: sqlite3.Connection, planet_id: int, commodity_id: int, supply_delta: int, demand_delta: int, source: str) -> None:
    supply_delta = max(-ECONOMY_BALANCE["npc_stock_nudge_max"] if source.startswith("npc_") else -9999, min(9999, int(supply_delta)))
    demand_delta = max(-ECONOMY_BALANCE["npc_stock_nudge_max"] if source.startswith("npc_") else -9999, min(9999, int(demand_delta)))
    conn.execute(
        "UPDATE market_prices SET supply=max(0,min(?,supply+?)), demand=max(0,min(?,demand+?)) WHERE planet_id=? AND commodity_id=?",
        (MARKET_LAW_BALANCE["max_stock"], supply_delta, MARKET_LAW_BALANCE["max_demand"], demand_delta, planet_id, commodity_id),
    )
    recalc_market_price(conn, planet_id, commodity_id, source, supply_delta, demand_delta)


def inventory_category(item_type: str, legal: int = 1) -> str:
    t = (item_type or "goods").lower().strip()
    if not legal or t in {"contraband", "booster", "illicit_goods", "black_market", "documents"}:
        return "illicit_goods"
    if t in {"ore", "gas", "crystal", "organics", "raw_material", "raw"}:
        return "raw_materials"
    if t in {"material", "component", "chemical", "food", "medical", "electronics"}:
        return "crafting_materials"
    if t in {"refined", "alloy", "wafer", "refined_material"}:
        return "refined_materials"
    if t in {"ship_part", "engine_part", "hull_part", "reactor_part"}:
        return "ship_parts"
    if t in {"module", "ship_module", "scanner", "shield", "engine", "stealth", "cargo_module"}:
        return "ship_modules"
    if t in {"weapon", "laser", "railgun", "missile", "ammo"}:
        return "weapons" if t != "ammo" else "consumables"
    if t in {"armor", "plating", "defense"}:
        return "armor"
    if t in {"fuel", "energy_cell", "reactor", "power_cell"}:
        return "fuel_supplies"
    if t in {"consumable", "repair", "medkit", "rations"}:
        return "consumables"
    if t in {"artifact", "rare", "relic", "ancient"}:
        return "rare_artifacts"
    if t in {"salvage", "scrap", "wreckage"}:
        return "salvage"
    if t in {"quest", "job"}:
        return "quest_items"
    return "goods"


def inventory_rarity(item_type: str, base_value: int, legal: int = 1) -> str:
    t = (item_type or "").lower().strip()
    if t in {"ultra", "ultra_artifact", "artifact_ultra"} or base_value >= 250000:
        return "ultra"
    if not legal:
        return "black_market" if base_value >= 2500 else "rare"
    if t in {"unique", "artifact_unique"} or base_value >= 50000:
        return "legendary"
    if t in {"artifact", "relic"} or base_value >= 18000:
        return "epic"
    if base_value >= 3500:
        return "rare"
    if base_value >= 650:
        return "uncommon"
    return ITEM_RARITY_BY_CATEGORY.get(t, "common")


