def ultra_item_def(code: str) -> Optional[Dict[str, Any]]:
    return ULTRA_ITEM_DEFS.get(str(code or "").strip().lower())


def ultra_item_reward_payload(code: str, qty: int = 1) -> Optional[Dict[str, Any]]:
    item = ultra_item_def(code)
    if not item:
        return None
    return {
        "code": item["code"],
        "name": item["name"],
        "itemType": "ultra_artifact",
        "category": "rare_artifacts",
        "rarity": "ultra",
        "qty": max(1, int(qty or 1)),
        "baseValue": int(item.get("base_value") or 0),
        "mass": float(item.get("mass") or 0.2),
        "description": item.get("description") or "An ultra-rare vanity collectible.",
        "imageUrl": item.get("image_url") or "",
        "accentColor": item.get("color") or "#ffd670",
        "specialText": item.get("special_text") or "You found something extraordinary.",
        "pool": item.get("pool") or "ultra",
        "sellable": 1,
        "legal": 1,
        "tier": 7,
        "maxTier": 7,
    }


def scaled_ultra_drop_chance(level: int, low: float = 0.0025, high: float = 0.01, max_level: int = 50) -> float:
    cap = max(1, int(max_level or 1))
    lvl = max(1, min(int(level or 1), cap))
    ratio = 0.0 if cap <= 1 else float(lvl - 1) / float(cap - 1)
    return float(low) + (float(high) - float(low)) * ratio


def roll_ultra_reward(codes: List[str], chance: float, rng: random.Random) -> Optional[Dict[str, Any]]:
    pool = [str(code) for code in (codes or []) if ultra_item_def(code)]
    if not pool or rng.random() >= float(chance):
        return None
    return ultra_item_reward_payload(rng.choice(pool))


def mission_ultra_codes(mission_key: str) -> List[str]:
    key = str(mission_key or "survey").lower()
    return list((ULTRA_ITEM_POOLS.get("mission_by_key") or {}).get(key) or ULTRA_ITEM_POOLS.get("mission") or [])


def roll_mission_ultra_reward(mission_key: str, level: int, seed: str) -> Optional[Dict[str, Any]]:
    chance = scaled_ultra_drop_chance(level, 0.0025, 0.01, int(WORLD_MISSION_BALANCE.get("planet_mission_max_level", 50) or 50))
    return roll_ultra_reward(mission_ultra_codes(mission_key), chance, random.Random(f"{seed}:mission-ultra"))


def roll_pirate_base_ultra_reward(tier: int, rng: random.Random) -> Optional[Dict[str, Any]]:
    chance = scaled_ultra_drop_chance(tier, 0.0025, 0.01, int(WORLD_SERVER_BALANCE.get("pirate_base_max_tier", 3) or 3))
    return roll_ultra_reward(list(ULTRA_ITEM_POOLS.get("pirate_base") or []), chance, rng)


def roll_mining_ultra_reward(seed: str) -> Optional[Dict[str, Any]]:
    return roll_ultra_reward(list(ULTRA_ITEM_POOLS.get("mining") or []), 0.005, random.Random(f"{seed}:mining-ultra"))


def roll_exploration_node_ultra_reward(seed: str) -> Optional[Dict[str, Any]]:
    return roll_ultra_reward(list(ULTRA_ITEM_POOLS.get("exploration_node") or []), 0.005, random.Random(f"{seed}:exploration-ultra"))


def grant_ultra_item_to_player(conn: sqlite3.Connection, player_id: int, code: str, source: str = "ultra_drop", god: bool = False) -> Optional[Dict[str, Any]]:
    reward = ultra_item_reward_payload(code)
    if not reward:
        return None
    add_inventory_item(
        conn,
        player_id,
        reward["code"],
        reward["name"],
        "ultra_artifact",
        int(reward.get("qty") or 1),
        1,
        int(reward.get("baseValue") or 0),
        float(reward.get("mass") or 0.2),
        reward.get("description") or "Ultra vanity collectible.",
        source,
        category="rare_artifacts",
        rarity="ultra",
        subcategory=str(reward.get("pool") or "ultra"),
        sellable=1,
        craftable_material=0,
        equippable=0,
        usable=0,
        image_id=reward["code"],
        tier=7,
        max_tier=7,
        tier_locked=1,
        tier_source="ultra_drop",
        respect_cargo=False,
        god=god,
    )
    return reward


def item_visual_payload(name: str = "", item_type: str = "goods", category: str = "goods", legal: int = 1, item_code: str = "") -> Dict[str, str]:
    ultra = ultra_item_def(item_code)
    if ultra:
        return {
            "icon": "✦",
            "label": "ULT",
            "tone": "ultra",
            "image_url": ultra.get("image_url") or "",
            "accentColor": ultra.get("color") or "#ffd670",
        }
    category = category or inventory_category(item_type, legal)
    base = dict(ITEM_VISUALS.get(category, ITEM_VISUALS["goods"]))
    code_key = str(item_code or "").lower().strip()
    if code_key and code_key in ITEM_CODE_VISUAL_OVERRIDES:
        base.update(ITEM_CODE_VISUAL_OVERRIDES[code_key])
    base.update(ITEM_TYPE_VISUAL_OVERRIDES.get((item_type or "").lower(), {}))
    if not int(legal or 0):
        base.update({"bg": "28101f", "fg": "ff4d9d"})
    initials = "".join([part[:1] for part in str(name or base["label"]).replace("-", " ").split()[:2]]).upper() or base["label"]
    svg = f"""<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 96 96'>
<defs><radialGradient id='g' cx='35%' cy='25%' r='75%'><stop offset='0%' stop-color='#{base['fg']}' stop-opacity='.55'/><stop offset='55%' stop-color='#{base['bg']}'/><stop offset='100%' stop-color='#02060b'/></radialGradient></defs>
<rect width='96' height='96' rx='18' fill='url(#g)'/>
<path d='M13 70 L48 14 L83 70 Z' fill='none' stroke='#{base['fg']}' stroke-opacity='.40' stroke-width='3'/>
<circle cx='48' cy='48' r='21' fill='#02060b' fill-opacity='.55' stroke='#{base['fg']}' stroke-opacity='.85' stroke-width='2'/>
<text x='48' y='55' text-anchor='middle' font-family='Segoe UI,Arial,sans-serif' font-size='20' font-weight='800' fill='#{base['fg']}'>{initials[:3]}</text>
</svg>"""
    return {
        "icon": base["icon"],
        "label": base["label"],
        "tone": category,
        "image_url": "data:image/svg+xml;utf8," + quote(svg),
    }


def attach_item_visual(item: Dict[str, Any], *, name_key: str = "name", item_type_key: str = "item_type", category_key: str = "category", legal_key: str = "legal") -> Dict[str, Any]:
    visual = item_visual_payload(
        str(item.get(name_key) or item.get("item_name") or item.get("code") or item.get("item_code") or "Item"),
        str(item.get(item_type_key) or item.get("type") or item.get("slot_type") or "goods"),
        str(item.get(category_key) or inventory_category(str(item.get(item_type_key) or "goods"), int(item.get(legal_key, 1) or 1))),
        int(item.get(legal_key, 1) or 1),
        str(item.get("item_code") or item.get("code") or ""),
    )
    item["visual"] = visual
    item["icon"] = visual["icon"]
    item["image_url"] = visual["image_url"]
    return item


_SHIP_VISUAL_CACHE: Dict[str, str] = {}


def ship_visual_payload(name: str = "Ship", role: str = "ship") -> str:
    role_l = str(role or "ship").lower()
    name_s = str(name or "Ship")
    cache_key = f"{role_l}|{name_s}"
    cached = _SHIP_VISUAL_CACHE.get(cache_key)
    if cached is not None:
        return cached
    color = {
        "combat": "ff4d57", "siege": "ff4d57", "fleet": "a65cff",
        "trade": "35f2ff", "cargo": "ffc247", "mining": "4dff91",
        "salvage": "ffae35", "exploration": "8cffff", "starter": "35f2ff",
    }.get(role_l, "35f2ff")
    initials = "".join([p[:1] for p in name_s.replace("-", " ").split()[:2]]).upper() or "SH"
    svg = f"""<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 180 110'>
<defs><linearGradient id='h' x1='0' x2='1'><stop offset='0%' stop-color='#07141d'/><stop offset='100%' stop-color='#{color}' stop-opacity='.55'/></linearGradient></defs>
<rect width='180' height='110' rx='18' fill='#02060b'/>
<path d='M12 56 L55 18 L140 31 L170 56 L140 80 L55 92 Z' fill='url(#h)' stroke='#{color}' stroke-width='3'/>
<path d='M55 18 L75 56 L55 92 M140 31 L117 56 L140 80' fill='none' stroke='#{color}' stroke-opacity='.55' stroke-width='2'/>
<circle cx='92' cy='56' r='18' fill='#02060b' stroke='#{color}' stroke-width='2'/>
<text x='92' y='63' text-anchor='middle' font-family='Segoe UI,Arial,sans-serif' font-size='20' font-weight='800' fill='#{color}'>{initials[:3]}</text>
</svg>"""
    out = "data:image/svg+xml;utf8," + quote(svg)
    if len(_SHIP_VISUAL_CACHE) > 512:
        _SHIP_VISUAL_CACHE.clear()
    _SHIP_VISUAL_CACHE[cache_key] = out
    return out



def clamp_tier(value: Any) -> int:
    try:
        return max(0, min(TIER_BALANCE["max_tier"], int(value)))
    except Exception:
        return TIER_BALANCE["default_tier"]


def infer_tier_from_value(base_value: int, category: str = "", rarity: str = "", legal: int = 1) -> int:
    value = int(base_value or 0)
    cat = str(category or "").lower()
    rar = str(rarity or "").lower()
    if "ultra" in rar:
        return 7
    if "legendary" in rar or "relic" in rar:
        return 7
    if "exotic" in rar:
        return 6
    if value >= 120000:
        return 6
    if value >= 65000:
        return 5
    if value >= 28000 or "epic" in rar:
        return 4
    if value >= 9000 or "rare" in rar or not int(legal):
        return 3 if not int(legal) else 2
    if value >= 1200 or "uncommon" in rar or cat in {"electronics", "medical", "component", "ship_modules", "weapons", "armor"}:
        return 2
    if value <= 90 or cat in {"ore", "food", "salvage", "scrap"}:
        return 0
    return 1


def resolve_tier_definition(tier: Any) -> Dict[str, Any]:
    return dict(TIER_DEFINITIONS.get(clamp_tier(tier), TIER_DEFINITIONS[TIER_BALANCE["default_tier"]]))


def calculate_tier_value_multiplier(tier: Any) -> float:
    return float(resolve_tier_definition(tier)["value_mult"])


def calculate_tier_stat_multiplier(tier: Any) -> float:
    return float(resolve_tier_definition(tier)["stat_mult"])


def calculate_tier_crafting_difficulty(tier: Any) -> float:
    return float(resolve_tier_definition(tier)["craft_difficulty"])


def calculate_tier_market_availability(tier: Any) -> float:
    return float(resolve_tier_definition(tier)["market_availability"])


def calculate_tier_upgrade_cost(current_tier: Any, base_value: int = 0) -> int:
    tier = clamp_tier(current_tier)
    next_tier = min(TIER_BALANCE["max_tier"], tier + 1)
    base = max(TIER_BALANCE["upgrade_base_credit_cost"], int(base_value or 0))
    return int(base * (next_tier ** TIER_BALANCE["upgrade_cost_power"]) * 0.42)


def calculate_tier_salvage_output(item: Dict[str, Any]) -> Dict[str, Any]:
    tier = clamp_tier(item.get("current_tier", item.get("tier", 1)))
    value = int(item.get("tier_value") or item.get("base_value") or 0)
    rarity_rank = INVENTORY_RARITY_ORDER.get(str(item.get("rarity") or "common"), 1)
    ratio = min(TIER_BALANCE["salvage_value_cap"], TIER_BALANCE["salvage_value_floor"] + (tier * 0.025) + (rarity_rank * 0.012))
    scrap = max(1, int(value * ratio / 12))
    materials = []
    if tier >= 1:
        materials.append({"item_code":"refined_alloy", "name":"Refined Hull Alloy", "qty":max(1, tier), "tier":max(0, tier-1)})
    if tier >= 2:
        materials.append({"item_code":"circuit_bundle", "name":"Circuit Wafer Bundle", "qty":max(1, tier//2), "tier":max(1, tier-1)})
    return {"scrap":scrap, "materials":materials, "salvage_value_ratio":round(ratio, 3)}


def apply_tier_to_item_stats(stats: Dict[str, Any], tier: Any) -> Dict[str, Any]:
    mult = calculate_tier_stat_multiplier(tier)
    out: Dict[str, Any] = {}
    for k, v in (stats or {}).items():
        if isinstance(v, (int, float)):
            if k in {"energy_use", "power_usage", "mass", "heat", "maintenance"}:
                out[k] = round(float(v) * (1.0 + clamp_tier(tier) * 0.10), 2)
            else:
                out[k] = round(float(v) * mult, 2)
        else:
            out[k] = v
    return out


def validate_tier_requirement(player: Dict[str, Any], tier: Any) -> Dict[str, Any]:
    definition = resolve_tier_definition(tier)
    needed = int(definition.get("min_level") or 1)
    level = int(player.get("level") or 1)
    return {"ok": level >= needed, "required_level": needed, "player_level": level, "reason": "" if level >= needed else f"requires player level {needed}"}


def get_max_tier_for_item(item: Dict[str, Any]) -> int:
    if int(item.get("tier_locked") or 0):
        return clamp_tier(item.get("current_tier", item.get("tier", item.get("base_tier", 1))))
    explicit = item.get("max_tier")
    if explicit not in (None, ""):
        return clamp_tier(explicit)
    cat = str(item.get("category") or "")
    if cat in {"weapons", "armor", "ship_modules", "ship_parts"}:
        return 5
    if cat in {"rare_artifacts"}:
        return 7
    if cat in {"raw_materials", "crafting_materials", "refined_materials", "salvage"}:
        return 4
    return 2


def get_tier_display_data(tier: Any, max_tier: Any = None) -> Dict[str, Any]:
    d = resolve_tier_definition(tier)
    current = clamp_tier(tier)
    d.update({"tier": current, "current_tier": current, "max_tier": clamp_tier(max_tier if max_tier not in (None, "") else get_max_tier_for_item({"current_tier":current}))})
    return d


def attach_tier_metadata(item: Dict[str, Any]) -> Dict[str, Any]:
    inferred = infer_tier_from_value(int(item.get("base_value") or item.get("price") or item.get("base_price") or 0), item.get("category") or item.get("item_type") or "", item.get("rarity") or "", int(item.get("legal", 1)))
    base_tier = clamp_tier(item.get("base_tier", item.get("tier", inferred)))
    current_tier = clamp_tier(item.get("current_tier", item.get("tier", base_tier)))
    max_tier = get_max_tier_for_item({**item, "current_tier": current_tier})
    item["tier"] = current_tier
    item["base_tier"] = base_tier
    item["current_tier"] = current_tier
    item["max_tier"] = max_tier
    item["tier_locked"] = bool(int(item.get("tier_locked") or (1 if max_tier <= current_tier and str(item.get("category") or "") in {"goods", "illicit_goods", "consumables"} else 0)))
    item["tier_source"] = item.get("tier_source") or item.get("source") or "system"
    item["tier_display"] = get_tier_display_data(current_tier, max_tier)
    base_val = int(item.get("base_value") or item.get("price") or item.get("base_price") or 0)
    item["tier_value"] = max(0, int(base_val * calculate_tier_value_multiplier(current_tier)))
    item["tier_stat_multiplier"] = calculate_tier_stat_multiplier(current_tier)
    return item


def tier_required_materials(current_tier: int) -> Dict[str, int]:
    next_tier = clamp_tier(current_tier + 1)
    return {
        TIER_BALANCE["upgrade_material_code"]: max(1, next_tier * 2),
        TIER_BALANCE["upgrade_circuit_code"]: max(0, next_tier - 1),
    }


def tier_upgrade_preview(conn: sqlite3.Connection, player_id: int, item: Dict[str, Any]) -> Dict[str, Any]:
    item = attach_tier_metadata(dict(item))
    current = int(item["current_tier"])
    max_t = int(item["max_tier"])
    if current >= max_t or item.get("tier_locked"):
        return {"can_upgrade": False, "reason": "tier locked or max tier reached", "current_tier": current, "next_tier": current, "max_tier": max_t}
    required = tier_required_materials(current)
    availability = material_availability(conn, player_id) if scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='inventory'") else {}
    materials = []
    missing = []
    for code, qty in required.items():
        if qty <= 0:
            continue
        have = int((availability.get(code) or {}).get("qty") or 0)
        row_data = {"item_code": code, "name": (availability.get(code) or {}).get("name") or label_for_api(code), "required": qty, "available": have, "met": have >= qty}
        materials.append(row_data)
        if have < qty:
            missing.append(row_data)
    cost = calculate_tier_upgrade_cost(current, int(item.get("base_value") or 0))
    skills = player_skill_totals(conn, player_id) if scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='player_skills'") else {}
    success = TIER_BALANCE["upgrade_success_base"] - (current * TIER_BALANCE["upgrade_success_penalty_per_tier"]) + (skills.get("engineering", 0) + skills.get("crafting", 0)) * TIER_BALANCE["upgrade_skill_bonus"]
    success = max(0.35, min(0.96, success))
    p = get_player(conn, player_id)
    blockers = []
    if missing:
        blockers.append("missing tier materials")
    if int(p.get("credits") or 0) < cost:
        blockers.append("not enough credits")
    return {"can_upgrade": not blockers, "reason": "; ".join(blockers), "current_tier": current, "next_tier": current + 1, "max_tier": max_t, "materials": materials, "credits": cost, "success_odds": round(success, 3), "before_multiplier": calculate_tier_stat_multiplier(current), "after_multiplier": calculate_tier_stat_multiplier(current + 1)}


def log_market_transaction(
    conn: sqlite3.Connection,
    player_id: int,
    planet_id: int,
    commodity_id: Optional[int],
    item_code: str,
    item_name: str,
    action: str,
    qty: int,
    unit_price: int,
    gross: int,
    fee: int,
    net: int,
    legal: int,
    source: str = "player",
) -> None:
    conn.execute(
        """
        INSERT INTO market_transactions
          (player_id,planet_id,commodity_id,item_code,item_name,action,qty,unit_price,gross,fee,net,legal,source,created_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)
        """,
        (player_id, planet_id, commodity_id, item_code, item_name, action, qty, unit_price, gross, fee, net, int(legal), source, iso()),
    )


def add_inventory_item(
    conn: sqlite3.Connection,
    player_id: int,
    item_code: str,
    name: str,
    item_type: str,
    qty: int,
    legal: int = 1,
    base_value: int = 0,
    mass: float = 1,
    description: str = "",
    source: str = "system",
    category: Optional[str] = None,
    rarity: Optional[str] = None,
    *,
    subcategory: str = "",
    stack_size: Optional[int] = None,
    cargo_exempt: int = 0,
    usable: Optional[int] = None,
    sellable: Optional[int] = None,
    craftable_material: Optional[int] = None,
    equippable: Optional[int] = None,
    image_id: str = "",
    tier: Optional[int] = None,
    max_tier: Optional[int] = None,
    tier_locked: int = 0,
    tier_source: Optional[str] = None,
    item_stats: Optional[Dict[str, Any]] = None,
    respect_cargo: bool = False,
    god: bool = False,
) -> None:
    if qty <= 0:
        return
    category = category or inventory_category(item_type, legal)
    rarity = rarity or inventory_rarity(item_type, base_value, legal)
    stack_size = int(stack_size or (1 if item_type in INVENTORY_BALANCE["non_stackable_types"] else INVENTORY_BALANCE["max_stack_default"]))
    usable = int(usable if usable is not None else (1 if category in {"consumables", "fuel_supplies"} or item_type in {"consumable", "repair", "medkit", "fuel", "energy_cell"} else 0))
    sellable = int(sellable if sellable is not None else (0 if category == "quest_items" else 1))
    craftable_material = int(craftable_material if craftable_material is not None else (1 if category in {"raw_materials", "crafting_materials", "refined_materials", "salvage"} else 0))
    equippable = int(equippable if equippable is not None else (1 if category in {"ship_modules", "weapons", "armor"} or item_type in {"ship_module", "module", "weapon", "armor"} else 0))
    cargo_exempt = int(cargo_exempt or (1 if category == "quest_items" else 0))
    inferred_tier = infer_tier_from_value(int(base_value), category, rarity, legal)
    current_tier = clamp_tier(tier if tier is not None else inferred_tier)
    base_tier = current_tier
    max_tier_value = max(current_tier, clamp_tier(max_tier if max_tier is not None else get_max_tier_for_item({"category": category, "current_tier": current_tier})))
    tier_source_value = tier_source or source or "system"
    item_stats_json = encode_json(item_stats or {})
    if respect_cargo and not god and not can_fit_cargo(conn, player_id, float(mass) * int(qty), cargo_exempt=bool(cargo_exempt)):
        raise HTTPException(400, "Not enough cargo capacity for inventory reward")
    conn.execute(
        """
        INSERT INTO inventory
          (player_id,item_code,name,item_type,category,subcategory,qty,legal,base_value,mass,cargo_exempt,usable,sellable,craftable_material,equippable,image_id,description,source,rarity,stack_size,reserved_qty,acquired_at,base_tier,current_tier,max_tier,tier_locked,tier_source,item_stats_json)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,0,?,?,?,?,?,?,?)
        ON CONFLICT(player_id,item_code) DO UPDATE SET
          qty=qty+excluded.qty,
          name=excluded.name,
          item_type=excluded.item_type,
          category=excluded.category,
          subcategory=excluded.subcategory,
          legal=excluded.legal,
          base_value=excluded.base_value,
          mass=excluded.mass,
          cargo_exempt=excluded.cargo_exempt,
          usable=excluded.usable,
          sellable=excluded.sellable,
          craftable_material=excluded.craftable_material,
          equippable=excluded.equippable,
          image_id=excluded.image_id,
          description=excluded.description,
          source=excluded.source,
          rarity=excluded.rarity,
          stack_size=excluded.stack_size,
          current_tier=max(current_tier, excluded.current_tier),
          max_tier=max(max_tier, excluded.max_tier),
          tier_locked=excluded.tier_locked,
          tier_source=excluded.tier_source,
          item_stats_json=excluded.item_stats_json
        """,
        (player_id, item_code, name, item_type, category, subcategory, int(qty), int(legal), int(base_value), float(mass), cargo_exempt, usable, sellable, craftable_material, equippable, image_id, description, source, rarity, stack_size, iso(), base_tier, current_tier, max_tier_value, int(tier_locked), tier_source_value, item_stats_json),
    )


def remove_inventory_item(conn: sqlite3.Connection, player_id: int, item_code: str, qty: int) -> Dict[str, Any]:
    inv = row(conn, "SELECT * FROM inventory WHERE player_id=? AND item_code=?", (player_id, item_code))
    if not inv or int(inv["qty"] or 0) - int(inv.get("reserved_qty") or 0) < qty:
        raise HTTPException(400, "Not enough inventory")
    conn.execute("UPDATE inventory SET qty=max(0,qty-?) WHERE player_id=? AND item_code=?", (qty, player_id, item_code))
    conn.execute("DELETE FROM inventory WHERE player_id=? AND item_code=? AND qty<=0", (player_id, item_code))
    return inv




def resolve_item_definition(conn: sqlite3.Connection, item_code: str) -> Dict[str, Any]:
    inv = row(conn, "SELECT * FROM inventory WHERE item_code=? ORDER BY id DESC LIMIT 1", (item_code,))
    if inv:
        return dict(inv)
    c = row(conn, "SELECT * FROM commodities WHERE code=?", (item_code,))
    if c:
        return {
            "item_code": c["code"], "name": c["name"], "item_type": c.get("category") or "goods",
            "category": "illicit_goods" if not int(c.get("legal", 1)) else "goods",
            "legal": int(c.get("legal", 1)), "base_value": int(c.get("base_price") or 0),
            "mass": float(c.get("mass") or 1), "description": c.get("description") or "Market commodity.",
            "rarity": inventory_rarity(c.get("category", "goods"), int(c.get("base_price") or 0), int(c.get("legal", 1))),
            "tier": clamp_tier(c.get("tier", infer_tier_from_value(int(c.get("base_price") or 0), c.get("category", "goods"), "", int(c.get("legal", 1))))),
            "current_tier": clamp_tier(c.get("tier", 1)), "max_tier": clamp_tier(c.get("max_tier", 2)), "tier_locked": int(c.get("tier_locked", 1)),
        }
    mt = row(conn, "SELECT * FROM module_templates WHERE code=?", (item_code,))
    if mt:
        return {
            "item_code": mt["code"], "name": mt["name"], "item_type": "ship_module", "category": "ship_modules",
            "legal": 1, "base_value": int(mt.get("price") or 0), "mass": 3.0,
            "description": f"{mt.get('rarity','rare')} {mt.get('slot_type','utility')} module",
            "rarity": mt.get("rarity") or "rare", "equippable": 1,
            "tier": clamp_tier(mt.get("tier", 1)), "current_tier": clamp_tier(mt.get("tier", 1)), "max_tier": clamp_tier(mt.get("max_tier", 5)), "tier_locked": 0,
            "stats": apply_tier_to_item_stats(decode_json(mt.get("stats_json"), {}) or {}, mt.get("tier", 1)),
        }
    return {"item_code": item_code, "name": label_for_api(item_code), "item_type": "goods", "category": "goods", "legal": 1, "base_value": 0, "mass": 1.0, "description": "Unknown inventory item.", "rarity": "common", "tier": 1, "current_tier": 1, "max_tier": 2, "tier_locked": 0}


def get_inventory_quantity(conn: sqlite3.Connection, player_id: int, item_code: str) -> int:
    inv = row(conn, "SELECT qty FROM inventory WHERE player_id=? AND item_code=?", (player_id, item_code))
    return int(inv.get("qty") or 0) if inv else 0


def get_available_quantity(conn: sqlite3.Connection, player_id: int, item_code: str) -> int:
    inv = row(conn, "SELECT qty,reserved_qty FROM inventory WHERE player_id=? AND item_code=?", (player_id, item_code))
    return max(0, int(inv.get("qty") or 0) - int(inv.get("reserved_qty") or 0)) if inv else 0


def reserve_inventory_quantity(conn: sqlite3.Connection, player_id: int, item_code: str, qty: int) -> None:
    qty = int(qty)
    if qty <= 0:
        return
    if get_available_quantity(conn, player_id, item_code) < qty:
        raise HTTPException(400, "Not enough available inventory to reserve")
    conn.execute("UPDATE inventory SET reserved_qty=reserved_qty+? WHERE player_id=? AND item_code=?", (qty, player_id, item_code))


def release_reserved_inventory_quantity(conn: sqlite3.Connection, player_id: int, item_code: str, qty: int) -> None:
    qty = int(qty)
    if qty <= 0:
        return
    conn.execute("UPDATE inventory SET reserved_qty=max(0,reserved_qty-?) WHERE player_id=? AND item_code=?", (qty, player_id, item_code))


def calculate_cargo_capacity(conn: sqlite3.Connection, player_id: int) -> int:
    p = get_player(conn, player_id)
    return int(p.get("max_cargo") or 0)


def can_fit_cargo(conn: sqlite3.Connection, player_id: int, added_mass: float, *, cargo_exempt: bool = False) -> bool:
    if cargo_exempt:
        return True
    usage = build_cargo_usage(conn, player_id)
    return math.ceil(float(usage.get("total") or 0) + float(added_mass or 0)) <= int(usage.get("max") or 0)


def validate_inventory_action(conn: sqlite3.Connection, player_id: int, item_code: str, qty: int, action: str) -> Dict[str, Any]:
    inv = row(conn, "SELECT * FROM inventory WHERE player_id=? AND item_code=?", (player_id, item_code))
    reasons: List[str] = []
    if not inv:
        reasons.append("not owned")
    else:
        available = max(0, int(inv.get("qty") or 0) - int(inv.get("reserved_qty") or 0))
        if available < int(qty): reasons.append("insufficient available quantity")
        if action in {"sell", "list"} and not int(inv.get("sellable", 1)): reasons.append("not sellable")
        if action == "use" and not int(inv.get("usable", 0)): reasons.append("not usable")
        if action == "equip" and not int(inv.get("equippable", 0)): reasons.append("not equippable")
        if int(inv.get("reserved_qty") or 0) > 0 and action in {"sell", "use", "equip", "craft", "list"}: reasons.append("some quantity reserved/listed")
    return {"ok": not reasons, "reasons": reasons, "item": inv}


def calculate_inventory_value(conn: sqlite3.Connection, player_id: int) -> int:
    return int(scalar(conn, "SELECT COALESCE(SUM(qty * base_value),0) FROM inventory WHERE player_id=?", (player_id,)) or 0)


def get_inventory_by_category(conn: sqlite3.Connection, player_id: int, category: str) -> List[Dict[str, Any]]:
    data = rows(conn, "SELECT * FROM inventory WHERE player_id=? AND category=? AND qty>0 ORDER BY rarity DESC, base_value DESC, name", (player_id, category))
    for item in data:
        enrich_inventory_entry(conn, player_id, item)
    return data


def item_used_in_recipes(conn: sqlite3.Connection, item_code: str) -> List[Dict[str, Any]]:
    hits = []
    for rec in rows(conn, "SELECT code,name,inputs_json FROM crafting_recipes ORDER BY name"):
        inputs = decode_json(rec.get("inputs_json"), {}) or {}
        if item_code in inputs:
            hits.append({"code": rec["code"], "name": rec["name"], "required": int(inputs[item_code])})
    return hits


def inventory_market_estimate(conn: sqlite3.Connection, player_id: int, item: Dict[str, Any]) -> Dict[str, Any]:
    player = get_player(conn, player_id)
    commodity = row(conn, "SELECT * FROM commodities WHERE code=?", (item.get("item_code"),))
    mp = row(conn, "SELECT * FROM market_prices WHERE planet_id=? AND commodity_id=?", (player["location_planet_id"], commodity["id"])) if commodity else None
    unit = int(mp["sell_price"]) if mp else max(1, int(int(item.get("tier_value") or item.get("base_value") or 0) * direct_vendor_sell_multiplier(item)))
    fee_rate = ECONOMY_BALANCE["legal_sell_fee"] if int(item.get("legal", 1)) else ECONOMY_BALANCE["illegal_sell_fee"]
    qty = int(item.get("available_qty") or max(0, int(item.get("qty") or 0) - int(item.get("reserved_qty") or 0)))
    gross = unit * qty
    fee = int(gross * fee_rate)
    return {"unit": unit, "gross": gross, "fee": fee, "net": max(0, gross - fee), "commodity_backed": bool(commodity)}


def illegal_item_risk(conn: sqlite3.Connection, player_id: int, item: Dict[str, Any]) -> Dict[str, Any]:
    if int(item.get("legal", 1)):
        return {"level": "none", "score": 0, "message": "Legal cargo."}
    player = get_player(conn, player_id)
    planet = row(conn, "SELECT * FROM planets WHERE id=?", (player["location_planet_id"],))
    security = int((planet or {}).get("security_level") or 50)
    stealth = get_ship_power(conn, player.get("active_ship_id")) // 240
    score = clamp_int(security - stealth, 1, 99)
    level = "critical" if score >= 75 else "high" if score >= 55 else "medium" if score >= 30 else "low"
    return {"level": level, "score": score, "message": f"{level.title()} customs risk at this location."}


def enrich_inventory_entry(conn: sqlite3.Connection, player_id: int, item: Dict[str, Any]) -> Dict[str, Any]:
    item["itemId"] = item.get("item_code")
    item["unit_value"] = int(item.get("base_value") or 0)
    item["total_value"] = int(item.get("unit_value") or 0) * int(item.get("qty") or 0)
    item["reserved_qty"] = int(item.get("reserved_qty") or 0)
    item["available_qty"] = max(0, int(item.get("qty") or 0) - item["reserved_qty"])
    item["cargo_mass"] = 0 if int(item.get("cargo_exempt") or 0) else round(float(item.get("mass") or 0) * int(item.get("qty") or 0), 2)
    item["available_cargo_mass"] = 0 if int(item.get("cargo_exempt") or 0) else round(float(item.get("mass") or 0) * int(item.get("available_qty") or 0), 2)
    item["category"] = item.get("category") or inventory_category(item.get("item_type", "goods"), int(item.get("legal", 1)))
    item["subcategory"] = item.get("subcategory") or item.get("item_type") or item["category"]
    item["category_label"] = INVENTORY_CATEGORY_LABELS.get(item["category"], label_for_api(item["category"]))
    item["rarity"] = item.get("rarity") or inventory_rarity(item.get("item_type", ""), int(item.get("base_value") or 0), int(item.get("legal", 1)))
    item["rarity_rank"] = INVENTORY_RARITY_ORDER.get(item["rarity"], 1)
    attach_tier_metadata(item)
    item["unit_value"] = int(item.get("tier_value") or item.get("unit_value") or item.get("base_value") or 0)
    item["total_value"] = int(item.get("unit_value") or 0) * int(item.get("qty") or 0)
    item["tier_upgrade"] = tier_upgrade_preview(conn, player_id, item) if item.get("category") in {"weapons", "armor", "ship_modules", "ship_parts", "refined_materials", "rare_artifacts", "salvage"} or int(item.get("max_tier") or 0) > int(item.get("current_tier") or 0) else {"can_upgrade": False, "reason": "not upgradeable"}
    item["salvage_preview"] = calculate_tier_salvage_output(item) if item.get("category") not in {"quest_items", "goods"} else None
    item["crafting_usage"] = item_used_in_recipes(conn, item.get("item_code"))
    item["used_in_recipe_count"] = len(item["crafting_usage"])
    item["market_sell_estimate"] = inventory_market_estimate(conn, player_id, item)
    item["illegal_risk"] = illegal_item_risk(conn, player_id, item)
    allowed = []
    blocked = []
    if int(item.get("sellable", 1)) and item["available_qty"] > 0: allowed.append("sell")
    elif not int(item.get("sellable", 1)): blocked.append("not sellable")
    if int(item.get("usable", 0)) and item["available_qty"] > 0: allowed.append("use")
    if int(item.get("equippable", 0)) and item["available_qty"] > 0: allowed.append("equip")
    if int(item.get("craftable_material", 0)) and item["available_qty"] > 0: allowed.append("craft with")
    if item["available_qty"] > 0 and item.get("source") not in {"equipped_module"}: allowed.append("list")
    if item["reserved_qty"] > 0: blocked.append(f"{item['reserved_qty']} reserved/listed")
    item["allowed_actions"] = allowed
    item["blocked_action_reasons"] = blocked
    item["sellable"] = bool(int(item.get("sellable", 1)) and item.get("source") != "equipped_module")
    item["usable"] = bool(int(item.get("usable", 0)))
    item["equippable"] = bool(int(item.get("equippable", 0)))
    item["craftable_material"] = bool(int(item.get("craftable_material", 0)))
    attach_item_visual(item)
    return item

def build_cargo_usage(conn: sqlite3.Connection, player_id: int) -> Dict[str, Any]:
    p = get_player(conn, player_id)
    market_mass = scalar(
        conn,
        "SELECT COALESCE(SUM(ch.qty * c.mass),0) FROM cargo_hold ch JOIN commodities c ON c.id=ch.commodity_id WHERE ch.player_id=?",
        (player_id,),
    )
    inventory_mass = scalar(conn, "SELECT COALESCE(SUM(CASE WHEN COALESCE(cargo_exempt,0)=1 THEN 0 ELSE qty * mass END),0) FROM inventory WHERE player_id=?", (player_id,))
    module_mass = scalar(conn, "SELECT COALESCE(COUNT(*) * 3,0) FROM ship_modules WHERE player_id=? AND equipped=0", (player_id,))
    pending_mass = pending_cargo_mass(conn, player_id)
    total = float(market_mass or 0) + float(inventory_mass or 0) + float(module_mass or 0) + float(pending_mass or 0)
    max_cargo = int(p.get("max_cargo") or 0)
    used = math.ceil(total)
    pct = int((used / max(1, max_cargo)) * 100)
    warnings = []
    if pct >= INVENTORY_BALANCE["cargo_critical_pct"]: warnings.append("critical cargo capacity")
    elif pct >= INVENTORY_BALANCE["cargo_warning_pct"]: warnings.append("cargo nearly full")
    return {
        "market_mass": round(float(market_mass or 0), 2),
        "inventory_mass": round(float(inventory_mass or 0), 2),
        "module_mass": round(float(module_mass or 0), 2),
        "pending_mass": round(float(pending_mass or 0), 2),
        "total": used,
        "max": max_cargo,
        "free": max(0, max_cargo - used),
        "pct": pct,
        "warning_level": "critical" if pct >= INVENTORY_BALANCE["cargo_critical_pct"] else "warning" if pct >= INVENTORY_BALANCE["cargo_warning_pct"] else "ok",
        "warnings": warnings,
        "over_capacity": used > max_cargo,
    }


def build_inventory_summary(conn: sqlite3.Connection, player_id: int) -> List[Dict[str, Any]]:
    cargo_rows = rows(
        conn,
        """
        SELECT ch.id, c.code as item_code, c.name, c.category as item_type,
               CASE WHEN c.legal=0 THEN 'illicit_goods' ELSE 'goods' END as category,
               c.category as subcategory,
               ch.qty, 0 as reserved_qty, 9999 as stack_size, c.legal, c.base_price as base_value, c.mass,
               0 as cargo_exempt, 0 as usable, 1 as sellable, 0 as craftable_material, 0 as equippable, '' as image_id,
               c.description, 'cargo_hold' as source, ch.avg_cost,
               c.id as commodity_id, '' as acquired_at,
               c.tier as base_tier, c.tier as current_tier, c.max_tier as max_tier, c.tier_locked as tier_locked, 'purchased' as tier_source, '{}' as item_stats_json
        FROM cargo_hold ch JOIN commodities c ON c.id=ch.commodity_id
        WHERE ch.player_id=? AND ch.qty>0
        """,
        (player_id,),
    )
    inv_rows = rows(
        conn,
        """
        SELECT id, item_code, name, item_type, category, subcategory, qty, reserved_qty, stack_size, legal, base_value, mass,
               cargo_exempt, usable, sellable, craftable_material, equippable, image_id,
               description, source, NULL as avg_cost, NULL as commodity_id, acquired_at,
               base_tier, current_tier, max_tier, tier_locked, tier_source, item_stats_json
        FROM inventory
        WHERE player_id=? AND qty>0
        """,
        (player_id,),
    )
    module_rows = rows(
        conn,
        """
        SELECT sm.id, mt.code as item_code, mt.name, 'ship_module' as item_type, 'ship_modules' as category,
               mt.slot_type as subcategory,
               1 as qty, 0 as reserved_qty, 1 as stack_size, 1 as legal, mt.price as base_value, 3.0 as mass,
               0 as cargo_exempt, 0 as usable, CASE WHEN sm.equipped=1 THEN 0 ELSE 1 END as sellable, 0 as craftable_material, 1 as equippable, '' as image_id,
               mt.rarity || ' ' || mt.slot_type || ' module' as description,
               CASE WHEN sm.equipped=1 THEN 'equipped_module' ELSE 'module_storage' END as source,
               NULL as avg_cost, NULL as commodity_id, '' as acquired_at,
               mt.tier as base_tier, sm.current_tier as current_tier, sm.max_tier as max_tier, 0 as tier_locked, sm.tier_source as tier_source, mt.stats_json as item_stats_json
        FROM ship_modules sm JOIN module_templates mt ON mt.id=sm.module_template_id
        WHERE sm.player_id=?
        """,
        (player_id,),
    )
    combined = cargo_rows + inv_rows + module_rows
    for item in combined:
        enrich_inventory_entry(conn, player_id, item)
    return sorted(combined, key=lambda x: (x["category"], -int(x.get("rarity_rank") or 1), x["name"]))


def label_for_api(value: str) -> str:
    return str(value or "").replace("_", " ").title()


def normalize_inventory_metadata(conn: sqlite3.Connection) -> None:
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='inventory'"):
        return
    conn.execute("""
        UPDATE inventory
        SET category=CASE
              WHEN item_type IN ('contraband','booster','documents','black_market') OR legal=0 THEN 'illicit_goods'
              WHEN item_type IN ('ore','gas','crystal','raw_material','raw') THEN 'raw_materials'
              WHEN item_type IN ('material','component','chemical','food','medical','electronics') THEN 'crafting_materials'
              WHEN item_type IN ('refined','alloy','wafer','refined_material') THEN 'refined_materials'
              WHEN item_type IN ('consumable','repair','medkit','ammo') THEN 'consumables'
              WHEN item_type IN ('fuel','energy_cell','reactor','power_cell') THEN 'fuel_supplies'
              WHEN item_type IN ('ship_part','engine_part','hull_part','reactor_part') THEN 'ship_parts'
              WHEN item_type IN ('ship_module','module','scanner','shield','engine','stealth','cargo_module') THEN 'ship_modules'
              WHEN item_type IN ('weapon','laser','railgun','missile') THEN 'weapons'
              WHEN item_type IN ('armor','plating','defense') THEN 'armor'
              WHEN item_type IN ('artifact','rare','relic','ancient') THEN 'rare_artifacts'
              WHEN item_type IN ('salvage','scrap','wreckage') THEN 'salvage'
              ELSE COALESCE(NULLIF(category,''),'goods')
            END,
            rarity=CASE
              WHEN legal=0 AND base_value >= 2500 THEN 'black_market'
              WHEN legal=0 THEN 'rare'
              WHEN base_value >= 50000 THEN 'legendary'
              WHEN base_value >= 18000 THEN 'epic'
              WHEN base_value >= 3500 THEN 'rare'
              WHEN base_value >= 650 THEN 'uncommon'
              ELSE COALESCE(NULLIF(rarity,''),'common')
            END,
            stack_size=CASE WHEN stack_size IS NULL OR stack_size <= 0 THEN 9999 ELSE stack_size END,
            reserved_qty=CASE WHEN reserved_qty IS NULL THEN 0 ELSE reserved_qty END,
            acquired_at=CASE WHEN acquired_at IS NULL OR acquired_at='' THEN datetime('now') ELSE acquired_at END,
            usable=CASE WHEN item_type IN ('consumable','repair','medkit','fuel','energy_cell') OR category IN ('consumables','fuel_supplies') THEN 1 ELSE COALESCE(usable,0) END,
            craftable_material=CASE WHEN category IN ('raw_materials','crafting_materials','refined_materials','salvage') OR item_type IN ('ore','gas','crystal','raw_material','material','component','chemical','refined','alloy','salvage','scrap') THEN 1 ELSE COALESCE(craftable_material,0) END,
            equippable=CASE WHEN category IN ('ship_modules','weapons','armor') OR item_type IN ('ship_module','module','weapon','armor') THEN 1 ELSE COALESCE(equippable,0) END,
            sellable=CASE WHEN sellable IS NULL THEN 1 ELSE sellable END,
            cargo_exempt=CASE WHEN category='quest_items' THEN 1 ELSE COALESCE(cargo_exempt,0) END
    """)





def player_market_listing_fee(qty: int, unit_price: int) -> int:
    gross = max(0, int(qty) * int(unit_price))
    return max(PLAYER_MARKET_BALANCE["min_listing_fee"], int(gross * PLAYER_MARKET_BALANCE["listing_fee_rate"]))


def player_market_sale_fee(gross: int) -> int:
    return int(max(0, gross) * PLAYER_MARKET_BALANCE["sale_fee_rate"])


def max_listing_unit_price(base_value: int) -> int:
    return max(1000, int(max(1, base_value) * PLAYER_MARKET_BALANCE["max_unit_price_mult"]))



def player_location_scope(conn: sqlite3.Connection, player_or_id: Any) -> Dict[str, Any]:
    pid = int(player_or_id.get("id") if isinstance(player_or_id, dict) else player_or_id)
    p = row(
        conn,
        """
        SELECT pl.id as player_id, pl.location_planet_id, p.name as planet_name, p.galaxy_id,
               g.name as galaxy_name, g.code as galaxy_code
        FROM players pl
        JOIN planets p ON p.id=pl.location_planet_id
        JOIN galaxies g ON g.id=p.galaxy_id
        WHERE pl.id=?
        """,
        (pid,),
    ) or {}
    return {
        "player_id": pid,
        "planet_id": int(p.get("location_planet_id") or 0),
        "planet_name": p.get("planet_name") or "Unknown Planet",
        "galaxy_id": int(p.get("galaxy_id") or 0),
        "galaxy_name": p.get("galaxy_name") or "Unknown Galaxy",
        "galaxy_code": p.get("galaxy_code") or "",
    }


def player_market_current_scope(conn: sqlite3.Connection, player_id: int) -> Dict[str, Any]:
    return player_location_scope(conn, player_id)


def can_trade_player_market_listing(conn: sqlite3.Connection, player_id: int, listing: Dict[str, Any]) -> bool:
    scope = player_market_current_scope(conn, player_id)
    listing_gid = int(listing.get("galaxy_id") or 0)
    if not listing_gid and listing.get("planet_id"):
        listing_gid = int(scalar(conn, "SELECT galaxy_id FROM planets WHERE id=?", (int(listing["planet_id"]),)) or 0)
    return listing_gid == int(scope.get("galaxy_id") or 0)


def storage_listing_from_row(storage: Dict[str, Any]) -> Dict[str, Any]:
    return {
        "origin": storage.get("item_type") or "inventory",
        "item_code": storage.get("item_code"),
        "item_name": storage.get("item_name"),
        "item_type": storage.get("item_type") or "goods",
        "category": storage.get("category") or "goods",
        "legal": int(storage.get("legal", 1)),
        "base_value": int(storage.get("base_value") or 0),
        "mass": float(storage.get("mass") or 1),
        "description": storage.get("description") or "Stored item.",
        "rarity": storage.get("rarity") or "common",
        "tier": clamp_tier(storage.get("tier", 1)),
        "max_tier": clamp_tier(storage.get("max_tier", 3)),
        "tier_source": storage.get("tier_source") or "storage",
    }


def store_item_at_current_planet(conn: sqlite3.Connection, player: Dict[str, Any], payload: Dict[str, Any], god: bool = False) -> Dict[str, Any]:
    if player_is_in_open_space(conn, int(player["id"])):
        raise HTTPException(400, "You must be docked at a planet or station to store cargo")
    scope = player_location_scope(conn, player)
    listing = listing_payload_from_inventory(conn, int(player["id"]), payload)
    qty = int(listing["qty"])
    remove_listing_source_item(conn, int(player["id"]), listing)
    now = iso()
    conn.execute(
        """
        INSERT INTO player_storage_items
          (player_id,galaxy_id,planet_id,item_code,item_name,item_type,category,qty,legal,base_value,mass,description,rarity,tier,max_tier,tier_source,source_ref,metadata_json,created_at,updated_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
        ON CONFLICT(player_id,planet_id,item_code,item_type,category,rarity,tier) DO UPDATE SET
          qty=qty+excluded.qty,
          item_name=excluded.item_name,
          legal=excluded.legal,
          base_value=excluded.base_value,
          mass=excluded.mass,
          description=excluded.description,
          max_tier=max(max_tier, excluded.max_tier),
          tier_source=excluded.tier_source,
          metadata_json=excluded.metadata_json,
          updated_at=excluded.updated_at
        """,
        (
            int(player["id"]), int(scope["galaxy_id"]), int(scope["planet_id"]), listing["item_code"], listing["item_name"],
            listing.get("item_type") or "goods", listing.get("category") or "goods", qty, int(listing.get("legal", 1)),
            int(listing.get("base_value") or 0), float(listing.get("mass") or 1), listing.get("description") or "",
            listing.get("rarity") or "common", clamp_tier(listing.get("tier", 1)), clamp_tier(listing.get("max_tier", 3)),
            listing.get("tier_source") or "storage", listing.get("source_ref") or "", encode_json({"storedFrom": listing.get("origin") or "inventory"}),
            now, now,
        ),
    )
    add_event(conn, int(player["id"]), "storage", f"Stored {qty}x {listing['item_name']} at {scope['planet_name']} in {scope['galaxy_name']}.", {"scope": scope, "item": listing["item_code"], "qty": qty})
    return {"message": f"Stored {qty}x {listing['item_name']} at {scope['planet_name']}.", "scope": scope}


def withdraw_item_from_current_planet(conn: sqlite3.Connection, player: Dict[str, Any], storage_id: int, qty: int, god: bool = False) -> Dict[str, Any]:
    if player_is_in_open_space(conn, int(player["id"])):
        raise HTTPException(400, "You must be docked at the cargo planet or station to withdraw storage")
    scope = player_location_scope(conn, player)
    storage = row(conn, "SELECT * FROM player_storage_items WHERE id=? AND player_id=?", (int(storage_id), int(player["id"])))
    if not storage or int(storage.get("qty") or 0) <= 0:
        raise HTTPException(404, "Stored item not found")
    if int(storage.get("planet_id") or 0) != int(scope["planet_id"]):
        raise HTTPException(400, "You can only remove storage from your current planet")
    qty = max(1, min(int(qty), int(storage["qty"])))
    mass = float(storage.get("mass") or 1) * qty
    if storage.get("item_type") not in {"ship_module", "module"} and not god and not can_fit_cargo(conn, int(player["id"]), mass, cargo_exempt=False):
        raise HTTPException(400, "Not enough cargo capacity to withdraw this storage")
    add_listing_item_to_player(conn, int(player["id"]), storage_listing_from_row(storage), qty, "planet_storage_withdraw")
    remaining = int(storage["qty"]) - qty
    conn.execute("UPDATE player_storage_items SET qty=?, updated_at=? WHERE id=?", (remaining, iso(), int(storage_id)))
    conn.execute("DELETE FROM player_storage_items WHERE id=? AND qty<=0", (int(storage_id),))
    add_event(conn, int(player["id"]), "storage", f"Withdrew {qty}x {storage['item_name']} from {scope['planet_name']} storage.", {"scope": scope, "item": storage.get("item_code"), "qty": qty})
    return {"message": f"Withdrew {qty}x {storage['item_name']} from storage.", "scope": scope}


def build_player_storage_state(conn: sqlite3.Connection, player: Dict[str, Any]) -> Dict[str, Any]:
    scope = player_location_scope(conn, player)
    in_open_space = player_is_in_open_space(conn, int(player["id"]))
    stored = rows(
        conn,
        """
        SELECT psi.*, p.name as planet_name, g.name as galaxy_name, g.code as galaxy_code,
               CASE WHEN psi.planet_id=? AND ?=0 THEN 1 ELSE 0 END as can_modify
        FROM player_storage_items psi
        JOIN planets p ON p.id=psi.planet_id
        JOIN galaxies g ON g.id=psi.galaxy_id
        WHERE psi.player_id=? AND psi.qty>0
        ORDER BY g.name, p.name, psi.category, psi.item_name
        """,
        (int(scope["planet_id"]), 1 if in_open_space else 0, int(player["id"])),
    )
    for item in stored:
        item["current_tier"] = clamp_tier(item.get("tier", 1))
        item["tier_display"] = get_tier_display_data(item["current_tier"], item.get("max_tier", 3))
        item["available_here"] = bool(item.get("can_modify"))
        attach_item_visual(item, name_key="item_name", item_type_key="item_type", category_key="category", legal_key="legal")
    deposit_candidates = [i for i in build_inventory_summary(conn, int(player["id"])) if int(i.get("available_qty") or i.get("qty") or 0) > 0 and i.get("source") != "equipped_module"]
    galaxy_counts: Dict[str, Dict[str, Any]] = {}
    for item in stored:
        gid = str(item.get("galaxy_id"))
        rec = galaxy_counts.setdefault(gid, {"galaxyId": item.get("galaxy_id"), "galaxyName": item.get("galaxy_name"), "qty": 0, "mass": 0.0})
        rec["qty"] += int(item.get("qty") or 0)
        rec["mass"] += float(item.get("mass") or 1) * int(item.get("qty") or 0)
    return {
        "scope": scope,
        "stored": stored,
        "depositCandidates": deposit_candidates,
        "galaxies": list(galaxy_counts.values()),
        "rules": {
            "view": "Remote planet storage is visible for planning only.",
            "modify": "Deposits and withdrawals require being physically docked on the item planet.",
            "globalOnly": "Credits/gold only. Materials, items, ships, modules, cargo, equipment, and storage are planet-scoped.",
            "planetScoped": True,
            "goldGlobalOnly": True,
            "currentPlanetId": int(scope["planet_id"]),
            "currentGalaxyId": int(scope["galaxy_id"]),
            "inOpenSpace": in_open_space,
        },
    }


def ensure_player_market_content(conn: sqlite3.Connection) -> None:
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='player_market_listings'"):
        return
    active = scalar(conn, "SELECT COUNT(*) FROM player_market_listings WHERE seller_player_id IS NULL AND status='active'")
    needed = max(0, PLAYER_MARKET_BALANCE["npc_seed_listing_count"] - int(active or 0))
    if needed <= 0:
        return
    commodities = rows(conn, "SELECT * FROM commodities ORDER BY legal DESC, base_price DESC LIMIT 40")
    planets = rows(conn, "SELECT id, name, galaxy_id FROM planets ORDER BY id LIMIT 24")
    if not commodities or not planets:
        return
    rng = random.Random(6606 + int(active or 0))
    seller_names = ["Vega Exchange", "Kestrel Yard", "Orin Freight", "Sable Salvage", "Rook Cartel", "Mira Foundry", "Asha Logistics", "Nyx Free Traders"]
    for i in range(needed):
        c = rng.choice(commodities)
        pl = rng.choice(planets)
        qty = rng.randint(2, 18 if int(c.get("legal", 1)) else 7)
        unit = int(int(c["base_price"]) * rng.uniform(0.92, 1.38 if int(c.get("legal", 1)) else 1.90))
        now = iso()
        conn.execute(
            """
            INSERT INTO player_market_listings
              (seller_player_id,seller_name,planet_id,galaxy_id,origin,source_ref,item_code,item_name,item_type,category,qty,remaining_qty,unit_price,legal,base_value,mass,description,rarity,status,created_at,expires_at)
            VALUES (NULL,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            """,
            (
                rng.choice(seller_names), pl["id"], int(pl.get("galaxy_id") or 0), "npc_seed", "", c["code"], c["name"], c["category"],
                inventory_category(c["category"], int(c.get("legal", 1))), qty, qty, unit, int(c.get("legal", 1)),
                int(c["base_price"]), float(c.get("mass") or 1), c.get("description") or "Player-market supply.",
                inventory_rarity(c.get("category", "goods"), int(c["base_price"]), int(c.get("legal", 1))), "active", now, iso(utcnow()+timedelta(days=7))
            ),
        )


def listing_payload_from_inventory(conn: sqlite3.Connection, player_id: int, payload: Dict[str, Any]) -> Dict[str, Any]:
    source = str(payload.get("source") or "inventory")
    qty = max(1, min(int(payload.get("qty", 1)), PLAYER_MARKET_BALANCE["max_single_listing_qty"]))
    if source == "cargo_hold":
        commodity_id = int(payload.get("commodity_id") or 0)
        holding = row(conn, "SELECT ch.*, c.code, c.name, c.legal, c.category, c.base_price, c.mass, c.description FROM cargo_hold ch JOIN commodities c ON c.id=ch.commodity_id WHERE ch.player_id=? AND ch.commodity_id=?", (player_id, commodity_id))
        if not holding or int(holding["qty"] or 0) < qty:
            raise HTTPException(400, "Not enough cargo to list")
        if is_trade_good_category(holding.get("category")):
            raise HTTPException(400, "Trade goods are market cargo only. They cannot be listed on the player market.")
        return {
            "origin": "cargo_hold", "source_ref": str(commodity_id), "item_code": holding["code"], "item_name": holding["name"],
            "item_type": holding["category"], "category": "illicit_goods" if not int(holding.get("legal", 1)) else "goods",
            "qty": qty, "legal": int(holding.get("legal", 1)), "base_value": int(holding.get("base_price") or 0),
            "mass": float(holding.get("mass") or 1), "description": holding.get("description") or "Cargo-market commodity.",
            "rarity": inventory_rarity(holding.get("category", "goods"), int(holding.get("base_price") or 0), int(holding.get("legal", 1))),
            "tier": clamp_tier(holding.get("tier", 1)), "max_tier": clamp_tier(holding.get("max_tier", 2)), "tier_source": "listed",
        }
    if source == "module_storage":
        module_id = int(payload.get("module_id") or payload.get("id") or 0)
        mod = row(conn, "SELECT sm.*, mt.code, mt.name, mt.slot_type, mt.rarity, mt.price, mt.stats_json FROM ship_modules sm JOIN module_templates mt ON mt.id=sm.module_template_id WHERE sm.id=? AND sm.player_id=? AND sm.equipped=0", (module_id, player_id))
        if not mod or qty != 1:
            raise HTTPException(400, "Module listing requires one unequipped module")
        return {
            "origin": "module_storage", "source_ref": str(module_id), "item_code": mod["code"], "item_name": mod["name"],
            "item_type": "ship_module", "category": "ship_modules", "qty": 1, "legal": 1, "base_value": int(mod.get("price") or 0),
            "mass": 3.0, "description": f"{mod['rarity']} {mod['slot_type']} module", "rarity": mod.get("rarity") or "rare",
            "tier": clamp_tier(mod.get("current_tier", 1)), "max_tier": clamp_tier(mod.get("max_tier", 5)), "tier_source": mod.get("tier_source") or "listed",
        }
    item_code = str(payload.get("item_code") or "")
    inv = row(conn, "SELECT * FROM inventory WHERE player_id=? AND item_code=?", (player_id, item_code))
    if not inv or int(inv["qty"] or 0) - int(inv.get("reserved_qty") or 0) < qty:
        raise HTTPException(400, "Not enough inventory to list")
    return {
        "origin": "inventory", "source_ref": item_code, "item_code": inv["item_code"], "item_name": inv["name"],
        "item_type": inv["item_type"], "category": inv.get("category") or inventory_category(inv.get("item_type", "goods"), int(inv.get("legal", 1))),
        "qty": qty, "legal": int(inv.get("legal", 1)), "base_value": int(inv.get("base_value") or 0),
        "mass": float(inv.get("mass") or 1), "description": inv.get("description") or "Inventory item.",
        "rarity": inv.get("rarity") or inventory_rarity(inv.get("item_type", "goods"), int(inv.get("base_value") or 0), int(inv.get("legal", 1))),
        "tier": clamp_tier(inv.get("current_tier", 1)), "max_tier": clamp_tier(inv.get("max_tier", 3)), "tier_source": inv.get("tier_source") or "listed",
    }


def remove_listing_source_item(conn: sqlite3.Connection, player_id: int, listing: Dict[str, Any]) -> None:
    qty = int(listing["qty"])
    if listing["origin"] == "cargo_hold":
        commodity_id = int(listing["source_ref"] or 0)
        holding = row(conn, "SELECT ch.*, c.mass FROM cargo_hold ch JOIN commodities c ON c.id=ch.commodity_id WHERE ch.player_id=? AND ch.commodity_id=?", (player_id, commodity_id))
        if not holding or int(holding["qty"] or 0) < qty:
            raise HTTPException(400, "Not enough cargo to list")
        mass = int(math.ceil(float(holding.get("mass") or 1) * qty))
        conn.execute("UPDATE cargo_hold SET qty=qty-? WHERE id=?", (qty, holding["id"]))
        conn.execute("DELETE FROM cargo_hold WHERE id=? AND qty<=0", (holding["id"],))
        conn.execute("UPDATE players SET cargo=max(0,cargo-?) WHERE id=?", (mass, player_id))
    elif listing["origin"] == "module_storage":
        module_id = int(listing["source_ref"] or 0)
        mod = row(conn, "SELECT * FROM ship_modules WHERE id=? AND player_id=? AND equipped=0", (module_id, player_id))
        if not mod:
            raise HTTPException(400, "Module is no longer listable")
        conn.execute("DELETE FROM ship_modules WHERE id=?", (module_id,))
    else:
        remove_inventory_item(conn, player_id, listing["item_code"], qty)


def add_listing_item_to_player(conn: sqlite3.Connection, player_id: int, listing: Dict[str, Any], qty: int, source: str) -> None:
    if qty <= 0:
        return
    code = listing["item_code"]
    if listing.get("origin") == "module_storage" or listing.get("item_type") in {"ship_module", "module"}:
        mt = row(conn, "SELECT * FROM module_templates WHERE code=?", (code,))
        if mt:
            for _ in range(qty):
                conn.execute("INSERT INTO ship_modules (player_id,ship_id,module_template_id,slot_type,equipped,durability) VALUES (?,?,?,?,0,100)", (player_id, None, mt["id"], mt["slot_type"]))
            return
    add_inventory_item(
        conn, player_id, code, listing["item_name"], listing.get("item_type") or "goods", qty,
        int(listing.get("legal", 1)), int(listing.get("base_value") or 0), float(listing.get("mass") or 1),
        listing.get("description") or "Player-market item.", source, listing.get("category"), listing.get("rarity"),
        tier=clamp_tier(listing.get("tier", 1)), max_tier=listing.get("max_tier"), tier_source=source,
    )


def build_player_market_state(conn: sqlite3.Connection, player_id: int) -> Dict[str, Any]:
    ensure_player_market_content(conn)
    scope = player_market_current_scope(conn, player_id)
    # Backfill legacy listings that predate galaxy-aware market rules.
    conn.execute("UPDATE player_market_listings SET galaxy_id=(SELECT galaxy_id FROM planets WHERE planets.id=player_market_listings.planet_id) WHERE galaxy_id IS NULL OR galaxy_id=0")
    active = rows(
        conn,
        """
        SELECT pml.*, p.name as planet_name, g.name as galaxy_name, g.code as galaxy_code,
               CASE WHEN pml.seller_player_id=? THEN 1 ELSE 0 END as own_listing,
               CASE WHEN COALESCE(pml.galaxy_id,p.galaxy_id)=? THEN 1 ELSE 0 END as can_trade_here
        FROM player_market_listings pml
        LEFT JOIN planets p ON p.id=pml.planet_id
        LEFT JOIN galaxies g ON g.id=COALESCE(pml.galaxy_id,p.galaxy_id)
        WHERE pml.status='active' AND pml.remaining_qty>0
        ORDER BY can_trade_here DESC, g.name, pml.legal DESC, pml.category, pml.unit_price, pml.id DESC
        LIMIT 300
        """,
        (player_id, int(scope.get("galaxy_id") or 0)),
    )
    history = rows(
        conn,
        """
        SELECT pml.*, p.name as planet_name, g.name as galaxy_name, g.code as galaxy_code,
               CASE WHEN pml.seller_player_id=? THEN 1 ELSE 0 END as own_listing,
               CASE WHEN COALESCE(pml.galaxy_id,p.galaxy_id)=? THEN 1 ELSE 0 END as can_trade_here
        FROM player_market_listings pml
        LEFT JOIN planets p ON p.id=pml.planet_id
        LEFT JOIN galaxies g ON g.id=COALESCE(pml.galaxy_id,p.galaxy_id)
        WHERE pml.status<>'active' OR pml.seller_player_id=?
        ORDER BY pml.id DESC
        LIMIT 120
        """,
        (player_id, int(scope.get("galaxy_id") or 0), player_id),
    )
    for listing in active + history:
        listing["galaxy_id"] = int(listing.get("galaxy_id") or 0) or int(scalar(conn, "SELECT galaxy_id FROM planets WHERE id=?", (listing.get("planet_id"),)) or 0)
        listing["current_tier"] = clamp_tier(listing.get("tier", 1))
        listing["tier_display"] = get_tier_display_data(listing["current_tier"], listing.get("max_tier", 3))
        listing["can_trade_here"] = bool(listing.get("can_trade_here"))
        listing["remote_market"] = not listing["can_trade_here"]
        attach_item_visual(listing, name_key="item_name", item_type_key="item_type", category_key="category", legal_key="legal")
    galaxy_rows = rows(conn, "SELECT id, name, code FROM galaxies ORDER BY name")
    return {"active": active, "history": history, "balance": PLAYER_MARKET_BALANCE, "scope": scope, "galaxies": galaxy_rows, "rules": {"view": "All galaxy listings are visible.", "trade": "Buying, selling, listing, and cancelling are restricted to your current galaxy."}}


def ensure_loop_set_module_templates(conn: sqlite3.Connection) -> None:
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='module_templates'"):
        return
    for module in CRAFTING_LOOP_SET_BASE_MODULES:
        stats = dict(module.get("stats") or {})
        conn.execute(
            """
            INSERT INTO module_templates
              (code,name,slot_type,rarity,price,craftable,stats_json,tier,max_tier,min_ship_tier,power_usage)
            VALUES (?,?,?,?,?,?,?,?,?,?,?)
            ON CONFLICT(code) DO UPDATE SET
              name=excluded.name,
              slot_type=excluded.slot_type,
              rarity=excluded.rarity,
              price=excluded.price,
              craftable=excluded.craftable,
              stats_json=excluded.stats_json,
              tier=excluded.tier,
              max_tier=excluded.max_tier,
              min_ship_tier=excluded.min_ship_tier,
              power_usage=excluded.power_usage
            """,
            (
                module["code"],
                module["name"],
                canonical_slot_type(module.get("slot") or "utility"),
                module.get("rarity") or "common",
                int(module.get("price") or 10000),
                1,
                encode_json(stats),
                1,
                7,
                0,
                int(module.get("power_usage") or max(2, int(module.get("price") or 10000) // 12000)),
            ),
        )


def ensure_ranked_module_templates(conn: sqlite3.Connection) -> None:
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='module_templates'"):
        return
    base_templates = {r["code"]: r for r in rows(conn, "SELECT * FROM module_templates")}
    for recipe in CRAFTING_RECIPE_DEFINITIONS:
        output = recipe.get("output") or {}
        if output.get("kind") != "module":
            continue
        code = str(output.get("module_code") or "")
        base_code = recipe_base_code_from_variant(code)
        if code in base_templates or not base_code:
            continue
        base = base_templates.get(base_code)
        if not base:
            continue
        rank_cfg = crafting_rank_config(str(recipe.get("recipe_rank_key") or "basic"))
        base_stats = decode_json(base.get("stats_json"), {}) or {}
        scaled_stats = {k: scale_recipe_stat_value(v, float(rank_cfg.get("module_stat_mult", 1.0))) for k, v in base_stats.items()}
        conn.execute(
            """
            INSERT INTO module_templates
              (code,name,slot_type,rarity,price,craftable,stats_json,tier,max_tier,min_ship_tier,power_usage)
            VALUES (?,?,?,?,?,?,?,?,?,?,?)
            ON CONFLICT(code) DO UPDATE SET
              name=excluded.name, slot_type=excluded.slot_type, rarity=excluded.rarity, price=excluded.price,
              craftable=excluded.craftable, stats_json=excluded.stats_json, tier=excluded.tier, max_tier=excluded.max_tier,
              min_ship_tier=excluded.min_ship_tier, power_usage=excluded.power_usage
            """,
            (
                code,
                recipe_variant_display_name(base.get("name") or code, str(recipe.get("recipe_rank_key") or "basic"), str(recipe.get("recipe_rank_name") or "Basic")),
                base.get("slot_type"),
                rank_cfg.get("rarity", base.get("rarity") or "common"),
                max(int(base.get("price") or 1), int(round(int(base.get("price") or 1) * float(rank_cfg.get("cost_mult", 1.0))))),
                1,
                encode_json(scaled_stats),
                int(rank_cfg.get("tier", 1)),
                max(int(rank_cfg.get("tier", 1)), int(base.get("max_tier") or 5)),
                max(0, int(rank_cfg.get("tier", 1)) - 1),
                max(0, int(base.get("power_usage") or 0) + max(0, int(rank_cfg.get("tier", 1)) - 1) * 4),
            ),
        )


def ensure_crafting_content(conn: sqlite3.Connection) -> None:
    global CRAFTING_RECIPE_DEFINITIONS, CRAFTING_RANK_CONFIGS
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='crafting_recipes'"):
        return
    CRAFTING_RANK_CONFIGS = get_crafting_rank_configs()
    CRAFTING_RECIPE_DEFINITIONS = build_ranked_recipe_definitions()
    now = iso()
    ensure_loop_set_module_templates(conn)
    ensure_ranked_module_templates(conn)
    for recipe in CRAFTING_RECIPE_DEFINITIONS:
        conn.execute(
            """
            INSERT INTO crafting_recipes
              (code,name,category,description,inputs_json,output_json,credits,energy,craft_minutes,required_jobs_json,required_job_rank,required_skill_tree,required_skill_total,base_success,xp_reward,recipe_rank_key,recipe_rank_name,base_recipe_code,unlock_model,recipe_family,set_code,set_name,updated_at)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            ON CONFLICT(code) DO UPDATE SET
              name=excluded.name, category=excluded.category, description=excluded.description,
              inputs_json=excluded.inputs_json, output_json=excluded.output_json, credits=excluded.credits,
              energy=excluded.energy, craft_minutes=excluded.craft_minutes, required_jobs_json=excluded.required_jobs_json,
              required_job_rank=excluded.required_job_rank, required_skill_tree=excluded.required_skill_tree,
              required_skill_total=excluded.required_skill_total, base_success=excluded.base_success,
              xp_reward=excluded.xp_reward, recipe_rank_key=excluded.recipe_rank_key, recipe_rank_name=excluded.recipe_rank_name,
              base_recipe_code=excluded.base_recipe_code, unlock_model=excluded.unlock_model, recipe_family=excluded.recipe_family,
              set_code=excluded.set_code, set_name=excluded.set_name, updated_at=excluded.updated_at
            """,
            (
                recipe["code"], recipe["name"], recipe["category"], recipe["description"],
                encode_json(recipe["inputs"]), encode_json(recipe["output"]), int(recipe["credits"]), int(recipe["energy"]),
                int(recipe["craft_minutes"]), encode_json(recipe.get("required_jobs", [])), int(recipe.get("required_job_rank", 1)),
                recipe.get("required_skill_tree", ""), int(recipe.get("required_skill_total", 0)), float(recipe.get("base_success", 0.85)),
                int(recipe.get("xp", 0)), recipe.get("recipe_rank_key", "basic"), recipe.get("recipe_rank_name", "Basic"),
                recipe.get("base_recipe_code", recipe["code"]), recipe.get("unlock_model", "unlimited"), recipe.get("recipe_family", recipe_output_family_code(recipe.get("output") or {})),
                recipe.get("set_code", ""), recipe.get("set_name", ""), now,
            ),
        )
        output = recipe.get("output") or {}
        output_tier = clamp_tier(output.get("outputTier", output.get("tier", infer_tier_from_value(int(output.get("base_value") or recipe.get("credits") or 0), output.get("category") or recipe.get("category") or "", output.get("rarity") or "", int(output.get("legal", 1))))))
        recipe_tier = max(output_tier, infer_tier_from_value(int(recipe.get("credits") or 0), recipe.get("category") or "", "", 1))
        conn.execute("UPDATE crafting_recipes SET recipe_tier=?, output_tier=?, required_material_tiers_json=COALESCE(NULLIF(required_material_tiers_json,''),'{}') WHERE code=?", (recipe_tier, output_tier, recipe["code"]))
        conn.execute("UPDATE crafting_recipes SET required_material_tiers_json=?, recipe_family=? WHERE code=?", (encode_json(recipe.get("required_material_tiers") or {}), recipe.get("recipe_family", recipe_output_family_code(recipe.get("output") or {})), recipe["code"]))


def ensure_refinery_content(conn: sqlite3.Connection) -> None:
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='planet_establishments'"):
        return
    for planet in rows(conn, "SELECT id FROM planets"):
        if not row(conn, "SELECT 1 FROM planet_establishments WHERE planet_id=? AND service_type='refinery'", (planet["id"],)):
            conn.execute(
                "INSERT INTO planet_establishments (planet_id,name,service_type,price,level) VALUES (?,?,?,?,?)",
                (planet["id"], "Refinery", "refinery", 14000000, 1),
            )


def recipe_from_row(recipe: Dict[str, Any]) -> Dict[str, Any]:
    out = dict(recipe)
    out["inputs"] = decode_json(recipe.get("inputs_json"), {}) or {}
    out["output"] = decode_json(recipe.get("output_json"), {}) or {}
    out["required_jobs"] = decode_json(recipe.get("required_jobs_json"), []) or []
    out["xp_reward"] = int(recipe.get("xp_reward") or 0)
    out["recipe_tier"] = clamp_tier(recipe.get("recipe_tier", 1))
    out["output_tier"] = clamp_tier(recipe.get("output_tier", 1))
    out["required_material_tiers"] = decode_json(recipe.get("required_material_tiers_json"), {}) or {}
    out["recipe_rank_key"] = str(recipe.get("recipe_rank_key") or "basic")
    out["recipe_rank_name"] = str(recipe.get("recipe_rank_name") or "Basic")
    out["base_recipe_code"] = str(recipe.get("base_recipe_code") or out.get("code") or "")
    out["unlock_model"] = str(recipe.get("unlock_model") or ("unlimited" if out["recipe_rank_key"] == "basic" else "consumable"))
    out["recipe_family"] = str(recipe.get("recipe_family") or recipe_output_family_code(out.get("output") or {}))
    out["set_code"] = str(recipe.get("set_code") or "")
    out["set_name"] = str(recipe.get("set_name") or "")
    out["tier_display"] = get_tier_display_data(out["recipe_tier"], TIER_BALANCE["max_tier"])
    return out


def player_recipe_license_map(conn: sqlite3.Connection, player_id: int) -> Dict[str, Dict[str, Any]]:
    cache_key = ("player_recipe_license_map", int(player_id))
    cached = request_cache_get(cache_key)
    if cached is not None:
        return {k: dict(v) for k, v in cached.items()}
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='player_recipe_licenses'"):
        return request_cache_set(cache_key, {})
    data = {r["recipe_code"]: r for r in rows(conn, "SELECT * FROM player_recipe_licenses WHERE player_id=?", (player_id,))}
    request_cache_set(cache_key, {k: dict(v) for k, v in data.items()})
    return data


def ensure_starter_recipe_licenses(conn: sqlite3.Connection, player_id: int) -> None:
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='player_recipe_licenses'"):
        return
    if int(scalar(conn, "SELECT COUNT(*) FROM player_recipe_licenses WHERE player_id=?", (player_id,)) or 0) > 0:
        return
    now = iso()
    for recipe in CRAFTING_RECIPE_DEFINITIONS:
        if str(recipe.get("recipe_rank_key") or "") != "improved":
            continue
        charges = 1 if (recipe.get("output") or {}).get("kind") == "module" else 2
        conn.execute("INSERT OR IGNORE INTO player_recipe_licenses (player_id,recipe_code,charges_remaining,acquired_at,updated_at) VALUES (?,?,?,?,?)", (player_id, recipe["code"], charges, now, now))


def recipe_license_state(conn: sqlite3.Connection, player_id: int, recipe: Dict[str, Any], cache: Optional[Dict[str, Dict[str, Any]]] = None) -> Dict[str, Any]:
    unlock_model = str(recipe.get("unlock_model") or ("unlimited" if str(recipe.get("recipe_rank_key") or "basic") == "basic" else "consumable"))
    if unlock_model == "unlimited":
        return {"owned": True, "charges_remaining": None, "unlimited": True}
    licenses = cache if cache is not None else player_recipe_license_map(conn, player_id)
    lic = licenses.get(recipe["code"])
    charges = int(lic.get("charges_remaining") or 0) if lic else 0
    return {"owned": charges > 0, "charges_remaining": charges, "unlimited": False}


def consume_recipe_license(conn: sqlite3.Connection, player_id: int, recipe: Dict[str, Any]) -> None:
    state = recipe_license_state(conn, player_id, recipe)
    if state["unlimited"]:
        return
    if not state["owned"]:
        raise HTTPException(400, "Recipe copy not owned")
    conn.execute("UPDATE player_recipe_licenses SET charges_remaining=max(0,charges_remaining-1), updated_at=? WHERE player_id=? AND recipe_code=?", (iso(), player_id, recipe["code"]))
    conn.execute("DELETE FROM player_recipe_licenses WHERE player_id=? AND recipe_code=? AND charges_remaining<=0", (player_id, recipe["code"]))


def recipe_drop_rank_allowed(rank_key: str, allowed_ranks: List[str]) -> bool:
    if rank_key in set(RECIPE_DROP_BALANCE.get("excluded_ranks") or []):
        return False
    if rank_key == "legendary" and not bool(RECIPE_DROP_BALANCE.get("legendary_drops_enabled", False)):
        return False
    return rank_key in set(allowed_ranks or [])


def weighted_rank_pick(rng: random.Random, weights: Dict[str, Any], allowed: List[str]) -> str:
    clean = {k: max(0.0, float(v or 0)) for k, v in (weights or {}).items() if recipe_drop_rank_allowed(k, allowed)}
    if not clean:
        return allowed[0] if allowed else "improved"
    total = sum(clean.values())
    roll = rng.uniform(0, total)
    upto = 0.0
    for rank, weight in clean.items():
        upto += weight
        if roll <= upto:
            return rank
    return next(iter(clean))


def grant_recipe_copy(conn: sqlite3.Connection, player_id: int, recipe_code: str, charges: int = 1) -> Optional[Dict[str, Any]]:
    recipe = row(conn, "SELECT * FROM crafting_recipes WHERE code=?", (recipe_code,))
    if not recipe:
        return None
    recipe = recipe_from_row(recipe)
    if recipe.get("unlock_model") == "unlimited":
        return None
    now = iso()
    conn.execute(
        """
        INSERT INTO player_recipe_licenses (player_id,recipe_code,charges_remaining,acquired_at,updated_at)
        VALUES (?,?,?,?,?)
        ON CONFLICT(player_id,recipe_code) DO UPDATE SET
          charges_remaining=player_recipe_licenses.charges_remaining+excluded.charges_remaining,
          updated_at=excluded.updated_at
        """,
        (player_id, recipe_code, max(1, int(charges)), now, now),
    )
    return {
        "code": recipe_code,
        "name": recipe.get("name"),
        "rank": recipe.get("recipe_rank_name"),
        "rank_key": recipe.get("recipe_rank_key"),
        "charges": max(1, int(charges)),
        "set_name": recipe.get("set_name"),
    }


def random_recipe_drop_candidate(conn: sqlite3.Connection, rng: random.Random, allowed_ranks: List[str], exclude_known: Optional[set] = None) -> Optional[Dict[str, Any]]:
    exclude_known = exclude_known or set()
    legal_ranks = [r for r in allowed_ranks if recipe_drop_rank_allowed(r, allowed_ranks)]
    if not legal_ranks:
        return None
    placeholders = ",".join("?" for _ in legal_ranks)
    candidates = rows(
        conn,
        f"""
        SELECT code,name,recipe_rank_key,recipe_rank_name,set_name,category
        FROM crafting_recipes
        WHERE unlock_model='consumable'
          AND recipe_rank_key IN ({placeholders})
        ORDER BY RANDOM()
        LIMIT 80
        """,
        tuple(legal_ranks),
    )
    candidates = [c for c in candidates if c["code"] not in exclude_known]
    if not candidates:
        return None
    rank_weights = RECIPE_DROP_BALANCE.get("normal_kill_rank_weights") or {}
    weighted = []
    for c in candidates:
        weight = float(rank_weights.get(c.get("recipe_rank_key"), 1))
        # Slightly favor set recipes, since these are the chase items.
        if c.get("set_name"):
            weight *= 1.25
        weighted.append((c, max(0.1, weight)))
    total = sum(w for _, w in weighted)
    roll = rng.uniform(0, total)
    acc = 0.0
    for c, w in weighted:
        acc += w
        if roll <= acc:
            return c
    return weighted[-1][0]


def roll_recipe_copy_drops(
    conn: sqlite3.Connection,
    player_id: int,
    source: str,
    rng: random.Random,
    *,
    min_slots: int,
    max_slots: int,
    slot_chance: float,
    allowed_ranks: List[str],
    rank_weights: Optional[Dict[str, Any]] = None,
) -> List[Dict[str, Any]]:
    awarded: List[Dict[str, Any]] = []
    max_slots = max(0, int(max_slots))
    min_slots = max(0, min(int(min_slots), max_slots))
    slots = rng.randint(min_slots, max_slots) if max_slots > 0 else 0
    seen: set = set()
    for _ in range(slots):
        if rng.random() > float(slot_chance):
            continue
        local_allowed = list(allowed_ranks or [])
        if rank_weights:
            picked_rank = weighted_rank_pick(rng, rank_weights, local_allowed)
            local_allowed = [picked_rank]
        candidate = random_recipe_drop_candidate(conn, rng, local_allowed, seen)
        if not candidate:
            continue
        seen.add(candidate["code"])
        grant = grant_recipe_copy(conn, player_id, candidate["code"], 1)
        if grant:
            grant["source"] = source
            awarded.append(grant)
    if awarded:
        add_event(conn, player_id, "recipe_drop", f"Recovered {len(awarded)} recipe copy/copies from {source}.", {"recipes": awarded})
    return awarded


def combat_target_can_drop_recipes(target: Dict[str, Any]) -> bool:
    role = str(target.get("role") or target.get("career") or target.get("targetType") or "").lower()
    allowed_roles = set(RECIPE_DROP_BALANCE.get("normal_kill_role_bonus_roles") or [])
    return bool(allowed_roles.intersection(set(role.replace("-", "_").split("_") + role.split()))) or any(r in role for r in allowed_roles)


def roll_normal_combat_recipe_drops(conn: sqlite3.Connection, player_id: int, target: Dict[str, Any], rng: random.Random) -> List[Dict[str, Any]]:
    if not RECIPE_DROP_BALANCE.get("normal_kill_enabled", True):
        return []
    chance = float(RECIPE_DROP_BALANCE.get("normal_kill_slot_chance", 0.18))
    if combat_target_can_drop_recipes(target):
        chance += float(RECIPE_DROP_BALANCE.get("normal_kill_pirate_bonus", 0.10))
    return roll_recipe_copy_drops(
        conn,
        player_id,
        "open-world combat",
        rng,
        min_slots=0,
        max_slots=int(RECIPE_DROP_BALANCE.get("normal_kill_max_recipes", 2)),
        slot_chance=chance,
        allowed_ranks=list(RECIPE_DROP_BALANCE.get("normal_kill_allowed_ranks") or ["improved", "advanced"]),
        rank_weights=RECIPE_DROP_BALANCE.get("normal_kill_rank_weights") or {},
    )


def roll_pirate_base_completion_recipe_drops(conn: sqlite3.Connection, player_id: int, rng: random.Random) -> List[Dict[str, Any]]:
    if not RECIPE_DROP_BALANCE.get("pirate_base_completion_enabled", True):
        return []
    return roll_recipe_copy_drops(
        conn,
        player_id,
        "pirate base raid completion",
        rng,
        min_slots=int(RECIPE_DROP_BALANCE.get("pirate_base_completion_min_recipes", 2)),
        max_slots=int(RECIPE_DROP_BALANCE.get("pirate_base_completion_max_recipes", 4)),
        slot_chance=float(RECIPE_DROP_BALANCE.get("pirate_base_completion_slot_chance", 0.24)),
        allowed_ranks=list(RECIPE_DROP_BALANCE.get("pirate_base_completion_allowed_ranks") or ["improved", "advanced", "elite"]),
        rank_weights=RECIPE_DROP_BALANCE.get("pirate_base_completion_rank_weights") or {},
    )


def roll_pirate_station_enemy_recipe_drop(conn: sqlite3.Connection, player_id: int, station_tier: int, rng: random.Random) -> List[Dict[str, Any]]:
    tier = pirate_station_tier(station_tier)
    chance_by_tier = PIRATE_STATION_BALANCE.get("recipe_drop_chance_by_tier") or {}
    if rng.random() > float(chance_by_tier.get(str(tier), 0.05)):
        return []
    allowed_ranks = ["improved"] if tier == 1 else (["improved", "advanced"] if tier == 2 else ["improved", "advanced", "elite"])
    placeholders = ",".join("?" for _ in allowed_ranks)
    recipe_tier_hi = min(7, tier + 2)
    candidates = rows(
        conn,
        f"""
        SELECT code,name,recipe_rank_key,recipe_rank_name,set_name,category,recipe_tier,output_tier
        FROM crafting_recipes
        WHERE unlock_model='consumable'
          AND recipe_rank_key IN ({placeholders})
          AND COALESCE(NULLIF(output_tier,0), recipe_tier) BETWEEN ? AND ?
        ORDER BY RANDOM()
        LIMIT 40
        """,
        tuple(allowed_ranks + [tier, recipe_tier_hi]),
    )
    if not candidates:
        return []
    rank_weights = RECIPE_DROP_BALANCE.get("normal_kill_rank_weights") or {}
    weighted = []
    for candidate in candidates:
        weight = float(rank_weights.get(candidate.get("recipe_rank_key"), 1.0))
        if int(candidate.get("output_tier") or candidate.get("recipe_tier") or 1) == tier:
            weight *= 1.35
        if candidate.get("set_name"):
            weight *= 1.15
        weighted.append((candidate, max(0.1, weight)))
    total = sum(w for _, w in weighted)
    roll = rng.uniform(0, total)
    acc = 0.0
    picked = weighted[-1][0]
    for candidate, weight in weighted:
        acc += weight
        if roll <= acc:
            picked = candidate
            break
    grant = grant_recipe_copy(conn, player_id, picked["code"], 1)
    if not grant:
        return []
    grant["source"] = "pirate station pirate"
    add_event(conn, player_id, "recipe_drop", f"Recovered a recipe copy from a pirate station defender: {grant.get('name')}.", {"recipes": [grant], "stationTier": tier})
    return [grant]


def material_availability(conn: sqlite3.Connection, player_id: int) -> Dict[str, Dict[str, Any]]:
    cache_key = ("material_availability", int(player_id))
    cached = request_cache_get(cache_key)
    if cached is not None:
        return {k: {**v, "sources": list(v.get("sources", []))} for k, v in cached.items()}
    available: Dict[str, Dict[str, Any]] = {}
    for inv in rows(conn, "SELECT item_code,name,qty,reserved_qty,base_value,mass,legal,item_type,category,current_tier FROM inventory WHERE player_id=? AND qty>0", (player_id,)):
        code = inv["item_code"]
        qty = max(0, int(inv.get("qty") or 0) - int(inv.get("reserved_qty") or 0))
        if qty <= 0:
            continue
        entry = available.setdefault(code, {"item_code": code, "name": inv.get("name") or code, "qty": 0, "mass": float(inv.get("mass") or 0), "legal": int(inv.get("legal") or 1), "tier": clamp_tier(inv.get("current_tier", 1)), "sources": []})
        entry["qty"] += qty
        entry["sources"].append("inventory")
    for ch in rows(conn, "SELECT ch.qty, c.code, c.name, c.mass, c.legal, c.category, c.tier FROM cargo_hold ch JOIN commodities c ON c.id=ch.commodity_id WHERE ch.player_id=? AND ch.qty>0", (player_id,)):
        code = ch["code"]
        entry = available.setdefault(code, {"item_code": code, "name": ch.get("name") or code, "qty": 0, "mass": float(ch.get("mass") or 0), "legal": int(ch.get("legal") or 1), "tier": clamp_tier(ch.get("tier", 1)), "sources": []})
        entry["qty"] += int(ch.get("qty") or 0)
        entry["sources"].append("cargo")
    request_cache_set(cache_key, {k: {**v, "sources": list(v.get("sources", []))} for k, v in available.items()})
    return available


def recipe_output_preview(conn: sqlite3.Connection, output: Dict[str, Any]) -> Dict[str, Any]:
    if output.get("kind") == "module":
        mt = row(conn, "SELECT * FROM module_templates WHERE code=?", (output.get("module_code"),))
        if not mt:
            return {"kind":"module", "missing":True, "name":output.get("module_code"), "qty":int(output.get("qty") or 1)}
        data = {"kind":"module", "module_code":mt["code"], "name":mt["name"], "slot_type":mt["slot_type"], "rarity":mt["rarity"], "qty":int(output.get("qty") or 1), "base_value":int(mt.get("price") or 0), "mass":3, "stats":apply_tier_to_item_stats(decode_json(mt.get("stats_json"), {}) or {}, output.get("tier", mt.get("tier", 1))), "item_type":"ship_module", "category":"ship_modules", "legal":1, "current_tier":clamp_tier(output.get("tier", mt.get("tier", 1))), "max_tier":clamp_tier(mt.get("max_tier", 5)), "tier_source":"crafted"}
        mod_set = MODULE_SET_FAMILIES.get(recipe_base_code_from_variant(mt["code"]), {})
        data["set_code"] = mod_set.get("set_code", "")
        data["set_name"] = mod_set.get("set_name", "")
        data["set_loop"] = mod_set.get("loop", "")
        attach_tier_metadata(data)
        return attach_item_visual(data)
    data = dict(output)
    data["category"] = data.get("category") or inventory_category(data.get("item_type", "goods"), int(data.get("legal", 1) or 1))
    data["current_tier"] = clamp_tier(data.get("tier", data.get("outputTier", 1)))
    data["max_tier"] = max(data["current_tier"], clamp_tier(data.get("maxTier", get_max_tier_for_item(data))))
    attach_tier_metadata(data)
    return attach_item_visual(data)


def crafting_cost_discount(conn: sqlite3.Connection, player_id: int) -> float:
    skills = player_skill_totals(conn, player_id)
    discount = skills.get("engineering", 0) * CRAFTING_BALANCE["engineering_cost_discount_per_skill"] + skills.get("crafting", 0) * CRAFTING_BALANCE["crafting_cost_discount_per_skill"]
    return min(CRAFTING_BALANCE["max_cost_discount"], max(0.0, discount))


def effective_recipe_cost(conn: sqlite3.Connection, player_id: int, recipe: Dict[str, Any]) -> int:
    tier_factor = 0.88 + (0.12 * calculate_tier_crafting_difficulty(int(recipe.get("recipe_tier") or 1)))
    base_cost = int(int(recipe.get("credits") or 0) * tier_factor * (1.0 - crafting_cost_discount(conn, player_id)))
    return balanced_recipe_credit_cost(recipe, base_cost)


def crafting_success_odds(conn: sqlite3.Connection, player_id: int, recipe: Dict[str, Any], planet: Optional[Dict[str, Any]], god: bool = False) -> float:
    if god:
        return 1.0
    skills = player_skill_totals(conn, player_id)
    active = active_job_runtime(conn, player_id)
    req_tree = recipe.get("required_skill_tree") or "crafting"
    odds = float(recipe.get("base_success") or 0.80)
    odds -= max(0, int(recipe.get("recipe_tier") or 1) - 1) * 0.035
    odds += skills.get("crafting", 0) * CRAFTING_BALANCE["skill_success_bonus"]
    odds += skills.get("engineering", 0) * (CRAFTING_BALANCE["skill_success_bonus"] * 0.55)
    odds += skills.get(req_tree, 0) * (CRAFTING_BALANCE["skill_success_bonus"] * 0.75)
    if active and active.get("job_code") in (recipe.get("required_jobs") or []):
        odds += int(active.get("computed_rank") or active.get("rank") or 1) * CRAFTING_BALANCE["job_rank_success_bonus"]
    if planet:
        effects = planet_control_effects(planet)
        odds += (int(planet.get("stability_level") or 60) - 50) * CRAFTING_BALANCE["stability_success_bonus"]
        odds += float(effects.get("crafting_bonus") or 0) * 0.002
        if not int((recipe.get("output") or {}).get("legal", 1)) or recipe.get("category") == "Illicit Goods":
            odds -= int(planet.get("security_level") or 50) * CRAFTING_BALANCE["illegal_security_penalty"]
            odds += skills.get("smuggling", 0) * 0.006
    return max(0.42, min(0.98, odds))


def material_unit_mass(conn: sqlite3.Connection, player_id: int, code: str) -> float:
    inv = row(conn, "SELECT mass FROM inventory WHERE player_id=? AND item_code=? LIMIT 1", (player_id, code))
    if inv:
        return float(inv.get("mass") or 0)
    c = row(conn, "SELECT mass FROM commodities WHERE code=?", (code,))
    return float(c.get("mass") or 0) if c else 0.0


def recipe_input_mass(conn: sqlite3.Connection, player_id: int, inputs: Dict[str, Any]) -> float:
    return sum(material_unit_mass(conn, player_id, code) * int(qty) for code, qty in inputs.items())


def recipe_output_mass(output: Dict[str, Any]) -> float:
    if output.get("kind") == "module":
        return 3.0 * int(output.get("qty") or 1)
    return float(output.get("mass") or 0) * int(output.get("qty") or 1)



def recipe_requirement_report(conn: sqlite3.Connection, player_id: int, recipe: Dict[str, Any], planet: Optional[Dict[str, Any]], god: bool = False) -> Dict[str, Any]:
    available = material_availability(conn, player_id)
    inputs = recipe.get("inputs") or {}
    input_rows = []
    missing = []
    req_tiers = recipe.get("required_material_tiers") or {}
    for code, need in inputs.items():
        have = int((available.get(code) or {}).get("qty") or 0)
        have_tier = clamp_tier((available.get(code) or {}).get("tier", 1))
        need_tier = clamp_tier(req_tiers.get(code, 0)) if isinstance(req_tiers, dict) else 0
        row_data = {
            "item_code": code,
            "name": (available.get(code) or {}).get("name") or label_for_api(code),
            "required": int(need),
            "available": have,
            "tier": have_tier,
            "required_tier": need_tier,
            "met": have >= int(need) and have_tier >= need_tier,
        }
        input_rows.append(row_data)
        if have < int(need) or have_tier < need_tier:
            missing.append(row_data)
    active = active_job_runtime(conn, player_id)
    req_jobs = recipe.get("required_jobs") or []
    req_rank = int(recipe.get("required_job_rank") or 1)
    job_ok = True if not req_jobs else bool(active and active.get("job_code") in req_jobs and int(active.get("computed_rank") or active.get("rank") or 1) >= req_rank)
    skills = player_skill_totals(conn, player_id)
    req_tree = recipe.get("required_skill_tree") or "crafting"
    req_total = int(recipe.get("required_skill_total") or 0)
    skill_ok = skills.get(req_tree, 0) >= req_total
    blockers = []
    if missing:
        blockers.append("Missing materials")
    if not job_ok:
        blockers.append(f"Requires {' or '.join(req_jobs)} rank {req_rank}")
    if not skill_ok:
        blockers.append(f"Requires {label_for_api(req_tree)} {req_total}")
    if recipe.get("requires_refinery"):
        refinery_available = bool(planet and planet_has_service(conn, int(planet["id"]), "refinery"))
        if not refinery_available:
            blockers.append("Requires refinery access")
    else:
        refinery_available = True
    effective_credits = effective_recipe_cost(conn, player_id, recipe)
    if not god and int((get_player(conn, player_id) or {}).get("credits") or 0) < effective_credits:
        blockers.append("Insufficient credits")
    if not god and int((get_player(conn, player_id) or {}).get("energy") or 0) < int(recipe.get("energy") or 0):
        blockers.append("Insufficient energy")
    license_state = recipe_license_state(conn, player_id, recipe)
    if not license_state["owned"] and not god:
        blockers.append("Recipe copy not owned")
    return {
        "inputs": input_rows,
        "missing": missing,
        "job_ok": job_ok,
        "skill_ok": skill_ok,
        "blockers": blockers,
        "can_craft": len(blockers) == 0 or god,
        "effective_credits": effective_credits,
        "discount_pct": int(round(crafting_cost_discount(conn, player_id) * 100)),
        "success_odds": crafting_success_odds(conn, player_id, recipe, planet, god),
        "refinery_available": refinery_available,
        "owned_recipe": bool(license_state["owned"]),
        "recipe_uses_remaining": license_state["charges_remaining"],
        "recipe_unlimited": bool(license_state["unlimited"]),
        "recipe_unlock_model": recipe.get("unlock_model", "unlimited"),
    }


def build_crafting_state(conn: sqlite3.Connection, player_id: int, planet: Optional[Dict[str, Any]], god: bool = False) -> List[Dict[str, Any]]:
    ensure_starter_recipe_licenses(conn, player_id)
    out = []
    for raw in rows(conn, "SELECT * FROM crafting_recipes ORDER BY category, recipe_tier, name"):
        rec = recipe_from_row(raw)
        enrich_recipe_timing(rec)
        rec.update(recipe_requirement_report(conn, player_id, rec, planet, god))
        rec.pop("inputs_json", None); rec.pop("output_json", None); rec.pop("required_jobs_json", None)
        out.append(rec)
    return out


def output_time_key(recipe: Dict[str, Any]) -> str:
    output = recipe.get("output") or {}
    kind = str(output.get("kind") or "").lower()
    item_type = str(output.get("item_type") or output.get("category") or recipe.get("category") or "").lower()
    module_code = str(output.get("module_code") or "").lower()
    if kind == "ship":
        return "ship"
    if kind == "module":
        if any(x in module_code for x in ["weapon", "railgun", "missile", "lance", "turret"]):
            return "weapon"
        if any(x in module_code for x in ["armor", "shield"]):
            return "armor"
        return "module"
    if "ammo" in item_type or str(output.get("item_code") or "").lower() in {"ammo", "railgun_ammo"}:
        return "ammo"
    if "consum" in item_type or "booster" in item_type or "repair" in item_type:
        return "consumable"
    if "refined" in item_type:
        return "refined"
    if "component" in item_type:
        return "component"
    if "illicit" in item_type or int(output.get("legal", 1)) == 0:
        return "illicit_goods"
    if "material" in item_type or "ore" in item_type or "chemical" in item_type:
        return "material"
    return "goods"


def recipe_output_tier(recipe: Dict[str, Any]) -> int:
    output = recipe.get("output") or {}
    return clamp_tier(output.get("tier", output.get("outputTier", recipe.get("output_tier", recipe.get("recipe_tier", 1)))))


def recipe_output_qty(recipe: Dict[str, Any]) -> int:
    output = recipe.get("output") or {}
    return max(1, int(output.get("qty") or 1))


def recipe_output_rarity(recipe: Dict[str, Any]) -> str:
    output = recipe.get("output") or {}
    if output.get("rarity"):
        return str(output.get("rarity")).lower()
    if recipe.get("recipe_tier", 1) >= 6:
        return "legendary"
    if recipe.get("recipe_tier", 1) >= 5:
        return "epic"
    if recipe.get("recipe_tier", 1) >= 3:
        return "rare"
    if recipe.get("recipe_tier", 1) >= 2:
        return "uncommon"
    return "common"


def recipe_ship_class_key(recipe: Dict[str, Any]) -> str:
    output = recipe.get("output") or {}
    text = " ".join(str(output.get(k) or "") for k in ["ship_class", "class_name", "template_code", "ship_code", "name", "item_code"]).lower()
    for key in ["dreadnought", "capital", "carrier", "cruiser", "destroyer", "frigate", "freighter", "fighter", "scout", "shuttle"]:
        if key in text:
            return key
    tier = recipe_output_tier(recipe)
    if tier >= 7:
        return "dreadnought"
    if tier >= 6:
        return "capital"
    if tier >= 5:
        return "carrier"
    if tier >= 4:
        return "cruiser"
    if tier >= 3:
        return "frigate"
    return "shuttle"


def crafting_duration_seconds(recipe: Dict[str, Any]) -> int:
    if not CRAFTING_BALANCE.get("timed_crafting_enabled", True):
        return 0
    output_key = output_time_key(recipe)
    tier = recipe_output_tier(recipe)
    qty = recipe_output_qty(recipe)
    rarity = recipe_output_rarity(recipe)
    tier_mult = float((CRAFTING_BALANCE.get("tier_time_multiplier") or {}).get(str(tier), 1 + max(0, tier - 1) * 0.8))
    rarity_mult = float((CRAFTING_BALANCE.get("rarity_time_multiplier") or {}).get(rarity, 1.0))
    base_seconds = int((CRAFTING_BALANCE.get("base_seconds_by_output") or {}).get(output_key, 60))
    per_unit = int((CRAFTING_BALANCE.get("per_unit_seconds_by_output") or {}).get(output_key, 10))

    if output_key == "ship":
        ship_key = recipe_ship_class_key(recipe)
        base_seconds = int((CRAFTING_BALANCE.get("ship_class_seconds") or {}).get(ship_key, base_seconds))
        seconds = int(base_seconds * tier_mult * rarity_mult)
    else:
        recipe_minutes = int(recipe.get("craft_minutes") or 0)
        recipe_base = recipe_minutes * 60 if recipe_minutes > 0 else base_seconds
        seconds = int((recipe_base + per_unit * qty) * tier_mult * rarity_mult)

    min_seconds = int(CRAFTING_BALANCE.get("min_seconds", 5))
    max_seconds = int((CRAFTING_BALANCE.get("max_seconds_by_output") or {}).get(output_key, 86400))
    seconds = max(min_seconds, min(max_seconds, seconds))
    return balanced_crafting_seconds(seconds, recipe)


def craft_duration_label(seconds: int) -> str:
    seconds = max(0, int(seconds or 0))
    if seconds < 60:
        return f"{seconds}s"
    if seconds < 3600:
        return f"{math.ceil(seconds / 60)}m"
    if seconds < 86400:
        hours = seconds / 3600
        return f"{hours:.1f}h" if hours < 10 else f"{math.ceil(hours)}h"
    days = seconds / 86400
    return f"{days:.1f}d" if days < 10 else f"{math.ceil(days)}d"


def enrich_recipe_timing(recipe: Dict[str, Any]) -> None:
    seconds = crafting_duration_seconds(recipe)
    recipe["craft_seconds"] = seconds
    recipe["craft_time_seconds"] = seconds
    recipe["craft_time_label"] = craft_duration_label(seconds)
    recipe["timed_crafting"] = bool(CRAFTING_BALANCE.get("timed_crafting_enabled", True))


def active_crafting_jobs(conn: sqlite3.Connection, player_id: int) -> List[Dict[str, Any]]:
    return rows(conn, "SELECT * FROM crafting_queue WHERE player_id=? AND status='active' ORDER BY completes_at, id", (player_id,))


def crafting_queue_payload(conn: sqlite3.Connection, player_id: int) -> List[Dict[str, Any]]:
    now = utcnow()
    out: List[Dict[str, Any]] = []
    for job in rows(conn, "SELECT * FROM crafting_queue WHERE player_id=? AND status IN ('active','complete','failed','cancelled') ORDER BY CASE status WHEN 'active' THEN 0 ELSE 1 END, completes_at DESC LIMIT 40", (player_id,)):
        started = parse_dt(job.get("started_at")) or now
        completes = parse_dt(job.get("completes_at")) or now
        completed = parse_dt(job.get("completed_at")) if job.get("completed_at") else None
        total = max(1, int((completes - started).total_seconds()))
        elapsed = int(((completed or now) - started).total_seconds())
        remaining = max(0, int((completes - now).total_seconds())) if job.get("status") == "active" else 0
        job = dict(job)
        job["recipe_snapshot"] = decode_json(job.get("recipe_snapshot_json"), {})
        job["output_preview"] = decode_json(job.get("output_preview_json"), {})
        job["output"] = decode_json(job.get("output_json"), {})
        job["progress_pct"] = 100 if job.get("status") != "active" else clamp_int((elapsed / total) * 100, 0, 100)
        job["remaining_seconds"] = remaining
        job["remaining_label"] = craft_duration_label(remaining)
        job["total_seconds"] = total
        job["total_label"] = craft_duration_label(total)
        out.append(job)
    return out


def finalize_crafting_job(conn: sqlite3.Connection, job: Dict[str, Any], god: bool = False, record_guild: bool = True) -> Dict[str, Any]:
    player_id = int(job["player_id"])
    recipe = decode_json(job.get("recipe_snapshot_json"), {}) or {}
    if not recipe:
        recipe_raw = row(conn, "SELECT * FROM crafting_recipes WHERE code=?", (job["recipe_code"],))
        recipe = recipe_from_row(recipe_raw) if recipe_raw else {"code": job["recipe_code"], "name": job["recipe_name"], "output": {}}

    odds = float(job.get("success_odds") or 0)
    roll = random.random()
    if god and CRAFTING_BALANCE.get("god_instant_crafting"):
        outcome = "critical_success"
    elif roll <= odds * float(CRAFTING_BALANCE.get("critical_success_chance", 0.07)):
        outcome = "critical_success"
    elif roll <= odds:
        outcome = "success"
    else:
        outcome = "failure"

    output = apply_recipe_output(conn, player_id, recipe, outcome, god)
    xp = int(job.get("xp_reward") or recipe.get("xp_reward") or 0)
    if outcome == "critical_success":
        xp = int(xp * 1.25)
    elif outcome == "failure":
        xp = max(1, int(xp * 0.25))
    add_xp(conn, player_id, xp)

    active = active_job_runtime(conn, player_id)
    effective_credits = int(job.get("credits_spent") or 0)
    if active and active.get("job_code") in {"engineer", "shipwright"}:
        increment_job_metrics(conn, player_id, active["job_code"], {"crafts": 1, "craft_value": max(effective_credits, int((recipe.get("output") or {}).get("base_value") or 0))})
        new_job = row(conn, "SELECT * FROM player_jobs WHERE player_id=? AND job_code=?", (player_id, active["job_code"]))
        metrics = get_job_metrics(conn, player_id, active["job_code"])
        new_rank = job_rank_from_metrics(active["job_code"], int(new_job.get("xp") or 0), metrics)
        conn.execute("UPDATE player_jobs SET rank=? WHERE player_id=? AND job_code=?", (new_rank, player_id, active["job_code"]))

    player = get_player(conn, player_id)
    if recipe.get("category") == "Illicit Goods" and outcome in {"success", "critical_success"}:
        conn.execute("UPDATE planets SET security_level=max(1,min(100,security_level-1)), stability_level=max(1,min(100,stability_level-1)), pirate_activity=max(1,min(100,pirate_activity+1)) WHERE id=?", (player["location_planet_id"],))
    elif outcome in {"success", "critical_success"} and recipe.get("category") in {"Refined Materials", "Ship Modules"}:
        conn.execute("UPDATE planets SET market_activity=max(1,min(100,market_activity+1)), stability_level=max(1,min(100,stability_level+1)) WHERE id=?", (player["location_planet_id"],))

    grant_action_progression(conn, player_id, "crafting", max(0.5, int(recipe.get("recipe_tier") or 1) * (1.25 if outcome in {"success", "critical_success"} else 0.45)), outcome in {"success", "critical_success"})
    record_crafting_history(conn, player_id, recipe, outcome, output, xp, int(job.get("credits_spent") or 0), int(job.get("energy_spent") or 0))
    if outcome in {"success", "critical_success"}:
        recipe_output = recipe.get("output") or {}
        output_kind = str(output.get("kind") or recipe_output.get("kind") or "item")
        output_qty = max(1, int(output.get("qty") or recipe_output.get("qty") or 1))
        output_tier = clamp_tier(recipe_output.get("tier", recipe_output.get("outputTier", recipe.get("recipe_tier", 1))))
        output_value = int(recipe_output.get("base_value") or output.get("base_value") or 0) * output_qty
        if output_kind == "module":
            module_code = output.get("module_code") or recipe_output.get("module_code")
            module_template = row(conn, "SELECT price FROM module_templates WHERE code=?", (module_code,)) if module_code else None
            output_value = int((module_template or {}).get("price") or output_value or 0) * output_qty
        metrics = {
            "items_crafted": output_qty,
            "crafting_value_created": max(effective_credits, output_value),
            "equipment_crafted": output_qty if output_kind == "module" else 0,
            "ships_crafted": output_qty if output_kind == "ship" else 0,
            "high_tier_crafts": output_qty if output_tier >= 4 else 0,
        }
        if str(recipe.get("category") or "") == "Refined Materials":
            metrics["processing_output_value"] = output_value
            metrics["rare_output_generated"] = output_qty if output_tier >= 4 else 0
        emit_player_metrics(conn, player_id, metrics, player=player, metadata={"action": "crafting_complete", "recipe": recipe.get("code"), "recipe_name": recipe.get("name"), "outcome": outcome, "output_kind": output_kind, "output_tier": output_tier, "job_id": job.get("id")})

    output_name = output.get("name") or output.get("item_code") or output.get("kind")
    if outcome == "failure":
        msg = f"Crafting failed after timer: {recipe.get('name') or job.get('recipe_name')}. Salvaged {output.get('scrap', 0)} scrap and gained {xp} XP."
    else:
        msg = f"{outcome.replace('_',' ').title()} complete: crafted {output.get('qty',1)}x {output_name}. Gained {xp} XP."
    conn.execute("UPDATE crafting_queue SET status=?, completed_at=?, outcome=?, output_json=?, message=? WHERE id=?", ("failed" if outcome == "failure" else "complete", iso(), outcome, encode_json(output), msg, job["id"]))
    add_event(conn, player_id, "crafting", msg, {"recipe": recipe.get("code"), "outcome": outcome, "output": output, "job_id": job["id"]})
    if record_guild:
        nova_safe_record_guild_contribution(conn, player_id, "crafting", max(25, xp), int(output.get("qty") or 1), "crafting_complete", {"jobId": job["id"], "recipe": recipe.get("code"), "outcome": outcome})
    return {"message": msg, "outcome": outcome, "output": output, "xp": xp}


def resolve_completed_crafting_jobs(conn: sqlite3.Connection, player_id: int, god: bool = False, record_guild: bool = True) -> List[Dict[str, Any]]:
    completed: List[Dict[str, Any]] = []
    for job in rows(conn, "SELECT * FROM crafting_queue WHERE player_id=? AND status='active' AND completes_at<=? ORDER BY completes_at, id", (player_id, iso())):
        completed.append(finalize_crafting_job(conn, job, god, record_guild=record_guild))
    return completed


def remove_crafting_material(conn: sqlite3.Connection, player_id: int, item_code: str, qty: int) -> None:
    remaining = int(qty)
    inv = row(conn, "SELECT * FROM inventory WHERE player_id=? AND item_code=?", (player_id, item_code))
    if inv:
        take = min(remaining, max(0, int(inv.get("qty") or 0) - int(inv.get("reserved_qty") or 0)))
        if take:
            conn.execute("UPDATE inventory SET qty=max(0,qty-?) WHERE player_id=? AND item_code=?", (take, player_id, item_code))
            conn.execute("DELETE FROM inventory WHERE player_id=? AND item_code=? AND qty<=0", (player_id, item_code))
            remaining -= take
    if remaining > 0:
        commodity = row(conn, "SELECT * FROM commodities WHERE code=?", (item_code,))
        holding = row(conn, "SELECT * FROM cargo_hold WHERE player_id=? AND commodity_id=?", (player_id, commodity["id"])) if commodity else None
        if holding:
            take = min(remaining, int(holding.get("qty") or 0))
            if take:
                conn.execute("UPDATE cargo_hold SET qty=max(0,qty-?) WHERE player_id=? AND commodity_id=?", (take, player_id, commodity["id"]))
                conn.execute("DELETE FROM cargo_hold WHERE player_id=? AND commodity_id=? AND qty<=0", (player_id, commodity["id"]))
                conn.execute("UPDATE players SET cargo=max(0,cargo-?) WHERE id=?", (int(math.ceil(float(commodity.get("mass") or 0)*take)), player_id))
                remaining -= take
    if remaining > 0:
        raise HTTPException(400, f"Missing required material: {item_code}")


def consume_recipe_inputs(conn: sqlite3.Connection, player_id: int, recipe: Dict[str, Any]) -> None:
    player = get_player(conn, player_id)
    for code, qty in (recipe.get("inputs") or {}).items():
        remove_crafting_material(conn, player_id, code, int(qty))
        commodity = row(conn, "SELECT * FROM commodities WHERE code=?", (code,))
        if commodity:
            mutate_market(conn, player["location_planet_id"], commodity["id"], 0, CRAFTING_BALANCE["market_input_demand_nudge"], "player_crafting_input")


def apply_recipe_output(conn: sqlite3.Connection, player_id: int, recipe: Dict[str, Any], outcome: str, god: bool = False) -> Dict[str, Any]:
    output = dict(recipe.get("output") or {})
    if outcome not in {"success", "critical_success"}:
        scrap_value = max(1, int(int(recipe.get("credits") or 0) * CRAFTING_BALANCE["failure_scrap_credit"] / 50))
        conn.execute("UPDATE players SET scrap=scrap+? WHERE id=?", (scrap_value, player_id))
        return {"kind":"failure_scrap", "scrap":scrap_value}
    qty = int(output.get("qty") or 1)
    if outcome == "critical_success" and output.get("kind") != "module":
        qty = max(qty + 1, int(math.ceil(qty * 1.25)))
    if output.get("kind") == "module":
        mt = row(conn, "SELECT * FROM module_templates WHERE code=?", (output.get("module_code"),))
        if not mt:
            raise HTTPException(500, "Recipe output module template missing")
        ids = []
        for _ in range(max(1, qty)):
            crafted_tier = clamp_tier(output.get("tier", output.get("outputTier", mt.get("tier", 1))))
            conn.execute("INSERT INTO ship_modules (player_id,ship_id,module_template_id,slot_type,equipped,durability,current_tier,max_tier,tier_source) VALUES (?,?,?,?,?,?,?,?,?)", (player_id, None, mt["id"], mt["slot_type"], 0, 100, crafted_tier, clamp_tier(mt.get("max_tier", 5)), "crafted"))
            ids.append(conn.execute("SELECT last_insert_rowid()").fetchone()[0])
        return {"kind":"module", "module_code":mt["code"], "name":mt["name"], "qty":len(ids), "module_ids":ids}
    add_inventory_item(conn, player_id, output["item_code"], output["name"], output.get("item_type", "crafted"), qty, int(output.get("legal", 1)), int(output.get("base_value") or 0), float(output.get("mass") or 1), output.get("description", "Crafted item"), "crafting", output.get("category"), output.get("rarity"), tier=clamp_tier(output.get("tier", output.get("outputTier", recipe.get("output_tier", 1)))), max_tier=output.get("maxTier"), tier_source="crafted", respect_cargo=True, god=god)
    commodity = row(conn, "SELECT * FROM commodities WHERE code=?", (output.get("item_code"),))
    player = get_player(conn, player_id)
    if commodity:
        mutate_market(conn, player["location_planet_id"], commodity["id"], CRAFTING_BALANCE["market_output_supply_nudge"], 0, "player_crafting_output")
    return {"kind":"item", "item_code":output["item_code"], "name":output["name"], "qty":qty, "legal":int(output.get("legal", 1))}


def record_crafting_history(conn: sqlite3.Connection, player_id: int, recipe: Dict[str, Any], outcome: str, output: Dict[str, Any], xp: int, credits: int, energy: int) -> None:
    conn.execute("INSERT INTO crafting_history (player_id,recipe_code,recipe_name,outcome,output_json,xp_reward,credits_spent,energy_spent,created_at) VALUES (?,?,?,?,?,?,?,?,?)", (player_id, recipe["code"], recipe["name"], outcome, encode_json(output), int(xp), int(credits), int(energy), iso()))

def mutate_planet_conditions(
    conn: sqlite3.Connection,
    planet_id: int,
    rng: random.Random,
    source: str,
    *,
    security_delta: int = 0,
    stability_delta: int = 0,
    pirate_delta: int = 0,
    market_delta: int = 0,
) -> Dict[str, int]:
    # NPC condition drift is intentionally probabilistic and tiny. This keeps planets alive without wild offline swings.
    if rng.random() > SIMULATION_BALANCE["condition_change_chance"]:
        return {}
    deltas = {
        "security_level": int(security_delta),
        "stability_level": int(stability_delta),
        "pirate_activity": int(pirate_delta),
        "market_activity": int(market_delta),
    }
    deltas = {k: v for k, v in deltas.items() if v}
    if not deltas:
        return {}
    conn.execute(
        """
        UPDATE planets
        SET security_level=max(1,min(99,security_level+?)),
            stability_level=max(1,min(99,stability_level+?)),
            pirate_activity=max(1,min(99,pirate_activity+?)),
            market_activity=max(1,min(99,market_activity+?))
        WHERE id=?
        """,
        (
            deltas.get("security_level", 0),
            deltas.get("stability_level", 0),
            deltas.get("pirate_activity", 0),
            deltas.get("market_activity", 0),
            planet_id,
        ),
    )
    return {"source": source, **deltas}


def npc_action_candidates(npc: Dict[str, Any]) -> List[str]:
    profile = NPC_CAREER_PROFILES.get(npc.get("career_code") or "trader", NPC_CAREER_PROFILES["trader"])
    return profile.get("actions", ["legal_buy"])


def choose_market_commodity(conn: sqlite3.Connection, legal: Optional[bool] = None, categories: Optional[List[str]] = None) -> Optional[Dict[str, Any]]:
    sql = "SELECT * FROM commodities WHERE 1=1"
    params: List[Any] = []
    if legal is not None:
        sql += " AND legal=?"; params.append(1 if legal else 0)
    if categories:
        sql += " AND category IN (%s)" % ",".join("?" for _ in categories); params.extend(categories)
    pool = rows(conn, sql, tuple(params))
    return random.choice(pool) if pool else None


def simulate_single_npc_action(conn: sqlite3.Connection, npc: Dict[str, Any], planet: Dict[str, Any], rng: random.Random) -> Optional[str]:
    actions = npc_action_candidates(npc)
    action = rng.choice(actions)
    career = npc.get("career_code") or "civilian"
    # NPCs roll like players, but weaker: their activity, level, job rank, and power matter, then a weakness multiplier applies.
    npc_roll = int((int(npc.get("power") or 30) + int(npc.get("level") or 1) * 1.2 + int(npc.get("job_rank") or 1) * 4) * rng.uniform(0.52, 0.78))
    activity_mult = max(0.4, min(1.8, int(npc.get("activity_rate") or 50) / 55.0))
    base_qty = max(1, int(rng.randint(1, 6) * activity_mult * max(1, int(planet.get("npc_density") or 50) / 55.0)))
    msg = None
    atype = f"npc_{career}"
    commodity = None
    condition_impact: Dict[str, Any] = {}

    if action in {"legal_buy", "dock_inspection", "collect_fees"}:
        commodity = choose_market_commodity(conn, legal=True)
        if not commodity: return None
        qty = base_qty
        mutate_market(conn, planet["id"], commodity["id"], -qty, max(1, qty // 2), "npc_legal_buy")
        condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_legal_buy", market_delta=1)
        msg = f"{npc['name']} bought {qty}x {commodity['name']} from {planet['name']} markets."
    elif action in {"legal_sell", "hauler_delivery", "supply_contract", "defense_delivery", "parts_delivery"}:
        cats = ["industrial", "electronics", "energy", "medical", "chemical", "food"]
        commodity = choose_market_commodity(conn, legal=True, categories=cats) or choose_market_commodity(conn, legal=True)
        if not commodity: return None
        qty = base_qty + rng.randint(1, 8)
        mutate_market(conn, planet["id"], commodity["id"], qty, -max(1, qty // 3), "npc_delivery")
        condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_delivery", stability_delta=1, market_delta=1)
        msg = f"{npc['name']} delivered {qty}x {commodity['name']} to {planet['name']}."
    elif action in {"smuggle", "illegal_sell"}:
        commodity = choose_market_commodity(conn, legal=False)
        if not commodity: return None
        customs_roll = resolve_npc_roll(conn, "customs", planet["id"], "standard")
        qty = max(1, base_qty // 2)
        if customs_roll > npc_roll + rng.randint(-12, 25):
            mutate_market(conn, planet["id"], commodity["id"], -qty, max(1, qty // 2), "npc_customs_caught_smuggler")
            condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_customs_caught_smuggler", security_delta=1, stability_delta=1, pirate_delta=-1)
            msg = f"NPC customs caught {npc['name']} trying to move {qty}x {commodity['name']} near {planet['name']}."
            atype = "npc_customs"
        else:
            mutate_market(conn, planet["id"], commodity["id"], qty, -1, "npc_smuggler_success")
            condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_smuggler_success", security_delta=-1, stability_delta=-1, pirate_delta=1, market_delta=1)
            msg = f"{npc['name']} slipped {qty}x {commodity['name']} into {planet['name']} black markets."
            atype = "npc_smuggler"
    elif action in {"bribe_customs"}:
        commodity = choose_market_commodity(conn, legal=False)
        if not commodity: return None
        success = rng.randint(1, 100) < max(5, 42 - int(planet.get("lawfulness") or 50) // 3 + int(npc.get("job_rank") or 1) * 2)
        qty = max(1, base_qty // 2)
        if success:
            mutate_market(conn, planet["id"], commodity["id"], qty, -1, "npc_bribed_customs")
            condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_bribed_customs", security_delta=-1, stability_delta=-1, pirate_delta=1)
            msg = f"{npc['name']} bribed a minor port official and moved {qty}x {commodity['name']}."
        else:
            mutate_market(conn, planet["id"], commodity["id"], -qty, max(1, qty // 2), "npc_failed_bribe")
            condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_failed_bribe", security_delta=1, stability_delta=1, pirate_delta=-1)
            msg = f"{npc['name']} failed a customs bribe and lost {qty}x {commodity['name']}."
        atype = "npc_bribe"
    elif action in {"customs_scan", "seize_contraband"}:
        commodity = choose_market_commodity(conn, legal=False)
        if not commodity: return None
        qty = max(1, base_qty // 2)
        mutate_market(conn, planet["id"], commodity["id"], -qty, max(1, qty // 2), "npc_customs_seizure")
        condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_customs_seizure", security_delta=1, stability_delta=1, pirate_delta=-1)
        msg = f"{npc['name']} seized {qty}x {commodity['name']} from NPC traffic around {planet['name']}."
        atype = "npc_customs"
    elif action in {"pirate_disruption", "merc_contract"}:
        commodity = choose_market_commodity(conn)
        if not commodity: return None
        qty = max(1, base_qty)
        mutate_market(conn, planet["id"], commodity["id"], -qty, rng.randint(0, 2), "npc_hostile_disruption")
        condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_hostile_disruption", security_delta=-1, stability_delta=-2, pirate_delta=1, market_delta=-1)
        if rng.random() < 0.22:
            conn.execute("INSERT INTO bounties (name,target_type,planet_id,threat,reward,status) VALUES (?,?,?,?,?,?)", (f"{npc['name']} Wing", "npc", planet["id"], clamp_int(npc_roll, 15, 120), rng.randint(35000, 275000), "open"))
        msg = f"{npc['name']} disrupted {commodity['name']} traffic near {planet['name']}."
        atype = "npc_hostile"
    elif action in {"bounty_spawn", "pirate_hunt", "patrol", "escort_convoy"}:
        if rng.random() < 0.42:
            conn.execute("INSERT INTO bounties (name,target_type,planet_id,threat,reward,status) VALUES (?,?,?,?,?,?)", (f"Wanted Pilot {uuid.uuid4().hex[:5]}", "npc", planet["id"], clamp_int(npc_roll + rng.randint(-10, 22), 10, 130), rng.randint(25000, 220000), "open"))
            condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_bounty_report", stability_delta=-1, pirate_delta=1)
            msg = f"{npc['name']} reported a new NPC bounty near {planet['name']}."
        else:
            commodity = choose_market_commodity(conn, legal=True)
            if not commodity: return None
            mutate_market(conn, planet["id"], commodity["id"], max(1, base_qty // 2), -1, "npc_route_secured")
            condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_route_secured", security_delta=1, stability_delta=1, pirate_delta=-1, market_delta=1)
            msg = f"{npc['name']} secured a convoy lane and improved {commodity['name']} flow."
        atype = "npc_security"
    elif action in {"mine_ore", "sell_ore"}:
        commodity = row(conn, "SELECT * FROM commodities WHERE code='ore'")
        if not commodity: return None
        qty = base_qty + max(2, int(npc_roll / 12))
        mutate_market(conn, planet["id"], commodity["id"], qty, -1, "npc_mining_output")
        condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_mining_output", stability_delta=1, market_delta=1)
        msg = f"{npc['name']} mined and sold {qty}x {commodity['name']} on {planet['name']}."
        atype = "npc_miner"
    elif action in {"salvage_scrap", "sell_components"}:
        commodity = choose_market_commodity(conn, legal=True, categories=["electronics", "industrial", "energy"])
        if not commodity: return None
        qty = base_qty + max(1, int(npc_roll / 18))
        mutate_market(conn, planet["id"], commodity["id"], qty, -1, "npc_salvage_output")
        condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_salvage_output", stability_delta=1, market_delta=1)
        msg = f"{npc['name']} recovered {qty}x {commodity['name']} from wreckage near {planet['name']}."
        atype = "npc_salvager"
    elif action in {"repair_contract", "module_output", "ship_parts_output"}:
        commodity = choose_market_commodity(conn, legal=True, categories=["industrial", "electronics", "chemical"])
        if not commodity: return None
        qty = base_qty + rng.randint(2, 7)
        mutate_market(conn, planet["id"], commodity["id"], qty, -1, "npc_engineering_output")
        condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_engineering_output", stability_delta=1, market_delta=1)
        msg = f"{npc['name']} completed engineering work and released {qty}x {commodity['name']} supply."
        atype = "npc_engineer"
    elif action in {"medical_shift", "rescue_response"}:
        commodity = choose_market_commodity(conn, legal=True, categories=["medical", "chemical", "food"])
        if not commodity: return None
        qty = max(1, base_qty)
        mutate_market(conn, planet["id"], commodity["id"], -max(1, qty // 2), qty, "npc_medical_demand")
        condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_medical_demand", stability_delta=1)
        msg = f"{npc['name']} treated NPC casualties, increasing demand for {commodity['name']}."
        atype = "npc_medic"
    elif action in {"stabilize_market", "reduce_tension"}:
        commodity = choose_market_commodity(conn)
        if not commodity: return None
        mp = row(conn, "SELECT * FROM market_prices WHERE planet_id=? AND commodity_id=?", (planet["id"], commodity["id"]))
        if mp:
            # Pull extremes mildly back toward center so players do not hit hard walls forever.
            supply_delta = 1 if mp["supply"] < 35 else -1 if mp["supply"] > 95 else 0
            demand_delta = -1 if mp["demand"] > 100 else 1 if mp["demand"] < 25 else 0
            mutate_market(conn, planet["id"], commodity["id"], supply_delta, demand_delta, "npc_diplomatic_stabilizer")
        condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_diplomatic_stabilizer", stability_delta=1, market_delta=1)
        msg = f"{npc['name']} negotiated local contracts that stabilized {commodity['name']} markets."
        atype = "npc_diplomat"
    elif action in {"discover_route", "scan_anomaly"}:
        commodity = choose_market_commodity(conn, legal=True, categories=["energy", "electronics", "industrial"])
        if not commodity: return None
        mutate_market(conn, planet["id"], commodity["id"], max(1, base_qty // 2), -1, "npc_exploration_discovery")
        condition_impact = mutate_planet_conditions(conn, planet["id"], rng, "npc_exploration_discovery", stability_delta=1, market_delta=1)
        msg = f"{npc['name']} charted a route that opened minor {commodity['name']} supply."
        atype = "npc_explorer"
    else:
        commodity = choose_market_commodity(conn)
        if not commodity: return None
        mutate_market(conn, planet["id"], commodity["id"], 1, 0, "npc_misc")
        msg = f"{npc['name']} completed local work near {planet['name']}."

    xp_gain = rng.randint(80, 420) + max(0, npc_roll * 4)
    credits_gain = rng.randint(250, 2500) + max(0, npc_roll * 30)
    progression = grant_npc_progression(conn, npc, atype, xp_gain, rng)
    conn.execute("UPDATE npc_agents SET credits=credits+?, last_action_at=? WHERE id=?", (credits_gain, iso(), npc["id"]))
    conn.execute("INSERT INTO npc_action_log (planet_id, action_type, actor_name, message, impact_json, created_at) VALUES (?,?,?,?,?,?)", (planet["id"], atype, npc["name"], msg, encode_json({"simulated": True, "career": career, "npc_roll": npc_roll, "creditsGain": credits_gain, "level": progression.get("level"), "job_rank": progression.get("jobRank"), "skills": progression.get("skills"), "conditions": condition_impact}), iso()))
    return msg


def simulate_npc_activity(conn: sqlite3.Connection, force: bool = False) -> int:
    ensure_persistent_npc_content(conn)
    tick = row(conn, "SELECT * FROM simulation_ticks WHERE id=1")
    now = utcnow()
    if tick and not force:
        last = parse_dt(tick["last_tick_at"]) or now
        if (now - last).total_seconds() < SIMULATION_BALANCE["tick_minutes"] * 60:
            return 0
    conn.execute("INSERT OR REPLACE INTO simulation_ticks (id,last_tick_at,last_action_count) VALUES (1,?,0)", (iso(now),))
    planets = rows(conn, "SELECT * FROM planets")
    if not planets:
        return 0
    rng = random.Random(int(now.timestamp() // max(1, SIMULATION_BALANCE["tick_minutes"] * 60)))
    action_count = 0
    for p in planets:
        target = target_npc_count_for_planet(p)
        # Planets with high density/activity simulate more visible actions. Hostility increases combat/crime turbulence.
        visible_actions = clamp_int(
            int((target * (int(p.get("npc_activity") or 50) / 100.0)) / SIMULATION_BALANCE["visible_action_divisor"]),
            SIMULATION_BALANCE["min_visible_actions_per_planet"],
            SIMULATION_BALANCE["max_visible_actions_per_planet"],
        )
        if force:
            visible_actions = min(target, max(visible_actions, SIMULATION_BALANCE["forced_min_visible_actions_per_planet"]))
        npcs = rows(conn, "SELECT * FROM npc_agents WHERE planet_id=? ORDER BY RANDOM() LIMIT ?", (p["id"], visible_actions))
        for npc in npcs:
            if simulate_single_npc_action(conn, npc, p, rng):
                action_count += 1
        # Always-on background macro drift based on planet personality.
        commodities = rows(conn, "SELECT * FROM commodities")
        if commodities:
            macro_rolls = clamp_int(int(target / SIMULATION_BALANCE["market_macro_roll_divisor"]), 1, SIMULATION_BALANCE["max_macro_rolls_per_planet"])
            for _ in range(macro_rolls):
                c = rng.choice(commodities)
                if rng.randint(1, 100) <= int(p.get("npc_economy_bias") or 50):
                    qty = max(1, int(rng.randint(1, 5) * ECONOMY_CONFIG["npc_market_force"] * max(1, int(p.get("npc_density") or 50) / 35)))
                    mutate_market(conn, p["id"], c["id"], qty if rng.random() < 0.55 else -qty, rng.randint(-1, 2), "npc_population_drift")
                    action_count += 1
                if not c["legal"] and rng.randint(1, 100) <= int(p.get("npc_criminal_bias") or 50) // 2:
                    qty = max(1, rng.randint(1, 4))
                    mutate_market(conn, p["id"], c["id"], qty, -1, "npc_black_market_drift")
                    action_count += 1
        # Anti-wall guard rails: small and visible. Enough to prevent hard stops, not enough to replace players.
        for code in ["ore", "chemicals", "meds", "microchips", "nutrient_paste", "bio_gel", "reactor"]:
            c = row(conn, "SELECT * FROM commodities WHERE code=?", (code,))
            if c:
                mp = row(conn, "SELECT * FROM market_prices WHERE planet_id=? AND commodity_id=?", (p["id"], c["id"]))
                if mp and mp["supply"] < 8:
                    qty = 6 + rng.randint(0, 7)
                    mutate_market(conn, p["id"], c["id"], qty, -1, "npc_anti_wall_restock")
                    conn.execute("INSERT INTO npc_action_log (planet_id, action_type, actor_name, message, impact_json, created_at) VALUES (?,?,?,?,?,?)", (p["id"], "npc_restock", "Automated Supply Board", f"NPC contracts restocked {qty}x {c['name']} so progression does not hit a hard wall.", encode_json({"anti_wall": True}), iso()))
                    action_count += 1
    conn.execute("UPDATE simulation_ticks SET last_action_count=? WHERE id=1", (action_count,))
    conn.execute("DELETE FROM npc_action_log WHERE id NOT IN (SELECT id FROM npc_action_log ORDER BY id DESC LIMIT ?)", (SIMULATION_BALANCE["event_log_limit"],))
    return action_count

def level_xp_required(level: int) -> int:
    # Incremental player-level curve for the 12h/day progression target.
    # 1-25 moves quickly, 26-75 is the main middle, 76+ turns into the hard wall.
    level = max(1, int(level or 1))
    cfg = PROGRESSION_BALANCE.get("player_level_curve", {})
    early_cutoff = int(cfg.get("early_cutoff", 25) or 25)
    mid_cutoff = int(cfg.get("mid_cutoff", 75) or 75)
    if level <= early_cutoff:
        return int(float(cfg.get("early_base", 350)) + float(cfg.get("early_level_mult", 105)) * (level ** float(cfg.get("early_power", 1.12))))
    if level <= mid_cutoff:
        return int(float(cfg.get("mid_base", 3100)) + float(cfg.get("mid_level_mult", 62)) * ((level - early_cutoff) ** float(cfg.get("mid_power", 1.62))))
    return int(float(cfg.get("late_base", 20000)) + float(cfg.get("late_level_mult", 1150)) * ((level - mid_cutoff) ** float(cfg.get("late_power", 1.72))))



def ship_part_specs(ship: Dict[str, Any]) -> List[Tuple[str, str, int, int]]:
    max_hull = int(ship.get("max_hull") or ship.get("hull") or 1000)
    max_shield = int(ship.get("max_shield") or ship.get("shield") or 500)
    return [
        ("hull", "Hull Plating", max_hull, 3),
        ("shield", "Shield Emitters", max_shield, 2),
        ("engine", "Drive Core", max(250, int(max_hull * 0.28)), 6),
        ("weapons", "Weapon Mounts", max(200, int(max_hull * 0.22)), 5),
        ("cargo", "Cargo Systems", max(180, int(max_hull * 0.18)), 4),
        ("life_support", "Life Support", max(150, int(max_hull * 0.14)), 8),
    ]


_SHIP_PARTS_LAST_RUN: float = 0.0
_SHIP_PARTS_INTERVAL_SECONDS: float = 600.0  # 10 min


def ensure_ship_parts(conn: sqlite3.Connection, force: bool = False) -> None:
    global _SHIP_PARTS_LAST_RUN
    now_mono = time.monotonic()
    if not force and (now_mono - _SHIP_PARTS_LAST_RUN) < _SHIP_PARTS_INTERVAL_SECONDS:
        return
    _SHIP_PARTS_LAST_RUN = now_mono
    for ship in rows(conn, "SELECT * FROM ships"):
        for part_key, name, max_hp, rate in ship_part_specs(ship):
            conn.execute(
                "INSERT OR IGNORE INTO ship_parts (ship_id,part_key,name,hp,max_hp,repair_rate) VALUES (?,?,?,?,?,?)",
                (ship["id"], part_key, name, max_hp, max_hp, rate),
            )


_RADAR_CONTENT_LAST_RUN: float = 0.0
_RADAR_CONTENT_INTERVAL_SECONDS: float = 600.0  # 10 min


def ensure_radar_content(conn: sqlite3.Connection, force: bool = False) -> None:
    global _RADAR_CONTENT_LAST_RUN
    now_mono = time.monotonic()
    if not force and (now_mono - _RADAR_CONTENT_LAST_RUN) < _RADAR_CONTENT_INTERVAL_SECONDS:
        return
    _RADAR_CONTENT_LAST_RUN = now_mono
    radar_modules = [
        ("basic_radar_array", "Basic Radar Array", "scanner", "common", 9000, 1, 4, 0, 4, {"radar_strength": 16, "radar_range": 10, "scanning": 3, "scan_success": 8, "scan_ping_radius": 5, "scan_cooldown_reduction": 18, "scan_blip_duration": 3}),
        ("civilian_radar_array", "Civilian Radar Array", "scanner", "uncommon", 28000, 2, 5, 1, 6, {"radar_strength": 28, "radar_range": 16, "scanning": 6, "scan_success": 14, "scan_ping_radius": 9, "scan_cooldown_reduction": 35, "scan_blip_duration": 6}),
        ("military_radar_array", "Military Radar Array", "scanner", "rare", 85000, 3, 6, 2, 10, {"radar_strength": 44, "radar_range": 24, "scanning": 10, "scan_success": 24, "evasion": 3, "counter_scan": 4, "scan_ping_radius": 14, "scan_cooldown_reduction": 55, "scan_blip_duration": 10}),
        ("deep_space_radar", "Deep-Space Radar Suite", "scanner", "epic", 190000, 4, 7, 3, 14, {"radar_strength": 62, "radar_range": 34, "scanning": 16, "scan_success": 34, "salvage": 4, "counter_scan": 6, "scan_ping_radius": 21, "scan_cooldown_reduction": 75, "scan_blip_duration": 15}),
    ]
    for code, name, slot, rarity, price, tier, max_tier, min_ship_tier, power_usage, stats in radar_modules:
        conn.execute(
            """INSERT OR IGNORE INTO module_templates
               (code,name,slot_type,rarity,price,craftable,stats_json,tier,max_tier,min_ship_tier,power_usage)
               VALUES (?,?,?,?,?,?,?,?,?,?,?)""",
            (code, name, slot, rarity, price, 1, encode_json(stats), tier, max_tier, min_ship_tier, power_usage),
        )
        existing = row(conn, "SELECT * FROM module_templates WHERE code=?", (code,))
        if existing:
            merged = decode_json(existing.get("stats_json"), {}) or {}
            changed = False
            for stat_key, stat_value in stats.items():
                if merged.get(stat_key) != stat_value:
                    merged[stat_key] = stat_value
                    changed = True
            if changed:
                conn.execute("UPDATE module_templates SET stats_json=?, max_tier=max(COALESCE(max_tier,?), ?), power_usage=? WHERE code=?", (encode_json(merged), max_tier, max_tier, power_usage, code))
    # Existing DeepScan modules now help radar detection without replacing dedicated radar.
    existing = row(conn, "SELECT * FROM module_templates WHERE code='scanner_array'")
    if existing:
        stats = decode_json(existing.get("stats_json"), {}) or {}
        changed = False
        for stat_key, stat_value in {"radar_strength": 20, "radar_range": 10, "scan_success": 18, "scan_ping_radius": 4, "scan_cooldown_reduction": 12, "scan_blip_duration": 2}.items():
            if not stats.get(stat_key):
                stats[stat_key] = stat_value
                changed = True
        if changed:
            conn.execute("UPDATE module_templates SET stats_json=? WHERE code='scanner_array'", (encode_json(stats),))
    module_scan_updates = {
        "ore_probe_array": {"scan_success": 8},
        "wreck_locator": {"scan_success": 10},
        "anomaly_lens": {"scan_success": 22},
        "relic_decoder": {"scan_success": 28},
        "targeting_matrix": {"scan_success": 12},
        "warrant_scanner": {"scan_success": 24},
        "precision_calibrator": {"scan_success": 14},
        "customs_transponder": {"scan_success": 8},
        "silent_running_mesh": {"counter_scan": 18},
        "false_manifest_ai": {"counter_scan": 14},
        "signature_scrubber": {"counter_scan": 32},
        "smuggle_compartment": {"counter_scan": 10},
    }
    for code, additions in module_scan_updates.items():
        existing = row(conn, "SELECT * FROM module_templates WHERE code=?", (code,))
        if not existing:
            continue
        stats = decode_json(existing.get("stats_json"), {}) or {}
        changed = False
        for stat_key, stat_value in additions.items():
            if not stats.get(stat_key):
                stats[stat_key] = stat_value
                changed = True
        if changed:
            conn.execute("UPDATE module_templates SET stats_json=? WHERE code=?", (encode_json(stats), code))


