ATTACK_SHIP_ROLES = {"combat", "gunship", "siege", "fleet", "carrier", "interceptor", "mercenary", "bounty", "security", "patrol", "raider", "pirate"}


def normalized_ship_weapon_slots(slots_json: str, role: str = "", size_class: str = "M", tier: int = 1) -> Dict[str, Any]:
    counts = decode_json(slots_json, {}) or {}
    if not isinstance(counts, dict):
        counts = {}
    role_key = str(role or "").lower()
    size_key = str(size_class or "M").upper()
    tier = max(1, int(tier or 1))
    is_attack = role_key in ATTACK_SHIP_ROLES or any(x in role_key for x in ("combat", "gun", "siege", "fleet", "carrier", "interceptor", "pirate", "raider"))
    if is_attack:
        size_cap = {"XS": 2, "S": 3, "M": 4, "L": 6, "XL": 6, "C": 6}.get(size_key, 4)
        tier_cap = 2 + min(4, max(0, tier - 1))
        target = max(2, min(6, size_cap, tier_cap, int(counts.get("weapon", 0) or 2)))
    else:
        target = 1
    counts["weapon"] = max(1, target)
    counts.setdefault("defense", 1)
    counts.setdefault("utility", 1)
    counts.setdefault("core", 1)
    return counts


def ensure_ship_weapon_slot_content(conn: sqlite3.Connection) -> None:
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='ship_templates'"):
        return
    for st in rows(conn, "SELECT id, role, size_class, ship_tier, slots_json FROM ship_templates"):
        normalized = normalized_ship_weapon_slots(st.get("slots_json") or "{}", st.get("role") or "", st.get("size_class") or "M", int(st.get("ship_tier") or 1))
        conn.execute("UPDATE ship_templates SET slots_json=? WHERE id=?", (encode_json(normalized), st["id"]))


def ensure_ship_size_content(conn: sqlite3.Connection) -> None:
    for code, (size_class, mass) in SHIP_SIZE_OVERRIDES.items():
        conn.execute("UPDATE ship_templates SET size_class=?, mass=? WHERE code=?", (size_class, float(mass), code))
    for s in rows(conn, "SELECT s.id, t.size_class, t.mass FROM ships s JOIN ship_templates t ON t.id=s.template_id"):
        conn.execute("UPDATE ships SET size_class=?, mass=? WHERE id=? AND (size_class IS NULL OR size_class='' OR mass IS NULL OR mass=340)", (s.get("size_class") or "M", float(s.get("mass") or 340), s["id"]))


