def normalize_username(value: str) -> str:
    username = (value or "").strip().lower()
    safe = "".join(ch for ch in username if ch.isalnum() or ch in {"_", "-"})
    if len(safe) < PROFILE_LIMITS["username_min"] or len(safe) > PROFILE_LIMITS["username_max"]:
        raise HTTPException(400, f"Username must be {PROFILE_LIMITS['username_min']}-{PROFILE_LIMITS['username_max']} characters and use letters, numbers, underscore, or dash")
    return safe


def normalize_display_name(value: str) -> str:
    display = " ".join((value or "").strip().split())
    if len(display) < PROFILE_LIMITS["display_min"] or len(display) > PROFILE_LIMITS["display_max"]:
        raise HTTPException(400, f"Display name must be {PROFILE_LIMITS['display_min']}-{PROFILE_LIMITS['display_max']} characters")
    return display


def normalize_bio(value: str) -> str:
    bio = (value or "").strip()
    return bio[:PROFILE_LIMITS["bio_max"]]


def clean_avatar_id(value: Optional[str], faction_code: Optional[str] = None, seed: str = "") -> str:
    avatar_id = (value or DEFAULT_AVATAR_ID).strip()
    avatar_id = PROFILE_LEGACY_AVATAR_ID_MAP.get(avatar_id, avatar_id)
    avatar = PROFILE_AVATAR_BY_ID.get(avatar_id)
    if avatar and (not faction_code or avatar.get("faction_code") == faction_code):
        return avatar_id
    return default_avatar_id_for_faction_code(faction_code, seed)


def avatar_payload(avatar_id: Optional[str], faction_code: Optional[str] = None, seed: str = "") -> Dict[str, str]:
    return PROFILE_AVATAR_BY_ID.get(clean_avatar_id(avatar_id, faction_code, seed), PROFILE_AVATAR_BY_ID[DEFAULT_AVATAR_ID])


def achievement_tier_for_progress(progress: int) -> int:
    progress = int(progress or 0)
    tier = 0
    for i, target in enumerate(ACHIEVEMENT_TIER_THRESHOLDS, start=1):
        if progress >= int(target):
            tier = i
    return tier


_ENSURED_ACHIEVEMENT_PLAYERS: set = set()


def ensure_achievement_rows(conn: sqlite3.Connection, player_id: int) -> None:
    pid = int(player_id)
    if pid in _ENSURED_ACHIEVEMENT_PLAYERS:
        return
    now = iso()
    for loop_key in ACHIEVEMENT_LOOPS.keys():
        conn.execute(
            "INSERT OR IGNORE INTO player_achievement_progress (player_id,loop_key,progress,tier_unlocked,updated_at) VALUES (?,?,?,?,?)",
            (player_id, loop_key, 0, 0, now),
        )
    _ENSURED_ACHIEVEMENT_PLAYERS.add(pid)


def grant_achievement_progress(conn: sqlite3.Connection, player_id: int, loop_key: str, amount: float = 1.0) -> Dict[str, Any]:
    if loop_key not in ACHIEVEMENT_LOOPS:
        return {}
    ensure_achievement_rows(conn, player_id)
    inc = max(1, int(round(float(amount or 1.0))))
    current = row(conn, "SELECT * FROM player_achievement_progress WHERE player_id=? AND loop_key=?", (player_id, loop_key)) or {"progress": 0, "tier_unlocked": 0}
    progress = int(current.get("progress") or 0) + inc
    tier = achievement_tier_for_progress(progress)
    old_tier = int(current.get("tier_unlocked") or 0)
    conn.execute(
        "UPDATE player_achievement_progress SET progress=?, tier_unlocked=?, updated_at=? WHERE player_id=? AND loop_key=?",
        (progress, tier, iso(), player_id, loop_key),
    )
    if tier > old_tier:
        meta = ACHIEVEMENT_LOOPS[loop_key]
        add_event(conn, player_id, "achievement", f"Achievement unlocked: {meta['name']} Tier {tier}.", {"loop": loop_key, "tier": tier, "badge": achievement_badge_code(loop_key, tier)})
    return {"loop": loop_key, "progress": progress, "tier": tier, "tierUp": tier > old_tier}


def selected_badge_is_unlocked(conn: sqlite3.Connection, player_id: int, badge_code: str) -> bool:
    badge_code = str(badge_code or "").strip()
    m = re.match(r"^([a-z0-9_]+)_t([1-8])$", badge_code)
    if not m:
        return False
    loop_key, tier_s = m.group(1), m.group(2)
    row_data = row(conn, "SELECT tier_unlocked FROM player_achievement_progress WHERE player_id=? AND loop_key=?", (player_id, loop_key))
    return bool(row_data and int(row_data.get("tier_unlocked") or 0) >= int(tier_s))


def achievement_passive_buffs(conn: sqlite3.Connection, player_id: int) -> Dict[str, float]:
    buffs: Dict[str, float] = {}
    for r in rows(conn, "SELECT loop_key,tier_unlocked FROM player_achievement_progress WHERE player_id=?", (player_id,)):
        if int(r.get("tier_unlocked") or 0) >= 8:
            for k, v in (ACHIEVEMENT_LOOPS.get(r["loop_key"], {}).get("buff") or {}).items():
                buffs[k] = buffs.get(k, 0.0) + float(v or 0)
    return buffs


def build_achievements_state(conn: sqlite3.Connection, player_id: int) -> Dict[str, Any]:
    ensure_achievement_rows(conn, player_id)
    progress_rows = {r["loop_key"]: r for r in rows(conn, "SELECT * FROM player_achievement_progress WHERE player_id=?", (player_id,))}
    loops = []
    unlocked_badges = []
    for loop_key, meta in ACHIEVEMENT_LOOPS.items():
        r = progress_rows.get(loop_key) or {}
        progress = int(r.get("progress") or 0)
        tier = achievement_tier_for_progress(progress)
        next_target = ACHIEVEMENT_TIER_THRESHOLDS[tier] if tier < 8 else ACHIEVEMENT_TIER_THRESHOLDS[-1]
        badges = []
        for t in range(1, 9):
            unlocked = tier >= t
            badge = {"code": achievement_badge_code(loop_key, t), "url": achievement_badge_url(loop_key, t), "tier": t, "unlocked": unlocked}
            badges.append(badge)
            if unlocked:
                unlocked_badges.append({**badge, "loopKey": loop_key, "name": meta["name"], "theme": ACHIEVEMENT_BADGE_THEME.get(loop_key)})
        loops.append({
            "loopKey": loop_key,
            "name": meta["name"],
            "summary": meta["summary"],
            "progress": progress,
            "tierUnlocked": tier,
            "nextTarget": next_target,
            "currentTarget": ACHIEVEMENT_TIER_THRESHOLDS[tier-1] if tier > 0 else 0,
            "percentToNext": 100 if tier >= 8 else int((progress / max(1, next_target)) * 100),
            "badges": badges,
            "tier8PassiveBuff": meta.get("buff") or {},
            "badgeUrl": achievement_badge_url(loop_key, max(1, tier or 1)),
            "theme": ACHIEVEMENT_BADGE_THEME.get(loop_key),
        })
    return {"loops": loops, "unlockedBadges": unlocked_badges, "passiveBuffs": achievement_passive_buffs(conn, player_id)}


def build_player_profile_stats(conn: sqlite3.Connection, player: Dict[str, Any], public: bool = False) -> Dict[str, Any]:
    pid = int(player["id"])
    events = rows(conn, "SELECT category, COUNT(*) as count FROM events WHERE player_id=? GROUP BY category", (pid,))
    by_cat = {e["category"]: int(e["count"] or 0) for e in events}
    jobs = rows(conn, "SELECT job_code, rank, xp FROM player_jobs WHERE player_id=? ORDER BY rank DESC, xp DESC LIMIT 8", (pid,))
    skills = rows(conn, "SELECT skill_key, level, xp FROM player_skills WHERE player_id=? ORDER BY level DESC, xp DESC LIMIT 8", (pid,))
    planet_count = int(scalar(conn, "SELECT COUNT(*) FROM planets WHERE controller_type='guild' AND controller_id=?", (player.get("guild_id"),)) or 0) if player.get("guild_id") else 0
    public_stats = {
        "level": int(player.get("level") or 1),
        "xp": int(player.get("xp") or 0),
        "careerHighlights": jobs,
        "skillHighlights": skills,
        "eventCounts": by_cat,
        "planetsGuildControls": planet_count,
        "joinedAt": player.get("created_at") or None,
        "travelEvents": by_cat.get("travel", 0),
        "combatEvents": by_cat.get("combat", 0) + by_cat.get("bounty", 0),
        "craftingEvents": by_cat.get("crafting", 0),
        "miningEvents": by_cat.get("mining", 0),
        "salvageEvents": by_cat.get("salvage", 0),
        "explorationEvents": by_cat.get("exploration", 0),
    }
    if public:
        return public_stats
    public_stats.update({
        "credits": int(player.get("credits") or 0),
        "fuel": int(player.get("fuel") or 0),
        "energy": int(player.get("energy") or 0),
        "health": int(player.get("health") or 0),
        "shipPower": int(get_ship_power(conn, int(player.get("active_ship_id") or 0))) if player.get("active_ship_id") else 0,
        "cargo": int(player.get("cargo") or 0),
    })
    return public_stats


_PUBLIC_PROFILE_CACHE: Dict[int, Tuple[float, Dict[str, Any]]] = {}
_PUBLIC_PROFILE_TTL: float = 30.0


def _invalidate_public_profile_cache(target_user_id: Optional[int] = None) -> None:
    if target_user_id is None:
        _PUBLIC_PROFILE_CACHE.clear()
    else:
        _PUBLIC_PROFILE_CACHE.pop(int(target_user_id), None)
    try:
        invalidate_public_profiles_state_cache()
    except NameError:
        pass


def public_profile_payload(conn: sqlite3.Connection, target_user_id: int, viewer_player_id: Optional[int] = None) -> Dict[str, Any]:
    # Cache only when there's no viewer (used by build_state to populate the
    # community profiles list — that path runs ~80 times per /api/state which
    # was previously ~700 SQL queries). When a viewer is present we still log
    # the view, so we bypass the cache for that case.
    cache_eligible = viewer_player_id is None
    now_mono = time.monotonic()
    if cache_eligible:
        cached = _PUBLIC_PROFILE_CACHE.get(int(target_user_id))
        if cached and (now_mono - cached[0]) < _PUBLIC_PROFILE_TTL:
            return cached[1]
    target = row(conn, "SELECT u.*, p.id as player_id, p.callsign, p.level, p.xp, p.guild_id, p.location_planet_id, p.active_ship_id FROM users u JOIN players p ON p.user_id=u.id WHERE u.id=?", (target_user_id,))
    if not target:
        return {}
    player = row(conn, "SELECT * FROM players WHERE id=?", (target["player_id"],))
    profile = ensure_user_profile(conn, target, player)
    faction_code = player_faction_code(conn, player)
    avatar = avatar_payload(profile.get("avatar_id"), faction_code, target.get("username") or target.get("callsign") or "")
    selected_badge = profile.get("selected_badge_code") or ""
    ach = build_achievements_state(conn, int(player["id"]))
    top_achievements = sorted(ach["loops"], key=lambda x: (x["tierUnlocked"], x["progress"]), reverse=True)[:6]
    loc = row(conn, "SELECT p.name as location_name, g.name as galaxy_name FROM planets p JOIN galaxies g ON g.id=p.galaxy_id WHERE p.id=?", (player.get("location_planet_id"),))
    current_ship = row(conn, "SELECT s.name, t.name as template_name, t.class_name, t.role FROM ships s JOIN ship_templates t ON t.id=s.template_id WHERE s.id=?", (player.get("active_ship_id"),)) if player.get("active_ship_id") else None
    payload = {
        "userId": target_user_id,
        "playerId": player["id"],
        "username": target.get("username"),
        "displayName": profile.get("display_name") or player.get("callsign") or target.get("username"),
        "avatarId": clean_avatar_id(profile.get("avatar_id"), faction_code, target.get("username") or target.get("callsign") or ""),
        "avatarUrl": avatar["url"],
        "bio": profile.get("bio") or "",
        "selectedBadgeCode": selected_badge,
        "selectedBadgeUrl": selected_badge,
        "selectedBadge": next((b for b in ach["unlockedBadges"] if b["code"] == selected_badge), None),
        "homeGalaxy": loc.get("galaxy_name") if loc else None,
        "currentLocation": loc.get("location_name") if loc else None,
        "currentShip": current_ship,
        "stats": build_player_profile_stats(conn, player, public=True),
        "topAchievements": top_achievements,
        "passiveBuffsPublic": ach["passiveBuffs"],
    }
    if viewer_player_id:
        conn.execute("INSERT INTO player_profile_views (viewer_player_id,target_player_id,viewed_at) VALUES (?,?,?)", (viewer_player_id, player["id"], iso()))
    if cache_eligible:
        _PUBLIC_PROFILE_CACHE[int(target_user_id)] = (now_mono, payload)
    return payload


def ensure_user_profile(conn: sqlite3.Connection, user: Dict[str, Any], player: Dict[str, Any]) -> Dict[str, Any]:
    existing = row(conn, "SELECT * FROM user_profiles WHERE user_id=?", (user["id"],))
    faction_code = player_faction_code(conn, player)
    seed = str(player.get("callsign") or user.get("username") or "")
    if existing:
        avatar_id = clean_avatar_id(existing.get("avatar_id"), faction_code, seed)
        if avatar_id != existing.get("avatar_id"):
            conn.execute("UPDATE user_profiles SET avatar_id=?, updated_at=? WHERE user_id=?", (avatar_id, iso(), user["id"]))
            existing["avatar_id"] = avatar_id
        return existing
    raw_display = str(player.get("callsign") or user.get("username") or "Pilot")
    try:
        display = normalize_display_name(raw_display)
    except HTTPException:
        display = "Nova Pilot"
    seed_avatar = default_avatar_id_for_faction_code(faction_code, seed)
    conn.execute(
        "INSERT INTO user_profiles (user_id,display_name,avatar_id,bio,updated_at) VALUES (?,?,?,?,?)",
        (user["id"], display, clean_avatar_id(seed_avatar, faction_code, seed), "", iso()),
    )
    return row(conn, "SELECT * FROM user_profiles WHERE user_id=?", (user["id"],)) or {}


def profile_payload(conn: sqlite3.Connection, user: Dict[str, Any], player: Dict[str, Any]) -> Dict[str, Any]:
    profile = ensure_user_profile(conn, user, player)
    faction_code = player_faction_code(conn, player)
    seed = str(player.get("callsign") or user.get("username") or "")
    avatar = avatar_payload(profile.get("avatar_id"), faction_code, seed)
    current_job = row(conn, "SELECT j.name, j.code, pj.rank, pj.xp FROM player_jobs pj JOIN jobs j ON j.code=pj.job_code WHERE pj.player_id=? AND pj.active=1 LIMIT 1", (player["id"],))
    current_ship = row(conn, "SELECT s.name, t.name as template_name, t.class_name, t.role FROM ships s JOIN ship_templates t ON t.id=s.template_id WHERE s.id=?", (player.get("active_ship_id"),)) if player.get("active_ship_id") else None
    loc = row(conn, "SELECT p.name as location_name, g.name as galaxy_name FROM planets p JOIN galaxies g ON g.id=p.galaxy_id WHERE p.id=?", (player.get("location_planet_id"),))
    achievements = build_achievements_state(conn, int(player["id"]))
    selected_badge = profile.get("selected_badge_code") or ""
    return {
        "username": user.get("username"),
        "displayName": profile.get("display_name") or player.get("callsign") or user.get("username"),
        "avatarId": clean_avatar_id(profile.get("avatar_id"), faction_code, seed),
        "avatarUrl": avatar["url"],
        "avatarLabel": avatar["label"],
        "bio": profile.get("bio") or "",
        "selectedBadgeCode": selected_badge,
        "selectedBadgeUrl": selected_badge,
        "selectedBadge": next((b for b in achievements["unlockedBadges"] if b["code"] == selected_badge), None),
        "homeGalaxy": loc.get("galaxy_name") if loc else None,
        "currentLocation": loc.get("location_name") if loc else None,
        "currentJob": current_job,
        "currentShip": current_ship,
        "stats": build_player_profile_stats(conn, player, public=False),
        "achievements": achievements,
    }


def profile_summary_payload(conn: sqlite3.Connection, user: Dict[str, Any], player: Dict[str, Any]) -> Dict[str, Any]:
    profile = ensure_user_profile(conn, user, player)
