def build_profile_state_slice(conn: sqlite3.Connection, user: Dict[str, Any], player: Dict[str, Any]) -> Dict[str, Any]:
    achievements = build_achievements_state(conn, int(player["id"]))
    profile = profile_payload(conn, user, player)
    profile["deferred"] = False
    return {
        "profile": profile,
        "achievements": achievements,
        "avatar_options": avatar_options_for_faction_code(player_faction_code(conn, player)),
        "server_time": iso(),
    }


SOCIAL_PROFILE_DEFERRED_ENDPOINTS = {
    "profile": "/api/state/profile",
    "achievements": "/api/achievements",
    "avatar_options": "/api/state/profile",
    "public_profiles": "/api/profile/public-profiles",
    "chat_messages": "/api/state/chat",
    "party": "/api/state/party",
    "social": "/api/state/social",
}


def attach_deferred_social_profile_sections(state: Dict[str, Any], conn: sqlite3.Connection, player: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(state, dict):
        return state
    try:
        versions_fn = globals().get("nova_leaderboard_state_versions")
        flags_fn = globals().get("nova_leaderboard_state_flags")
        if callable(versions_fn):
            state.setdefault("state_versions", versions_fn(conn, player))
        if callable(flags_fn):
            state.setdefault("state_flags", flags_fn(conn, player))
    except Exception:
        pass
    deferred = state.setdefault("deferred_sections", {})
    for key, endpoint in SOCIAL_PROFILE_DEFERRED_ENDPOINTS.items():
        deferred.setdefault(key, {"endpoint": endpoint, "reason": "not_hot_path"})
    return state


def ensure_profile_content(conn: sqlite3.Connection) -> None:
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='user_profiles'"):
        return
    for u in rows(conn, "SELECT u.*, p.id as player_id, p.callsign FROM users u JOIN players p ON p.user_id=u.id"):
        player_stub = {"id": u["player_id"], "callsign": u.get("callsign") or u.get("username"), "active_ship_id": None, "location_planet_id": None}
        ensure_user_profile(conn, u, player_stub)
        ensure_achievement_rows(conn, int(u["player_id"]))
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='chat_messages'"):
        return
    if scalar(conn, "SELECT COUNT(*) FROM chat_messages") == 0:
        seeds = [
            ("system", "System Beacon", "default", "Sector relay online. Pilot identity, avatar sync, and local channel are active."),
            ("npc", "Station Control", "female_07", "Docking lanes are nominal. Keep your manifest current before trade runs."),
            ("npc", "Market Broker", "male_09", "Legal goods are moving clean. Illicit cargo is profitable, but security scans are tightening."),
            ("npc", "Security Net", "male_04", "Pirate chatter detected near low-stability routes. Escorts and patrols are paying better."),
        ]
        for idx, (kind, name, avatar_id, msg) in enumerate(seeds):
            conn.execute(
                "INSERT INTO chat_messages (user_id,player_id,sender_type,sender_name,avatar_id,message,created_at) VALUES (NULL,NULL,?,?,?,?,?)",
                (kind, name, clean_avatar_id(avatar_id), msg, iso(utcnow() - timedelta(minutes=(len(seeds)-idx)*6))),
            )



def skill_point_cost_for_next_level(current_level: int) -> int:
    # Level 1 costs 1 point, level 2 costs 2, level 3 costs 4, level 4 costs 8, etc.
    current_level = max(0, int(current_level or 0))
    return 2 ** current_level


def skill_point_total_spent_for_level(level: int) -> int:
    level = max(0, int(level or 0))
    return (2 ** level) - 1 if level > 0 else 0


def skill_xp_required(level: int) -> int:
    # Cumulative skill XP threshold. Piecewise on purpose: starter quarter is reachable,
    # the middle takes real rotation, and 75-100 is the long completion wall.
    level = max(1, int(level or 1))
    max_level = max(1, int(SKILL_XP_BALANCE.get("max_level", 100) or 100))
    early_cutoff = clamp_int(int(SKILL_XP_BALANCE.get("early_level_cutoff", 25) or 25), 1, max_level)
    mid_cutoff = clamp_int(int(SKILL_XP_BALANCE.get("mid_level_cutoff", 75) or 75), early_cutoff, max_level)
    early_xp = max(1, int(SKILL_XP_BALANCE.get("early_xp_at_cutoff", 11000) or 11000))
    mid_xp = max(early_xp + 1, int(SKILL_XP_BALANCE.get("mid_xp_at_cutoff", 23000) or 23000))
    cap_xp = max(mid_xp + 1, int(SKILL_XP_BALANCE.get("max_xp_at_cap", 35000) or 35000))
    if level <= early_cutoff:
        t = level / float(max(1, early_cutoff))
        return int(max(1, early_xp * (t ** float(SKILL_XP_BALANCE.get("early_curve_power", 1.55) or 1.55))))
    if level <= mid_cutoff:
        t = (level - early_cutoff) / float(max(1, mid_cutoff - early_cutoff))
        return int(early_xp + (mid_xp - early_xp) * (t ** float(SKILL_XP_BALANCE.get("mid_curve_power", 1.45) or 1.45)))
    t = (level - mid_cutoff) / float(max(1, max_level - mid_cutoff))
    return int(mid_xp + (cap_xp - mid_xp) * (t ** float(SKILL_XP_BALANCE.get("late_curve_power", 2.20) or 2.20)))


def skill_level_from_xp(xp: int, max_level: int = None) -> int:
    xp = max(0, int(xp or 0))
    max_level = int(max_level or SKILL_XP_BALANCE["max_level"])
    level = 0
    while level < max_level and xp >= skill_xp_required(level + 1):
        level += 1
    return level


def skill_progress_payload(xp: int, max_level: int = None) -> Dict[str, Any]:
    max_level = int(max_level or SKILL_XP_BALANCE["max_level"])
    level = skill_level_from_xp(xp, max_level)
    if level >= max_level:
        return {"level": level, "xp": int(xp or 0), "next_xp": None, "xp_into_level": 0, "xp_needed": 0, "progress_pct": 100}
    prev_req = skill_xp_required(level)
    next_req = skill_xp_required(level + 1)
    into = max(0, int(xp or 0) - prev_req)
    need = max(1, next_req - prev_req)
    return {"level": level, "xp": int(xp or 0), "next_xp": next_req, "xp_into_level": into, "xp_needed": max(0, next_req - int(xp or 0)), "progress_pct": round(min(100, into / need * 100), 1)}


def ensure_progression_content(conn: sqlite3.Connection) -> None:
    if not scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='skill_nodes'"):
        return
    for key, d in PHASE16_SKILL_CATALOG.items():
        conn.execute(
            """
            INSERT INTO skill_nodes
              (key,tree,name,max_level,cost_base,req_json,buff_json,description,summary,category,icon,trained_by_json,affects_json,passive_bonuses_json,unlock_json,xp_curve_base)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            ON CONFLICT(key) DO UPDATE SET
              tree=excluded.tree,
              name=excluded.name,
              max_level=max(skill_nodes.max_level, excluded.max_level),
              description=excluded.description,
              summary=excluded.summary,
              category=excluded.category,
              icon=excluded.icon,
              trained_by_json=excluded.trained_by_json,
              affects_json=excluded.affects_json,
              passive_bonuses_json=excluded.passive_bonuses_json,
              unlock_json=excluded.unlock_json,
              xp_curve_base=excluded.xp_curve_base
            """,
            (
                key, key, d["name"], SKILL_XP_BALANCE["max_level"], 0, "{}", encode_json({key: 1}),
                d["description"], d["summary"], d["category"], d["icon"],
                encode_json(d.get("trained_by", [])), encode_json(d.get("affects", [])), encode_json(d.get("bonuses", [])),
                encode_json(d.get("unlocks", [])), SKILL_XP_BALANCE["base_curve"],
            ),
        )
    if scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='jobs'"):
        for code, d in PHASE16_CAREER_DETAILS.items():
            j = row(conn, "SELECT * FROM jobs WHERE code=?", (code,))
            if j:
                perks = list(dict.fromkeys((decode_json(j.get("perks_json"), []) or []) + d.get("bonuses", [])))
                req = decode_json(j.get("req_json"), {}) or {}
                req["preferred_skills"] = d.get("preferred_skills", [])
                req["preferred_ships"] = d.get("preferred_ships", [])
                conn.execute(
                    "UPDATE jobs SET req_json=?, perks_json=? WHERE code=?",
                    (encode_json(req), encode_json(perks), code),
                )
    # Convert legacy manual-only skill levels into starter XP once so old saves do not show impossible zero progress.
    for ps in rows(conn, "SELECT ps.*, sn.max_level FROM player_skills ps JOIN skill_nodes sn ON sn.key=ps.skill_key WHERE COALESCE(ps.xp,0)=0 AND COALESCE(ps.level,0)>0"):
        starter_xp = skill_xp_required(int(ps["level"]))
        conn.execute("UPDATE player_skills SET xp=?, updated_at=? WHERE player_id=? AND skill_key=?", (starter_xp, iso(), ps["player_id"], ps["skill_key"]))


def grant_skill_xp(conn: sqlite3.Connection, player_id: int, skill_key: str, amount: int) -> Dict[str, Any]:
    if skill_key not in PHASE16_SKILL_CATALOG:
        return {"skill": skill_key, "xp_added": 0, "level_before": 0, "level_after": 0}
    amount = max(0, int((amount or 0) * eco_mult("reward_mult.pve_xp", 0.72)))
    if amount <= 0:
        return {"skill": skill_key, "xp_added": 0, "level_before": 0, "level_after": 0}
    node = row(conn, "SELECT * FROM skill_nodes WHERE key=?", (skill_key,))
    max_level = int((node or {}).get("max_level") or SKILL_XP_BALANCE["max_level"])
    existing = row(conn, "SELECT * FROM player_skills WHERE player_id=? AND skill_key=?", (player_id, skill_key))
    old_xp = int((existing or {}).get("xp") or 0)
    old_level = int((existing or {}).get("level") or skill_level_from_xp(old_xp, max_level))
    new_xp = old_xp + amount
    new_level = skill_level_from_xp(new_xp, max_level)
    conn.execute(
        """
        INSERT INTO player_skills (player_id,skill_key,level,xp,updated_at)
        VALUES (?,?,?,?,?)
        ON CONFLICT(player_id,skill_key) DO UPDATE SET
          xp=excluded.xp,
          level=excluded.level,
          updated_at=excluded.updated_at
        """,
        (player_id, skill_key, new_level, new_xp, iso()),
    )
    return {"skill": skill_key, "xp_added": amount, "level_before": old_level, "level_after": new_level}


def active_career_code(conn: sqlite3.Connection, player_id: int) -> Optional[str]:
    active = row(conn, "SELECT job_code FROM player_jobs WHERE player_id=? AND active=1", (player_id,))
    return active["job_code"] if active else None


def grant_career_xp_if_active(conn: sqlite3.Connection, player_id: int, action_key: str, multiplier: float = 1.0) -> Dict[str, Any]:
    active = active_career_code(conn, player_id)
    cfg = ACTION_PROGRESSION.get(action_key, {})
    if not active or active not in (cfg.get("careers") or {}):
        return {}
    xp = max(1, int((cfg["careers"][active]) * multiplier * eco_mult("reward_mult.pve_xp", 0.72)))
    conn.execute(
        "INSERT INTO player_jobs (player_id,job_code,xp,rank,active,last_active_at) VALUES (?,?,?,?,1,?) "
        "ON CONFLICT(player_id,job_code) DO UPDATE SET xp=player_jobs.xp+excluded.xp, last_active_at=excluded.last_active_at",
        (player_id, active, xp, 1, iso()),
    )
    metrics = get_job_metrics(conn, player_id, active)
    row_now = row(conn, "SELECT * FROM player_jobs WHERE player_id=? AND job_code=?", (player_id, active))
    rank = job_rank_from_metrics(active, int((row_now or {}).get("xp") or 0), metrics)
    conn.execute("UPDATE player_jobs SET rank=? WHERE player_id=? AND job_code=?", (rank, player_id, active))
    return {"career": active, "xp_added": xp, "rank": rank}


def grant_action_progression(conn: sqlite3.Connection, player_id: int, action_key: str, multiplier: float = 1.0, success: bool = True) -> Dict[str, Any]:
    cfg = ACTION_PROGRESSION.get(action_key)
    if not cfg:
        return {}
    mult = max(0.05, float(multiplier or 1.0))
    if not success:
        mult *= 0.35
    skill_results = []
    training_mult = float(SKILL_XP_BALANCE.get("action_training_xp_mult", 1.0) or 1.0)
    for skill_key, xp in (cfg.get("skills") or {}).items():
        skill_results.append(grant_skill_xp(conn, player_id, skill_key, int(xp * mult * training_mult)))
    career_result = grant_career_xp_if_active(conn, player_id, action_key, mult if success else mult * 0.75)
    achievement_result = {}
    loop_key = ACHIEVEMENT_ACTION_MAP.get(action_key)
    if loop_key:
        achievement_result = grant_achievement_progress(conn, player_id, loop_key, max(1, mult if success else mult * 0.35))
    return {"action": action_key, "skills": skill_results, "career": career_result, "achievement": achievement_result}


def skill_effects_for_display(skill_key: str, level: int) -> List[str]:
    level = max(0, int(level or 0))
    if skill_key == "smuggling":
        return [f"-{min(30, level * 0.45):.1f}% caught chance pressure", f"-{min(25, level * 0.35):.1f}% heat gain", f"+{min(18, level * 0.30):.1f}% illicit profit pressure"]
    if skill_key == "jailbreaking":
        return [f"+{min(70, level * 0.70):.1f}% breakout scaling before security/heat penalties", "Breakout final chance hard-capped at 80%", f"-{min(30, level * 0.25):.1f}% breakout cooldown pressure"]
    if skill_key == "trading":
        return [f"+{min(14, level * 0.18):.1f}% legal trade edge cap pressure", "No legal risk added", "Improves market readouts"]
    if skill_key == "crafting":
        return [f"+{min(24, level * 0.22):.1f}% crafting success pressure", "Less material waste on failures", "Supports higher-tier recipe unlocks"]
    if skill_key == "engineering":
        return [f"+{min(28, level * 0.24):.1f}% upgrade/install pressure", f"-{min(22, level * 0.20):.1f}% repair cost pressure", "Improves module work"]
    if skill_key == "piloting":
        return [f"-{min(22, level * 0.18):.1f}% travel fuel pressure", "Slight route evasion bonus", "Improves hauling/exploration routes"]
    return [f"Level {level} passive scaling is active", "Related actions grant this skill XP", "Career bonuses can stack with this skill inside caps"]


def build_skills_state(conn: sqlite3.Connection, player_id: int) -> List[Dict[str, Any]]:
    cache_key = ("build_skills_state", int(player_id))
    cached = request_cache_get(cache_key)
    if cached is not None:
        return clone_cached(cached)
    player_levels = {r["skill_key"]: r for r in rows(conn, "SELECT * FROM player_skills WHERE player_id=?", (player_id,))}
    node_rows = {r["key"]: r for r in rows(conn, "SELECT * FROM skill_nodes")}
    out: List[Dict[str, Any]] = []
    for key, d in PHASE16_SKILL_CATALOG.items():
        node = node_rows.get(key) or {}
        ps = player_levels.get(key) or {}
        progress = skill_progress_payload(int(ps.get("xp") or 0), int(node.get("max_level") or SKILL_XP_BALANCE["max_level"]))
        out.append({
            "key": key,
            "tree": key,
            "name": d["name"],
            "icon": d.get("icon"),
            "category": d.get("category"),
            "summary": d.get("summary"),
            "description": d.get("description"),
            "trained_by": d.get("trained_by", []),
            "affects": d.get("affects", []),
            "passive_bonuses": d.get("bonuses", []),
            "current_effects": skill_effects_for_display(key, progress["level"]),
            "level": progress["level"],
            "xp": progress["xp"],
            "next_xp": progress["next_xp"],
            "xp_needed": progress["xp_needed"],
            "progress_pct": progress["progress_pct"],
            "max_level": int(node.get("max_level") or SKILL_XP_BALANCE["max_level"]),
        })
    request_cache_set(cache_key, clone_cached(out))
    return out


def career_rank_label(job_code: str, rank: int) -> str:
    base = {
        1:"Rookie", 2:"Licensed Operator", 3:"Specialist", 4:"Veteran", 5:"Elite",
        6:"Master", 7:"Sector Renowned", 8:"Guild Authority", 9:"Legendary", 10:"Mythic"
    }
    special = {
        "miner": {1:"Prospector", 5:"Deep-Core Veteran", 10:"Master Extractor"},
        "trader": {1:"Broker", 5:"Market Baron", 10:"Merchant Prince"},
        "smuggler": {1:"Runner", 5:"Ghost Lane Veteran", 10:"Black-Lane Legend"},
        "bounty_hunter": {1:"Tracker", 5:"Warrant Specialist", 10:"Sector Reaper"},
        "engineer": {1:"Mechanic", 5:"Systems Architect", 10:"Master Engineer"},
    }
    return (special.get(job_code, {}).get(int(rank)) or base.get(int(rank), f"Rank {rank}"))


def career_bonus_display(job_code: str, rank: int) -> List[str]:
    rank = max(1, int(rank or 1))
    details = PHASE16_CAREER_DETAILS.get(job_code, {})
    out = []
    for b in details.get("bonuses", [])[:5]:
        out.append(f"{b} • Rank {rank} scaling")
    if job_code == "smuggler":
        out.append("Illicit risk reduction stacks with Smuggling skill, but risk never reaches zero.")
    if job_code == "engineer":
        out.append("Craft/upgrade bonuses stack with Engineering and Crafting skills inside success caps.")
    if job_code == "trader":
        out.append("Legal market bonuses are capped to prevent infinite buy/sell loops.")
    return out or ["Matching career actions gain stronger rewards and career XP."]


def career_action_keys(job_code: str) -> List[str]:
    return [k for k, v in ACTION_PROGRESSION.items() if job_code in (v.get("careers") or {})]


def build_chat_messages(conn: sqlite3.Connection, current_user_id: int) -> List[Dict[str, Any]]:
    raw = rows(conn, "SELECT * FROM chat_messages ORDER BY id DESC LIMIT 80")
    raw.reverse()
    messages: List[Dict[str, Any]] = []
    user_cache: Dict[int, Dict[str, Any]] = {}
    for msg in raw:
        sender_name = msg.get("sender_name") or "Unknown"
        avatar_id = clean_avatar_id(msg.get("avatar_id"))
        if msg.get("user_id"):
            uid = int(msg["user_id"])
            if uid not in user_cache:
                u = row(conn, "SELECT u.id,u.username,p.id as player_id,p.callsign,f.code as faction_code,up.display_name,up.avatar_id,up.selected_badge_code FROM users u LEFT JOIN players p ON p.user_id=u.id LEFT JOIN factions f ON f.id=p.faction_id LEFT JOIN user_profiles up ON up.user_id=u.id WHERE u.id=?", (uid,)) or {}
                user_cache[uid] = u
            u = user_cache[uid]
            sender_name = u.get("display_name") or u.get("callsign") or u.get("username") or sender_name
            avatar_id = clean_avatar_id(u.get("avatar_id") or avatar_id, u.get("faction_code"), u.get("username") or u.get("callsign") or "")
        avatar = avatar_payload(avatar_id, (user_cache.get(int(msg["user_id"])) or {}).get("faction_code") if msg.get("user_id") else None)
        selected_badge_code = ""
        player_id = msg.get("player_id")
        if msg.get("user_id"):
            selected_badge_code = (user_cache.get(int(msg["user_id"])) or {}).get("selected_badge_code") or ""
        messages.append({
            "id": msg["id"],
            "userId": msg.get("user_id"),
            "playerId": player_id,
            "senderType": msg.get("sender_type") or "player",
            "senderName": sender_name,
            "avatarId": avatar_id,
            "avatarUrl": avatar["url"],
            "selectedBadgeCode": selected_badge_code,
            "selectedBadgeUrl": selected_badge_code,
            "message": msg.get("message") or "",
            "createdAt": msg.get("created_at"),
            "isCurrentUser": bool(msg.get("user_id") and int(msg["user_id"]) == int(current_user_id)),
        })
    return messages

def run_background_world_tick(conn: sqlite3.Connection) -> None:
    simulate_npc_activity(conn, force=False)
    ensure_server_world_control(conn, force=False)
    process_server_events(conn)
    process_planet_faction_wars(conn, None)
    process_territory_influence(conn, force=False)
    process_guild_planet_xp_bonus(conn)


def simulation_background_loop() -> None:
    # Dedicated server-side loop. The DB timestamp still controls the real tick interval, so duplicate calls stay harmless.
    time.sleep(5)
    while not SIMULATION_STOP_EVENT.is_set():
        conn = None
        try:
            conn = connect()
            conn.execute("BEGIN IMMEDIATE")
            run_background_world_tick(conn)
            conn.commit()
        except Exception:
            if conn:
                conn.rollback()
        finally:
            if conn:
                conn.close()
        SIMULATION_STOP_EVENT.wait(SIMULATION_BALANCE["background_loop_seconds"])


def start_simulation_thread() -> None:
    global SIMULATION_THREAD_STARTED
    if SIMULATION_THREAD_STARTED:
        return
    SIMULATION_THREAD_STARTED = True
    threading.Thread(target=simulation_background_loop, name="nova-world-simulation", daemon=True).start()


@app.on_event("startup")
def on_startup() -> None:
    if should_reset_db_on_start():
        marker = DB_PATH.with_name(".nova_reset_db_on_start_applied")
        if not marker.exists():
            backup_and_remove_db("manual-reset")
            marker.write_text(iso(), encoding="utf-8")
    try:
        migrate()
    except Exception as exc:
        if not should_rebuild_bad_db():
            raise
        backup = backup_and_remove_db("migration-failed")
        print(f"WARNING: Nova DB migration failed ({exc!r}). Backed up stale DB to {backup}. Rebuilding clean DB.", flush=True)
        migrate()
    start_simulation_thread()


@app.on_event("shutdown")
def on_shutdown() -> None:
    SIMULATION_STOP_EVENT.set()


def current_context(authorization: Optional[str] = Header(default=None)) -> Tuple[Dict[str,Any], Dict[str,Any]]:
    return auth_context_from_header(authorization)


def ensure_action_allowed(conn: sqlite3.Connection, user: Dict[str,Any], player: Dict[str,Any], action: ActionRequest) -> None:
    nonce = str(action.nonce or "").strip()
    if not nonce or len(nonce) > 128 or not re.match(r"^[A-Za-z0-9_.:-]+$", nonce):
        raise HTTPException(400, "Action nonce required")
    try:
        conn.execute("INSERT INTO action_nonces (player_id, nonce, created_at) VALUES (?,?,?)", (player["id"], nonce, iso()))
    except sqlite3.IntegrityError:
        raise HTTPException(409, "Duplicate action nonce rejected")
    conn.execute("DELETE FROM action_nonces WHERE created_at < ?", (iso(utcnow() - timedelta(hours=6)),))
    enforce_action_cooldown(int(player["id"]), action.type)
    legal_status = resolve_player_legal_state(conn, player["id"])
    jail_allowed = {"attempt_bribe", "attempt_breakout", "admin_godmode", "update_profile", "send_chat_message"}
    if legal_status.get("jailed") and action.type not in jail_allowed and not user["god_mode"]:
        raise HTTPException(409, f"You are jailed until {legal_status.get('jailedUntil')}: {legal_status.get('jailReason') or 'detained'}")
    h_until = parse_dt(player.get("hospital_until"))
    if h_until and h_until > utcnow() and action.type not in {"hospital_expedite","get_state","admin_godmode","launch_starter_ship","update_profile","send_chat_message"} and not user["god_mode"]:
        raise HTTPException(409, f"You are recovering until {h_until.isoformat()}")
    t_until = parse_dt(player.get("travel_until"))
    if t_until and t_until > utcnow() and action.type not in {"complete_travel","auto_explore_battle_tick","admin_godmode","update_profile","send_chat_message"} and not user["god_mode"]:
        raise HTTPException(409, f"You are in transit until {t_until.isoformat()}")
    cargo_status = cargo_operation_status(conn, player["id"])
    cargo_allowed = {"admin_godmode", "update_profile", "send_chat_message", "cancel_cargo_operation"}
    if cargo_status.get("active") and action.type not in cargo_allowed and not user["god_mode"]:
        raise HTTPException(409, f"Cargo {cargo_status.get('operationLabel','handling')} in progress until {cargo_status.get('completeAt')}. You cannot leave, change ships, fight, or start more cargo work.")
    departure_actions = {"go_here", "galaxy_travel"}
    travel_to_current_dock = False
    if action.type == "travel":
        try:
            travel_to_current_dock = int((action.payload or {}).get("planet_id") or 0) == int(player.get("location_planet_id") or 0) and player_is_in_open_space(conn, player["id"])
        except Exception:
            travel_to_current_dock = False
    if (action.type in departure_actions or (action.type == "travel" and not travel_to_current_dock)) and not user["god_mode"]:
        usage = build_cargo_usage(conn, player["id"])
        if usage.get("over_capacity"):
            raise HTTPException(409, f"Cargo overweight: {usage.get('total')}/{usage.get('max')} capacity. Reduce cargo to 100% or less before leaving the planet.")
    station_run = active_pirate_station_run(conn, player["id"])
    station_allowed = {"admin_godmode", "update_profile", "send_chat_message", "pirate_station_move", "pirate_station_retreat", "pirate_station_start_battle", "pirate_station_resolve_battle", "pirate_station_close_battle"}
    if station_run and action.type not in station_allowed and not user["god_mode"]:
        raise HTTPException(409, "You are inside a pirate station assault. Finish, retreat, or close the battle screen before using normal planet/system actions.")
    mission_run = active_planet_mission(conn, player["id"]) if scalar(conn, "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='planet_mission_runs'") else None
    mission_allowed = {"admin_godmode", "update_profile", "send_chat_message", "cancel_planet_mission"}
    if mission_run and action.type not in mission_allowed and not user["god_mode"]:
        raise HTTPException(409, "Planet mission in progress. Cancel it or wait for completion before using normal actions.")


def prune_admin_action_logs(conn: sqlite3.Connection) -> None:
    # Keep the game-wide action feed bounded. Admin table displays the merged last 500.
    conn.execute("DELETE FROM events WHERE id NOT IN (SELECT id FROM events ORDER BY id DESC LIMIT 500)")
    if PERF_NPC_LOGS_ENABLED:
        conn.execute("DELETE FROM npc_action_log WHERE id NOT IN (SELECT id FROM npc_action_log ORDER BY id DESC LIMIT 200)")
    else:
        conn.execute("DELETE FROM npc_action_log")
    conn.execute("DELETE FROM market_transactions WHERE id NOT IN (SELECT id FROM market_transactions ORDER BY id DESC LIMIT 500)")
    conn.execute("DELETE FROM combat_battles WHERE id NOT IN (SELECT id FROM combat_battles ORDER BY id DESC LIMIT 500)")


def add_event(conn: sqlite3.Connection, player_id: int, category: str, message: str, meta: Optional[dict] = None) -> None:
    conn.execute("INSERT INTO events (player_id,category,message,meta_json,created_at) VALUES (?,?,?,?,?)", (player_id, category, message, encode_json(meta or {}), iso()))
    prune_admin_action_logs(conn)


def admin_actor_rows(conn: sqlite3.Connection) -> List[Dict[str, Any]]:
    player_rows = rows(conn, """
        SELECT
            'player' AS actor_type,
            p.id AS actor_id,
            u.username,
            p.callsign AS name,
            p.level,
            p.xp,
            p.credits,
            p.fuel,
            p.max_fuel,
            p.energy,
            p.max_energy,
            p.cargo,
            p.max_cargo,
            p.health,
            p.max_health,
            p.heat,
            p.security_status,
            pl.name AS location_name,
            g.name AS galaxy_name,
            s.id AS ship_id,
            s.name AS ship_name,
            s.hull,
            s.max_hull,
            s.shield,
            s.max_shield,
            s.armor,
            s.destroyed,
            st.class_name,
            st.role AS ship_role,
            st.ship_tier,
            p.travel_mode,
            p.travel_until,
            p.hospital_until,
            p.cargo_operation_summary,
            p.cargo_operation_until,
            COALESCE(u.god_mode,0) AS god_mode
        FROM players p
        JOIN users u ON u.id=p.user_id
        LEFT JOIN planets pl ON pl.id=p.location_planet_id
        LEFT JOIN galaxies g ON g.id=pl.galaxy_id
        LEFT JOIN ships s ON s.id=p.active_ship_id
        LEFT JOIN ship_templates st ON st.id=s.template_id
        ORDER BY p.id
    """)
    out: List[Dict[str, Any]] = []
    now = utcnow()
    for r in player_rows:
        action = "Docked"
        if r.get("hospital_until") and parse_dt(r.get("hospital_until")) and parse_dt(r.get("hospital_until")) > now:
            action = "Recovering"
        elif r.get("cargo_operation_until") and parse_dt(r.get("cargo_operation_until")) and parse_dt(r.get("cargo_operation_until")) > now:
            action = r.get("cargo_operation_summary") or "Cargo operation"
        elif r.get("travel_until") and parse_dt(r.get("travel_until")) and parse_dt(r.get("travel_until")) > now:
            action = f"{label_for_api(r.get('travel_mode') or 'travel')} in progress"
        ship = {
            "id": r.get("ship_id"),
            "name": r.get("ship_name"),
            "role": r.get("ship_role"),
            "className": r.get("class_name"),
            "tier": r.get("ship_tier"),
            "hull": r.get("hull"),
            "maxHull": r.get("max_hull"),
            "shield": r.get("shield"),
            "maxShield": r.get("max_shield"),
            "armor": r.get("armor"),
            "destroyed": bool(r.get("destroyed")),
            "combatRating": get_ship_power(conn, r.get("ship_id")) if r.get("ship_id") else 0,
        }
        out.append({
            "id": f"player:{r.get('actor_id')}",
            "actorType": "player",
            "actorId": r.get("actor_id"),
            "username": r.get("username"),
            "name": r.get("name"),
            "level": r.get("level"),
            "xp": r.get("xp"),
            "location": r.get("location_name"),
            "galaxy": r.get("galaxy_name"),
            "currentAction": action,
            "status": "God Mode" if r.get("god_mode") else r.get("security_status"),
            "stats": {
                "credits": r.get("credits"), "fuel": r.get("fuel"), "maxFuel": r.get("max_fuel"),
                "energy": r.get("energy"), "maxEnergy": r.get("max_energy"), "cargo": r.get("cargo"),
                "maxCargo": r.get("max_cargo"), "health": r.get("health"), "maxHealth": r.get("max_health"),
                "heat": r.get("heat")
            },
            "ship": ship,
            "profile": {"username": r.get("username"), "callsign": r.get("name"), "godMode": bool(r.get("god_mode"))},
        })

    npc_rows = rows(conn, """
        SELECT
            n.*,
            p.name AS location_name,
            g.name AS galaxy_name,
            p.security_level AS npc_security_level,
            ns.objective,
            ns.action_state,
            ns.target_object_key,
            ns.x_pct,
            ns.y_pct,
            ns.destination_x_pct,
            ns.destination_y_pct,
            ns.action_until,
            ns.arrival_at,
            ns.cargo_json,
            ns.updated_at AS map_updated_at
        FROM npc_agents n
        LEFT JOIN planets p ON p.id=n.planet_id
        LEFT JOIN galaxies g ON g.id=p.galaxy_id
        LEFT JOIN npc_map_state ns ON ns.npc_id=n.id
        ORDER BY COALESCE(n.alive,1) DESC, n.id
    """)
    for n in npc_rows:
        cargo_meta = decode_json(n.get("cargo_json"), {}) or {}
        action = cargo_meta.get("objectiveLabel") or label_for_api(n.get("objective") or "idle")
        action_state = label_for_api(n.get("action_state") or ("alive" if n.get("alive") else "dead"))
        ship = npc_combat_ship_profile(n)
        out.append({
            "id": f"npc:{n.get('id')}",
            "actorType": "npc",
            "actorId": n.get("id"),
            "username": "",
            "name": n.get("name"),
            "level": n.get("level"),
            "xp": n.get("xp"),
            "location": n.get("location_name"),
            "galaxy": n.get("galaxy_name"),
            "currentAction": f"{action}: {action_state}",
            "status": "Alive" if int(n.get("alive") or 0) else "Dead",
            "stats": {
                "power": n.get("power"), "credits": n.get("credits"), "aggression": n.get("aggression"),
                "friendliness": n.get("friendliness"), "jobRank": n.get("job_rank"), "generation": n.get("generation"),
                "deathCount": n.get("death_count"), "activityRate": n.get("activity_rate"),
                "skills": decode_json(n.get("skills_json"), {}) or {},
                "x": n.get("x_pct"), "y": n.get("y_pct"),
            },
            "ship": {
                "name": ship.get("name"),
                "role": ship.get("role"),
                "className": n.get("ship_class"),
                "tier": ship.get("tier"),
                "hull": ship.get("hull"),
                "maxHull": ship.get("hull"),
                "shield": ship.get("shield"),
                "maxShield": ship.get("shield"),
                "armor": ship.get("armor"),
                "combatRating": ship.get("combatRating"),
            },
            "profile": {
                "career": n.get("career_code"), "role": n.get("role"), "disposition": n.get("disposition"),
                "marketBias": n.get("market_bias"), "target": cargo_meta.get("objectiveTargetName") or n.get("target_object_key"),
            },
        })
    return out


def admin_game_action_rows(conn: sqlite3.Connection) -> List[Dict[str, Any]]:
    rows_out: List[Dict[str, Any]] = []
    for e in rows(conn, """
        SELECT e.id, e.category, e.message, e.meta_json, e.created_at, p.callsign, u.username
        FROM events e
        LEFT JOIN players p ON p.id=e.player_id
        LEFT JOIN users u ON u.id=p.user_id
        ORDER BY e.id DESC LIMIT 500
    """):
        rows_out.append({
            "id": f"event:{e.get('id')}",
            "source": "event",
            "actionType": e.get("category") or "event",
            "actor": e.get("callsign") or e.get("username") or "System",
            "message": e.get("message"),
            "createdAt": e.get("created_at"),
            "meta": decode_json(e.get("meta_json"), {}) or {},
        })
    for e in rows(conn, "SELECT * FROM npc_action_log ORDER BY id DESC LIMIT 500"):
        rows_out.append({
            "id": f"npc:{e.get('id')}",
            "source": "npc_action",
            "actionType": e.get("action_type") or "npc",
            "actor": e.get("actor_name") or "NPC",
            "message": e.get("message"),
            "createdAt": e.get("created_at"),
            "meta": decode_json(e.get("impact_json"), {}) or {},
        })
    for e in rows(conn, """
        SELECT mt.*, p.callsign
        FROM market_transactions mt
        LEFT JOIN players p ON p.id=mt.player_id
        ORDER BY mt.id DESC LIMIT 500
    """):
        action = e.get("action") or "market"
        rows_out.append({
            "id": f"market:{e.get('id')}",
            "source": "market_transaction",
            "actionType": action,
            "actor": e.get("callsign") or e.get("source") or "Market",
            "message": f"{label_for_api(action)} {e.get('qty')}x {e.get('item_name')} for {e.get('net')} credits.",
            "createdAt": e.get("created_at"),
            "meta": {"itemCode": e.get("item_code"), "qty": e.get("qty"), "gross": e.get("gross"), "fee": e.get("fee"), "net": e.get("net"), "legal": e.get("legal")},
        })
    for e in rows(conn, """
        SELECT cb.*, p.callsign
        FROM combat_battles cb
        LEFT JOIN players p ON p.id=cb.player_id
        ORDER BY cb.id DESC LIMIT 500
    """):
        rows_out.append({
            "id": f"combat:{e.get('id')}",
            "source": "combat",
            "actionType": "combat",
            "actor": e.get("callsign") or "Player",
            "message": e.get("summary") or f"Combat vs {e.get('target_name')}",
            "createdAt": e.get("completed_at") or e.get("started_at"),
            "meta": {"target": e.get("target_name"), "targetType": e.get("target_type"), "status": e.get("status"), "outcome": e.get("outcome"), "winner": e.get("winner"), "legalState": e.get("legal_state")},
        })
    rows_out.sort(key=lambda x: x.get("createdAt") or "", reverse=True)
    return rows_out[:500]


def ship_size_class(ship: Dict[str, Any]) -> str:
    code = str(ship.get("size_class") or "").upper()
    if code in {"S", "M", "L", "C"}:
        return code
    hull = int(ship.get("max_hull") or ship.get("hull") or 1000)
    if hull >= 80000:
        return "C"
    if hull >= 20000:
        return "L"
    if hull >= 6500:
        return "M"
    return "S"


def ship_mass_value(ship: Dict[str, Any]) -> float:
    mass = float(ship.get("mass") or 0)
    if mass > 0:
        return mass
    size = ship_size_class(ship)
    cfg = SHIP_SIZE_BALANCE.get(size, SHIP_SIZE_BALANCE["M"])
    return float(cfg.get("mass") or 340)


def ship_jump_drive_bonus(conn: sqlite3.Connection, ship_id: int) -> float:
    bonus = 0.0
    for m in rows(conn, "SELECT sm.durability, mt.stats_json, mt.slot_type, mt.code FROM ship_modules sm JOIN module_templates mt ON mt.id=sm.module_template_id WHERE sm.ship_id=? AND sm.equipped=1", (ship_id,)):
        stats = decode_json(m.get("stats_json"), {}) or {}
        if str(m.get("slot_type") or "").lower() in {"core", "engine"} or "drive" in str(m.get("code") or "").lower() or "jump" in stats:
            durability = max(0.15, float(m.get("durability") or 100) / 100.0)
            bonus += (float(stats.get("drive_speed") or 0) + float(stats.get("jump") or 0) / 100.0 + float(stats.get("fuel") or 0) / 600.0) * durability
    return max(0.0, bonus)


def effective_ship_map_speed(conn: sqlite3.Connection, ship: Dict[str, Any]) -> float:
    if not ship:
        return 1.0
    base = max(0.1, float(ship.get("drive_speed") or 1.0))
    size = ship_size_class(ship)
    cfg = SHIP_SIZE_BALANCE.get(size, SHIP_SIZE_BALANCE["M"])
    size_mult = float(cfg.get("speed_mult") or 1.0)
    mass = max(1.0, ship_mass_value(ship))
    baseline = float(cfg.get("mass") or mass or 340)
    mass_penalty = (baseline / mass) ** float(SHIP_SIZE_BALANCE.get("mass_speed_exponent", 0.18))
    jump_bonus = ship_jump_drive_bonus(conn, int(ship.get("id") or 0)) * float(SHIP_SIZE_BALANCE.get("jump_drive_speed_weight", 0.55))
    speed = (base + jump_bonus) * size_mult * mass_penalty
    return round(max(float(SHIP_SIZE_BALANCE.get("minimum_map_speed", 0.28)), min(float(SHIP_SIZE_BALANCE.get("maximum_map_speed", 4.25)), float(speed))), 4)


def ship_speed_profile(conn: sqlite3.Connection, ship: Dict[str, Any]) -> Dict[str, Any]:
    size = ship_size_class(ship or {})
    return {
        "size_class": size,
        "size_label": SHIP_SIZE_BALANCE.get(size, {}).get("label", size),
        "mass": round(ship_mass_value(ship or {}), 2),
        "base_drive_speed": float((ship or {}).get("drive_speed") or 0),
        "jump_drive_bonus": round(ship_jump_drive_bonus(conn, int((ship or {}).get("id") or 0)), 3),
        "effective_map_speed": effective_ship_map_speed(conn, ship or {}),
    }


def get_ship_power(conn: sqlite3.Connection, ship_id: int) -> int:
    cache_key = ("ship_power", int(ship_id or 0))
    cached = request_cache_get(cache_key)
    if cached is not None:
        return int(cached)
    ship = row(conn, "SELECT * FROM ships WHERE id=?", (ship_id,))
    if not ship or ship["destroyed"]:
        return request_cache_set(cache_key, 0)
    ensure_ship_parts(conn)
    parts = rows(conn, "SELECT * FROM ship_parts WHERE ship_id=?", (ship_id,))
    part_ratio = sum((p["hp"] / max(1, p["max_hp"])) for p in parts) / max(1, len(parts))
    engine = next((p for p in parts if p["part_key"] == "engine"), None)
    weapons = next((p for p in parts if p["part_key"] == "weapons"), None)
    engine_ratio = (engine["hp"] / max(1, engine["max_hp"])) if engine else 1
    weapon_ratio = (weapons["hp"] / max(1, weapons["max_hp"])) if weapons else 1
    power = ship["hull"]//20 + ship["shield"]//12 + ship["armor"]*35 + int(ship["drive_speed"]*100*engine_ratio)
    for m in rows(conn, "SELECT sm.durability, mt.stats_json FROM ship_modules sm JOIN module_templates mt ON mt.id=sm.module_template_id WHERE sm.ship_id=? AND sm.equipped=1", (ship_id,)):
        stats = decode_json(m["stats_json"], {})
        durability_ratio = max(0.10, (m["durability"] or 100) / 100)
        power += int((stats.get("damage",0) * weapon_ratio + stats.get("shield",0)//2 + stats.get("armor",0)*40 + stats.get("drones",0)*100) * durability_ratio)
    result = int(power * max(0.25, part_ratio))
    request_cache_set(cache_key, result)
    return result


def get_player(conn: sqlite3.Connection, player_id: int) -> Dict[str,Any]:
    p = row(conn, "SELECT * FROM players WHERE id=?", (player_id,))
    if not p:
        raise HTTPException(404, "Player not found")
    return p



