@app.get("/api/battle-alert")
def battle_alert(ctx: Tuple[Dict[str,Any], Dict[str,Any]] = Depends(current_context)) -> Dict[str, Any]:
    user, player = ctx
    conn = connect()
    p = resolve_completed_travel(conn, get_player(conn, player["id"]))
    p = resolve_intercept_if_close(conn, p)
    resolve_player_legal_state(conn, player["id"])
    battle_row = row(conn, "SELECT * FROM combat_battles WHERE player_id=? AND status='active' ORDER BY id DESC LIMIT 1", (player["id"],))
    if not battle_row:
        actor_battle = combat_actor_active_battle(conn, f"player:{player['id']}")
        if actor_battle:
            battle_row = row(conn, "SELECT * FROM combat_battles WHERE id=? AND status='active'", (int(actor_battle["id"]),))
    battle = None
    if battle_row:
        try:
            session = load_combat_session(conn, int(battle_row["id"]), None)
            player_ref = f"player:{player['id']}"
            if (int(session.get("player_id") or 0) == int(player["id"]) or player_ref in (session.get("actor_refs") or [])) and not combat_ref_is_escaped(session, player_ref):
                battle = build_combat_session_payload(session, int(player["id"]))
        except Exception:
            battle = build_combat_battle_payload(battle_row)
    conn.commit()
    conn.close()
    return {
        "hasActiveBattle": bool(battle),
        "battle": battle,
        "recommendedPollMs": 350,
    }





COMBAT_LEGAL_ROLES = {"pirate", "mercenary", "bounty", "hunter", "hostile", "outlaw", "raider"}
COMBAT_SECURITY_ROLES = {"security", "patrol", "marshal", "customs", "turret", "gate_turret", "security_defense"}


def combat_actor_immunity_key(actor_ref: str) -> str:
    return f"combat_immunity:{actor_ref}"


def combat_post_battle_immunity_seconds() -> int:
    return max(5, int(COMBAT_BALANCE.get("post_battle_immunity_seconds", 5) or 5))


def set_combat_actor_immunity(conn: sqlite3.Connection, actor_ref: str, seconds: Optional[int] = None) -> None:
    seconds = int(seconds if seconds is not None else combat_post_battle_immunity_seconds())
    app_state_put_json(conn, combat_actor_immunity_key(str(actor_ref)), {"until": iso(utcnow() + timedelta(seconds=max(1, seconds)))})


def combat_actor_immunity_until(conn: sqlite3.Connection, actor_ref: str) -> Optional[datetime]:
    data = app_state_get_json(conn, combat_actor_immunity_key(str(actor_ref)))
    until = parse_dt(data.get("until")) if data else None
    if until and until > utcnow():
        return until
    if until:
        app_state_delete(conn, combat_actor_immunity_key(str(actor_ref)))
    return None


def combat_actor_active_battle_key(actor_ref: str) -> str:
    return f"combat_active_actor:{actor_ref}"


def set_combat_actor_active_battle(conn: sqlite3.Connection, actor_ref: str, battle_id: int) -> None:
    app_state_put_json(conn, combat_actor_active_battle_key(str(actor_ref)), {"battle_id": int(battle_id), "since": iso()})


def clear_combat_actor_active_battle(conn: sqlite3.Connection, actor_ref: str) -> None:
    app_state_delete(conn, combat_actor_active_battle_key(str(actor_ref)))


def combat_actor_active_battle(conn: sqlite3.Connection, actor_ref: str) -> Optional[Dict[str, Any]]:
    data = app_state_get_json(conn, combat_actor_active_battle_key(str(actor_ref)))
    battle_id = int(data.get("battle_id") or 0) if data else 0
    if not battle_id:
        return None
    battle = row(conn, "SELECT id,status,completed_at FROM combat_battles WHERE id=?", (battle_id,))
    if battle and str(battle.get("status") or "") == "active":
        return battle
    clear_combat_actor_active_battle(conn, actor_ref)
    return None


def combat_actor_is_immune(conn: sqlite3.Connection, actor_ref: str) -> bool:
    return bool(combat_actor_immunity_until(conn, actor_ref) or galaxy_spawn_immunity_until(conn, actor_ref))


def player_escape_chance(conn: sqlite3.Connection, player: Dict[str, Any]) -> float:
    ship = row(conn, "SELECT s.*, t.drive_speed, t.mass, t.size_class, t.role FROM ships s JOIN ship_templates t ON t.id=s.template_id WHERE s.id=?", (player.get("active_ship_id"),)) if player.get("active_ship_id") else None
    skills = player_skill_totals(conn, player["id"])
    speed = float((ship or {}).get("drive_speed") or 1.0)
    mass = max(80.0, float((ship or {}).get("mass") or 340.0))
    speed_score = speed * 0.16 + min(0.22, 220.0 / mass * 0.10)
    skill_score = min(0.24, int(skills.get("piloting", 0)) * 0.006 + int(skills.get("stealth", 0)) * 0.004 + int(skills.get("exploration", 0)) * 0.002)
    role = str((ship or {}).get("role") or "").lower()
    role_bonus = 0.08 if role in {"exploration", "trade", "cargo", "starter"} else 0.03 if role in {"combat", "siege", "fleet"} else 0.05
    chance = 0.22 + speed_score + skill_score + role_bonus
    return max(float(COMBAT_BALANCE.get("escape_chance_min", 0.20)), min(float(COMBAT_BALANCE.get("escape_chance_max", 0.80)), chance))

def combat_now_block_reason(conn: sqlite3.Connection, player: Dict[str, Any]) -> Optional[str]:
    status = jail_heat_status(conn, player["id"])
    if status.get("jailed"):
        return f"Jailed: {status.get('jailReason') or 'detained'}"

    travel = build_travel_state(conn, player)
    mode = str(travel.get("mode") or player.get("travel_mode") or "").lower()

    # Combat immunity is intentionally narrow: docked ships and galaxy-map
    # travel are protected. Local/system travel, open-space waypoints, cargo
    # work, and intercept paths remain valid battle states.
    if travel.get("docked"):
        return "Docked ships cannot be attacked. Undock or move into open space to fight."
    travel_until = parse_dt(player.get("travel_until"))
    if travel_until and travel_until > utcnow() and mode in {"galaxy", "galaxy_route"}:
        return f"Galaxy travel in progress until {player.get('travel_until')}"

    if not player.get("active_ship_id"):
        return "No active ship"
    ship = row(conn, "SELECT * FROM ships WHERE id=?", (player.get("active_ship_id"),))
    if not ship or int(ship.get("destroyed") or 0):
        return "Active ship is destroyed or unavailable"
    # Do not globally block the Fight page after an NPC battle. Specific PvP/unlawful cooldowns are enforced on those actions.
    return None


def combat_pilot_balance_context(conn: sqlite3.Connection, player_id: Any) -> Dict[str, Any]:
    try:
        pid = int(player_id or 0)
    except Exception:
        pid = 0
    if not pid:
        return {"player_id": 0, "level": 1, "skill_score": 0.0, "levelMult": 1.0, "skillMult": 1.0, "accuracyBonus": 0.0, "evasionBonus": 0.0}
    player = row(conn, "SELECT level FROM players WHERE id=?", (pid,)) or {}
    skills = player_skill_totals(conn, pid)
    skill_score = (
        float(skills.get("combat") or 0) +
        float(skills.get("piloting") or 0) * 0.60 +
        float(skills.get("bounty_hunting") or 0) * 0.35 +
        float(skills.get("engineering") or 0) * 0.15
    )
    level = max(1, int(player.get("level") or 1))
    level_mult = 1.0 + min(float(COMBAT_MATCHUP_BALANCE["level_mult_cap"]), max(0, level - 1) * float(COMBAT_MATCHUP_BALANCE["level_mult_per_level"]))
    skill_mult = 1.0 + min(float(COMBAT_MATCHUP_BALANCE["skill_mult_cap"]), skill_score * float(COMBAT_MATCHUP_BALANCE["skill_mult_per_point"]))
    return {
        "player_id": pid,
        "level": level,
        "skill_score": round(skill_score, 2),
        "levelMult": round(level_mult, 4),
        "skillMult": round(skill_mult, 4),
        "accuracyBonus": min(float(COMBAT_MATCHUP_BALANCE["max_accuracy_bonus"]), skill_score * float(COMBAT_MATCHUP_BALANCE["skill_accuracy_per_point"])),
        "evasionBonus": min(float(COMBAT_MATCHUP_BALANCE["max_evasion_bonus"]), skill_score * float(COMBAT_MATCHUP_BALANCE["skill_evasion_per_point"])),
    }


def apply_pilot_combat_scaling(profile: Dict[str, Any], pilot_ctx: Dict[str, Any]) -> Dict[str, Any]:
    if not profile or not pilot_ctx or not int(pilot_ctx.get("player_id") or 0):
        return profile
    level_mult = float(pilot_ctx.get("levelMult") or 1.0)
    skill_mult = float(pilot_ctx.get("skillMult") or 1.0)
    defense_mult = level_mult * (1.0 + (skill_mult - 1.0) * 0.78)
    offense_mult = skill_mult * (1.0 + (level_mult - 1.0) * 0.55)
    profile["hull"] = max(1, int(int(profile.get("hull") or 1) * defense_mult))
    profile["shield"] = max(0, int(int(profile.get("shield") or 0) * defense_mult))
    profile["armor"] = max(0, int(int(profile.get("armor") or 0) + max(0, int(pilot_ctx.get("level") or 1) - 1) * 0.20 + float(pilot_ctx.get("skill_score") or 0) * 0.018))
    profile["combatRating"] = max(1, int(int(profile.get("combatRating") or 1) * ((offense_mult + defense_mult) / 2.0)))
    profile["accuracy"] = min(0.94, float(profile.get("accuracy") or 0.55) + float(pilot_ctx.get("accuracyBonus") or 0.0))
    profile["evasion"] = min(0.60, float(profile.get("evasion") or 0.05) + float(pilot_ctx.get("evasionBonus") or 0.0))
    scaled_weapons = []
    for weapon in profile.get("weapons") or []:
        w = dict(weapon)
        w["damage"] = max(1, int(int(w.get("damage") or 1) * offense_mult))
        scaled_weapons.append(w)
    profile["weapons"] = scaled_weapons
    stats = dict(profile.get("stats") or {})
    stats.update({"pilotLevel": int(pilot_ctx.get("level") or 1), "pilotSkillScore": float(pilot_ctx.get("skill_score") or 0.0), "levelMult": round(level_mult, 3), "skillMult": round(skill_mult, 3)})
    profile["stats"] = stats
    return profile


def combat_profile_balance_score(profile: Dict[str, Any]) -> float:
    if not profile:
        return 1.0
    rating = max(1.0, float(profile.get("combatRating") or 1))
    durability = max(1.0, float(profile.get("hull") or 0) + float(profile.get("shield") or 0) * 0.72 + float(profile.get("armor") or 0) * 65.0)
    weapons = profile.get("weapons") or []
    weapon_score = 0.0
    for weapon in weapons:
        cost = max(1, combat_weapon_energy_requirement(weapon))
        weapon_score += float(weapon.get("damage") or 0) * float(weapon.get("accuracy") or 0.55) / (0.65 + cost * 0.35)
    return max(1.0, rating * 0.48 + durability * 0.10 + weapon_score * 5.2)


def estimated_combat_win_chance(your: Dict[str, Any], enemy: Dict[str, Any]) -> int:
    your_score = combat_profile_balance_score(your)
    enemy_score = combat_profile_balance_score(enemy)
    ratio = your_score / max(1.0, enemy_score)
    curve = float(COMBAT_MATCHUP_BALANCE.get("win_curve", 1.7))
    span = float(COMBAT_MATCHUP_BALANCE.get("win_curve_span", 38))
    return max(12, min(88, int(round(50 + math.tanh(math.log(max(0.01, ratio)) * curve) * span))))


def combat_ship_profile(conn: sqlite3.Connection, ship: Optional[Dict[str, Any]], fallback_name: str = "Unknown Ship") -> Dict[str, Any]:
    if not ship:
        return {"name": fallback_name, "image_url": ship_visual_payload(fallback_name, "ship"), "hull": 600, "shield": 250, "armor": 12, "energy": 100, "combatRating": 100, "accuracy": 0.58, "evasion": 0.12, "weapons": normalize_combat_weapons([{"name":"Improvised Battery","type":"laser","damage":85,"accuracy":0.55,"requiredEnergy":2}], 100, False), "utilities": [dict(UTILITY_ARCHETYPES[0]), dict(UTILITY_ARCHETYPES[5])], "attackEnergyMax": int(COMBAT_BALANCE.get("attack_energy_max", 12)), "stats": {}}
    derived = ship_derived_stats(conn, ship)
    installed = ship_installed_modules(conn, int(ship["id"]))
    weapons = []
    for m in installed:
        compat = m.get("compatibleSlotTypes") or [m.get("slot_type") or "utility"]
        if isinstance(compat, str):
            compat = [compat]
        stats = m.get("stats") or decode_json(m.get("stats_json"), {}) or {}
        if any(x in {"weapon", "mining"} for x in compat) or stats.get("damage"):
            dmg = int(stats.get("damage") or stats.get("mining", 0) * 2.2 or 60)
            wtype = "missile" if "missile" in str(m.get("name", "")).lower() else "laser" if "laser" in str(m.get("name", "")).lower() else "projectile"
            projectile_count = clamp_int(int(stats.get("projectile_count") or stats.get("projectileCount") or stats.get("projectiles") or stats.get("volley") or 1), 1, 6)
            weapons.append({"name": m.get("name") or "Weapon", "type": wtype, "damage": max(35, dmg), "accuracy": min(0.88, 0.55 + int(m.get("current_tier") or 1) * 0.035), "energy": int(m.get("power_usage") or stats.get("energy_use") or 8), "projectileCount": projectile_count, "projectile_count": projectile_count})
    combat_role = str(ship.get("role") or ship.get("class_name") or "").lower() in {"combat", "siege", "fleet", "gunship", "interceptor", "patrol", "security", "bounty", "mercenary"}
    weapons = normalize_combat_weapons(weapons, int(derived.get("combat_rating") or get_ship_power(conn, int(ship["id"])) or 100), combat_role)
    utilities = combat_utilities_from_modules(installed, derived)
    profile = {
        "id": ship.get("id"), "name": ship.get("name") or ship.get("template_name") or fallback_name,
        "class": ship.get("class_name") or ship.get("role") or "ship", "role": ship.get("role") or "general",
        "tier": int(ship.get("current_tier") or ship.get("ship_tier") or 1),
        "image_url": ship.get("image_url") or ship_visual_payload(ship.get("name") or ship.get("template_name") or fallback_name, ship.get("role") or ship.get("class_name")),
        "hull": max(100, int(derived.get("hull") or ship.get("hull") or ship.get("max_hull") or 600)),
        "shield": max(0, int(derived.get("shield") or ship.get("shield") or ship.get("max_shield") or 250)),
        "armor": max(0, int(derived.get("armor") or ship.get("armor") or 10)),
        "energy": max(60, int(derived.get("energy_capacity") or 100)),
        "combatRating": max(1, int(derived.get("combat_rating") or get_ship_power(conn, int(ship["id"])) or 100)),
        "accuracy": min(0.92, 0.52 + max(0, int(derived.get("scan_strength") or 0)) / 900.0),
        "evasion": min(0.55, max(0.05, int(derived.get("evasion") or 0) / 650.0)),
        "weapons": weapons, "utilities": utilities, "attackEnergyMax": int(COMBAT_BALANCE.get("attack_energy_max", 12)), "stats": derived,
    }
    return apply_pilot_combat_scaling(profile, combat_pilot_balance_context(conn, ship.get("player_id")))

PIRATE_SECURITY_BANDS = [
    {"key": "null_sec", "name": "0-sec endgame", "security_min": 0, "security_max": 14, "level_min": 45, "level_max": 80, "tier_min": 5, "tier_max": 7, "power_floor": 3600, "power_per_level": 86, "power_cap": 14000},
    {"key": "deep_low_sec", "name": "deep low-sec", "security_min": 15, "security_max": 34, "level_min": 30, "level_max": 58, "tier_min": 4, "tier_max": 6, "power_floor": 2400, "power_per_level": 68, "power_cap": 9800},
    {"key": "low_sec", "name": "low-sec", "security_min": 35, "security_max": 54, "level_min": 18, "level_max": 38, "tier_min": 3, "tier_max": 5, "power_floor": 1400, "power_per_level": 50, "power_cap": 6400},
    {"key": "border_sec", "name": "border-sec", "security_min": 55, "security_max": 74, "level_min": 8, "level_max": 24, "tier_min": 2, "tier_max": 4, "power_floor": 700, "power_per_level": 34, "power_cap": 3800},
    {"key": "high_sec", "name": "high-sec", "security_min": 75, "security_max": 100, "level_min": 1, "level_max": 14, "tier_min": 1, "tier_max": 2, "power_floor": 160, "power_per_level": 22, "power_cap": 1800},
]


def pirate_like_role(role: str, career: str = "") -> bool:
    blob = f"{role or ''} {career or ''}".lower()
    return any(key in blob for key in ("pirate", "raider", "outlaw", "corsair", "reaver")) or str(career or "").lower() == "mercenary"


def pirate_security_value(source: Dict[str, Any]) -> int:
    for key in ("npc_security_level", "npcSecurityLevel", "planet_security_level", "planetSecurityLevel", "security_level", "securityLevel"):
        value = source.get(key)
        if value is None or value == "":
            continue
        try:
            return clamp_int(int(float(value)), 0, 100)
        except Exception:
            continue
    return 50


def pirate_security_band(security_level: int) -> Dict[str, Any]:
    security = clamp_int(int(security_level or 0), 0, 100)
    for band in PIRATE_SECURITY_BANDS:
        if security >= int(band["security_min"]) and security <= int(band["security_max"]):
            return band
    return PIRATE_SECURITY_BANDS[-1]


def pirate_level_for_security(base_level: int, security_level: int, rng: random.Random) -> int:
    band = pirate_security_band(security_level)
    lo = int(band["level_min"])
    hi = int(band["level_max"])
    base = max(1, int(base_level or 1))
    if base < lo:
        mode = min(hi, lo + max(1, int((hi - lo) * 0.35)))
        return clamp_int(int(rng.triangular(lo, hi, mode)), lo, hi)
    return clamp_int(base, lo, hi)


def pirate_power_for_security(base_power: int, level: int, band: Dict[str, Any]) -> int:
    floor = int(band.get("power_floor") or 80) + int(level) * int(band.get("power_per_level") or 32)
    cap = int(band.get("power_cap") or 99999)
    return clamp_int(max(80, int(base_power or 0), floor), 80, cap)


def pirate_tier_for_security(level: int, security_level: int, rng: random.Random) -> int:
    band = pirate_security_band(security_level)
    lo = int(band["tier_min"])
    hi = int(band["tier_max"])
    base = max(lo, int(math.ceil(max(1, int(level or 1)) / 10.0)))
    roll = base + rng.choice([-1, 0, 0, 1])
    if band["key"] == "null_sec" and rng.random() < 0.35:
        roll = max(roll, hi - rng.randint(0, 1))
    return clamp_int(roll, lo, min(hi, int(TIER_BALANCE.get("max_tier", 7) or 7)))


def pirate_weapon_entry(name: str, weapon_type: str, level: int, power: int, tier: int, base: int, scale: float, accuracy: float, energy: int, projectile_count: int = 1) -> Dict[str, Any]:
    tier_mult = 1.0 + max(0, int(tier) - 1) * 0.12
    return {
        "name": name,
        "type": weapon_type,
        "damage": int((base + int(power) * scale) * tier_mult),
        "accuracy": min(0.92, float(accuracy) + int(level) * 0.005 + int(tier) * 0.006),
        "requiredEnergy": clamp_attack_energy_cost(energy),
        "projectileCount": clamp_int(projectile_count, 1, 6),
        "projectile_count": clamp_int(projectile_count, 1, 6),
    }


