    if t == "trade_unlock":
        return trade_set_lock(conn, player, int(payload.get("tradeId") or payload.get("trade_id") or 0), False)

    if t == "trade_approve":
        return trade_approve(conn, player, int(payload.get("tradeId") or payload.get("trade_id") or 0))


    if t == "enter_pirate_station":
        player = interrupt_active_local_travel(conn, player, "pirate station approach")
        station_id = int(payload.get("station_id") or payload.get("stationId") or 0)
        station = row(conn, "SELECT * FROM pirate_stations WHERE id=?", (station_id,))
        if not station:
            raise HTTPException(404, "Pirate station not found")
        range_status = action_range_status(conn, player, station, "system")
        if not god and not range_status["inRange"]:
            return start_pirate_station_approach(conn, player, station, god)
        return begin_pirate_station_run(conn, player, station_id)

    if t == "pirate_station_move":
        dx = float(payload.get("dx") or 0)
        dy = float(payload.get("dy") or 0)
        return move_pirate_station_player(conn, player, dx, dy)

    if t == "pirate_station_retreat":
        return retreat_pirate_station(conn, player, escaped=False)

    if t == "pirate_station_start_battle":
        enemy_id = int(payload.get("enemy_id") or payload.get("enemyId") or 0)
        return start_pirate_station_battle(conn, player, enemy_id)

    if t == "pirate_station_resolve_battle":
        return resolve_pirate_station_battle(conn, player, god)

    if t == "pirate_station_close_battle":
        return close_pirate_station_battle(conn, player)

    if t in {"admin_update_settings", "admin_update_world_spacing"}:
        if not user.get("god_mode"):
            raise HTTPException(403, "Admin only")
        settings = save_fuel_world_settings(conn, {
            "planet_gap_multiplier": payload.get("planet_gap_multiplier", payload.get("planetGapMultiplier")),
            "planet_min_gap": payload.get("planet_min_gap", payload.get("planetMinGap")),
            "galaxy_gap_multiplier": payload.get("galaxy_gap_multiplier", payload.get("galaxyGapMultiplier")),
            "galaxy_min_gap": payload.get("galaxy_min_gap", payload.get("galaxyMinGap")),
            "fuel_price_per_unit": payload.get("fuel_price_per_unit", payload.get("fuelPricePerUnit")),
        })
        result = rewrite_world_geometry(conn, settings)
        rebalance_trade_goods_market(conn)
        app_state_put_json(conn, FUEL_WORLD_PATCH_KEY, {"applied": True, "version": 4, "updated_at": iso(), "adminRewrite": True})
        add_event(conn, None, "admin", f"World spacing and market baselines rewritten by {user.get('username') or 'admin'}.", {"settings": settings, "result": result})
        return {"message": "World spacing settings saved and galaxy/planet positions regenerated.", "settings": settings, "result": result}

    if t in {"admin_regenerate_world", "admin_regenerate_world_spacing"}:
        if not user.get("god_mode"):
            raise HTTPException(403, "Admin only")
        ensure_fuel_market_world_patch(conn, int(player["id"]), force=True)
        result = rewrite_world_geometry(conn, fuel_world_settings(conn))
        rebalance_trade_goods_market(conn)
        add_event(conn, None, "admin", f"World geometry and trade markets regenerated by {user.get('username') or 'admin'}.", {"result": result})
        return {"message": "World geometry and trade market baselines regenerated.", "settings": fuel_world_settings(conn), "result": result}

    if t == "admin_simulate_npc_events":
        if not user.get("god_mode"):
            raise HTTPException(403, "Admin only")
        market_updates = simulate_galaxy_background_market(conn, player, force=True)
        npc_updates = simulate_active_galaxy_npc_activity(conn, player, force=True)
        add_event(conn, None, "admin", f"NPC/market simulation pulse completed in current galaxy: {npc_updates} NPC actions, {market_updates} market updates.", {"npcActions": npc_updates, "marketUpdates": market_updates})
        return {"message": f"Simulation pulse complete: {npc_updates} NPC actions, {market_updates} market updates.", "npcActions": npc_updates, "marketUpdates": market_updates}

    if t == "admin_spawn_map_objects":
        return admin_spawn_map_objects(conn, user, player, payload)

    if t == "go_here":
        map_type = str(payload.get("map_type") or "system").lower()
        if map_type == "galaxy":
            raise HTTPException(400, "Galaxy map travel is gate-only. Select a destination galaxy instead.")
        x_pct = max(1.0, min(99.0, float(payload.get("x_pct") or 50)))
        y_pct = max(1.0, min(99.0, float(payload.get("y_pct") or 50)))
        player = interrupt_active_local_travel(conn, player, "new waypoint")
        current = row(conn, "SELECT * FROM planets WHERE id=?", (player["location_planet_id"],))
        if not current:
            raise HTTPException(400, "Current location is unknown")
        origin_node = current_player_map_position(conn, player, map_type)
        distance = ((float(origin_node.get("x_pct") or 50) - x_pct) ** 2 + (float(origin_node.get("y_pct") or 50) - y_pct) ** 2) ** 0.5
        ship = row(conn, "SELECT * FROM ships WHERE id=?", (player["active_ship_id"],)) if player.get("active_ship_id") else None
        seconds = fuel_adjusted_route_seconds(conn, player, ship or {}, distance, god)
        fuel_cost = fuel_adjusted_travel_cost(conn, player, max(1, int(distance / 14)), god)
        spend(conn, pid, fuel=fuel_cost, god=god)
        now = utcnow()
        arrival = now + timedelta(seconds=seconds)
        clear_player_open_space(conn, pid)
        conn.execute("UPDATE players SET player_base_docked_id=NULL WHERE id=?", (pid,))
        clear_player_intercept(conn, pid)
        clear_player_route(conn, pid)
        set_player_waypoint(conn, pid, {
            "map_type": map_type,
            "x_pct": x_pct,
            "y_pct": y_pct,
            "label": payload.get("label") or "Open-space waypoint",
            "origin_x_pct": float(origin_node.get("x_pct") or 50),
            "origin_y_pct": float(origin_node.get("y_pct") or 50),
            "started_at": iso(now),
            "arrival_at": iso(arrival),
        })
        conn.execute(
            """UPDATE players
               SET travel_until=?, travel_destination_id=?, travel_mode='waypoint',
                   travel_started_at=?, travel_origin_planet_id=?, travel_origin_galaxy_id=?, travel_destination_galaxy_id=?
               WHERE id=?""",
            (iso(arrival), current["id"], iso(now), current["id"], current["galaxy_id"], current["galaxy_id"], pid),
        )
        add_event(conn, pid, "travel", f"Open-space waypoint plotted to {x_pct:.1f} / {y_pct:.1f}. ETA {seconds} seconds.", {"map_type": map_type, "x_pct": x_pct, "y_pct": y_pct})
        return {"message": f"Open-space waypoint plotted to {x_pct:.1f} / {y_pct:.1f}.", "seconds": seconds, "fuel_cost": fuel_cost, "x_pct": x_pct, "y_pct": y_pct}

    if t == "cancel_travel":
        travel_state = build_travel_state(conn, player)
        if not travel_state.get("active"):
            return {"message": "No active travel route to cancel."}
        mode = str(travel_state.get("mode") or "").lower()
        map_type = str(travel_state.get("map_type") or ("galaxy" if mode in {"galaxy", "galaxy_route"} else "system")).lower()
        if map_type == "galaxy" or mode in {"galaxy", "galaxy_route"}:
            raise HTTPException(409, "Gate jumps are already initiated and cannot be cancelled into galaxy open space.")
        point = current_player_map_position(conn, player, map_type)
        clear_player_waypoint(conn, pid)
        clear_player_intercept(conn, pid)
        clear_player_route(conn, pid)
        set_player_open_space(conn, pid, {
            "active": True,
            "map_type": map_type,
            "x_pct": float(point.get("x_pct") or 50),
            "y_pct": float(point.get("y_pct") or 50),
            "anchor_planet_id": player.get("location_planet_id"),
            "anchor_galaxy_id": player.get("travel_origin_galaxy_id"),
            "arrived_at": iso(),
            "label": "Cancelled route position",
        })
        conn.execute(
            """UPDATE players
               SET travel_until=NULL, travel_destination_id=NULL, travel_mode=NULL,
                   travel_started_at=NULL, travel_origin_planet_id=NULL, travel_origin_galaxy_id=NULL, travel_destination_galaxy_id=NULL
               WHERE id=?""",
            (pid,),
        )
        add_event(conn, pid, "travel", f"Travel cancelled at {point.get('x_pct'):.1f} / {point.get('y_pct'):.1f}.", {"map_type": map_type, "x_pct": point.get("x_pct"), "y_pct": point.get("y_pct")})
        return {"message": "Travel cancelled. Ship is holding in open space.", "open_space": True, "x_pct": point.get("x_pct"), "y_pct": point.get("y_pct"), "map_type": map_type}

    if t == "scan_object":
        map_type = str(payload.get("map_type") or payload.get("mapType") or "system").lower()
        map_type = "galaxy" if map_type == "galaxy" else "system"
        nodes, target, gid, scan_planet_id = resolve_object_scan_target(conn, player, map_type, payload)
        target_key = object_scan_target_key(target)
        if target_key in object_scan_known_targets(conn, player, gid, map_type):
            unlocked = {**target, "scanUnlocked": True, "scanResult": {"success": True, "alreadyKnown": True}}
            return {"message": f"Scan already resolved: {target.get('realName') or target.get('name') or target.get('label') or 'target'}.", "scan": {"success": True, "alreadyKnown": True, "successChance": 100}, "target": unlocked}
        spend(conn, pid, energy=int(SCAN_OBJECT_BALANCE["energy"]), god=god)
        scan_result = object_scan_roll(conn, player, target, god)
        target_name = target.get("realName") or target.get("name") or target.get("label") or target.get("ship_name") or "target"
        if scan_result.get("success"):
            store_object_scan_success(conn, player, target, map_type, gid, scan_result)
            unlocked = {**target, "scanUnlocked": True, "scanResult": scan_result, "scanLabel": "Scanned"}
            add_event(conn, pid, "exploration", f"Scan resolved {target_name}.", {"map_type": map_type, "target_key": target_key, **scan_result})
            grant_action_progression(conn, pid, "exploration", max(1.0, float(scan_result.get("successChance") or 20) / 28.0), True)
            return {"message": f"Scan resolved: {target_name}. Inspect is now available.", "scan": scan_result, "target": unlocked, "forceStateRefresh": True}
        add_event(conn, pid, "exploration", f"Scan failed against {target_name}.", {"map_type": map_type, "target_key": target_key, **scan_result})
        grant_action_progression(conn, pid, "exploration", 0.6, True)
        return {"message": f"Scan failed: {target_name} resisted or stayed noisy. Chance {scan_result['successChance']}%, roll {scan_result['roll']}.", "scan": scan_result, "forceStateRefresh": False}

    if t == "scan_area":
        map_type = str(payload.get("map_type") or "system").lower()
        map_type = "galaxy" if map_type == "galaxy" else "system"
        profile = scan_area_profile_for_player(conn, player, map_type)
        if profile.get("cooldown_active"):
            raise HTTPException(409, f"Area scan cooling down for {int(profile.get('remaining_seconds') or 0)} seconds.")
        x_pct = clamp_pct(float(payload.get("x_pct") if payload.get("x_pct") is not None else 50), 1, 99)
        y_pct = clamp_pct(float(payload.get("y_pct") if payload.get("y_pct") is not None else 50), 1, 99)
        spend(conn, pid, energy=OPEN_WORLD_BALANCE["scan_area_energy"], god=god)
        nodes, candidates = scan_area_candidate_objects(conn, player, map_type)
        revealed = create_scan_area_ping_and_blips(
            conn,
            player,
            map_type,
            x_pct,
            y_pct,
            float(profile["radius_pct"]),
            int(profile["duration_seconds"]),
            candidates,
            nodes,
        )
        cooldown_until = utcnow() + timedelta(seconds=int(profile["cooldown_seconds"]))
        conn.execute("UPDATE players SET scan_area_cooldown_until=? WHERE id=?", (iso(cooldown_until), pid))
        profile = scan_area_profile_for_player(conn, get_player(conn, pid) or player, map_type)
        scan_quality = clamp_int(45 + int(player_skill_totals(conn, pid).get("scanning", 0) or 0) * 2 + random.randint(-8, 18), 5, 99)
        add_event(conn, pid, "exploration", f"Area scan pinged {revealed} class contacts. Signal quality {scan_quality}%.", {"map_type": map_type, "scan_quality": scan_quality, "revealed": revealed, "radius_pct": profile["radius_pct"], "duration_seconds": profile["duration_seconds"], "cooldown_seconds": profile["cooldown_seconds"]})
        grant_action_progression(conn, pid, "exploration", max(1.0, (scan_quality / 35) + revealed * 0.15), True)
        return {"message": f"Area scan pinged {revealed} class contacts for {int(profile['duration_seconds'])} seconds. Radius {profile['radius_pct']}%, cooldown {int(profile['cooldown_seconds'])}s.", "scan_quality": scan_quality, "revealed": revealed, "scan_area": profile, "forceStateRefresh": True}

    if t == "scan_exploration_site":
        player = interrupt_active_local_travel(conn, player, "exploration scan")
        site_id = str(payload.get("site_id") or payload.get("siteId") or "")
        obj = row(conn, "SELECT * FROM map_objects WHERE object_key=? AND kind='exploration' AND state NOT IN ('deleted','expired','depleted') AND qty_remaining>0", (site_id,))
        if not obj:
            raise HTTPException(404, "Exploration signal is gone or already investigated")
        caps = player_tool_capabilities(conn, player)
        if not caps.get("can_scan") and not god:
            raise HTTPException(400, "Requires an equipped scanner/probe/relic module")
        site = map_object_to_payload(obj, player)
        require_player_action_range(conn, player, site, str(site.get("map_type") or "system"), "scan exploration site", god)
        energy = int(site.get("scanEnergy") or OPEN_WORLD_BALANCE["scan_site_energy"])
        spend(conn, pid, energy=energy, god=god)
        meta = decode_json(obj.get("metadata_json"), {}) or {}
        meta["signalState"] = "resolved"
        meta["signalQuality"] = min(100, int(meta.get("signalQuality") or 50) + 8)
        meta["name"] = meta.get("realName") or obj.get("name")
        conn.execute("UPDATE map_objects SET name=?, metadata_json=?, state='available', updated_at=? WHERE id=?", (meta.get("realName") or obj.get("name"), encode_json(meta), iso(), obj["id"]))
        map_op = start_player_map_operation(conn, player, site_id, "scanning", 8, f"Scanned {meta.get('realName') or site.get('name')}.", {"signalQuality": meta["signalQuality"]})
        grant_action_progression(conn, pid, "exploration", max(1.0, int(site.get("signalQuality") or 50) / 25), True)
        add_event(conn, pid, "exploration", f"Scanned {meta.get('realName') or site.get('name')}: {site.get('rewardHint')} potential, {site.get('riskBand')} risk.")
        return {"message": f"Scan complete: {meta.get('realName') or site.get('name')} shows {site.get('rewardHint')} potential, {site.get('riskBand')} risk, quality {meta['signalQuality']}%.", "mapOperation": map_op}

    if t == "investigate_exploration_site":
        player = interrupt_active_local_travel(conn, player, "exploration investigation")
        site_id = str(payload.get("site_id") or payload.get("siteId") or "")
        obj = row(conn, "SELECT * FROM map_objects WHERE object_key=? AND kind='exploration' AND state NOT IN ('deleted','expired','depleted') AND qty_remaining>0", (site_id,))
        if not obj:
            raise HTTPException(404, "Exploration site is gone or already investigated")
        caps = player_tool_capabilities(conn, player)
        if not caps.get("can_investigate") and not god:
            raise HTTPException(400, "Requires an equipped scanner/probe/relic module")
        site = map_object_to_payload(obj, player)
        require_player_action_range(conn, player, site, str(site.get("map_type") or "system"), "investigate exploration site", god)
        energy = int(site.get("investigateEnergy") or OPEN_WORLD_BALANCE["investigate_site_energy"])
        spend(conn, pid, energy=energy, god=god)
        skills = player_skill_totals(conn, pid)
        scan_skill = int(skills.get("scanning", 0) or 0)
        exploration_skill = int(skills.get("exploration", 0) or 0)
        quality = int(site.get("signalQuality") or 50)
        tier = int(site.get("rewardTier") or site.get("tier") or 1)
        risk = int(site.get("riskLevel") or 40)
        roll = random.randint(1, 100) + scan_skill + exploration_skill + quality // 8 - risk // 10
        if roll < 35:
            payout = random.randint(0, 450 * tier)
            outcome = "low-yield"
        elif roll < 75:
            payout = random.randint(1200 * tier, 4500 * tier)
            outcome = "useful"
        else:
            payout = random.randint(6000 * tier, 18000 * tier)
            outcome = "jackpot"
        if not god:
            conn.execute("UPDATE players SET credits=credits+? WHERE id=?", (payout, pid))
        ultra_reward = roll_exploration_node_ultra_reward(f"{pid}:{site_id}:{tier}:{quality}")
        if ultra_reward:
            granted_ultra = grant_ultra_item_to_player(conn, pid, ultra_reward["code"], "exploration_ultra", god=god)
            if granted_ultra:
                ultra_reward = granted_ultra
        conn.execute("UPDATE map_objects SET qty_remaining=0, state='depleted', locked_by_player_id=NULL, operation_type='', operation_until=NULL, updated_at=? WHERE id=?", (iso(), obj["id"]))
        result_payload = {"outcome": outcome, "payout": payout}
        if ultra_reward:
            result_payload["ultraItem"] = ultra_reward
        map_op = start_player_map_operation(conn, player, site_id, "investigation", 14 + tier * 3, f"Investigated {site.get('realName') or site.get('name')} — {outcome}.", result_payload)
        grant_action_progression(conn, pid, "exploration", max(2.0, tier * 2.2), True)
        event_message = f"Investigation {outcome}: {site.get('realName') or site.get('name')} yielded {payout:,} credits."
        if ultra_reward:
            event_message += f" Ultra discovery: {ultra_reward['name']}."
        add_event(conn, pid, "exploration", event_message, {"site_id": site_id, "outcome": outcome, "payout": payout, "ultraItem": ultra_reward})
        message = f"Investigation {outcome}: recovered {payout:,} credits. Factors: signal quality {quality}%, exploration {exploration_skill}, scanning {scan_skill}, risk {risk}%."
        if ultra_reward:
            message += f" Ultra discovery: {ultra_reward['name']} — {ultra_reward.get('specialText') or ultra_reward.get('description')}."
        return {"message": message, "mapOperation": map_op, "ultraItem": ultra_reward}

    if t == "resolve_intercept_now":
        player_now = get_player(conn, pid)
        if player_now.get("travel_mode") != "intercept":
            return {"message": "No active intercept course."}
        dest = row(conn, "SELECT * FROM planets WHERE id=?", (player_now.get("travel_destination_id"),))
        origin = row(conn, "SELECT * FROM planets WHERE id=?", (player_now.get("travel_origin_planet_id") or player_now.get("location_planet_id"),))
        if not dest:
            raise HTTPException(404, "Intercept destination is no longer available")
        contact = intercept_contact_status(conn, player_now)
        if not contact.get("inContact"):
            if build_travel_state(conn, player_now).get("active"):
                return {"message": "No contact yet. Intercept course is still tracking; battle starts only when ship circles touch.", "mode": "intercept_tracking", "contact": contact}
            return finish_intercept_without_contact(conn, player_now, dest, origin, contact, action_result=True)
        meta = get_player_intercept(conn, pid)
        target_point = contact.get("target") or {}
        if target_point:
            meta["x_pct"] = target_point.get("x_pct")
            meta["y_pct"] = target_point.get("y_pct")
            meta["contact_distance_pct"] = contact.get("distancePct")
            meta["contact_range_pct"] = contact.get("contactRangePct")
            set_player_intercept(conn, pid, meta)
        return resolve_completed_intercept(conn, player_now, dest, origin, action_result=True)

    if t == "intercept_traveler":
        target_ref = normalize_traveler_target_ref(str(payload.get("target_ref") or payload.get("traveler_id") or payload.get("id") or ""))
        current = row(conn, "SELECT * FROM planets WHERE id=?", (player["location_planet_id"],))
        if not current:
            raise HTTPException(400, "Current location is unknown")
        player = interrupt_active_local_travel(conn, player, "intercept course")

        system_map = build_system_map(conn, player)
        galaxy_map = build_galaxy_map(conn, player)
        traffic = list(system_map.get("traffic", [])) + list(galaxy_map.get("traffic", []))
        target = next((x for x in traffic if x.get("combatTargetRef") == target_ref or x.get("id") == target_ref), None)
        if not target:
            _ = get_combat_target(conn, player, target_ref)
            target = {"name": target_ref, "x_pct": 50, "y_pct": 50, "to": current["id"], "id": target_ref + ":system"}
        map_type = "galaxy" if str(target.get("id") or target_ref).endswith(":galaxy") else "system"
        if map_type == "system":
            dest_planet_id = int(target.get("to") or current["id"])
        else:
            dest_galaxy_id = int(target.get("to") or current.get("galaxy_id") or 0)
            pick = row(conn, "SELECT * FROM planets WHERE galaxy_id=? ORDER BY security_level DESC, id LIMIT 1", (dest_galaxy_id,))
            dest_planet_id = int((pick or current)["id"])
        dest = row(conn, "SELECT * FROM planets WHERE id=?", (dest_planet_id,))
        if not dest:
            raise HTTPException(404, "Intercept destination drifted out of range")

        spend(conn, pid, fuel=OPEN_WORLD_BALANCE["min_intercept_fuel"], energy=OPEN_WORLD_BALANCE["intercept_energy"], god=god)
        now = utcnow()
        open_space = get_player_open_space(conn, pid)
        if open_space.get("active") and (not open_space.get("map_type") or str(open_space.get("map_type")) == map_type):
            origin_x = float(open_space.get("x_pct") or 50)
            origin_y = float(open_space.get("y_pct") or 50)
        else:
            origin_node = player_map_center(conn, player, map_type, (system_map if map_type == "system" else galaxy_map).get("nodes", []))
            origin_x = float(origin_node.get("x_pct") or 50)
            origin_y = float(origin_node.get("y_pct") or 50)
        target_x = float(target.get("x_pct") or 50)
        target_y = float(target.get("y_pct") or 50)
        intercept_ship = row(conn, "SELECT * FROM ships WHERE id=?", (player.get("active_ship_id"),)) if player.get("active_ship_id") else {}
        intercept = predict_intercept_solution(conn, intercept_ship or {}, {"x_pct": origin_x, "y_pct": origin_y}, target, now)
        target_point = intercept["point"]
        seconds = int(intercept["seconds"])
        arrival = now + timedelta(seconds=seconds)
        set_player_intercept(conn, pid, {
            "target_ref": target_ref,
            "target_name": target.get("name") or target_ref,
            "target_role": target.get("role"),
            "map_type": map_type,
            "origin_x_pct": origin_x,
            "origin_y_pct": origin_y,
            "x_pct": float(target_point.get("x_pct") or target_x),
            "y_pct": float(target_point.get("y_pct") or target_y),
            "target_start_x_pct": target_x,
            "target_start_y_pct": target_y,
            "target_destination_x_pct": float((intercept.get("targetDestination") or {}).get("x_pct") or target_x),
            "target_destination_y_pct": float((intercept.get("targetDestination") or {}).get("y_pct") or target_y),
            "target_velocity": intercept.get("targetVelocity"),
            "predicted_contact_seconds": intercept.get("predictedContactSeconds"),
            "started_at": iso(now),
            "arrival_at": iso(arrival),
        })
        conn.execute(
            """UPDATE players
               SET travel_until=?, travel_destination_id=?, travel_mode='intercept',
                   travel_started_at=?, travel_origin_planet_id=?, travel_origin_galaxy_id=?, travel_destination_galaxy_id=?
               WHERE id=?""",
            (iso(arrival), dest_planet_id, iso(now), current["id"], current["galaxy_id"], dest.get("galaxy_id"), pid),
        )
        add_event(conn, pid, "combat", f"Intercept course plotted against {target.get('name') or target_ref}. Course aims at predicted intersection, not the target's current position.", {"target_ref": target_ref, "etaSeconds": seconds, "map_type": map_type, "intercept": intercept})
        return {"message": f"Intercept course plotted against {target.get('name') or target_ref}. Predicted contact in about {seconds} seconds.", "target_ref": target_ref, "etaSeconds": seconds, "mode": "intercept", "intercept": intercept}

    if t == "mine_ore_site":
        player = interrupt_active_local_travel(conn, player, "mining operation")
        site_id = str(payload.get("site_id") or payload.get("siteId") or "")
        obj = row(conn, "SELECT * FROM map_objects WHERE object_key=? AND kind='ore' AND state NOT IN ('deleted','expired','depleted') AND qty_remaining>0", (site_id,))
        if not obj:
            raise HTTPException(404, "Ore field is gone or depleted")
        caps = player_tool_capabilities(conn, player)
        if not caps.get("can_mine") and not god:
            raise HTTPException(400, "Requires an equipped mining laser/drill")
        site = map_object_to_payload(obj, player)
        require_player_action_range(conn, player, site, str(site.get("map_type") or "system"), "mine ore site", god)
        energy = int(site.get("energyCost") or OPEN_WORLD_BALANCE["ore_mine_min_energy"])
        qty = max(1, min(int(site.get("qtyRemaining") or site.get("qty") or 1), max(1, int(site.get("tier") or 1) * 4 + 6)))
        code = str(obj.get("code") or site.get("oreCode") or "ore")
        spend(conn, pid, energy=energy, fuel=max(1, int(site.get("tier") or 1)), god=god)
        seconds = max(8, min(90, int(16 + int(site.get("tier") or 1) * 7)))
        ultra_reward = roll_mining_ultra_reward(f"{pid}:{site_id}:{qty}:{code}:{seconds}")
        result_payload = {"qty": qty, "ore_code": code}
        if ultra_reward:
            result_payload["ultraItem"] = ultra_reward
        map_op = start_player_map_operation(conn, player, site_id, "mining", seconds, f"Mining {site.get('name')} — extracting {qty} units.", result_payload)
        conn.execute("UPDATE map_objects SET state='being_mined', locked_by_player_id=?, operation_type='mining', operation_until=?, updated_at=? WHERE id=?", (pid, map_op["ends_at"], iso(), obj["id"]))
        cargo_payload = {"ore_code": code, "ore_name": site.get("name"), "tier": int(site.get("tier") or 1), "unit_value": int(site.get("unitValue") or 60), "mass_each": float(site.get("massEach") or 1), "map_object_key": site_id, "location_name": "open space"}
        if ultra_reward:
            cargo_payload["ultra_item_code"] = ultra_reward.get("code")
        op = begin_cargo_operation(conn, pid, player["location_planet_id"], "mine_ore_site", code, site.get("name") or label_for_api(code), qty, float(site.get("massEach") or 1) * qty, 0, 0, 0, 1, cargo_payload, god)
        remaining = max(0, int(obj.get("qty_remaining") or 0) - qty)
        conn.execute("UPDATE map_objects SET qty_remaining=?, state=?, locked_by_player_id=NULL, operation_type='', operation_until=NULL, updated_at=? WHERE id=?", (remaining, "depleted" if remaining <= 0 else "available", iso(), obj["id"]))
        op["mapOperation"] = map_op
        op["message"] = f"Mining started: {site.get('name')} ({qty} units). Watch the active operation indicator. " + op.get("message", "")
        return op

